import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_ENTRE_RIOS: Article[] = [
  { id: 'const-entre-rios-art-1', lawId: 'const-entre-rios', number: '1', title: 'Forma de gobierno republicana y representativa', originalText: `La Provincia de Entre Ríos, como parte integrante de la Nación Argentina, organiza su gobierno bajo la forma republicana representativa, como lo establece esta Constitución y en el ejercicio de su soberanía no reconoce más limitación que la Constitución Federal que ha jurado obedecer y las leyes y disposiciones que en su conformidad se dictaren.`, currentText: `La Provincia de Entre Ríos, como parte integrante de la Nación Argentina, organiza su gobierno bajo la forma republicana representativa, como lo establece esta Constitución y en el ejercicio de su soberanía no reconoce más limitación que la Constitución Federal que ha jurado obedecer y las leyes y disposiciones que en su conformidad se dictaren.`, plainLanguageExplanation: 'Entre Ríos es una provincia argentina que se rige por el sistema republicano y representativo. Solo reconoce como límite a su autonomía la Constitución Nacional y las leyes federales.', practicalEffects: [], examples: ['Las leyes que dicta la Legislatura entrerriana deben respetar la Constitución Nacional, pero en todo lo no delegado al gobierno federal la provincia legisla con plena autonomía.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma republicana', 'soberanía provincial', 'Constitución Nacional', 'autonomía provincial'], order: 0, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-2', lawId: 'const-entre-rios', number: '2', title: 'División territorial en departamentos', originalText: `El territorio de la Provincia queda dividido en diecisiete departamentos denominados: Paraná, Diamante, Victoria, Gualeguay, Gualeguaychú, Uruguay, Colón, Concordia, La Paz, Villaguay, Tala, Nogoyá, San José de Feliciano, Federación, Federal, Islas del Ibicuy y San Salvador, con los límites que les acuerdan las leyes vigentes y sin perjuicio de la facultad legislativa de crear otros y modificar la jurisdicción territorial y administrativa.`, currentText: `El territorio de la Provincia queda dividido en diecisiete departamentos denominados: Paraná, Diamante, Victoria, Gualeguay, Gualeguaychú, Uruguay, Colón, Concordia, La Paz, Villaguay, Tala, Nogoyá, San José de Feliciano, Federación, Federal, Islas del Ibicuy y San Salvador, con los límites que les acuerdan las leyes vigentes y sin perjuicio de la facultad legislativa de crear otros y modificar la jurisdicción territorial y administrativa.`, plainLanguageExplanation: 'El territorio de Entre Ríos se divide en 17 departamentos. La Legislatura puede crear nuevos departamentos o cambiar sus límites.', practicalEffects: [], examples: ['Los 17 departamentos son: Paraná, Diamante, Victoria, Gualeguay, Gualeguaychú, Uruguay, Colón, Concordia, La Paz, Villaguay, Tala, Nogoyá, San José de Feliciano, Federación, Federal, Islas del Ibicuy y San Salvador.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['departamentos', 'territorio provincial', 'división territorial', 'organización territorial'], order: 1, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-3', lawId: 'const-entre-rios', number: '3', title: 'Capital de la Provincia', originalText: `Las autoridades que ejercen el gobierno residirán en la ciudad de Paraná, Capital de la Provincia.`, currentText: `Las autoridades que ejercen el gobierno residirán en la ciudad de Paraná, Capital de la Provincia.`, plainLanguageExplanation: 'La ciudad de Paraná es la capital de Entre Ríos y sede de los poderes del Estado provincial.', practicalEffects: [], examples: ['El Gobernador, la Legislatura y el Superior Tribunal de Justicia tienen sus sedes en Paraná.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Paraná', 'capital provincial', 'sede del gobierno'], order: 2, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-4', lawId: 'const-entre-rios', number: '4', title: 'Soberanía popular y participación ciudadana', originalText: `Todo poder público emana del pueblo; pero éste no gobierna ni delibera sino por medio de sus representantes y con arreglo a lo que esta Constitución establece. Todos los habitantes de la Provincia gozan de los derechos de petición y reunión pacífica. Se asegura el derecho a la plena participación en las decisiones de los poderes públicos sobre los asuntos de interés general a través de los procedimientos que esta Constitución dispone. Es nula cualquier disposición adoptada por las autoridades a requisición de fuerza armada o de reunión sediciosa.`, currentText: `Todo poder público emana del pueblo; pero éste no gobierna ni delibera sino por medio de sus representantes y con arreglo a lo que esta Constitución establece. Todos los habitantes de la Provincia gozan de los derechos de petición y reunión pacífica. Se asegura el derecho a la plena participación en las decisiones de los poderes públicos sobre los asuntos de interés general a través de los procedimientos que esta Constitución dispone. Es nula cualquier disposición adoptada por las autoridades a requisición de fuerza armada o de reunión sediciosa.`, plainLanguageExplanation: 'El poder pertenece al pueblo, que lo ejerce a través de representantes. Todos tienen derecho a peticionar y reunirse. Las decisiones tomadas bajo presión de fuerzas armadas o grupos sediciosos son nulas.', practicalEffects: [], examples: ['Un ciudadano puede presentar una petición a la Legislatura. Un decreto dictado a pedido de un grupo armado es nulo de pleno derecho.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['soberanía popular', 'representación', 'derecho de petición', 'reunión pacífica', 'participación ciudadana'], order: 3, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-5', lawId: 'const-entre-rios', number: '5', title: 'Derechos implícitos y no restricción de garantías', originalText: `Los derechos, declaraciones y garantías enumerados en la Constitución Nacional y que esta Constitución da por reproducidos, no serán entendidos como negación de otros derechos y garantías no enumerados, pero que nacen del principio de la soberanía del pueblo, de la forma republicana de gobierno y que corresponden al hombre en su calidad de tal. Los derechos y garantías consagrados por esta Constitución no serán alterados por las leyes que reglamenten su ejercicio, ni limitados por más restricciones que las indispensables para asegurar la vida del Estado, el derecho de terceros, la moral y el orden público.`, currentText: `Los derechos, declaraciones y garantías enumerados en la Constitución Nacional y que esta Constitución da por reproducidos, no serán entendidos como negación de otros derechos y garantías no enumerados, pero que nacen del principio de la soberanía del pueblo, de la forma republicana de gobierno y que corresponden al hombre en su calidad de tal. Los derechos y garantías consagrados por esta Constitución no serán alterados por las leyes que reglamenten su ejercicio, ni limitados por más restricciones que las indispensables para asegurar la vida del Estado, el derecho de terceros, la moral y el orden público.`, plainLanguageExplanation: 'Los derechos no enumerados en la Constitución también existen si derivan de la dignidad humana o la forma republicana. Las leyes pueden reglamentar los derechos pero no pueden alterarlos ni restringirlos más de lo estrictamente necesario.', practicalEffects: [], examples: ['El derecho a la privacidad digital puede invocarse aunque no figure textualmente en la Constitución, porque deriva de la dignidad humana. Una ley que prohibiera publicar opiniones políticas sería inconstitucional por alterar el derecho a la libre expresión.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos implícitos', 'reglamentación de derechos', 'no restricción', 'garantías fundamentales'], order: 4, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-6', lawId: 'const-entre-rios', number: '6', title: 'Supremacía constitucional, prohibición de golpes y memoria democrática', originalText: `En ningún caso podrán las autoridades de la Provincia suspender la observancia de esta Constitución, ni la de la Nación, ni la efectividad de las garantías y derechos establecidos en ambas. La Constitución Nacional y esta Constitución no perderán su vigencia si se dejaren de observar por actos de fuerza o fueren suspendidas, abrogadas o derogadas por otro medio distinto de los que ellas disponen. Queda garantizado el sistema democrático de gobierno. Cualquier acto de fuerza contrario a esta Constitución, a las instituciones por ella establecidas o al sistema republicano es insanablemente nulo. Es condición de idoneidad para ocupar cualquier función de gobierno no haber desempeñado a partir del 24 de marzo de 1976 cargos de responsabilidad política en los regímenes de facto. Los delitos que sean cometidos en el ejercicio de la función usurpada no podrán ser objeto de indulto o conmutación de pena. Quienes hayan participado en delitos de lesa humanidad o incurran en su apología, serán inhabilitados a perpetuidad para ejercer la función pública. Queda prohibida la institucionalización de secciones especiales en los cuerpos de seguridad destinadas a la represión o discriminación de carácter político. El Estado garantiza el rescate de la memoria reciente. Los habitantes de la Provincia tienen el derecho de resistencia legítima contra quienes ejecutaren los actos de fuerza aquí enunciados.`, currentText: `En ningún caso podrán las autoridades de la Provincia suspender la observancia de esta Constitución, ni la de la Nación, ni la efectividad de las garantías y derechos establecidos en ambas. La Constitución Nacional y esta Constitución no perderán su vigencia si se dejaren de observar por actos de fuerza o fueren suspendidas, abrogadas o derogadas por otro medio distinto de los que ellas disponen. Queda garantizado el sistema democrático de gobierno. Cualquier acto de fuerza contrario a esta Constitución, a las instituciones por ella establecidas o al sistema republicano es insanablemente nulo. Es condición de idoneidad para ocupar cualquier función de gobierno no haber desempeñado a partir del 24 de marzo de 1976 cargos de responsabilidad política en los regímenes de facto. Los delitos que sean cometidos en el ejercicio de la función usurpada no podrán ser objeto de indulto o conmutación de pena. Quienes hayan participado en delitos de lesa humanidad o incurran en su apología, serán inhabilitados a perpetuidad para ejercer la función pública. Queda prohibida la institucionalización de secciones especiales en los cuerpos de seguridad destinadas a la represión o discriminación de carácter político. El Estado garantiza el rescate de la memoria reciente. Los habitantes de la Provincia tienen el derecho de resistencia legítima contra quienes ejecutaren los actos de fuerza aquí enunciados.`, plainLanguageExplanation: 'La Constitución no puede suspenderse ni por golpe de Estado. Quienes hayan tenido responsabilidad política en la dictadura del 24/3/1976 no pueden ejercer cargos de gobierno. Los responsables de delitos de lesa humanidad quedan inhabilitados a perpetuidad para la función pública. Los ciudadanos tienen derecho de resistencia legítima frente a quienes intenten imponer un golpe.', practicalEffects: [], examples: ['Un ex funcionario de la última dictadura militar no puede postularse para gobernador. Un juez que detecta una disposición dictada por un régimen de facto puede declararla nula sin necesidad de declaración previa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['supremacía constitucional', 'democracia', 'dictadura', 'lesa humanidad', 'memoria histórica', 'derecho de resistencia', 'golpe de estado'], order: 5, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-7', lawId: 'const-entre-rios', number: '7', title: 'Derechos de los habitantes e intervención federal', originalText: `Los habitantes de la Provincia, gozan en su territorio de todos los derechos y garantías declarados por la Constitución Nacional, con arreglo a las leyes que reglamenten su ejercicio. En caso de intervención del Gobierno Federal, los actos administrativos que el representante nacional practique durante el desempeño de su función serán, válidos para la Provincia, si hubieren sido realizados de acuerdo con esta Constitución y las leyes de la Provincia. Los magistrados y funcionarios nombrados por una intervención federal tendrán carácter precario y transitorio. Cesarán en sus cargos al concluir la intervención o de pleno derecho a los noventa días de asumir las autoridades provinciales electas.`, currentText: `Los habitantes de la Provincia, gozan en su territorio de todos los derechos y garantías declarados por la Constitución Nacional, con arreglo a las leyes que reglamenten su ejercicio. En caso de intervención del Gobierno Federal, los actos administrativos que el representante nacional practique durante el desempeño de su función serán, válidos para la Provincia, si hubieren sido realizados de acuerdo con esta Constitución y las leyes de la Provincia. Los magistrados y funcionarios nombrados por una intervención federal tendrán carácter precario y transitorio. Cesarán en sus cargos al concluir la intervención o de pleno derecho a los noventa días de asumir las autoridades provinciales electas.`, plainLanguageExplanation: 'Los habitantes de Entre Ríos gozan de todos los derechos constitucionales nacionales. Durante una intervención federal, los actos del interventor son válidos si respetan la Constitución provincial. Los funcionarios nombrados por el interventor son temporarios y cesan cuando asumen las autoridades electas.', practicalEffects: [], examples: ['Si el gobierno nacional interviene la provincia, el interventor puede dictar decretos válidos, pero los jueces que nombre son transitorios: cesan a los 90 días de que el gobernador electo asume.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos constitucionales', 'intervención federal', 'magistrados transitorios', 'autoridades provinciales'], order: 6, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-8', lawId: 'const-entre-rios', number: '8', title: 'Soberanía tributaria provincial — prohibición de delegación', originalText: `Toda autoridad que en virtud de las leyes de la Nación sea ejercida en el territorio de la Provincia deberá respetar los derechos y garantías que esta Constitución acuerda, y será obligación de los magistrados imponer sin demoras su efectivo cumplimiento. Las autoridades provinciales no admitirán el ejercicio por cualquier otra de facultades no delegadas a la Nación bajo apercibimiento de ser considerado causal de mal desempeño. Esta Constitución reivindica la potestad provincial en materia tributaria vedándose la delegación de atribuciones locales a la Nación. La Provincia no podrá celebrar tratados o convenios con la Nación u otras provincias, mediante los cuales se declinen los derechos de establecer o percibir impuestos que le son privativos. Sólo se podrán suscribir convenios de coparticipación que no menoscaben sus ingresos.`, currentText: `Toda autoridad que en virtud de las leyes de la Nación sea ejercida en el territorio de la Provincia deberá respetar los derechos y garantías que esta Constitución acuerda, y será obligación de los magistrados imponer sin demoras su efectivo cumplimiento. Las autoridades provinciales no admitirán el ejercicio por cualquier otra de facultades no delegadas a la Nación bajo apercibimiento de ser considerado causal de mal desempeño. Esta Constitución reivindica la potestad provincial en materia tributaria vedándose la delegación de atribuciones locales a la Nación. La Provincia no podrá celebrar tratados o convenios con la Nación u otras provincias, mediante los cuales se declinen los derechos de establecer o percibir impuestos que le son privativos. Sólo se podrán suscribir convenios de coparticipación que no menoscaben sus ingresos.`, plainLanguageExplanation: 'Toda autoridad federal que actúe en Entre Ríos debe respetar los derechos provinciales. La provincia no puede ceder sus potestades tributarias a la Nación. Solo puede firmar convenios de coparticipación que no reduzcan sus ingresos. Quien permita que la Nación ejerza facultades tributarias provinciales comete mal desempeño.', practicalEffects: [], examples: ['Si el gobierno nacional pretende cobrar un impuesto que por la Constitución provincial le corresponde a Entre Ríos, el gobernador debe resistirlo. Ceder ese poder tributario sería causal de juicio político.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['soberanía tributaria', 'coparticipación', 'facultades no delegadas', 'mal desempeño', 'potestad provincial'], order: 7, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-9', lawId: 'const-entre-rios', number: '9', title: 'Libertad de culto y neutralidad religiosa del Estado', originalText: `El Estado no podrá dictar leyes ni otras medidas que restrinjan o protejan culto alguno. Es inviolable en el territorio de la Provincia el derecho que todo hombre tiene para profesar su culto libre y públicamente, según los dictados de su conciencia, sin más limitaciones que las impuestas por la moral, las buenas costumbres y el orden público.`, currentText: `El Estado no podrá dictar leyes ni otras medidas que restrinjan o protejan culto alguno. Es inviolable en el territorio de la Provincia el derecho que todo hombre tiene para profesar su culto libre y públicamente, según los dictados de su conciencia, sin más limitaciones que las impuestas por la moral, las buenas costumbres y el orden público.`, plainLanguageExplanation: 'El Estado provincial es neutro en materia religiosa: no puede favorecer ni perjudicar a ningún culto. Todo habitante tiene libertad de practicar su religión pública y privadamente, siempre que no afecte la moral o el orden público.', practicalEffects: [], examples: ['El gobierno provincial no puede subsidiar exclusivamente a la Iglesia Católica ni puede prohibir el proselitismo de una religión en particular. Una persona puede practicar cualquier religión en su domicilio o en espacios públicos habilitados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de culto', 'libertad religiosa', 'neutralidad estatal', 'Estado laico'], order: 8, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-10', lawId: 'const-entre-rios', number: '10', title: 'Derecho a la identidad y registro civil', originalText: `El Estado garantiza el derecho a la identidad personal. Arbitrará las medidas para la adecuada e inmediata identificación de las personas. No podrá negarse ningún servicio urgente en razón de la falta de identificación del peticionante. El registro del estado civil de las personas será uniformemente llevado en toda la Provincia por las autoridades civiles, sin distinción de creencias religiosas, en la forma que lo establezca la ley.`, currentText: `El Estado garantiza el derecho a la identidad personal. Arbitrará las medidas para la adecuada e inmediata identificación de las personas. No podrá negarse ningún servicio urgente en razón de la falta de identificación del peticionante. El registro del estado civil de las personas será uniformemente llevado en toda la Provincia por las autoridades civiles, sin distinción de creencias religiosas, en la forma que lo establezca la ley.`, plainLanguageExplanation: 'Toda persona tiene derecho a su identidad. El Estado debe asegurar la identificación de las personas y no puede negar servicios urgentes (salud, emergencias) por falta de documento. El registro civil es laico y uniforme en toda la provincia.', practicalEffects: [], examples: ['Un hospital público no puede negar la atención de urgencia a alguien que no lleva su DNI. El registro de nacimientos y matrimonios lo llevan autoridades civiles, no eclesiásticas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['identidad personal', 'registro civil', 'servicio urgente', 'documento de identidad', 'laicismo'], order: 9, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-11', lawId: 'const-entre-rios', number: '11', title: 'Derecho de enseñar y aprender', originalText: `Todos los habitantes de la Provincia gozan del derecho de enseñar y aprender conforme a las leyes que reglamenten su ejercicio.`, currentText: `Todos los habitantes de la Provincia gozan del derecho de enseñar y aprender conforme a las leyes que reglamenten su ejercicio.`, plainLanguageExplanation: 'Todo habitante de Entre Ríos tiene derecho a dar y recibir educación. Las leyes pueden regular cómo se ejerce ese derecho pero no pueden suprimirlo.', practicalEffects: [], examples: ['Una persona puede abrir una escuela privada o dar clases particulares. Los padres pueden elegir la educación de sus hijos dentro del marco legal vigente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación', 'enseñar', 'aprender', 'libertad de enseñanza'], order: 10, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-12', lawId: 'const-entre-rios', number: '12', title: 'Libertad de expresión y prohibición de censura previa', originalText: `El Estado garantiza la libertad de expresión, creencias y corrientes de pensamiento. La libertad de la palabra escrita o hablada, es un derecho asegurado a los habitantes de la Provincia, sin que en ningún caso puedan dictarse medidas preventivas para el uso de esta libertad, ni restringirla ni limitarla en manera alguna. Los que abusen de esta libertad, serán responsables ante la justicia ordinaria en la forma que lo prescriba la ley.`, currentText: `El Estado garantiza la libertad de expresión, creencias y corrientes de pensamiento. La libertad de la palabra escrita o hablada, es un derecho asegurado a los habitantes de la Provincia, sin que en ningún caso puedan dictarse medidas preventivas para el uso de esta libertad, ni restringirla ni limitarla en manera alguna. Los que abusen de esta libertad, serán responsables ante la justicia ordinaria en la forma que lo prescriba la ley.`, plainLanguageExplanation: 'La libertad de expresión y pensamiento están garantizadas. El Estado no puede dictar medidas preventivas (censura previa) para impedir publicaciones. Quien abusa de esta libertad responde ante la justicia, pero después de publicar, no antes.', practicalEffects: [], examples: ['Un periódico no puede ser clausurado preventivamente por sus notas. Si una nota es calumniosa, el afectado puede demandar al periodista, pero no puede pedirle al juez que impida la publicación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de expresión', 'censura previa', 'libertad de prensa', 'responsabilidad posterior'], order: 11, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-13', lawId: 'const-entre-rios', number: '13', title: 'Acceso a la información pública y derecho a réplica', originalText: `Se reconoce el derecho al acceso informal y gratuito a la información pública, completa, veraz, adecuada y oportuna, que estuviera en poder de cualquiera de los poderes u órganos, entes o empresas del Estado, municipios, comunas y universidades. Sólo mediante una ley puede restringirse, en resguardo de otros derechos que al tiempo de la solicitud prevalezcan sobre éste, la que deberá establecer el plazo de reserva de dicha información. La información será recopilada en el medio de almacenamiento de datos de acceso más universal que permita la tecnología disponible. Toda persona afectada en su honra o reputación por informaciones maliciosas, inexactas o agraviantes, emitidas en su perjuicio a través de un medio de comunicación social de cualquier especie, tiene el derecho a obtener su rectificación o respuesta por el mismo medio. La mera crítica no está sujeta al derecho a réplica. La ley reglamentará lo previsto en la presente disposición.`, currentText: `Se reconoce el derecho al acceso informal y gratuito a la información pública, completa, veraz, adecuada y oportuna, que estuviera en poder de cualquiera de los poderes u órganos, entes o empresas del Estado, municipios, comunas y universidades. Sólo mediante una ley puede restringirse, en resguardo de otros derechos que al tiempo de la solicitud prevalezcan sobre éste, la que deberá establecer el plazo de reserva de dicha información. La información será recopilada en el medio de almacenamiento de datos de acceso más universal que permita la tecnología disponible. Toda persona afectada en su honra o reputación por informaciones maliciosas, inexactas o agraviantes, emitidas en su perjuicio a través de un medio de comunicación social de cualquier especie, tiene el derecho a obtener su rectificación o respuesta por el mismo medio. La mera crítica no está sujeta al derecho a réplica. La ley reglamentará lo previsto en la presente disposición.`, plainLanguageExplanation: 'Cualquier persona puede pedir información al Estado (incluyendo municipios y universidades) gratis. Si un medio publica algo falso que daña el honor de alguien, esa persona puede exigir rectificación en el mismo medio. La mera crítica no da derecho a réplica.', practicalEffects: [], examples: ['Un ciudadano puede pedir el presupuesto ejecutado de un municipio sin acreditar motivo. Si un diario publica datos falsos sobre alguien, esa persona puede exigir rectificación en ese mismo diario.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acceso a información pública', 'derecho a réplica', 'rectificación', 'transparencia', 'honor'], order: 12, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-14', lawId: 'const-entre-rios', number: '14', title: 'Publicidad oficial — criterios de distribución y transparencia', originalText: `La publicidad oficial comprende la realizada por la Provincia, los municipios y las comunas, en todos sus estamentos y organismos. Su objeto es garantizar la vigencia del principio republicano de publicidad de los actos de gobierno y el derecho a la información pública. Su adjudicación se rige por los principios de transparencia, eficacia, pluralismo y austeridad. La ley establecerá pautas objetivas para asegurar la distribución equitativa y no discriminatoria de espacios en los medios de comunicación social que se inscriban para tal fin. La publicidad oficial no podrá incluir mensajes discriminatorios ni contrarios a los principios constitucionales. La de los entes y empresas deberá tener relación directa con el objeto social de los mismos.`, currentText: `La publicidad oficial comprende la realizada por la Provincia, los municipios y las comunas, en todos sus estamentos y organismos. Su objeto es garantizar la vigencia del principio republicano de publicidad de los actos de gobierno y el derecho a la información pública. Su adjudicación se rige por los principios de transparencia, eficacia, pluralismo y austeridad. La ley establecerá pautas objetivas para asegurar la distribución equitativa y no discriminatoria de espacios en los medios de comunicación social que se inscriban para tal fin. La publicidad oficial no podrá incluir mensajes discriminatorios ni contrarios a los principios constitucionales. La de los entes y empresas deberá tener relación directa con el objeto social de los mismos.`, plainLanguageExplanation: 'La pauta publicitaria del Estado debe distribuirse equitativamente entre medios. No puede usarse para premiar o castigar medios por su línea editorial. Los mensajes oficiales no pueden incluir contenidos discriminatorios.', practicalEffects: [], examples: ['El gobierno provincial no puede concentrar toda la publicidad oficial en medios afines. La distribución debe seguir criterios objetivos fijados por ley.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidad oficial', 'libertad de prensa', 'distribución equitativa', 'transparencia', 'medios de comunicación'], order: 13, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-15', lawId: 'const-entre-rios', number: '15', title: 'Igualdad, dignidad humana y no discriminación', originalText: `El Estado garantiza el derecho a la diversidad, al pluralismo y la igualdad de oportunidades. No podrán ser fundamento de privilegio: la naturaleza, la filiación, el sexo, la riqueza, las ideas políticas, la condición cultural, ni las creencias religiosas o cualquier otra condición o circunstancia personal o social. La dignidad de la persona, los derechos inalienables que le son inherentes, el libre desarrollo de la personalidad, el respeto a la ley y a los derechos de los demás, son el fundamento del orden político y de la paz social. Los derechos humanos y las garantías establecidas expresa o implícitamente por el orden jurídico vigente tienen plena operatividad.`, currentText: `El Estado garantiza el derecho a la diversidad, al pluralismo y la igualdad de oportunidades. No podrán ser fundamento de privilegio: la naturaleza, la filiación, el sexo, la riqueza, las ideas políticas, la condición cultural, ni las creencias religiosas o cualquier otra condición o circunstancia personal o social. La dignidad de la persona, los derechos inalienables que le son inherentes, el libre desarrollo de la personalidad, el respeto a la ley y a los derechos de los demás, son el fundamento del orden político y de la paz social. Los derechos humanos y las garantías establecidas expresa o implícitamente por el orden jurídico vigente tienen plena operatividad.`, plainLanguageExplanation: 'Nadie puede ser privilegiado o discriminado por origen, sexo, riqueza, ideas políticas, cultura o religión. La dignidad humana es la base del orden político. Los derechos humanos reconocidos por el ordenamiento jurídico son directamente operativos.', practicalEffects: [], examples: ['No se puede negar un empleo público a alguien por sus ideas políticas. Un juez puede aplicar directamente los derechos humanos reconocidos aunque no haya ley reglamentaria específica.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['igualdad', 'no discriminación', 'dignidad humana', 'pluralismo', 'derechos humanos'], order: 14, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-16', lawId: 'const-entre-rios', number: '16', title: 'Derecho a la vida', originalText: `La Provincia reconoce y garantiza a las personas el derecho a la vida y, en general, desde la concepción hasta la muerte digna. Nadie puede ser privado de ella arbitrariamente.`, currentText: `La Provincia reconoce y garantiza a las personas el derecho a la vida y, en general, desde la concepción hasta la muerte digna. Nadie puede ser privado de ella arbitrariamente.`, plainLanguageExplanation: 'El derecho a la vida está protegido desde la concepción hasta la muerte digna. Nadie puede ser privado de su vida arbitrariamente.', practicalEffects: [], examples: ['Este artículo sirve de fundamento para impugnar normas que atenten contra la vida humana, y para demandar al Estado cuando su omisión cause la muerte de una persona.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho a la vida', 'concepción', 'muerte digna', 'inviolabilidad de la vida'], order: 15, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-17', lawId: 'const-entre-rios', number: '17', title: 'Igualdad de género y equidad en representación política', originalText: `Se garantiza la igualdad real de oportunidades y de trato para mujeres y varones en el pleno y efectivo ejercicio de los derechos que fueren reconocidos en el ordenamiento jurídico. Una política de Estado prevendrá en forma continua todo tipo de violencia y dispondrá acciones positivas para corregir cualquier desigualdad de género. Adopta el principio de equidad de género en todos los órdenes, eliminando de sus políticas públicas cualquier exclusión, segregación o discriminación que se le oponga. Asegura a la mujer la igualdad real de oportunidades para el acceso a los diferentes estamentos y organismos del Estado provincial, municipal y comunal. Establece y sostiene la equidad de género en la representación política y partidaria y en la conformación de candidaturas con probabilidad de resultar electas. Promueve el acceso efectivo de la mujer a todos los niveles de participación, representación, decisión y conducción de las organizaciones de la sociedad civil. Reconoce el valor social del trabajo en el ámbito del hogar.`, currentText: `Se garantiza la igualdad real de oportunidades y de trato para mujeres y varones en el pleno y efectivo ejercicio de los derechos que fueren reconocidos en el ordenamiento jurídico. Una política de Estado prevendrá en forma continua todo tipo de violencia y dispondrá acciones positivas para corregir cualquier desigualdad de género. Adopta el principio de equidad de género en todos los órdenes, eliminando de sus políticas públicas cualquier exclusión, segregación o discriminación que se le oponga. Asegura a la mujer la igualdad real de oportunidades para el acceso a los diferentes estamentos y organismos del Estado provincial, municipal y comunal. Establece y sostiene la equidad de género en la representación política y partidaria y en la conformación de candidaturas con probabilidad de resultar electas. Promueve el acceso efectivo de la mujer a todos los niveles de participación, representación, decisión y conducción de las organizaciones de la sociedad civil. Reconoce el valor social del trabajo en el ámbito del hogar.`, plainLanguageExplanation: 'El Estado debe garantizar igualdad real (no solo formal) entre varones y mujeres en todos los ámbitos: acceso a cargos públicos, representación política y candidaturas electorales. Las listas electorales deben garantizar paridad real de chances para las mujeres. Se reconoce el valor del trabajo doméstico.', practicalEffects: [], examples: ['Las listas de candidatos para la Legislatura deben respetar criterios de paridad de género con chances reales de ganar. Una mujer puede demandar al Estado si no accede a un cargo público por razones de género.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['igualdad de género', 'paridad política', 'violencia de género', 'trabajo doméstico', 'discriminación'], order: 16, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-18', lawId: 'const-entre-rios', number: '18', title: 'Protección de la familia, niñez, jóvenes y adultos mayores', originalText: `El Estado reconoce a la familia como el núcleo fundamental de la sociedad a la que protege promoviendo su desarrollo y afianzamiento. Brinda asistencia especial a la maternidad e infancia e impulsa políticas activas contra las adicciones. Asegura la investigación científica, prevención, tratamiento, asistencia familiar y recuperación e inserción de los afectados. Establece la protección integral de los niños, niñas y adolescentes, en especial aquellos en situación de carencia, discriminación o ejercicio abusivo de autoridad familiar o de terceros. Promueve asimismo el desarrollo y la integración de los jóvenes y su participación social y estatal. Con la participación de la familia, el Estado reconoce a los adultos mayores el pleno ejercicio de sus derechos, brindándoles asistencia, seguridad y previsión social. Promueve la conciencia de respeto y solidaridad entre las generaciones. Y los protege contra toda violencia.`, currentText: `El Estado reconoce a la familia como el núcleo fundamental de la sociedad a la que protege promoviendo su desarrollo y afianzamiento. Brinda asistencia especial a la maternidad e infancia e impulsa políticas activas contra las adicciones. Asegura la investigación científica, prevención, tratamiento, asistencia familiar y recuperación e inserción de los afectados. Establece la protección integral de los niños, niñas y adolescentes, en especial aquellos en situación de carencia, discriminación o ejercicio abusivo de autoridad familiar o de terceros. Promueve asimismo el desarrollo y la integración de los jóvenes y su participación social y estatal. Con la participación de la familia, el Estado reconoce a los adultos mayores el pleno ejercicio de sus derechos, brindándoles asistencia, seguridad y previsión social. Promueve la conciencia de respeto y solidaridad entre las generaciones. Y los protege contra toda violencia.`, plainLanguageExplanation: 'El Estado protege a la familia, la maternidad, la infancia y los adultos mayores. Tiene obligación de intervenir para proteger a niños y adolescentes víctimas de abuso o abandono. Políticas contra las adicciones y programas de inserción de jóvenes son mandatos constitucionales.', practicalEffects: [], examples: ['Si un menor es víctima de violencia familiar, el Estado puede intervenir para protegerlo. El Estado debe proveer políticas de prevención de adicciones y programas de integración de jóvenes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['familia', 'niñez', 'adolescencia', 'adultos mayores', 'maternidad', 'adicciones', 'violencia familiar'], order: 17, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-19', lawId: 'const-entre-rios', number: '19', title: 'Derecho a la salud y sistema sanitario público', originalText: `La Provincia reconoce la salud como derecho humano fundamental, desarrollando políticas de atención primaria. La asistencia sanitaria será gratuita, universal, igualitaria, integral, adecuada y oportuna. Será prioritaria la inversión en salud, garantizando el primer nivel de atención, así como la formación y capacitación. Se implementará un seguro provincial de salud para toda la población y una progresiva descentralización hospitalaria. El medicamento es un bien social básico. El Estado regula y fiscaliza el circuito de producción, comercialización y consumo de éstos y de los productos alimenticios, tecnología médica y acredita los servicios en salud. La ley propenderá a jerarquizar el nivel de atención hospitalaria de tiempo completo.`, currentText: `La Provincia reconoce la salud como derecho humano fundamental, desarrollando políticas de atención primaria. La asistencia sanitaria será gratuita, universal, igualitaria, integral, adecuada y oportuna. Será prioritaria la inversión en salud, garantizando el primer nivel de atención, así como la formación y capacitación. Se implementará un seguro provincial de salud para toda la población y una progresiva descentralización hospitalaria. El medicamento es un bien social básico. El Estado regula y fiscaliza el circuito de producción, comercialización y consumo de éstos y de los productos alimenticios, tecnología médica y acredita los servicios en salud. La ley propenderá a jerarquizar el nivel de atención hospitalaria de tiempo completo.`, plainLanguageExplanation: 'La salud es un derecho humano. La atención sanitaria pública es gratuita, universal e integral. El medicamento es un bien social básico — el Estado regula su producción y comercialización.', practicalEffects: [], examples: ['Un hospital público no puede cobrar por atención a personas sin obra social. El Estado puede regular precios de medicamentos por ser bienes sociales básicos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho a la salud', 'salud pública', 'medicamentos', 'atención primaria', 'seguro de salud', 'hospital público'], order: 18, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-20', lawId: 'const-entre-rios', number: '20', title: 'Derechos sexuales y reproductivos', originalText: `Los derechos sexuales y reproductivos son derechos humanos básicos. La Provincia asegura mediante políticas públicas la información, orientación, métodos y prestaciones de servicios referidos a la salud sexual, la procreación responsable y la protección a la mujer embarazada.`, currentText: `Los derechos sexuales y reproductivos son derechos humanos básicos. La Provincia asegura mediante políticas públicas la información, orientación, métodos y prestaciones de servicios referidos a la salud sexual, la procreación responsable y la protección a la mujer embarazada.`, plainLanguageExplanation: 'Los derechos sexuales y reproductivos son derechos humanos. El Estado provincial debe proveer información, orientación, métodos anticonceptivos y atención para la salud sexual y reproductiva.', practicalEffects: [], examples: ['Los centros de salud deben proveer información sobre métodos anticonceptivos y cuidados durante el embarazo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['salud sexual', 'derechos reproductivos', 'procreación responsable', 'mujer embarazada', 'anticonceptivos'], order: 19, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-21', lawId: 'const-entre-rios', number: '21', title: 'Derechos de las personas con discapacidad', originalText: `El Estado asegura a las personas con discapacidad y en su caso a sus familias: la igualdad real de oportunidades; la atención integral de la salud orientada a la prevención y rehabilitación; la extensión de los beneficios de la seguridad y previsión social del titular que los tuviera a su cargo; el contralor de todo centro público o privado de asistencia y alojamiento; el desarrollo de un ambiente libre de barreras físicas; la gratuidad y accesibilidad al transporte público; el acceso a la educación en todos los niveles con la infraestructura necesaria. Un Instituto Provincial de la Discapacidad con participación de la familia y las organizaciones intermedias elabora y ejecuta políticas de equidad, protección, promoción, educación y difusión de los derechos de las personas con discapacidad y de los deberes sociales para con ellas. Fomenta la capacitación destinada a su inserción laboral.`, currentText: `El Estado asegura a las personas con discapacidad y en su caso a sus familias: la igualdad real de oportunidades; la atención integral de la salud orientada a la prevención y rehabilitación; la extensión de los beneficios de la seguridad y previsión social del titular que los tuviera a su cargo; el contralor de todo centro público o privado de asistencia y alojamiento; el desarrollo de un ambiente libre de barreras físicas; la gratuidad y accesibilidad al transporte público; el acceso a la educación en todos los niveles con la infraestructura necesaria. Un Instituto Provincial de la Discapacidad con participación de la familia y las organizaciones intermedias elabora y ejecuta políticas de equidad, protección, promoción, educación y difusión de los derechos de las personas con discapacidad y de los deberes sociales para con ellas. Fomenta la capacitación destinada a su inserción laboral.`, plainLanguageExplanation: 'El Estado garantiza a las personas con discapacidad igualdad real de oportunidades, salud integral, cobertura de seguridad social, transporte gratuito y educación en todos los niveles. El Instituto Provincial de la Discapacidad elabora políticas de protección y promueve su inserción laboral.', practicalEffects: [], examples: ['Una persona con discapacidad motriz tiene derecho a acceder gratuitamente al transporte público y a que los edificios públicos cuenten con rampas y accesos adecuados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['discapacidad', 'igualdad de oportunidades', 'salud', 'transporte gratuito', 'educación inclusiva', 'Instituto Provincial de la Discapacidad'], order: 20, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-22', lawId: 'const-entre-rios', number: '22', title: 'Derecho a un ambiente sano y desarrollo sustentable', originalText: `Todos los habitantes gozan del derecho a vivir en un ambiente sano y equilibrado, apto para el desarrollo humano, donde las actividades sean compatibles con el desarrollo sustentable, para mejorar la calidad de vida y satisfacer las necesidades presentes, sin comprometer la de las generaciones futuras. Tienen el deber de preservarlo y mejorarlo, como patrimonio común.`, currentText: `Todos los habitantes gozan del derecho a vivir en un ambiente sano y equilibrado, apto para el desarrollo humano, donde las actividades sean compatibles con el desarrollo sustentable, para mejorar la calidad de vida y satisfacer las necesidades presentes, sin comprometer la de las generaciones futuras. Tienen el deber de preservarlo y mejorarlo, como patrimonio común.`, plainLanguageExplanation: 'Todos tienen derecho a un ambiente sano y apto para el desarrollo humano. Las actividades productivas deben ser sustentables para no comprometer el bienestar de las generaciones futuras. Preservar el ambiente es también un deber ciudadano.', practicalEffects: [], examples: ['Un emprendimiento industrial que contamine un río puede ser impugnado judicialmente por vecinos que invocan este artículo, ya que vulnera su derecho a un ambiente sano.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ambiente sano', 'desarrollo sustentable', 'generaciones futuras', 'calidad de vida', 'patrimonio común'], order: 21, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-23', lawId: 'const-entre-rios', number: '23', title: 'Propiedad privada — inviolabilidad y función social', originalText: `La propiedad privada es inviolable y tiene función social.`, currentText: `La propiedad privada es inviolable y tiene función social.`, plainLanguageExplanation: 'La propiedad privada está garantizada constitucionalmente, pero no es absoluta: tiene una función social, lo que habilita al Estado a regular su uso en beneficio de la comunidad.', practicalEffects: [], examples: ['El Estado puede expropiar un inmueble privado para construir una escuela pública, pagando una indemnización justa, en ejercicio de la función social de la propiedad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['propiedad privada', 'inviolabilidad', 'función social', 'expropiación'], order: 22, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-24', lawId: 'const-entre-rios', number: '24', title: 'Derecho a la alimentación e ingreso mínimo de subsistencia', originalText: `El Estado asegura a todos los habitantes el derecho a la alimentación, así como un ingreso mínimo indispensable para la subsistencia en situaciones de falta de empleo regular, inestabilidad económica, social o catástrofes que coloquen al afectado en situación de desamparo. Un ente público con participación ciudadana tendrá a su cargo la efectivización de este derecho.`, currentText: `El Estado asegura a todos los habitantes el derecho a la alimentación, así como un ingreso mínimo indispensable para la subsistencia en situaciones de falta de empleo regular, inestabilidad económica, social o catástrofes que coloquen al afectado en situación de desamparo. Un ente público con participación ciudadana tendrá a su cargo la efectivización de este derecho.`, plainLanguageExplanation: 'El Estado garantiza el derecho a la alimentación y un ingreso mínimo para quien se encuentre en situación de desamparo por desempleo, crisis económica o catástrofes. Un organismo público con participación ciudadana debe hacer efectivo este derecho.', practicalEffects: [], examples: ['Una persona que pierde su trabajo y no tiene ingresos puede acceder a un subsidio de subsistencia provisto por el ente provincial creado a tal efecto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alimentación', 'ingreso mínimo', 'subsistencia', 'desempleo', 'desamparo', 'catástrofe'], order: 23, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-25', lawId: 'const-entre-rios', number: '25', title: 'Derecho a la vivienda digna', originalText: `El Estado promueve las condiciones necesarias para hacer efectivo el derecho de todos los habitantes a una vivienda digna, con sus servicios conexos y el espacio necesario para el desarrollo humano, en especial destinado a los sectores de menores recursos. Planifica y ejecuta una política concertada con los municipios, comunas e instituciones que lo requieran, con el aporte solidario de los interesados.`, currentText: `El Estado promueve las condiciones necesarias para hacer efectivo el derecho de todos los habitantes a una vivienda digna, con sus servicios conexos y el espacio necesario para el desarrollo humano, en especial destinado a los sectores de menores recursos. Planifica y ejecuta una política concertada con los municipios, comunas e instituciones que lo requieran, con el aporte solidario de los interesados.`, plainLanguageExplanation: 'El Estado tiene la obligación de crear condiciones para que todos puedan acceder a una vivienda digna con servicios básicos, priorizando a los sectores más vulnerables. Las políticas habitacionales se planifican en coordinación con municipios y comunas.', practicalEffects: [], examples: ['Los planes de vivienda social del Instituto Autárquico de Planeamiento y Vivienda (IAPV) tienen base constitucional en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['vivienda digna', 'sectores vulnerables', 'política habitacional', 'municipios', 'servicios básicos'], order: 24, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-26', lawId: 'const-entre-rios', number: '26', title: 'Cultura como derecho fundamental — financiamiento mínimo del 1%', originalText: `La cultura es un derecho fundamental. El Estado impulsa las siguientes acciones, entre otras: la promoción, protección y difusión del folclore, las artesanías y demás manifestaciones; el reconocimiento a la identidad y respeto a la diversidad cultural, la convivencia, la tolerancia y la inclusión social, estimulando el intercambio desde una perspectiva latinoamericana; la protección, preservación y divulgación de los bienes culturales, el patrimonio tangible e intangible, histórico, artístico, arqueológico, arquitectónico y paisajístico; la aplicación de las nuevas tecnologías de la comunicación para la producción cultural. Los fondos para su financiamiento no podrán ser inferiores al uno por ciento de las rentas no afectadas del total de las autorizadas en la ley de presupuesto.`, currentText: `La cultura es un derecho fundamental. El Estado impulsa las siguientes acciones, entre otras: la promoción, protección y difusión del folclore, las artesanías y demás manifestaciones; el reconocimiento a la identidad y respeto a la diversidad cultural, la convivencia, la tolerancia y la inclusión social, estimulando el intercambio desde una perspectiva latinoamericana; la protección, preservación y divulgación de los bienes culturales, el patrimonio tangible e intangible, histórico, artístico, arqueológico, arquitectónico y paisajístico; la aplicación de las nuevas tecnologías de la comunicación para la producción cultural. Los fondos para su financiamiento no podrán ser inferiores al uno por ciento de las rentas no afectadas del total de las autorizadas en la ley de presupuesto.`, plainLanguageExplanation: 'La cultura es un derecho fundamental. El Estado promueve el folclore, artesanías, patrimonio histórico y diversidad cultural. La Constitución exige que el presupuesto destine al menos el 1% de las rentas no afectadas al financiamiento de la cultura.', practicalEffects: [], examples: ['El gobierno provincial no puede aprobar un presupuesto que destine menos del 1% de sus rentas libres a cultura; de hacerlo, ese inciso presupuestario sería inconstitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cultura', 'patrimonio cultural', 'folclore', 'diversidad cultural', 'financiamiento cultural', '1% rentas'], order: 25, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-27', lawId: 'const-entre-rios', number: '27', title: 'Deporte como derecho social — Consejo Provincial del Deporte', originalText: `El Estado reconoce al deporte como derecho social. Promueve la actividad deportiva para la formación integral de la persona facilitando las condiciones materiales, profesionales y técnicas para su organización, desarrollo y el acceso a su práctica en igualdad de oportunidades. Asegura, a través del Consejo Provincial del Deporte, la participación de la comunidad deportiva en la elaboración, definición y coordinación de las políticas para el área. Preserva, en un marco de solidaridad comunitaria y educativa, la existencia de las instituciones deportivas con fines sociales, protegiendo su infraestructura.`, currentText: `El Estado reconoce al deporte como derecho social. Promueve la actividad deportiva para la formación integral de la persona facilitando las condiciones materiales, profesionales y técnicas para su organización, desarrollo y el acceso a su práctica en igualdad de oportunidades. Asegura, a través del Consejo Provincial del Deporte, la participación de la comunidad deportiva en la elaboración, definición y coordinación de las políticas para el área. Preserva, en un marco de solidaridad comunitaria y educativa, la existencia de las instituciones deportivas con fines sociales, protegiendo su infraestructura.`, plainLanguageExplanation: 'El Estado reconoce el deporte como un derecho social y promueve el acceso igualitario a su práctica. El Consejo Provincial del Deporte garantiza la participación de la comunidad deportiva en las políticas del área y protege las instituciones deportivas con fines sociales.', practicalEffects: [], examples: ['Un club de barrio con fines sociales tiene protección constitucional frente a intentos de demolición o privatización de su infraestructura.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deporte', 'derecho social', 'Consejo Provincial del Deporte', 'igualdad de oportunidades', 'clubes sociales'], order: 26, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-28', lawId: 'const-entre-rios', number: '28', title: 'Libertad de asociación y legitimación procesal de asociaciones', originalText: `Todas las personas tienen derecho a asociarse libremente con fines útiles para una sociedad democrática y pluralista. Las asociaciones con autorización para funcionar tienen legitimación procesal para interponer amparo o acción de inconstitucionalidad contra cualquier acto que viole derechos que ellas tengan como objeto proteger o promover.`, currentText: `Todas las personas tienen derecho a asociarse libremente con fines útiles para una sociedad democrática y pluralista. Las asociaciones con autorización para funcionar tienen legitimación procesal para interponer amparo o acción de inconstitucionalidad contra cualquier acto que viole derechos que ellas tengan como objeto proteger o promover.`, plainLanguageExplanation: 'Toda persona puede asociarse libremente para fines lícitos. Las asociaciones legalmente habilitadas pueden presentar amparos o acciones de inconstitucionalidad para defender los derechos que les compete proteger.', practicalEffects: [], examples: ['Una asociación de consumidores puede interponer una acción de amparo colectivo contra una empresa que afecte los derechos de sus representados, sin necesidad de que cada consumidor accione por separado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de asociación', 'amparo', 'legitimación procesal', 'acción de inconstitucionalidad', 'sociedad civil'], order: 27, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-29', lawId: 'const-entre-rios', number: '29', title: 'Partidos políticos — democracia interna y propaganda institucional', originalText: `Todos los ciudadanos tienen el derecho de asociarse libremente en partidos políticos. Se reconoce y garantiza la existencia de aquellos en cuya organización y funcionamiento se observen: la democracia interna, la adecuada y proporcional representación de las minorías y demás principios constitucionales. Son instituciones fundamentales del sistema democrático, concurren a la formación y expresión de la voluntad política del pueblo, son instrumentos de participación ciudadana, formulación de la política e integración del gobierno. Sólo a ellas compete postular candidatos para cargos públicos electivos. La Provincia contribuye a sostenerlos mediante un fondo partidario permanente. Los partidos políticos destinarán parte de los aportes públicos que reciban a actividades de capacitación e investigación, debiendo rendir cuentas periódicamente del origen y destino de sus fondos y de su patrimonio. Tendrán libre e igualitaria difusión de sus propuestas electorales a través de los medios de comunicación social. Una ley establecerá los límites de gastos y duración de las campañas publicitarias electorales. El gobierno, durante el desarrollo de éstas, no podrá realizar propaganda institucional que tienda a inducir el voto.`, currentText: `Todos los ciudadanos tienen el derecho de asociarse libremente en partidos políticos. Se reconoce y garantiza la existencia de aquellos en cuya organización y funcionamiento se observen: la democracia interna, la adecuada y proporcional representación de las minorías y demás principios constitucionales. Son instituciones fundamentales del sistema democrático, concurren a la formación y expresión de la voluntad política del pueblo, son instrumentos de participación ciudadana, formulación de la política e integración del gobierno. Sólo a ellas compete postular candidatos para cargos públicos electivos. La Provincia contribuye a sostenerlos mediante un fondo partidario permanente. Los partidos políticos destinarán parte de los aportes públicos que reciban a actividades de capacitación e investigación, debiendo rendir cuentas periódicamente del origen y destino de sus fondos y de su patrimonio. Tendrán libre e igualitaria difusión de sus propuestas electorales a través de los medios de comunicación social. Una ley establecerá los límites de gastos y duración de las campañas publicitarias electorales. El gobierno, durante el desarrollo de éstas, no podrá realizar propaganda institucional que tienda a inducir el voto.`, plainLanguageExplanation: 'Los partidos políticos son las únicas instituciones habilitadas para postular candidatos y deben funcionar con democracia interna. Reciben financiamiento público y deben rendir cuentas. Durante las campañas electorales, el gobierno no puede hacer propaganda institucional que oriente el voto.', practicalEffects: [], examples: ['Si el Poder Ejecutivo provincial difunde publicidad oficial durante una campaña electoral provincial que muestre logros de gestión con fines electorales, viola este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['partidos políticos', 'democracia interna', 'financiamiento partidario', 'propaganda institucional', 'campañas electorales', 'postulación de candidatos'], order: 28, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-30', lawId: 'const-entre-rios', number: '30', title: 'Defensa de consumidores y usuarios — tarifas justas en servicios públicos', originalText: `Se garantiza la defensa de los derechos de consumidores y usuarios de bienes y servicios públicos y privados. Las autoridades provinciales y municipales proveerán a la educación para el consumo responsable, a la defensa de la competencia contra toda forma de distorsión de los mercados, al control de los monopolios naturales y legales y al de la calidad, regularidad y continuidad de los servicios. Estos derechos son protegidos, controlados y su prestación regulada por un ente provincial o municipal. La norma establecerá los procedimientos para la prevención y solución de conflictos y los marcos regulatorios, previendo la participación de asociaciones de consumidores y usuarios. Existiendo organismos de defensa del consumidor en los municipios, éstos ejercerán las funciones en su jurisdicción. El Estado debe garantizar en los servicios públicos concesionados la fijación de un sistema tarifario justo, razonable y transparente.`, currentText: `Se garantiza la defensa de los derechos de consumidores y usuarios de bienes y servicios públicos y privados. Las autoridades provinciales y municipales proveerán a la educación para el consumo responsable, a la defensa de la competencia contra toda forma de distorsión de los mercados, al control de los monopolios naturales y legales y al de la calidad, regularidad y continuidad de los servicios. Estos derechos son protegidos, controlados y su prestación regulada por un ente provincial o municipal. La norma establecerá los procedimientos para la prevención y solución de conflictos y los marcos regulatorios, previendo la participación de asociaciones de consumidores y usuarios. Existiendo organismos de defensa del consumidor en los municipios, éstos ejercerán las funciones en su jurisdicción. El Estado debe garantizar en los servicios públicos concesionados la fijación de un sistema tarifario justo, razonable y transparente.`, plainLanguageExplanation: 'Se garantiza la protección de consumidores y usuarios. El Estado controla la calidad y continuidad de los servicios, regula monopolios y exige tarifas justas en servicios concesionados. Los municipios pueden ejercer estas funciones en su jurisdicción.', practicalEffects: [], examples: ['Si una empresa concesionaria del servicio de agua sube las tarifas de forma arbitraria o injustificada, los usuarios pueden reclamar ante el ente regulador provincial con base en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['consumidores', 'usuarios', 'servicios públicos', 'tarifas justas', 'defensa de la competencia', 'monopolios', 'ente regulador'], order: 29, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-31', lawId: 'const-entre-rios', number: '31', title: 'Libertad de circulación territorial', originalText: `Toda persona tiene derecho a entrar, permanecer, transitar y salir del territorio provincial, llevando consigo o despachando sus bienes o mercaderías.`, currentText: `Toda persona tiene derecho a entrar, permanecer, transitar y salir del territorio provincial, llevando consigo o despachando sus bienes o mercaderías.`, plainLanguageExplanation: 'Toda persona puede entrar, permanecer, circular y salir libremente de la Provincia de Entre Ríos, llevando sus bienes. Es una garantía de libre circulación territorial.', practicalEffects: [], examples: ['Un comerciante que transporta mercaderías entre provincias no puede ser detenido ni gravado por ingresar o salir del territorio entrerriano.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de circulación', 'tránsito', 'libre comercio', 'circulación de bienes'], order: 30, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-32', lawId: 'const-entre-rios', number: '32', title: 'Seguridad ciudadana — prevención del delito y asistencia a la víctima', originalText: `El Estado asume como deber irrenunciable la seguridad ciudadana mediante políticas de prevención del delito y de asistencia a la víctima.`, currentText: `El Estado asume como deber irrenunciable la seguridad ciudadana mediante políticas de prevención del delito y de asistencia a la víctima.`, plainLanguageExplanation: 'La seguridad ciudadana es un deber irrenunciable del Estado. Debe implementar políticas tanto de prevención del delito como de asistencia y reparación a las víctimas.', practicalEffects: [], examples: ['El Estado provincial no puede eliminar los programas de asistencia a víctimas de delitos ni reducir las políticas preventivas sin violar este deber constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['seguridad ciudadana', 'prevención del delito', 'asistencia a la víctima', 'deber estatal'], order: 31, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-33', lawId: 'const-entre-rios', number: '33', title: 'Pueblos originarios — preexistencia étnica, tierra comunitaria y educación bilingüe', originalText: `La Provincia reconoce la preexistencia étnica y cultural de sus pueblos originarios. Asegura el respeto a su identidad, la recuperación y conservación de su patrimonio y herencia cultural, la personería de sus comunidades y la propiedad comunitaria inmediata de la tierra que tradicionalmente ocupan. La ley dispondrá la entrega de otras, aptas y suficientes para su desarrollo humano, que serán adjudicadas como reparación histórica en forma gratuita. Serán, indivisibles e intransferibles a terceros. Reconoce a los pueblos originarios el derecho a una educación bilingüe e intercultural, a sus conocimientos ancestrales y producciones culturales, a participar en la protección, preservación y recuperación de los recursos naturales vinculados a su entorno y subsistencia, a su elevación socio-económica con planes adecuados y al efectivo respeto por sus tradiciones, creencias y formas de vida.`, currentText: `La Provincia reconoce la preexistencia étnica y cultural de sus pueblos originarios. Asegura el respeto a su identidad, la recuperación y conservación de su patrimonio y herencia cultural, la personería de sus comunidades y la propiedad comunitaria inmediata de la tierra que tradicionalmente ocupan. La ley dispondrá la entrega de otras, aptas y suficientes para su desarrollo humano, que serán adjudicadas como reparación histórica en forma gratuita. Serán, indivisibles e intransferibles a terceros. Reconoce a los pueblos originarios el derecho a una educación bilingüe e intercultural, a sus conocimientos ancestrales y producciones culturales, a participar en la protección, preservación y recuperación de los recursos naturales vinculados a su entorno y subsistencia, a su elevación socio-económica con planes adecuados y al efectivo respeto por sus tradiciones, creencias y formas de vida.`, plainLanguageExplanation: 'La Provincia reconoce la preexistencia histórica de los pueblos originarios y garantiza su identidad, cultura y propiedad comunitaria de la tierra. Las tierras adjudicadas son gratuitas, indivisibles e intransferibles. También reconoce su derecho a educación bilingüe intercultural y al manejo de sus recursos naturales.', practicalEffects: [], examples: ['Una comunidad indígena que ocupa tierras ancestrales tiene derecho a su titulación comunitaria en forma gratuita, sin que esas tierras puedan ser vendidas o divididas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pueblos originarios', 'preexistencia étnica', 'propiedad comunitaria', 'educación bilingüe', 'tierra indígena', 'reparación histórica'], order: 32, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-34', lawId: 'const-entre-rios', number: '34', title: 'Malvinas — causa irrenunciable y protección a veteranos de guerra', originalText: `La recuperación de las Islas Malvinas y demás espacios insulares y marítimos es una causa nacional legítima, permanente e irrenunciable, a la que la Provincia honra y adhiere. Dentro de sus competencias, adoptará políticas activas orientadas a la asistencia, integración y protección de los veteranos de guerra, facilitando su acceso a la educación, al trabajo, a la salud integral y a una vivienda digna.`, currentText: `La recuperación de las Islas Malvinas y demás espacios insulares y marítimos es una causa nacional legítima, permanente e irrenunciable, a la que la Provincia honra y adhiere. Dentro de sus competencias, adoptará políticas activas orientadas a la asistencia, integración y protección de los veteranos de guerra, facilitando su acceso a la educación, al trabajo, a la salud integral y a una vivienda digna.`, plainLanguageExplanation: 'La Provincia reafirma la causa irrenunciable de la soberanía argentina sobre las Islas Malvinas. Además, se compromete a implementar políticas de asistencia a los veteranos de guerra, garantizándoles acceso a educación, trabajo, salud y vivienda digna.', practicalEffects: [], examples: ['Un veterano de Malvinas residente en Entre Ríos tiene derecho a acceder a programas provinciales de salud integral y vivienda con base en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Malvinas', 'soberanía', 'veteranos de guerra', 'causa irrenunciable', 'asistencia social'], order: 33, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-35', lawId: 'const-entre-rios', number: '35', title: 'Operatividad progresiva de derechos y equilibrio fiscal', originalText: `El Estado adoptará las medidas necesarias para la operatividad progresiva de los derechos y garantías reconocidos en esta Constitución, conforme lo establece el artículo 122 inciso 8. El equilibrio fiscal constituye un deber del Estado y un derecho colectivo de los entrerrianos.`, currentText: `El Estado adoptará las medidas necesarias para la operatividad progresiva de los derechos y garantías reconocidos en esta Constitución, conforme lo establece el artículo 122 inciso 8. El equilibrio fiscal constituye un deber del Estado y un derecho colectivo de los entrerrianos.`, plainLanguageExplanation: 'El Estado debe avanzar progresivamente en hacer efectivos todos los derechos constitucionales. Al mismo tiempo, el equilibrio fiscal es tanto un deber del Estado como un derecho colectivo de los entrerrianos, lo que impone límites al gasto público irresponsable.', practicalEffects: [], examples: ['Si el gobierno provincial contrae deuda excesiva que compromete el equilibrio fiscal, cualquier ciudadano puede invocar este artículo para cuestionar esa política.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['operatividad progresiva', 'derechos constitucionales', 'equilibrio fiscal', 'responsabilidad fiscal', 'derecho colectivo'], order: 34, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-36', lawId: 'const-entre-rios', number: '36', title: 'Acceso igualitario al empleo público — idoneidad y concurso', originalText: `Todos los habitantes son admisibles en los empleos públicos provinciales, municipales y comunales o de otros organismos en los que tenga participación el Estado, sin más requisito que la idoneidad, sin perjuicio de las calidades especiales exigidas por esta Constitución. Sólo serán designados y ascendidos previo concurso que la asegure, en igualdad de oportunidades y sin discriminación. En ningún caso, las razones étnicas, religiosas, ideológicas, políticas, gremiales, sexuales, económicas, sociales, fundadas en caracteres físicos o de cualquier otra índole, serán motivo para discriminar o segregar al aspirante. La ley determinará las condiciones para los ingresos y ascensos y establecerá los funcionarios políticos sin estabilidad que podrán ser designados sin concurso. No podrán incluirse entre éstos los cargos de directores de hospitales y directores departamentales de escuelas.`, currentText: `Todos los habitantes son admisibles en los empleos públicos provinciales, municipales y comunales o de otros organismos en los que tenga participación el Estado, sin más requisito que la idoneidad, sin perjuicio de las calidades especiales exigidas por esta Constitución. Sólo serán designados y ascendidos previo concurso que la asegure, en igualdad de oportunidades y sin discriminación. En ningún caso, las razones étnicas, religiosas, ideológicas, políticas, gremiales, sexuales, económicas, sociales, fundadas en caracteres físicos o de cualquier otra índole, serán motivo para discriminar o segregar al aspirante. La ley determinará las condiciones para los ingresos y ascensos y establecerá los funcionarios políticos sin estabilidad que podrán ser designados sin concurso. No podrán incluirse entre éstos los cargos de directores de hospitales y directores departamentales de escuelas.`, plainLanguageExplanation: 'El acceso al empleo público requiere idoneidad y concurso, sin discriminación por ninguna causa. Solo ciertos cargos políticos pueden designarse sin concurso. Los directores de hospitales y directores de escuelas siempre deben concursar.', practicalEffects: [], examples: ['Si se designa a un director de hospital sin concurso previo, esa designación es inconstitucional y puede ser impugnada judicialmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['empleo público', 'concurso', 'idoneidad', 'igualdad de oportunidades', 'no discriminación', 'meritocracia'], order: 35, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-37', lawId: 'const-entre-rios', number: '37', title: 'Ética pública — declaración de bienes y conflictos de interés', originalText: `Los funcionarios y empleados públicos de los tres poderes del Estado, de los municipios y de las comunas, sirven exclusivamente a los intereses del pueblo. Deben observar, en el ejercicio de sus funciones, una conducta acorde con la ética pública, la que constituye un valor social que hace a la esencia del sistema republicano. Una ley de ética para el ejercicio de la función pública deberá contemplar, entre otras, las siguientes conductas: -Observar los principios de probidad, rectitud, prudencia, justicia, equidad, eficiencia y transparencia de los actos públicos. -Presentar, al tiempo de asumir y cesar en el cargo, manifestación de bienes. -Abstenerse de intervenir desde la función en actos en los que tengan vinculación, sea personal o a través de terceros que él represente o patrocine o cuando tuviera un interés particular, laboral, económico o financiero. -No aceptar gratificaciones, obsequios u otras prestaciones de significación con motivo o en ocasión del ejercicio de sus funciones. -No podrán desempeñar otras actividades, incluyendo el ejercicio de la docencia, cuando afecte u obstaculice la asistencia regular a las tareas propias del cargo.`, currentText: `Los funcionarios y empleados públicos de los tres poderes del Estado, de los municipios y de las comunas, sirven exclusivamente a los intereses del pueblo. Deben observar, en el ejercicio de sus funciones, una conducta acorde con la ética pública, la que constituye un valor social que hace a la esencia del sistema republicano. Una ley de ética para el ejercicio de la función pública deberá contemplar, entre otras, las siguientes conductas: -Observar los principios de probidad, rectitud, prudencia, justicia, equidad, eficiencia y transparencia de los actos públicos. -Presentar, al tiempo de asumir y cesar en el cargo, manifestación de bienes. -Abstenerse de intervenir desde la función en actos en los que tengan vinculación, sea personal o a través de terceros que él represente o patrocine o cuando tuviera un interés particular, laboral, económico o financiero. -No aceptar gratificaciones, obsequios u otras prestaciones de significación con motivo o en ocasión del ejercicio de sus funciones. -No podrán desempeñar otras actividades, incluyendo el ejercicio de la docencia, cuando afecte u obstaculice la asistencia regular a las tareas propias del cargo.`, plainLanguageExplanation: 'Los funcionarios públicos sirven al pueblo y deben actuar con probidad, transparencia y sin conflictos de interés. Están obligados a declarar su patrimonio al asumir y al cesar, y no pueden aceptar beneficios ni tener otras actividades que interfieran con su cargo.', practicalEffects: [], examples: ['Un funcionario provincial que participa en una licitación donde tiene interés económico personal incurre en conflicto de interés y viola este artículo, pudiendo ser sancionado o destituido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ética pública', 'declaración de bienes', 'conflicto de interés', 'probidad', 'transparencia', 'función pública'], order: 36, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-38', lawId: 'const-entre-rios', number: '38', title: 'Enjuiciamiento de funcionarios ante tribunales ordinarios', originalText: `Los funcionarios y empleados públicos, no sujetos al juicio político ni al jurado de enjuiciamiento, son enjuiciables ante los tribunales ordinarios, sin que puedan excusarse alegando orden o aprobación superior.`, currentText: `Los funcionarios y empleados públicos, no sujetos al juicio político ni al jurado de enjuiciamiento, son enjuiciables ante los tribunales ordinarios, sin que puedan excusarse alegando orden o aprobación superior.`, plainLanguageExplanation: 'Los funcionarios públicos que no están sujetos a procedimientos especiales de destitución pueden ser juzgados por la justicia ordinaria. No pueden eximirse de responsabilidad alegando que actuaron por orden de un superior.', practicalEffects: [], examples: ['Un empleado de un ministerio provincial que comete un delito en el ejercicio de sus funciones puede ser procesado penalmente por los tribunales ordinarios de la provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad funcionarios', 'tribunales ordinarios', 'obediencia debida', 'enjuiciamiento', 'función pública'], order: 37, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-39', lawId: 'const-entre-rios', number: '39', title: 'Deber de vindicación del funcionario imputado — inhabilitación por condena', originalText: `El funcionario o empleado público, a quien se impute delito cometido en el desempeño de sus funciones, está obligado a acusar para vindicarse bajo pena de destitución. La ley reglamentará el proceso respectivo. El funcionario o empleado público, sobre quien recayera condena penal firme por delito contra la administración pública, que acarree inhabilitación será apartado del cargo en forma inmediata.`, currentText: `El funcionario o empleado público, a quien se impute delito cometido en el desempeño de sus funciones, está obligado a acusar para vindicarse bajo pena de destitución. La ley reglamentará el proceso respectivo. El funcionario o empleado público, sobre quien recayera condena penal firme por delito contra la administración pública, que acarree inhabilitación será apartado del cargo en forma inmediata.`, plainLanguageExplanation: 'Si se imputa a un funcionario un delito en ejercicio de su cargo, debe acusar formalmente para defenderse o de lo contrario puede ser destituido. Si recae condena penal firme por delitos contra la administración pública, pierde el cargo de inmediato.', practicalEffects: [], examples: ['Un secretario de gobierno condenado por corrupción con inhabilitación debe ser separado de su cargo en forma inmediata, sin necesidad de esperar otro proceso administrativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['funcionario imputado', 'vindicación', 'condena penal', 'inhabilitación', 'destitución', 'corrupción'], order: 38, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-40', lawId: 'const-entre-rios', number: '40', title: 'Incompatibilidad — prohibición de acumular empleos públicos', originalText: `No podrán acumularse en una misma persona dos o más empleos, aunque el uno sea de la Provincia y el otro de la Nación, municipio o comuna con excepción de los del magisterio y los de carácter profesional técnico cuando la escasez del personal haga necesaria la acumulación. Fuera de estos casos, la aceptación del nuevo empleo hace caducar el anterior.`, currentText: `No podrán acumularse en una misma persona dos o más empleos, aunque el uno sea de la Provincia y el otro de la Nación, municipio o comuna con excepción de los del magisterio y los de carácter profesional técnico cuando la escasez del personal haga necesaria la acumulación. Fuera de estos casos, la aceptación del nuevo empleo hace caducar el anterior.`, plainLanguageExplanation: 'Una misma persona no puede tener dos empleos públicos simultáneos, ya sea en la provincia, la nación, municipios o comunas. La excepción aplica a docentes y técnicos cuando sea necesario por falta de personal. Si se acepta un segundo empleo sin excepción válida, el primero caduca automáticamente.', practicalEffects: [], examples: ['Un empleado de la administración provincial que acepta un cargo municipal sin estar en la excepción de docencia o técnica pierde automáticamente su empleo provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidad', 'acumulación de empleos', 'doble empleo', 'empleo público', 'magisterio', 'personal técnico'], order: 39, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-41', lawId: 'const-entre-rios', number: '41', title: 'Jubilación, pensión y seguro para empleados públicos', originalText: `Los funcionarios y empleados permanentes, provinciales, municipales, comunales, o en su caso, los herederos que determine la ley de la materia, tendrán derecho a jubilación, pensión o seguro. La ley será dictada con sujeción a normas técnicas que tengan en cuenta el principio de la proporcionalidad entre los aportes y beneficios, el tiempo de los servicios y la edad de los beneficiados, sin excluir los aportes del Estado, de las municipalidades y las comunas. La ley establecerá bases especiales para el caso de accidentes ocurridos con motivo de la prestación del servicio. La Legislatura no podrá acordar pensiones ni jubilaciones por leyes especiales.`, currentText: `Los funcionarios y empleados permanentes, provinciales, municipales, comunales, o en su caso, los herederos que determine la ley de la materia, tendrán derecho a jubilación, pensión o seguro. La ley será dictada con sujeción a normas técnicas que tengan en cuenta el principio de la proporcionalidad entre los aportes y beneficios, el tiempo de los servicios y la edad de los beneficiados, sin excluir los aportes del Estado, de las municipalidades y las comunas. La ley establecerá bases especiales para el caso de accidentes ocurridos con motivo de la prestación del servicio. La Legislatura no podrá acordar pensiones ni jubilaciones por leyes especiales.`, plainLanguageExplanation: 'Los empleados públicos permanentes tienen derecho a jubilación, pensión o seguro proporcional a sus aportes y años de servicio. La Legislatura no puede otorgar pensiones ni jubilaciones por leyes especiales individuales, garantizando igualdad de trato.', practicalEffects: [], examples: ['La Legislatura no puede sancionar una ley especial para jubilar anticipadamente a un funcionario amigo; todos los beneficios deben regirse por la ley general de previsión social.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jubilación', 'pensión', 'seguro', 'empleados públicos', 'previsión social', 'proporcionalidad'], order: 40, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-42', lawId: 'const-entre-rios', number: '42', title: 'Estabilidad del empleado público', originalText: `Ningún empleado de la Provincia, de las municipalidades o las comunas con más de un año consecutivo de servicio, podrá ser separado de su cargo mientras dure su buena conducta, sus aptitudes física y mental, y su contracción eficiente para la función encomendada, a excepción de aquellos para cuyo nombramiento o cesantía se haya previsto, por esta Constitución o por las leyes respectivas, normas especiales. La ley reglamentará esta garantía y los deberes y responsabilidades del empleado o funcionario y determinará las bases y tribunales administrativos para regular el ingreso, los ascensos, remociones, traslados e incompatibilidades.`, currentText: `Ningún empleado de la Provincia, de las municipalidades o las comunas con más de un año consecutivo de servicio, podrá ser separado de su cargo mientras dure su buena conducta, sus aptitudes física y mental, y su contracción eficiente para la función encomendada, a excepción de aquellos para cuyo nombramiento o cesantía se haya previsto, por esta Constitución o por las leyes respectivas, normas especiales. La ley reglamentará esta garantía y los deberes y responsabilidades del empleado o funcionario y determinará las bases y tribunales administrativos para regular el ingreso, los ascensos, remociones, traslados e incompatibilidades.`, plainLanguageExplanation: 'El empleado público con más de un año de servicio tiene estabilidad en su cargo mientras mantenga buena conducta, aptitudes y eficiencia. Solo puede ser removido por las causas y procedimientos que establece la ley. No aplica a funcionarios políticos con reglas especiales.', practicalEffects: [], examples: ['Un empleado municipal con dos años de antigüedad que es cesanteado sin sumario previo puede recurrir judicialmente exigiendo su reincorporación por violación de la estabilidad constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['estabilidad laboral', 'empleado público', 'buena conducta', 'sumario', 'cesantía', 'carrera administrativa'], order: 41, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-43', lawId: 'const-entre-rios', number: '43', title: 'Inhabilitación de deudores del Estado para cargos públicos', originalText: `No podrán ser empleados, funcionarios ni legisladores los deudores de la Provincia que, ejecutados legalmente, no hayan pagado sus deudas y los inhabilitados por sentencia.`, currentText: `No podrán ser empleados, funcionarios ni legisladores los deudores de la Provincia que, ejecutados legalmente, no hayan pagado sus deudas y los inhabilitados por sentencia.`, plainLanguageExplanation: 'Quien tenga una deuda ejecutada con la Provincia que no haya pagado, o esté inhabilitado por sentencia judicial, no puede ejercer ningún cargo público provincial.', practicalEffects: [], examples: ['Un contribuyente con deudas impositivas provinciales ejecutadas judicialmente no puede ser designado funcionario ni candidatearse a legislador mientras no regularice su situación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deudores del Estado', 'inhabilitación', 'cargos públicos', 'funcionarios', 'legisladores'], order: 42, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-44', lawId: 'const-entre-rios', number: '44', title: 'Responsabilidad individual de funcionarios — límites de atribuciones', originalText: `Las atribuciones de los funcionarios y empleados de la Provincia, municipalidades y comunas están limitadas por la Ley Suprema de la Nación, por esta Constitución y por las leyes que en su virtud dicte la Legislatura. Los funcionarios y empleados son individualmente responsables de los daños causados a terceros o al Estado por extralimitación o cumplimiento irregular de sus funciones. La Provincia no es responsable de los actos que los funcionarios y empleados practiquen fuera de sus atribuciones, salvo los casos que la ley determine.`, currentText: `Las atribuciones de los funcionarios y empleados de la Provincia, municipalidades y comunas están limitadas por la Ley Suprema de la Nación, por esta Constitución y por las leyes que en su virtud dicte la Legislatura. Los funcionarios y empleados son individualmente responsables de los daños causados a terceros o al Estado por extralimitación o cumplimiento irregular de sus funciones. La Provincia no es responsable de los actos que los funcionarios y empleados practiquen fuera de sus atribuciones, salvo los casos que la ley determine.`, plainLanguageExplanation: 'Las facultades de los funcionarios públicos tienen límites constitucionales y legales. Quienes excedan esos límites o actúen irregularmente responden personalmente por los daños ocasionados. La Provincia solo responde por actos dentro de las atribuciones de sus agentes.', practicalEffects: [], examples: ['Un inspector municipal que clausura un comercio sin competencia legal para hacerlo responde personalmente por los daños que esa clausura cause al comerciante.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad del Estado', 'extralimitación de funciones', 'atribuciones', 'daños', 'funcionarios públicos'], order: 43, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-45', lawId: 'const-entre-rios', number: '45', title: 'Prohibición de delegación de funciones sin autorización legal', originalText: `Ningún magistrado o empleado público podrá delegar, sin autorización legal, sus funciones en otra persona; ni un poder delegar en otro sus facultades constitucionales, siendo nulo, por consiguiente, lo que cualquiera de ellos obrase a nombre de otro ya sea por autorización suya o con cargo de darle cuenta, excepto los casos previstos por esta Constitución.`, currentText: `Ningún magistrado o empleado público podrá delegar, sin autorización legal, sus funciones en otra persona; ni un poder delegar en otro sus facultades constitucionales, siendo nulo, por consiguiente, lo que cualquiera de ellos obrase a nombre de otro ya sea por autorización suya o con cargo de darle cuenta, excepto los casos previstos por esta Constitución.`, plainLanguageExplanation: 'Los magistrados y empleados públicos no pueden delegar sus funciones a terceros sin una ley que lo autorice. Lo actuado en violación de esta norma es nulo. Los poderes del Estado tampoco pueden delegar sus facultades constitucionales entre sí sin autorización expresa.', practicalEffects: [], examples: ['Un juez que encarga a un empleado la firma de resoluciones sin habilitación legal está actuando de forma inconstitucional; esos actos serían nulos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['delegación de funciones', 'nulidad', 'indelegabilidad', 'magistrados', 'poderes del Estado'], order: 44, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-46', lawId: 'const-entre-rios', number: '46', title: 'Demandabilidad del Estado provincial — embargo de rentas por condena', originalText: `La Provincia, como persona civil, puede ser demandada ante sus propios tribunales, sin perjuicio de lo dispuesto por las leyes de competencia federal, sin necesidad de autorización previa del Poder Legislativo y sin privilegio alguno. Si fuera condenada al pago de una deuda, podrá ser ejecutada en la forma ordinaria y embargadas sus rentas, si transcurrido un año, desde la fecha en que el fallo condenatorio quedó firme, la Legislatura no arbitró los recursos para efectuar el pago. Exceptúanse de esta disposición las rentas o bienes especialmente afectados en garantía de una obligación.`, currentText: `La Provincia, como persona civil, puede ser demandada ante sus propios tribunales, sin perjuicio de lo dispuesto por las leyes de competencia federal, sin necesidad de autorización previa del Poder Legislativo y sin privilegio alguno. Si fuera condenada al pago de una deuda, podrá ser ejecutada en la forma ordinaria y embargadas sus rentas, si transcurrido un año, desde la fecha en que el fallo condenatorio quedó firme, la Legislatura no arbitró los recursos para efectuar el pago. Exceptúanse de esta disposición las rentas o bienes especialmente afectados en garantía de una obligación.`, plainLanguageExplanation: 'La Provincia puede ser demandada en juicio como cualquier persona, sin necesidad de autorización legislativa. Si es condenada y no paga en un año, sus rentas pueden ser embargadas por vía ordinaria, salvo las afectadas a garantías específicas.', practicalEffects: [], examples: ['Un proveedor al que la Provincia le debe dinero por una obra puede demandarlo directamente ante la justicia provincial y ejecutar la sentencia si el Estado no paga en el plazo constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['demandabilidad del Estado', 'embargo de rentas', 'juicio al Estado', 'condena al Estado', 'persona civil'], order: 45, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-47', lawId: 'const-entre-rios', number: '47', title: 'Publicidad de actos administrativos y finanzas públicas', originalText: `Los actos oficiales de toda la administración, y en especial, los que se relacionen con la percepción e inversión de la renta, deberán publicarse periódicamente en la forma que la ley lo establezca.`, currentText: `Los actos oficiales de toda la administración, y en especial, los que se relacionen con la percepción e inversión de la renta, deberán publicarse periódicamente en la forma que la ley lo establezca.`, plainLanguageExplanation: 'Todos los actos de la administración pública deben publicarse periódicamente, en especial los relacionados con el cobro y uso de los ingresos del Estado. Es la base constitucional de la transparencia y rendición de cuentas.', practicalEffects: [], examples: ['El Boletín Oficial de Entre Ríos y los portales de transparencia presupuestaria tienen fundamento en esta disposición constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidad', 'actos administrativos', 'transparencia', 'finanzas públicas', 'rendición de cuentas'], order: 46, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-48', lawId: 'const-entre-rios', number: '48', title: 'Prohibición de remuneraciones extraordinarias a funcionarios', originalText: `No podrá dictarse ley ni decreto que tenga por objeto acordar remuneraciones extraordinarias a miembros de los poderes públicos y ministros secretarios, por servicios hechos o que se les encargaren durante el ejercicio de sus funciones.`, currentText: `No podrá dictarse ley ni decreto que tenga por objeto acordar remuneraciones extraordinarias a miembros de los poderes públicos y ministros secretarios, por servicios hechos o que se les encargaren durante el ejercicio de sus funciones.`, plainLanguageExplanation: 'Está prohibido dictar leyes o decretos para darles bonificaciones o pagos adicionales a los funcionarios de los tres poderes y a los ministros por trabajos realizados durante su mandato.', practicalEffects: [], examples: ['Si el Poder Ejecutivo emite un decreto para pagarle un plus especial a un ministro por tareas extraordinarias, ese decreto sería inconstitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneraciones extraordinarias', 'funcionarios', 'prohibición', 'poderes públicos', 'ministros'], order: 47, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-49', lawId: 'const-entre-rios', number: '49', title: 'Iniciativa popular legislativa — 2% del padrón, mayores de 16 años', originalText: `Todos los habitantes mayores de dieciséis años con dos de residencia en la Provincia pueden presentar proyectos de ley ante cualquiera de las cámaras, con el dos por ciento, como mínimo, de firmas del padrón electoral provincial. La ley deberá contemplar una adecuada distribución territorial para suscribir la iniciativa. Si ésta versara sobre asunto de exclusivo interés local, el porcentaje de firmas se deberá establecer tomando como base el padrón del o de los departamentos o localidades respectivos. No pueden ser objeto de iniciativa aquellas normas referidas a la reforma constitucional, tributos, presupuesto, régimen electoral, tratados interprovinciales o convenios con el Estado Nacional. Las cámaras deben darle tratamiento dentro de un período de sesiones; la falta de despacho de comisión en el plazo de seis meses posteriores a su presentación, implica el giro automático al plenario que deberá considerarlo en la sesión siguiente a su remisión.`, currentText: `Todos los habitantes mayores de dieciséis años con dos de residencia en la Provincia pueden presentar proyectos de ley ante cualquiera de las cámaras, con el dos por ciento, como mínimo, de firmas del padrón electoral provincial. La ley deberá contemplar una adecuada distribución territorial para suscribir la iniciativa. Si ésta versara sobre asunto de exclusivo interés local, el porcentaje de firmas se deberá establecer tomando como base el padrón del o de los departamentos o localidades respectivos. No pueden ser objeto de iniciativa aquellas normas referidas a la reforma constitucional, tributos, presupuesto, régimen electoral, tratados interprovinciales o convenios con el Estado Nacional. Las cámaras deben darle tratamiento dentro de un período de sesiones; la falta de despacho de comisión en el plazo de seis meses posteriores a su presentación, implica el giro automático al plenario que deberá considerarlo en la sesión siguiente a su remisión.`, plainLanguageExplanation: 'Los entrerrianos mayores de 16 años con 2 años de residencia pueden presentar proyectos de ley con el respaldo del 2% del padrón electoral. La Legislatura debe tratar la iniciativa en el mismo período de sesiones. No puede usarse para reformar la Constitución, imponer tributos o modificar el régimen electoral.', practicalEffects: [], examples: ['Un grupo de ciudadanos preocupados por la contaminación de un río pueden presentar un proyecto de ley ambiental si reúnen el 2% de firmas del padrón provincial con distribución territorial adecuada.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['iniciativa popular', 'proyecto de ley ciudadano', '2% padrón', 'participación ciudadana', 'democracia directa'], order: 48, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-50', lawId: 'const-entre-rios', number: '50', title: 'Consulta popular — vinculante y no vinculante', originalText: `La Legislatura podrá someter a consulta para su sanción, reforma o derogación un proyecto de ley que verse sobre asuntos de trascendencia para los intereses de la Provincia. La ley de convocatoria no podrá ser vetada ni versar sobre temas inhabilitados para la iniciativa popular. Serán convocados a expedirse obligatoriamente, en comicios especiales, todos los habitantes habilitados para sufragar con dos años de residencia en la Provincia. El voto afirmativo del proyecto por la mayoría de los sufragantes, lo convertirá en ley y su promulgación será automática. El Poder Ejecutivo podrá someter a consulta no vinculante todo asunto de interés general. El voto no será obligatorio. Los departamentos deliberativo y ejecutivo municipales, pueden convocar a consulta popular, vinculante o no vinculante, en la forma prevista en el presente artículo o en su carta orgánica.`, currentText: `La Legislatura podrá someter a consulta para su sanción, reforma o derogación un proyecto de ley que verse sobre asuntos de trascendencia para los intereses de la Provincia. La ley de convocatoria no podrá ser vetada ni versar sobre temas inhabilitados para la iniciativa popular. Serán convocados a expedirse obligatoriamente, en comicios especiales, todos los habitantes habilitados para sufragar con dos años de residencia en la Provincia. El voto afirmativo del proyecto por la mayoría de los sufragantes, lo convertirá en ley y su promulgación será automática. El Poder Ejecutivo podrá someter a consulta no vinculante todo asunto de interés general. El voto no será obligatorio. Los departamentos deliberativo y ejecutivo municipales, pueden convocar a consulta popular, vinculante o no vinculante, en la forma prevista en el presente artículo o en su carta orgánica.`, plainLanguageExplanation: 'La Legislatura puede convocar a la ciudadanía a votar proyectos de ley de trascendencia. Si la mayoría vota a favor, el proyecto se convierte automáticamente en ley. El Poder Ejecutivo puede convocar consultas no vinculantes. Los municipios también pueden hacer consultas populares en su jurisdicción.', practicalEffects: [], examples: ['La Legislatura podría convocar a consulta popular para decidir si entre-rrianos aprueban una reforma educativa importante; si vota a favor la mayoría, se promulga como ley sin necesidad de otro acto legislativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['consulta popular', 'referéndum', 'democracia directa', 'vinculante', 'iniciativa ciudadana', 'participación'], order: 49, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-51', lawId: 'const-entre-rios', number: '51', title: 'Audiencia pública — consultiva, no vinculante', originalText: `La Legislatura, el Poder Ejecutivo y los municipios pueden convocar a audiencia pública, y los habitantes solicitarla, para debatir asuntos concernientes al interés general. La audiencia será consultiva y no vinculante. La autoridad deberá explicitar los fundamentos del acto bajo pena de nulidad, indicando de qué manera ha considerado las opiniones de la ciudadanía.`, currentText: `La Legislatura, el Poder Ejecutivo y los municipios pueden convocar a audiencia pública, y los habitantes solicitarla, para debatir asuntos concernientes al interés general. La audiencia será consultiva y no vinculante. La autoridad deberá explicitar los fundamentos del acto bajo pena de nulidad, indicando de qué manera ha considerado las opiniones de la ciudadanía.`, plainLanguageExplanation: 'Los poderes públicos y los ciudadanos pueden convocar o pedir audiencias públicas para debatir asuntos de interés general. Son consultivas y no vinculantes, pero la autoridad debe fundamentar su decisión final indicando cómo consideró la opinión ciudadana, bajo pena de nulidad.', practicalEffects: [], examples: ['Vecinos afectados por una obra pública pueden solicitar una audiencia pública; si la autoridad decide igual pero no explica cómo consideró las opiniones ciudadanas, el acto puede ser anulado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['audiencia pública', 'participación ciudadana', 'consulta', 'transparencia', 'fundamentación'], order: 50, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-52', lawId: 'const-entre-rios', number: '52', title: 'Revocatoria de mandato — 25% del padrón, a partir del primer año', originalText: `Por incumplimiento de la plataforma electoral o de los deberes propios de su cargo, los ciudadanos podrán revocar el mandato de todos los funcionarios electivos después de transcurrido un año del comienzo del mismo y antes de que resten seis meses para su término. El procedimiento revocatorio se habilitará por única vez ante el Tribunal Electoral a pedido de un número de ciudadanos inscriptos en el padrón provincial, departamental o local, según donde ejerza sus funciones el funcionario cuestionado, no inferior al veinticinco por ciento del padrón electoral. El Tribunal Electoral comprobará que dentro de los noventa días de iniciado el proceso, el pedido reúna los requisitos referidos y, sin pronunciarse sobre las causales invocadas, convocará a comicios según lo determine la ley. Si en la compulsa electoral, los votos a favor de la continuidad del funcionario fuesen inferiores al ochenta por ciento de los que obtuvo para acceder a su cargo, quedará automáticamente destituido, salvo que se trate de funcionarios municipales respecto de quienes se requiere el sesenta por ciento, en otro caso será confirmado. No se admitirá la solicitud ni avanzará de haber sido promovida mientras se sustancie el procedimiento destitutorio del funcionario previsto por esta Constitución.`, currentText: `Por incumplimiento de la plataforma electoral o de los deberes propios de su cargo, los ciudadanos podrán revocar el mandato de todos los funcionarios electivos después de transcurrido un año del comienzo del mismo y antes de que resten seis meses para su término. El procedimiento revocatorio se habilitará por única vez ante el Tribunal Electoral a pedido de un número de ciudadanos inscriptos en el padrón provincial, departamental o local, según donde ejerza sus funciones el funcionario cuestionado, no inferior al veinticinco por ciento del padrón electoral. El Tribunal Electoral comprobará que dentro de los noventa días de iniciado el proceso, el pedido reúna los requisitos referidos y, sin pronunciarse sobre las causales invocadas, convocará a comicios según lo determine la ley. Si en la compulsa electoral, los votos a favor de la continuidad del funcionario fuesen inferiores al ochenta por ciento de los que obtuvo para acceder a su cargo, quedará automáticamente destituido, salvo que se trate de funcionarios municipales respecto de quienes se requiere el sesenta por ciento, en otro caso será confirmado. No se admitirá la solicitud ni avanzará de haber sido promovida mientras se sustancie el procedimiento destitutorio del funcionario previsto por esta Constitución.`, plainLanguageExplanation: 'Los ciudadanos pueden revocar el mandato de cualquier funcionario electivo con el 25% del padrón electoral, después del primer año y antes de los últimos 6 meses. Si en el comicio el funcionario no alcanza el 80% de sus votos originales (60% en municipios), queda destituido.', practicalEffects: [], examples: ['Si un gobernador provincial es percibido como incumplidor, ciudadanos pueden iniciar una revocatoria. Si juntan el 25% del padrón y en el voto popular el funcionario obtiene menos del 80% de sus votos originales, pierde el mandato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocatoria de mandato', 'democracia directa', 'funcionarios electivos', 'Tribunal Electoral', '25% padrón'], order: 51, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-53', lawId: 'const-entre-rios', number: '53', title: 'Consejo Económico y Social — órgano consultivo no vinculante', originalText: `El Consejo Económico y Social es un órgano de consulta de los poderes públicos, cuya función será producir informes y dictámenes no vinculantes para la elaboración de políticas de Estado. Tendrá autonomía funcional y estará integrado por representantes de la producción, el trabajo, el ambientalismo, la educación, las profesiones, la ciencia y la tecnología en los términos en que la ley lo establezca. Sus miembros serán elegidos por las entidades representativas de cada sector. Forman parte del Consejo para el asesoramiento y la elaboración de las políticas específicas, los departamentos de familia, salud y cultura, como asimismo otros que se estimen necesarios. Son integrados por representantes de las entidades vinculadas a la materia, con participación regional y propendiendo a la descentralización.`, currentText: `El Consejo Económico y Social es un órgano de consulta de los poderes públicos, cuya función será producir informes y dictámenes no vinculantes para la elaboración de políticas de Estado. Tendrá autonomía funcional y estará integrado por representantes de la producción, el trabajo, el ambientalismo, la educación, las profesiones, la ciencia y la tecnología en los términos en que la ley lo establezca. Sus miembros serán elegidos por las entidades representativas de cada sector. Forman parte del Consejo para el asesoramiento y la elaboración de las políticas específicas, los departamentos de familia, salud y cultura, como asimismo otros que se estimen necesarios. Son integrados por representantes de las entidades vinculadas a la materia, con participación regional y propendiendo a la descentralización.`, plainLanguageExplanation: 'El Consejo Económico y Social asesora a los poderes públicos con informes y dictámenes no vinculantes. Integrado por representantes del sector productivo, laboral, ambiental, educativo y científico, promueve la participación social en la elaboración de políticas de Estado.', practicalEffects: [], examples: ['Antes de aprobar un plan provincial de desarrollo industrial, el Poder Ejecutivo puede consultar al Consejo Económico y Social para recibir recomendaciones de los sectores involucrados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo Económico y Social', 'órgano consultivo', 'políticas de Estado', 'dictámenes', 'participación sectorial'], order: 52, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-54', lawId: 'const-entre-rios', number: '54', title: 'Garantías de la detención — orden escrita y comunicación en 24 horas', originalText: `Ninguna persona puede ser detenida sin orden escrita emanada de autoridad competente y sin que preceda indagación sumaria que acredite indicio de su intervención en un hecho punible, salvo el caso de infraganti delito, en que podrá ser aprehendida por cualquier habitante y conducida inmediatamente ante la autoridad respectiva. En ningún caso la simple detención ni la prisión preventiva se cumplirá en las cárceles públicas destinadas a penados, ni podrá prolongarse por más de veinticuatro horas sin ser comunicada al juez o autoridad competente, poniendo a su disposición al detenido y los antecedentes del hecho.`, currentText: `Ninguna persona puede ser detenida sin orden escrita emanada de autoridad competente y sin que preceda indagación sumaria que acredite indicio de su intervención en un hecho punible, salvo el caso de infraganti delito, en que podrá ser aprehendida por cualquier habitante y conducida inmediatamente ante la autoridad respectiva. En ningún caso la simple detención ni la prisión preventiva se cumplirá en las cárceles públicas destinadas a penados, ni podrá prolongarse por más de veinticuatro horas sin ser comunicada al juez o autoridad competente, poniendo a su disposición al detenido y los antecedentes del hecho.`, plainLanguageExplanation: 'Nadie puede ser detenido sin orden judicial escrita y sin indicios previos de delito, salvo en flagrancia. El detenido no puede estar en cárceles de penados y la detención debe comunicarse a un juez dentro de las 24 horas.', practicalEffects: [], examples: ['Una persona detenida por la policía sin orden judicial y sin ser sorprendida en flagrancia puede exigir su liberación inmediata por violación de esta garantía constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['detención', 'orden judicial', 'garantías procesales', 'flagrancia', 'prisión preventiva', '24 horas'], order: 53, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-55', lawId: 'const-entre-rios', number: '55', title: 'Hábeas corpus provincial', originalText: `Toda persona detenida sin orden en forma de juez competente; por juez incompetente o por cualquier autoridad o individuo; o a quien se le niegue alguna de las garantías establecidas en la Constitución Nacional o Provincial o las leyes, podrá ocurrir, por sí o por conducto de otro, y valiéndose de cualquier medio de comunicación, ante el juez letrado inmediato, sin distinción de fueros ni instancias, para que se ordene su inmediata libertad, se lo someta al juez competente o se le acuerde la garantía negada, según el caso. El juez o tribunal ante quien se presente este recurso queda facultado para requerir toda clase de informes, para hacer comparecer al detenido a su presencia y deberá resolver en definitiva en un término sumarísimo que fijará la ley.`, currentText: `Toda persona detenida sin orden en forma de juez competente; por juez incompetente o por cualquier autoridad o individuo; o a quien se le niegue alguna de las garantías establecidas en la Constitución Nacional o Provincial o las leyes, podrá ocurrir, por sí o por conducto de otro, y valiéndose de cualquier medio de comunicación, ante el juez letrado inmediato, sin distinción de fueros ni instancias, para que se ordene su inmediata libertad, se lo someta al juez competente o se le acuerde la garantía negada, según el caso. El juez o tribunal ante quien se presente este recurso queda facultado para requerir toda clase de informes, para hacer comparecer al detenido a su presencia y deberá resolver en definitiva en un término sumarísimo que fijará la ley.`, plainLanguageExplanation: 'Cualquier persona detenida ilegalmente puede recurrir a cualquier juez, por cualquier medio, para obtener su libertad o la aplicación de sus garantías. Es el hábeas corpus provincial: una garantía urgente contra detenciones arbitrarias que el juez debe resolver en plazos mínimos.', practicalEffects: [], examples: ['Una persona que está detenida sin orden judicial puede mandar un mensaje desde la comisaría a un familiar para que presente un hábeas corpus ante cualquier juez, quien debe resolver en forma urgente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hábeas corpus', 'libertad personal', 'detención ilegal', 'garantías procesales', 'recurso urgente'], order: 54, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-56', lawId: 'const-entre-rios', number: '56', title: 'Acción de amparo — individual, colectivo, ambiental e información pública', originalText: `Todo habitante de la Provincia, las personas jurídicas reconocidas en la defensa de derechos o intereses de incidencia colectiva y el Defensor del Pueblo, podrán ejercer acción expedita, rápida y gratuita de amparo, siempre que no exista otro medio judicial más idóneo contra todo acto u omisión de autoridad administrativa provincial o municipal, judicial o legislativa en ejercicio de funciones administrativas, o de particulares, que en forma actual o inminente amenace, restrinja, altere, impida o lesione de manera manifiestamente ilegítima, derechos y garantías reconocidos por la Constitución Nacional, los instrumentos internacionales de protección de los derechos humanos, las leyes de la Nación, la presente Constitución, las leyes dictadas en su consecuencia y los tratados en que la Provincia sea parte. La acción también procederá cuando exista una afectación o el riesgo de una lesión a derechos difusos o de titularidad colectiva, para la protección ambiental o a derechos del usuario y el consumidor, o en caso de discriminación, así como cuando se desconociera o violara el derecho de libre acceso a la información pública.`, currentText: `Todo habitante de la Provincia, las personas jurídicas reconocidas en la defensa de derechos o intereses de incidencia colectiva y el Defensor del Pueblo, podrán ejercer acción expedita, rápida y gratuita de amparo, siempre que no exista otro medio judicial más idóneo contra todo acto u omisión de autoridad administrativa provincial o municipal, judicial o legislativa en ejercicio de funciones administrativas, o de particulares, que en forma actual o inminente amenace, restrinja, altere, impida o lesione de manera manifiestamente ilegítima, derechos y garantías reconocidos por la Constitución Nacional, los instrumentos internacionales de protección de los derechos humanos, las leyes de la Nación, la presente Constitución, las leyes dictadas en su consecuencia y los tratados en que la Provincia sea parte. La acción también procederá cuando exista una afectación o el riesgo de una lesión a derechos difusos o de titularidad colectiva, para la protección ambiental o a derechos del usuario y el consumidor, o en caso de discriminación, así como cuando se desconociera o violara el derecho de libre acceso a la información pública.`, plainLanguageExplanation: 'Cualquier habitante puede interponer un amparo rápido y gratuito contra actos u omisiones que amenacen sus derechos constitucionales. También procede para derechos colectivos, ambientales, de consumidores, en casos de discriminación y cuando se niega el acceso a información pública.', practicalEffects: [], examples: ['Una asociación ambiental puede interponer un amparo colectivo para detener una obra que contamina un humedal provincial, invocando la protección de derechos difusos ambientales garantizados en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['amparo', 'derechos fundamentales', 'derechos colectivos', 'medio ambiente', 'información pública', 'discriminación', 'Defensor del Pueblo'], order: 55, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-57', lawId: 'const-entre-rios', number: '57', title: 'Amparo por mora — demora injustificada de la administración', originalText: `Toda persona, parte en un expediente administrativo, podrá interponer amparo por mora a fin de obtener resolución inmediata, en el caso de demora injustificada de la autoridad interviniente en expedirse sobre el asunto requerido por el interesado. En tal supuesto, el juez emplazará a la administración o al funcionario remiso, bajo los apercibimientos que correspondan, a pronunciarse sobre el acto pretendido por el ocurrente en un plazo sumarísimo, aunque no podrá ordenarle en qué sentido lo debe hacer. La omisión en expedirse comportará la denegación tácita de la pretensión en trámite y agotará la vía administrativa, quedando expedita la acción judicial.`, currentText: `Toda persona, parte en un expediente administrativo, podrá interponer amparo por mora a fin de obtener resolución inmediata, en el caso de demora injustificada de la autoridad interviniente en expedirse sobre el asunto requerido por el interesado. En tal supuesto, el juez emplazará a la administración o al funcionario remiso, bajo los apercibimientos que correspondan, a pronunciarse sobre el acto pretendido por el ocurrente en un plazo sumarísimo, aunque no podrá ordenarle en qué sentido lo debe hacer. La omisión en expedirse comportará la denegación tácita de la pretensión en trámite y agotará la vía administrativa, quedando expedita la acción judicial.`, plainLanguageExplanation: 'Cuando la administración pública demora injustificadamente en resolver un expediente, el ciudadano puede presentar un amparo por mora. El juez ordena al funcionario que resuelva en un plazo mínimo, sin indicarle el sentido de la decisión. Si no responde, se considera denegado tácitamente.', practicalEffects: [], examples: ['Un contribuyente cuyo pedido de devolución de impuestos lleva un año sin resolución puede presentar un amparo por mora para forzar al organismo provincial a resolver en un plazo breve.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['amparo por mora', 'demora administrativa', 'expediente administrativo', 'silencio administrativo', 'acceso a la justicia'], order: 56, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-58', lawId: 'const-entre-rios', number: '58', title: 'Mandamiento de ejecución — obligar al funcionario a cumplir su deber legal', originalText: `Siempre que una ley u ordenanza imponga a un funcionario o corporación pública de carácter administrativo un deber expresamente determinado, todo aquel en cuyo interés deba ejecutarse el acto o que sufriere perjuicio material, moral o político, por la falta de cumplimiento del deber, puede demandar ante los tribunales su ejecución inmediata, y el tribunal, previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario o corporación un mandamiento de ejecución.`, currentText: `Siempre que una ley u ordenanza imponga a un funcionario o corporación pública de carácter administrativo un deber expresamente determinado, todo aquel en cuyo interés deba ejecutarse el acto o que sufriere perjuicio material, moral o político, por la falta de cumplimiento del deber, puede demandar ante los tribunales su ejecución inmediata, y el tribunal, previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario o corporación un mandamiento de ejecución.`, plainLanguageExplanation: 'Si una ley u ordenanza impone un deber claro a un funcionario y este no lo cumple, el perjudicado puede pedir al juez que ordene su ejecución inmediata mediante un mandamiento judicial. Es una herramienta para hacer cumplir obligaciones legales expresas de la administración.', practicalEffects: [], examples: ['Un vecino afectado por una obra ilegal que el municipio tiene obligación legal de demoler puede obtener un mandamiento judicial para que el intendente ordene la demolición de forma inmediata.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandamiento de ejecución', 'deber legal', 'funcionario', 'incumplimiento', 'acción judicial'], order: 57, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-59', lawId: 'const-entre-rios', number: '59', title: 'Mandamiento prohibitivo — impedir actos ilegales del funcionario', originalText: `Si un funcionario o corporación pública de carácter administrativo, ejecutase actos que le fueran expresamente prohibidos por las leyes u ordenanzas, el perjudicado podrá requerir de los tribunales, por procedimiento sumario, un mandamiento prohibitivo dirigido al funcionario o corporación.`, currentText: `Si un funcionario o corporación pública de carácter administrativo, ejecutase actos que le fueran expresamente prohibidos por las leyes u ordenanzas, el perjudicado podrá requerir de los tribunales, por procedimiento sumario, un mandamiento prohibitivo dirigido al funcionario o corporación.`, plainLanguageExplanation: 'Cuando un funcionario realiza actos que la ley le prohíbe expresamente, el perjudicado puede pedir al tribunal que emita un mandamiento prohibitivo para detener esa conducta por vía sumaría.', practicalEffects: [], examples: ['Si un municipio adjudica una licitación violando prohibiciones legales expresas, el concursante perjudicado puede obtener un mandamiento judicial prohibitivo que suspenda el proceso licitatorio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandamiento prohibitivo', 'actos ilegales', 'funcionario', 'prohibición legal', 'acción judicial sumaria'], order: 58, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-60', lawId: 'const-entre-rios', number: '60', title: 'Control de constitucionalidad — tres sentencias del STJ derogan la norma', originalText: `Es de ningún valor toda ley de la Provincia que viole o menoscabe las prescripciones establecidas por la Ley Suprema de la Nación y por esta Constitución, así como todo acto, contrato, decreto u ordenanza que contravenga a las mismas o las leyes dictadas en su consecuencia, pudiendo los interesados demandar o invocar su inconstitucionalidad o invalidez ante los tribunales competentes. Sin perjuicio de ello, los jueces al advertir la inconstitucionalidad de una norma, de oficio podrán declararla. La sentencia que pronuncie la inconstitucionalidad será declarativa y de condena pudiendo ser ejecutada. En el proceso respectivo podrán admitirse medidas cautelares. La declaración de inconstitucionalidad por tres veces y, por sentencia firme del Superior Tribunal de Justicia de una norma general provincial, produce su derogación en la parte afectada por el vicio.`, currentText: `Es de ningún valor toda ley de la Provincia que viole o menoscabe las prescripciones establecidas por la Ley Suprema de la Nación y por esta Constitución, así como todo acto, contrato, decreto u ordenanza que contravenga a las mismas o las leyes dictadas en su consecuencia, pudiendo los interesados demandar o invocar su inconstitucionalidad o invalidez ante los tribunales competentes. Sin perjuicio de ello, los jueces al advertir la inconstitucionalidad de una norma, de oficio podrán declararla. La sentencia que pronuncie la inconstitucionalidad será declarativa y de condena pudiendo ser ejecutada. En el proceso respectivo podrán admitirse medidas cautelares. La declaración de inconstitucionalidad por tres veces y, por sentencia firme del Superior Tribunal de Justicia de una norma general provincial, produce su derogación en la parte afectada por el vicio.`, plainLanguageExplanation: 'Las leyes y actos contrarios a la Constitución son nulos. Cualquier juez puede declararlos inconstitucionales, incluso de oficio. Cuando el Superior Tribunal de Justicia declara inconstitucional una norma provincial por tercera vez en sentencias firmes, esa norma queda derogada.', practicalEffects: [], examples: ['Si el Superior Tribunal declara inconstitucional el mismo artículo de una ley provincial en tres causas distintas con sentencia firme, ese artículo queda automáticamente derogado sin necesidad de acto legislativo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inconstitucionalidad', 'control de constitucionalidad', 'Superior Tribunal de Justicia', 'derogación', 'medidas cautelares', 'nulidad'], order: 59, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-61', lawId: 'const-entre-rios', number: '61', title: 'Acción directa de inconstitucionalidad ante el Superior Tribunal', originalText: `Todo habitante de la Provincia, en el solo interés de la legalidad, tiene acción directa para demandar ante el Superior Tribunal de Justicia la inconstitucionalidad de una norma general contraria a la presente Constitución. El firmante de una demanda temeraria será sancionado de acuerdo con la ley.`, currentText: `Todo habitante de la Provincia, en el solo interés de la legalidad, tiene acción directa para demandar ante el Superior Tribunal de Justicia la inconstitucionalidad de una norma general contraria a la presente Constitución. El firmante de una demanda temeraria será sancionado de acuerdo con la ley.`, plainLanguageExplanation: 'Cualquier habitante puede demandar directamente ante el Superior Tribunal de Justicia la inconstitucionalidad de una ley provincial, sin necesidad de ser parte en un caso concreto. Quien abusa de esta acción con demandas infundadas puede ser sancionado.', practicalEffects: [], examples: ['Un ciudadano que considera que una ley provincial viola la Constitución puede demandar su inconstitucionalidad directamente ante el Superior Tribunal, sin esperar ser afectado individualmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acción directa', 'inconstitucionalidad', 'Superior Tribunal de Justicia', 'norma general', 'control abstracto'], order: 60, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-62', lawId: 'const-entre-rios', number: '62', title: 'Acción por omisión inconstitucional — derecho sin reglamentar', originalText: `Si esta Constitución, una ley o una ordenanza dictadas en su consecuencia, otorgasen algún derecho que dependiera para su concreción de una ulterior reglamentación y ésta no se dictara dentro del año de la sanción de la norma que la impone, el interesado podrá demandar ante el Superior Tribunal de Justicia la condena de la autoridad renuente, a dictar la norma omitida. Ante el incumplimiento del obligado, el Tribunal integrará la misma o, de ser esto imposible ordenará, si correspondiere, la indemnización al demandante del daño resarcible que sumariamente acredite. Si la autoridad omitiere un deber constitucional indispensable para el regular funcionamiento del Estado, cualquier legitimado por la ley podrá, por la vía prevista en el apartado anterior, demandar se condene al funcionario remiso a cumplir la conducta debida o a que, en su defecto, la realice directamente el Tribunal.`, currentText: `Si esta Constitución, una ley o una ordenanza dictadas en su consecuencia, otorgasen algún derecho que dependiera para su concreción de una ulterior reglamentación y ésta no se dictara dentro del año de la sanción de la norma que la impone, el interesado podrá demandar ante el Superior Tribunal de Justicia la condena de la autoridad renuente, a dictar la norma omitida. Ante el incumplimiento del obligado, el Tribunal integrará la misma o, de ser esto imposible ordenará, si correspondiere, la indemnización al demandante del daño resarcible que sumariamente acredite. Si la autoridad omitiere un deber constitucional indispensable para el regular funcionamiento del Estado, cualquier legitimado por la ley podrá, por la vía prevista en el apartado anterior, demandar se condene al funcionario remiso a cumplir la conducta debida o a que, en su defecto, la realice directamente el Tribunal.`, plainLanguageExplanation: 'Si la autoridad no reglamenta un derecho constitucional o legal en el plazo de un año, cualquier interesado puede demandar ante el Superior Tribunal que la obligue a dictar la norma omitida. Si la omisión persiste, el Tribunal puede redactar la norma directamente o indemnizar al afectado.', practicalEffects: [], examples: ['Si la Legislatura sanciona una ley que reconoce un beneficio pero no dicta la reglamentación en un año, los beneficiarios pueden demandar al STJ para que ordene su reglamentación o la dicte el propio Tribunal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['omisión inconstitucional', 'inconstitucionalidad por omisión', 'reglamentación', 'Superior Tribunal', 'derechos sin reglamentar'], order: 61, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-63', lawId: 'const-entre-rios', number: '63', title: 'Hábeas data — derecho a conocer y rectificar datos personales', originalText: `Toda persona tiene derecho a interponer acción expedita, rápida y gratuita de hábeas data para tomar conocimiento de los datos referidos a ella, a sus familiares directos fallecidos, o a sus propios bienes, así como la fuente, finalidad y destino de los mismos, que consten en todo registro, archivo o banco de datos público o privado de carácter público, o que estuviesen almacenados en cualquier medio técnico apto para proveer informes. En caso de falsedad o uso discriminatorio de tales datos podrá exigir, sin cargo alguno, la inmediata rectificación o actualización de la información falsa o la supresión o confidencialidad de la sensible. El ejercicio de este derecho no puede afectar las fuentes de información periodística ni el secreto profesional. La acción no procederá cuando la obtención de los datos reclamados estuviese reglamentada.`, currentText: `Toda persona tiene derecho a interponer acción expedita, rápida y gratuita de hábeas data para tomar conocimiento de los datos referidos a ella, a sus familiares directos fallecidos, o a sus propios bienes, así como la fuente, finalidad y destino de los mismos, que consten en todo registro, archivo o banco de datos público o privado de carácter público, o que estuviesen almacenados en cualquier medio técnico apto para proveer informes. En caso de falsedad o uso discriminatorio de tales datos podrá exigir, sin cargo alguno, la inmediata rectificación o actualización de la información falsa o la supresión o confidencialidad de la sensible. El ejercicio de este derecho no puede afectar las fuentes de información periodística ni el secreto profesional. La acción no procederá cuando la obtención de los datos reclamados estuviese reglamentada.`, plainLanguageExplanation: 'Cualquier persona puede conocer los datos que el Estado o empresas privadas tengan sobre ella, y exigir su rectificación o supresión si son falsos o usados de forma discriminatoria. La acción es gratuita y no puede usarse para revelar fuentes periodísticas.', practicalEffects: [], examples: ['Una persona que figura en un registro de deudores con información incorrecta puede interponer un hábeas data para exigir que corrijan o eliminen ese dato de forma gratuita y urgente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hábeas data', 'datos personales', 'privacidad', 'rectificación', 'bases de datos', 'protección de datos'], order: 62, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-64', lawId: 'const-entre-rios', number: '64', title: 'Garantías del proceso penal — doble instancia y sistema acusatorio', originalText: `La Legislatura asegurará la doble instancia en el proceso penal, respetando los principios de contradicción, oralidad y publicidad en el sistema acusatorio. No podrán reabrirse procesos fenecidos, salvo en materia criminal cuando la revisión sea favorable al reo y el caso esté autorizado por la ley. La prueba en juicio se producirá públicamente con las limitaciones que la ley establezca. La ley no podrá atribuir a la confesión hecha ante la policía mayor valor probatorio que el de un indicio. El sumario será público, excepción hecha de la incomunicación que no podrá exceder de tres días. Toda persona declarada inocente respecto de una imputación por la que hubiese sido privada de su libertad de manera infundada o que se revele irracional en el curso del proceso, tendrá derecho a que el Estado, de acuerdo con la ley, le indemnice el daño sufrido a causa de su privación de libertad.`, currentText: `La Legislatura asegurará la doble instancia en el proceso penal, respetando los principios de contradicción, oralidad y publicidad en el sistema acusatorio. No podrán reabrirse procesos fenecidos, salvo en materia criminal cuando la revisión sea favorable al reo y el caso esté autorizado por la ley. La prueba en juicio se producirá públicamente con las limitaciones que la ley establezca. La ley no podrá atribuir a la confesión hecha ante la policía mayor valor probatorio que el de un indicio. El sumario será público, excepción hecha de la incomunicación que no podrá exceder de tres días. Toda persona declarada inocente respecto de una imputación por la que hubiese sido privada de su libertad de manera infundada o que se revele irracional en el curso del proceso, tendrá derecho a que el Estado, de acuerdo con la ley, le indemnice el daño sufrido a causa de su privación de libertad.`, plainLanguageExplanation: 'El proceso penal debe garantizar doble instancia, oralidad y publicidad. La confesión ante la policía solo vale como indicio. Quien sea detenido y luego absuelto por una imputación infundada tiene derecho a que el Estado lo indemnice.', practicalEffects: [], examples: ['Una persona que fue detenida preventivamente y luego sobreseída por ausencia de mérito puede demandar al Estado provincial una indemnización por el tiempo que estuvo privada de su libertad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['doble instancia', 'proceso penal', 'sistema acusatorio', 'oralidad', 'confesión policial', 'indemnización detención'], order: 63, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-65', lawId: 'const-entre-rios', number: '65', title: 'Tutela judicial efectiva — acceso gratuito, defensa y plazo razonable', originalText: `La Provincia asegura la tutela judicial continua y efectiva, el acceso irrestricto a la justicia, la gratuidad de los trámites a quienes carezcan de recursos suficientes y la inviolabilidad de la defensa de la persona y de los derechos, en todo procedimiento administrativo o proceso judicial. El principio de legalidad y la interdicción de la arbitrariedad deben regir los actos de los poderes públicos. Los actos de autoridad, las sentencias judiciales y los actos administrativos serán fundados suficientemente y decididos en tiempo razonable. El retardo en dictar sentencia y las dilaciones indebidas, cuando sean reiteradas, constituyen falta grave. Se promueve la utilización, difusión y desarrollo de las instancias no adversariales de resolución de conflictos, especialmente a través de la mediación, negociación, conciliación, facilitación y arbitraje.`, currentText: `La Provincia asegura la tutela judicial continua y efectiva, el acceso irrestricto a la justicia, la gratuidad de los trámites a quienes carezcan de recursos suficientes y la inviolabilidad de la defensa de la persona y de los derechos, en todo procedimiento administrativo o proceso judicial. El principio de legalidad y la interdicción de la arbitrariedad deben regir los actos de los poderes públicos. Los actos de autoridad, las sentencias judiciales y los actos administrativos serán fundados suficientemente y decididos en tiempo razonable. El retardo en dictar sentencia y las dilaciones indebidas, cuando sean reiteradas, constituyen falta grave. Se promueve la utilización, difusión y desarrollo de las instancias no adversariales de resolución de conflictos, especialmente a través de la mediación, negociación, conciliación, facilitación y arbitraje.`, plainLanguageExplanation: 'Toda persona tiene acceso irrestricto y gratuito a la justicia. Los fallos deben ser fundados y dictados en tiempo razonable; la morosidad judicial reiterada es falta grave. El Estado promueve métodos alternativos de resolución de conflictos como la mediación.', practicalEffects: [], examples: ['Una persona sin recursos económicos puede acceder gratuitamente a la justicia provincial a través del servicio de defensa oficial o la asistencia jurídica gratuita.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutela judicial efectiva', 'acceso a la justicia', 'gratuidad', 'plazo razonable', 'mediación', 'defensa en juicio'], order: 64, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-66', lawId: 'const-entre-rios', number: '66', title: 'Prohibición de tormentos — cárceles para reinserción — madres detenidas', originalText: `Queda prohibida toda especie de tormentos y vejámenes, bajo pena de destitución inmediata y sin perjuicio de las responsabilidades en que incurran los empleados o funcionarios que los apliquen, ordenen o consientan. Las cárceles y colonias penales productivas de la Provincia serán sanas y limpias para seguridad y no para mortificación de los recluidos, debiendo constituir centros de trabajo. Éstas y cualquier lugar de internación forzada deben constituir centros de tratamiento integral. La ejecución de la pena privativa de la libertad tiene como finalidad lograr que el condenado adquiera la capacidad de comprender y respetar la ley, procurando su adecuada reinserción social. Constituirá falta grave todo rigor innecesario infligido a los internos. La ejecución de la pena privativa de la libertad, en todas sus modalidades, estará sometida a permanente y efectivo contralor judicial. Las mujeres privadas de su libertad, deben ser alojadas en dependencias especiales, garantizando a las madres de niños menores de cinco años, espacios para convivir con ellos. Si el Estado no observara este mandato, las detenidas embarazadas o con niños cumplirán arresto domiciliario. Los menores privados de su libertad no pueden ser alojados en establecimientos de detención de adultos.`, currentText: `Queda prohibida toda especie de tormentos y vejámenes, bajo pena de destitución inmediata y sin perjuicio de las responsabilidades en que incurran los empleados o funcionarios que los apliquen, ordenen o consientan. Las cárceles y colonias penales productivas de la Provincia serán sanas y limpias para seguridad y no para mortificación de los recluidos, debiendo constituir centros de trabajo. Éstas y cualquier lugar de internación forzada deben constituir centros de tratamiento integral. La ejecución de la pena privativa de la libertad tiene como finalidad lograr que el condenado adquiera la capacidad de comprender y respetar la ley, procurando su adecuada reinserción social. Constituirá falta grave todo rigor innecesario infligido a los internos. La ejecución de la pena privativa de la libertad, en todas sus modalidades, estará sometida a permanente y efectivo contralor judicial. Las mujeres privadas de su libertad, deben ser alojadas en dependencias especiales, garantizando a las madres de niños menores de cinco años, espacios para convivir con ellos. Si el Estado no observara este mandato, las detenidas embarazadas o con niños cumplirán arresto domiciliario. Los menores privados de su libertad no pueden ser alojados en establecimientos de detención de adultos.`, plainLanguageExplanation: 'Queda prohibida la tortura y cualquier vejamen. Las cárceles deben ser sanas, orientadas a la reinserción y bajo control judicial permanente. Las mujeres deben alojarse en dependencias especiales; las madres de niños menores de cinco años tienen derecho a convivir con ellos, y si el Estado no lo garantiza, la madre cumple arresto domiciliario.', practicalEffects: [], examples: ['Una madre detenida con un bebé de dos años tiene derecho a estar en una unidad penitenciaria especial que le permita convivir con su hijo; si no la hubiera disponible, debe concedérsele arresto domiciliario.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tortura', 'tormentos', 'cárceles', 'reinserción social', 'mujeres detenidas', 'arresto domiciliario', 'menores privados de libertad'], order: 65, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-67', lawId: 'const-entre-rios', number: '67', title: 'Política económica — justicia social, pymes y desconcentración', originalText: `El Estado, mediante su legislación, promoverá el bienestar económico y social de la colectividad. La organización de la riqueza y su explotación deben respetar los principios de la justicia social. El Estado desarrollará políticas con el objeto de: a) Estimular la existencia de condiciones competitivas en los mercados y una equitativa distribución de la renta, promoviendo acciones tendientes a evitar que prácticas individuales o colectivas distorsionen o impidan la competencia o lesionen el bienestar general. b) Alentar el desarrollo económico de la pequeña y mediana empresa, domiciliada y radicada en la Provincia, con asistencia técnica y financiera, fomentándolas crediticia e impositivamente, protegiendo la radicación de industrias en sus comunidades de origen, la comercialización sustentable de sus productos y promoviendo el fortalecimiento de sus entidades representativas. c) Promover la desconcentración de los entes, organismos o empresas en todo el territorio de la Provincia.`, currentText: `El Estado, mediante su legislación, promoverá el bienestar económico y social de la colectividad. La organización de la riqueza y su explotación deben respetar los principios de la justicia social. El Estado desarrollará políticas con el objeto de: a) Estimular la existencia de condiciones competitivas en los mercados y una equitativa distribución de la renta, promoviendo acciones tendientes a evitar que prácticas individuales o colectivas distorsionen o impidan la competencia o lesionen el bienestar general. b) Alentar el desarrollo económico de la pequeña y mediana empresa, domiciliada y radicada en la Provincia, con asistencia técnica y financiera, fomentándolas crediticia e impositivamente, protegiendo la radicación de industrias en sus comunidades de origen, la comercialización sustentable de sus productos y promoviendo el fortalecimiento de sus entidades representativas. c) Promover la desconcentración de los entes, organismos o empresas en todo el territorio de la Provincia.`, plainLanguageExplanation: 'El Estado promueve el bienestar económico con justicia social. Sus políticas deben estimular la competencia, apoyar a las pymes con asistencia técnica y financiera, y desconcentrar organismos y empresas en todo el territorio provincial.', practicalEffects: [], examples: ['El Estado provincial puede ofrecer créditos blandos o exenciones impositivas a pymes radicadas en el interior provincial para evitar la concentración económica en Paraná.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['política económica', 'justicia social', 'pymes', 'competencia', 'desconcentración', 'distribución de la renta'], order: 66, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-68', lawId: 'const-entre-rios', number: '68', title: 'Fomento a la producción agropecuaria — industrialización y acceso a la tierra', originalText: `El Estado fomentará y protegerá la producción y, en especial, las industrias madres y las transformadoras de la producción rural; a cuyo objeto podrá conceder, con carácter temporario, primas, recompensa de estímulos, exoneración de impuestos y contribuciones u otros beneficios compatibles con esta Constitución; o concurrir a la formación de sus capitales, y al de los ya existentes, participando de la dirección y de la distribución de sus beneficios. Igualmente fomentará y orientará la aplicación de todo sistema, instrumento o procedimiento, que tienda a facilitar la comercialización de la producción aunque para ello deba acudir con sus recursos o crédito. Impulsará las condiciones esenciales para la diversificación, industrialización y participación equitativa en toda la cadena de valor de la producción, posibilitando el incremento de su rendimiento de manera sustentable. Resguardará al pequeño y mediano productor, y garantizará su participación en el Consejo Económico y Social. Procurará para la población rural el acceso a la propiedad de la tierra y promoverá su defensa.`, currentText: `El Estado fomentará y protegerá la producción y, en especial, las industrias madres y las transformadoras de la producción rural; a cuyo objeto podrá conceder, con carácter temporario, primas, recompensa de estímulos, exoneración de impuestos y contribuciones u otros beneficios compatibles con esta Constitución; o concurrir a la formación de sus capitales, y al de los ya existentes, participando de la dirección y de la distribución de sus beneficios. Igualmente fomentará y orientará la aplicación de todo sistema, instrumento o procedimiento, que tienda a facilitar la comercialización de la producción aunque para ello deba acudir con sus recursos o crédito. Impulsará las condiciones esenciales para la diversificación, industrialización y participación equitativa en toda la cadena de valor de la producción, posibilitando el incremento de su rendimiento de manera sustentable. Resguardará al pequeño y mediano productor, y garantizará su participación en el Consejo Económico y Social. Procurará para la población rural el acceso a la propiedad de la tierra y promoverá su defensa.`, plainLanguageExplanation: 'El Estado fomenta la producción agropecuaria e industrial, podiendo otorgar beneficios impositivos temporarios. Promueve la industrialización y el acceso a toda la cadena de valor. Protege al pequeño y mediano productor y procura el acceso a la propiedad de la tierra para la población rural.', practicalEffects: [], examples: ['El gobierno provincial puede eximir impositivamente a una empresa agroindustrial nueva en el interior para fomentar la radicación y la generación de empleo local, en cumplimiento de este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['producción agropecuaria', 'industrias', 'exención impositiva', 'pequeño productor', 'acceso a la tierra', 'cadena de valor'], order: 67, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-69', lawId: 'const-entre-rios', number: '69', title: 'Turismo — política sostenible e inversión pública y privada', originalText: `El Estado promoverá la actividad turística, favorecerá la iniciativa e inversión pública y privada, fomentará y sostendrá el turismo social. Coordinará con las representaciones sectoriales, municipios y comunas, una política sostenible y sustentable, para el desarrollo armónico de la actividad.`, currentText: `El Estado promoverá la actividad turística, favorecerá la iniciativa e inversión pública y privada, fomentará y sostendrá el turismo social. Coordinará con las representaciones sectoriales, municipios y comunas, una política sostenible y sustentable, para el desarrollo armónico de la actividad.`, plainLanguageExplanation: 'El Estado promueve el turismo como actividad económica estratégica, con participación pública y privada. También sostiene el turismo social para que sectores de bajos ingresos puedan acceder a la experiencia turística, coordinando políticas con municipios y comunas.', practicalEffects: [], examples: ['Los programas provinciales de turismo social que permiten a jubilados o trabajadores acceder a temporadas de verano con subsidio tienen fundamento constitucional en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['turismo', 'turismo social', 'inversión pública', 'desarrollo sustentable', 'municipios'], order: 68, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-70', lawId: 'const-entre-rios', number: '70', title: 'Medios de comunicación — desconcentración y fomento a cooperativas', originalText: `El Estado, dentro de su competencia, protegerá y alentará la explotación de sus recursos radioeléctricos y los medios de comunicación radicados en su territorio, como herramienta para el fortalecimiento de sus regiones y la conformación de su identidad cultural. Desalentará, mediante políticas activas, la conformación de monopolios, oligopolios o cualquier otra forma de concentración de los medios de comunicación social en el ámbito provincial. Promoverá la propiedad y gestión de medios de comunicación social por parte de organizaciones sociales, cooperativas y comunitarias sin fines de lucro.`, currentText: `El Estado, dentro de su competencia, protegerá y alentará la explotación de sus recursos radioeléctricos y los medios de comunicación radicados en su territorio, como herramienta para el fortalecimiento de sus regiones y la conformación de su identidad cultural. Desalentará, mediante políticas activas, la conformación de monopolios, oligopolios o cualquier otra forma de concentración de los medios de comunicación social en el ámbito provincial. Promoverá la propiedad y gestión de medios de comunicación social por parte de organizaciones sociales, cooperativas y comunitarias sin fines de lucro.`, plainLanguageExplanation: 'El Estado protege los medios de comunicación locales como herramienta cultural y regional, desalentando la concentración mediática. Promueve activamente la propiedad de medios por parte de cooperativas, organizaciones sociales y comunitarias sin fines de lucro.', practicalEffects: [], examples: ['Una radio comunitaria sin fines de lucro tiene respaldo constitucional para obtener una licencia radioeléctrica provincial; el Estado debe favorecerla frente a grupos concentrados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medios de comunicación', 'concentración mediática', 'monopolios', 'cooperativas', 'radio comunitaria', 'identidad cultural'], order: 69, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-71', lawId: 'const-entre-rios', number: '71', title: 'Inmigración, colonización e infraestructura de comunicación y transporte', originalText: `Promoverá la inmigración, el retorno de los entrerrianos emigrados, la colonización, la construcción de ferrocarriles, canales y otros medios de comunicación y de transporte, y la implantación y explotación de industrias o empresas que interesen al bien público.`, currentText: `Promoverá la inmigración, el retorno de los entrerrianos emigrados, la colonización, la construcción de ferrocarriles, canales y otros medios de comunicación y de transporte, y la implantación y explotación de industrias o empresas que interesen al bien público.`, plainLanguageExplanation: 'El Estado promueve la inmigración, el retorno de emigrados entrerrianos y la colonización de tierras, así como la construcción de infraestructura de comunicación, transporte e industrias de interés público.', practicalEffects: [], examples: ['El Estado puede ofrecer incentivos y tierras para la radicación de inmigrantes que quieran establecerse y desarrollar actividades productivas en la provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmigración', 'colonización', 'ferrocarriles', 'transporte', 'infraestructura', 'entrerrianos emigrados'], order: 70, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-72', lawId: 'const-entre-rios', number: '72', title: 'Infraestructura vial — construcción y mejoramiento de caminos', originalText: `Intensificará la construcción y mejoramiento progresivo de los caminos e incitará la iniciativa y cooperación privadas para la prosecución de la obra vial.`, currentText: `Intensificará la construcción y mejoramiento progresivo de los caminos e incitará la iniciativa y cooperación privadas para la prosecución de la obra vial.`, plainLanguageExplanation: 'El Estado tiene el mandato constitucional de construir y mejorar progresivamente la red vial provincial, incentivando también la participación privada en la obra pública de caminos.', practicalEffects: [], examples: ['El programa provincial de mejora de caminos rurales tiene base constitucional en este artículo, que obliga al Estado a invertir progresivamente en infraestructura vial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['infraestructura vial', 'caminos', 'obra pública', 'cooperación privada', 'red vial'], order: 71, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-73', lawId: 'const-entre-rios', number: '73', title: 'Inversión privada en servicios públicos e industrias — régimen mixto', originalText: `Estimulará la inversión de los capitales privados y en especial de los ahorros populares, en las empresas que exploten servicios públicos, en las entidades económico-financieras, en el establecimiento de las industrias que se asienten en la Provincia, e iniciará esta evolución sometiendo las explotaciones oficiales al régimen mixto y fortaleciendo las iniciativas particulares con la participación y el aporte del Estado.`, currentText: `Estimulará la inversión de los capitales privados y en especial de los ahorros populares, en las empresas que exploten servicios públicos, en las entidades económico-financieras, en el establecimiento de las industrias que se asienten en la Provincia, e iniciará esta evolución sometiendo las explotaciones oficiales al régimen mixto y fortaleciendo las iniciativas particulares con la participación y el aporte del Estado.`, plainLanguageExplanation: 'El Estado promueve la inversión privada, incluidos los ahorros populares, en servicios públicos, industrias y entidades financieras. Las empresas oficiales pueden adoptar el régimen mixto público-privado para fortalecer el desarrollo económico.', practicalEffects: [], examples: ['El Estado puede crear una empresa mixta donde particulares e inversores invierten en una planta industrial de interés público junto con el gobierno provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inversión privada', 'servicios públicos', 'régimen mixto', 'ahorros populares', 'industrias', 'empresa pública'], order: 72, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-74', lawId: 'const-entre-rios', number: '74', title: 'Banco de la Provincia — banco oficial no privatizable', originalText: `El Estado creará un Banco de la Provincia para contribuir al desarrollo de sus sectores productivos y canalizar el ahorro público y privado, por medio de una política crediticia que aumente el potencial económico de la Provincia y de sus habitantes, con sentido de justicia social. Será banco oficial y agente financiero del Estado, en la medida que su desarrollo lo permita y podrá serlo de los municipios que lo requieran. La Ley fijará su carta orgánica, garantizando en sus órganos directivos la participación democrática de los sectores de la producción, de los sectores sociales y de sus trabajadores. El Estado será siempre el accionista mayoritario, sin perjuicio de la participación privada en la formación del capital. En ningún caso se podrá disponer la privatización de sus acciones.`, currentText: `El Estado creará un Banco de la Provincia para contribuir al desarrollo de sus sectores productivos y canalizar el ahorro público y privado, por medio de una política crediticia que aumente el potencial económico de la Provincia y de sus habitantes, con sentido de justicia social. Será banco oficial y agente financiero del Estado, en la medida que su desarrollo lo permita y podrá serlo de los municipios que lo requieran. La Ley fijará su carta orgánica, garantizando en sus órganos directivos la participación democrática de los sectores de la producción, de los sectores sociales y de sus trabajadores. El Estado será siempre el accionista mayoritario, sin perjuicio de la participación privada en la formación del capital. En ningún caso se podrá disponer la privatización de sus acciones.`, plainLanguageExplanation: 'El Banco de la Provincia actúa como agente financiero del Estado, financiando el desarrollo económico con criterio de justicia social. El Estado siempre es el accionista mayoritario y la privatización del banco está prohibida constitucionalmente.', practicalEffects: [], examples: ['Cualquier ley provincial o decreto que intente privatizar el Banco de Entre Ríos sería inconstitucional, ya que la Constitución prohíbe expresamente la privatización de sus acciones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Banco de la Provincia', 'banco oficial', 'privatización prohibida', 'agente financiero', 'crédito productivo', 'justicia social'], order: 73, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-75', lawId: 'const-entre-rios', number: '75', title: 'Federalismo de concertación — acuerdos interprovinciales e internacionales', originalText: `El Estado promoverá el federalismo de concertación con el Estado nacional y con las restantes provincias para el desarrollo cultural, educativo, ambiental, económico y social. Podrá integrarse regionalmente celebrando acuerdos, con facultades de crear órganos administrativos de consulta y decisión, sujetos a la aprobación legislativa. Podrá realizar gestiones y celebrar acuerdos internacionales para satisfacer sus intereses, sin perjuicio de las facultades delegadas al gobierno federal. Fomentará la creación de regiones o microrregiones dentro de su territorio, atendiendo características de comunidad de intereses, afinidades poblacionales y geográficas, para posibilitar un desarrollo económico y social sustentable.`, currentText: `El Estado promoverá el federalismo de concertación con el Estado nacional y con las restantes provincias para el desarrollo cultural, educativo, ambiental, económico y social. Podrá integrarse regionalmente celebrando acuerdos, con facultades de crear órganos administrativos de consulta y decisión, sujetos a la aprobación legislativa. Podrá realizar gestiones y celebrar acuerdos internacionales para satisfacer sus intereses, sin perjuicio de las facultades delegadas al gobierno federal. Fomentará la creación de regiones o microrregiones dentro de su territorio, atendiendo características de comunidad de intereses, afinidades poblacionales y geográficas, para posibilitar un desarrollo económico y social sustentable.`, plainLanguageExplanation: 'La Provincia puede celebrar acuerdos con otras provincias y con el Estado Nacional para el desarrollo conjunto. También puede firmar acuerdos internacionales en materia de su competencia. Internamente, fomenta la creación de microrregiones para un desarrollo territorial más equitativo.', practicalEffects: [], examples: ['La Provincia de Entre Ríos puede firmar un acuerdo con Corrientes y Misiones para la gestión común del río Uruguay, con base en este artículo de federalismo de concertación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['federalismo', 'acuerdos interprovinciales', 'acuerdos internacionales', 'regiones', 'microrregiones', 'integración regional'], order: 74, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-76', lawId: 'const-entre-rios', number: '76', title: 'Cooperativismo y economía social — preferencia en licitaciones', originalText: `Estimulará la tendencia cooperativista, mutualista, asociativista, y la conformación de empresas de la economía social, basadas en los principios del bien común y en la gestión solidaria. Protegerá las organizaciones de ese carácter, fomentando su desarrollo, asistencia técnica y fiscalización, garantizando su naturaleza y finalidad. Controlará que las cooperativas de trabajo sean fuente de empleo decente. En las licitaciones y concesiones de servicios públicos que realice el Estado, en igualdad de condiciones, serán preferidas estas organizaciones. Alentará la propiedad y gestión cooperativa de empresas por sus trabajadores. Difundirá el pensamiento y la educación cooperativista, mutualista y asociativista. Brindará tratamiento impositivo adecuado a su naturaleza, y podrá concederles exenciones fiscales a las que colaboren con el desarrollo de la Provincia.`, currentText: `Estimulará la tendencia cooperativista, mutualista, asociativista, y la conformación de empresas de la economía social, basadas en los principios del bien común y en la gestión solidaria. Protegerá las organizaciones de ese carácter, fomentando su desarrollo, asistencia técnica y fiscalización, garantizando su naturaleza y finalidad. Controlará que las cooperativas de trabajo sean fuente de empleo decente. En las licitaciones y concesiones de servicios públicos que realice el Estado, en igualdad de condiciones, serán preferidas estas organizaciones. Alentará la propiedad y gestión cooperativa de empresas por sus trabajadores. Difundirá el pensamiento y la educación cooperativista, mutualista y asociativista. Brindará tratamiento impositivo adecuado a su naturaleza, y podrá concederles exenciones fiscales a las que colaboren con el desarrollo de la Provincia.`, plainLanguageExplanation: 'El Estado promueve el cooperativismo, mutualismo y economía social. En licitaciones de servicios públicos, en igualdad de condiciones, se da preferencia a las cooperativas. Se pueden otorgar exenciones fiscales a las que colaboren con el desarrollo provincial.', practicalEffects: [], examples: ['En una licitación para la gestión de un servicio de recolección de residuos, si una cooperativa ofrece las mismas condiciones que una empresa privada, el Estado debe adjudicársela a la cooperativa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cooperativismo', 'mutualismo', 'economía social', 'licitaciones', 'exenciones fiscales', 'empleo decente'], order: 75, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-77', lawId: 'const-entre-rios', number: '77', title: 'Colegios y Consejos Profesionales — matrícula y poder disciplinario', originalText: `El Estado reconoce y garantiza la plena vigencia de los Colegios y Consejos Profesionales, les confiere el gobierno de la matrícula, la defensa y promoción de sus intereses específicos, la facultad de dictar sus normas de ética e implementar métodos de resolución de conflictos de instancia voluntaria. Los Colegios y Consejos Profesionales aseguran el libre ejercicio de la profesión y su organización en forma democrática y pluralista y ejercen el poder disciplinario sobre sus miembros, dictando resoluciones que son revisables judicialmente. La Provincia reconoce la existencia de las entidades de previsión y seguridad social para profesionales, bajo los principios de solidaridad, proporcionalidad y obligatoriedad de afiliación y aporte. Asegura su autonomía económica y financiera, la dirección y administración de las mismas por representantes de sus afiliados y la intangibilidad frente al Estado, de los recursos que conforman su patrimonio.`, currentText: `El Estado reconoce y garantiza la plena vigencia de los Colegios y Consejos Profesionales, les confiere el gobierno de la matrícula, la defensa y promoción de sus intereses específicos, la facultad de dictar sus normas de ética e implementar métodos de resolución de conflictos de instancia voluntaria. Los Colegios y Consejos Profesionales aseguran el libre ejercicio de la profesión y su organización en forma democrática y pluralista y ejercen el poder disciplinario sobre sus miembros, dictando resoluciones que son revisables judicialmente. La Provincia reconoce la existencia de las entidades de previsión y seguridad social para profesionales, bajo los principios de solidaridad, proporcionalidad y obligatoriedad de afiliación y aporte. Asegura su autonomía económica y financiera, la dirección y administración de las mismas por representantes de sus afiliados y la intangibilidad frente al Estado, de los recursos que conforman su patrimonio.`, plainLanguageExplanation: 'Los colegios y consejos profesionales tienen reconocimiento constitucional para gobernar la matrícula y ejercer el poder disciplinario sobre sus miembros. Los fondos de previsión y seguridad social de profesionales son autónomos e intangibles frente al Estado.', practicalEffects: [], examples: ['El Colegio de Abogados de Entre Ríos puede sancionar a un abogado matriculado con suspensión por violación del código de ética; esa resolución es válida y revisable judicialmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['colegios profesionales', 'matrícula', 'poder disciplinario', 'ética profesional', 'previsión social profesional', 'autonomía'], order: 76, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-78', lawId: 'const-entre-rios', number: '78', title: 'Responsabilidad social empresarial — desarrollo sostenible', originalText: `Las empresas radicadas en la provincia tenderán a adoptar políticas socialmente responsables y promover el desarrollo sostenible. El Estado provincial, los municipios y comunas establecerán políticas activas con el mismo propósito.`, currentText: `Las empresas radicadas en la provincia tenderán a adoptar políticas socialmente responsables y promover el desarrollo sostenible. El Estado provincial, los municipios y comunas establecerán políticas activas con el mismo propósito.`, plainLanguageExplanation: 'Las empresas deben orientarse hacia la responsabilidad social y el desarrollo sostenible. El Estado provincial y los municipios deben implementar políticas activas en el mismo sentido, articulando la actividad económica con el bienestar social y ambiental.', practicalEffects: [], examples: ['Una empresa que opera en la provincia debe implementar medidas de responsabilidad social como apoyo comunitario y cuidado ambiental; el Estado puede exigirlo mediante normativa reglamentaria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad social empresarial', 'RSE', 'desarrollo sostenible', 'empresas', 'políticas activas'], order: 77, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-79', lawId: 'const-entre-rios', number: '79', title: 'Política tributaria — eliminar impuestos a artículos de primera necesidad', originalText: `La Legislatura, al dictar las leyes de carácter tributario, propenderá a la eliminación paulatina de los impuestos que pesen sobre los artículos de primera necesidad, debiendo evolucionar hacia la adopción de un régimen impositivo basado en los impuestos directos y en los que recaigan sobre los artículos superfluos.`, currentText: `La Legislatura, al dictar las leyes de carácter tributario, propenderá a la eliminación paulatina de los impuestos que pesen sobre los artículos de primera necesidad, debiendo evolucionar hacia la adopción de un régimen impositivo basado en los impuestos directos y en los que recaigan sobre los artículos superfluos.`, plainLanguageExplanation: 'La política impositiva provincial debe avanzar hacia la eliminación de los impuestos sobre bienes de primera necesidad y fortalecer los impuestos directos sobre la renta y los artículos superfluos, promoviendo un sistema tributario más progresivo y justo.', practicalEffects: [], examples: ['La Legislatura, al revisar el sistema tributario, debería reducir o eliminar las cargas sobre alimentos básicos, transfiriendo esa presión impositiva hacia artículos de lujo o directamente sobre el patrimonio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['política tributaria', 'impuestos directos', 'artículos de primera necesidad', 'progresividad fiscal', 'justicia impositiva'], order: 78, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-80', lawId: 'const-entre-rios', number: '80', title: 'Licitación pública obligatoria para bienes del Estado', originalText: `Toda enajenación de los bienes del fisco o del municipio, compras y demás contratos susceptibles de licitación se harán en esta forma y de un modo público, bajo pena de nulidad y sin perjuicio de las responsabilidades emergentes.`, currentText: `Toda enajenación de los bienes del fisco o del municipio, compras y demás contratos susceptibles de licitación se harán en esta forma y de un modo público, bajo pena de nulidad y sin perjuicio de las responsabilidades emergentes.`, plainLanguageExplanation: 'Las ventas de bienes del Estado provincial o municipal y los contratos que puedan licitarse deben hacerse a través de licitación pública. Los contratos celebrados sin cumplir este requisito son nulos y generan responsabilidad para los funcionarios intervinientes.', practicalEffects: [], examples: ['Si el gobierno provincial vende un inmueble fiscal sin llamar a licitación pública, esa operación es nula de pleno derecho y los funcionarios que la autorizaron pueden ser responsables.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['licitación pública', 'bienes fiscales', 'transparencia', 'contratos estatales', 'nulidad'], order: 79, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-81', lawId: 'const-entre-rios', number: '81', title: 'Enajenación de bienes fiscales por ley especial — colonización', originalText: `Cuando para la fundación de colonias o para otros fines de utilidad pública, se considere necesario la enajenación de los bienes del fisco en venta directa o la cesión gratuita, podrá la Legislatura, con dos tercios de votos presentes, autorizar estas formas de enajenación, tomando en cuenta cada caso y dictando una ley especial para cada uno. El Poder Ejecutivo dará cuenta del uso que haya hecho de cada autorización una vez cumplida la ley respectiva. La adquisición que haga la Provincia de bienes raíces con fines de colonización o para otros objetos, deberá ser autorizada por el voto de las dos terceras partes de los miembros presentes de cada cámara.`, currentText: `Cuando para la fundación de colonias o para otros fines de utilidad pública, se considere necesario la enajenación de los bienes del fisco en venta directa o la cesión gratuita, podrá la Legislatura, con dos tercios de votos presentes, autorizar estas formas de enajenación, tomando en cuenta cada caso y dictando una ley especial para cada uno. El Poder Ejecutivo dará cuenta del uso que haya hecho de cada autorización una vez cumplida la ley respectiva. La adquisición que haga la Provincia de bienes raíces con fines de colonización o para otros objetos, deberá ser autorizada por el voto de las dos terceras partes de los miembros presentes de cada cámara.`, plainLanguageExplanation: 'La venta directa o cesión gratuita de bienes fiscales requiere una ley especial aprobada por 2/3 de la Legislatura para cada caso. La compra de inmuebles con fines de colonización también exige ese quórum calificado.', practicalEffects: [], examples: ['Para ceder tierras fiscales a una comunidad indígena o a colonos, el gobierno provincial necesita que la Legislatura apruebe una ley especial con mayoría de dos tercios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes fiscales', 'colonización', 'ley especial', 'dos tercios', 'utilidad pública', 'enajenación'], order: 80, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-82', lawId: 'const-entre-rios', number: '82', title: 'Derecho al trabajo — negociación colectiva, salario mínimo y gremios', originalText: `El trabajo es un derecho que el Estado protege e impulsa. Promueve el empleo y el trabajo decente, en igualdad de condiciones para todos, reivindicando su competencia en materia de policía. Controla el efectivo cumplimiento de la norma laboral y de las disposiciones convencionales y sanciona su incumplimiento. Garantiza la promoción de las acciones tendientes a la erradicación del trabajo no registrado y el cumplimiento de la legislación sobre trabajo infantil. Genera mecanismos de acercamiento entre las ofertas y demandas de puestos de trabajo. Reglamenta las condiciones de trabajo de empleados públicos provinciales y municipales y especialmente: a) La negociación colectiva garantizando los principios de irrenunciabilidad, progresividad, primacía de la realidad, indemnidad y, en caso de duda, interpretación a favor del trabajador. b) El marco regulatorio general del empleado público provincial y municipal con participación de los trabajadores, que asegurará el cumplimiento de normas sobre higiene, seguridad y prevención de infortunios; y la participación de los trabajadores en la dirección y gestión de las empresas y entes autárquicos o descentralizados. c) El régimen de seguridad social para los empleados públicos provinciales y municipales en el ámbito de su competencia, con el objeto de proteger a trabajadores en actividad y pasivos. d) El salario mínimo para los obreros del Estado, el que se fijará conforme el costo de vida, no será inferior al vital y móvil. Todo incremento salarial, otorgado a partir de la presente Constitución, deberá estar sujeto a aportes y contribuciones. e) La inembargabilidad del hogar de familia. f) El fomento de la construcción de viviendas higiénicas, con el concurso del Estado, sea en forma de desembolsos directos, de otorgamiento de créditos o garantías o de liberación de gravámenes. g) El asociacionismo gremial, debiendo fomentarlo y orientarlo. h) El funcionamiento de un organismo administrativo laboral único, con competencia provincial y municipal, en el ámbito público y privado que ejerza el poder de policía, participe en la negociación colectiva y en la solución de los conflictos individuales a través de la mediación, conciliación y arbitraje.`, currentText: `El trabajo es un derecho que el Estado protege e impulsa. Promueve el empleo y el trabajo decente, en igualdad de condiciones para todos, reivindicando su competencia en materia de policía. Controla el efectivo cumplimiento de la norma laboral y de las disposiciones convencionales y sanciona su incumplimiento. Garantiza la promoción de las acciones tendientes a la erradicación del trabajo no registrado y el cumplimiento de la legislación sobre trabajo infantil. Genera mecanismos de acercamiento entre las ofertas y demandas de puestos de trabajo. Reglamenta las condiciones de trabajo de empleados públicos provinciales y municipales y especialmente: a) La negociación colectiva garantizando los principios de irrenunciabilidad, progresividad, primacía de la realidad, indemnidad y, en caso de duda, interpretación a favor del trabajador. b) El marco regulatorio general del empleado público provincial y municipal con participación de los trabajadores, que asegurará el cumplimiento de normas sobre higiene, seguridad y prevención de infortunios; y la participación de los trabajadores en la dirección y gestión de las empresas y entes autárquicos o descentralizados. c) El régimen de seguridad social para los empleados públicos provinciales y municipales en el ámbito de su competencia, con el objeto de proteger a trabajadores en actividad y pasivos. d) El salario mínimo para los obreros del Estado, el que se fijará conforme el costo de vida, no será inferior al vital y móvil. Todo incremento salarial, otorgado a partir de la presente Constitución, deberá estar sujeto a aportes y contribuciones. e) La inembargabilidad del hogar de familia. f) El fomento de la construcción de viviendas higiénicas, con el concurso del Estado, sea en forma de desembolsos directos, de otorgamiento de créditos o garantías o de liberación de gravámenes. g) El asociacionismo gremial, debiendo fomentarlo y orientarlo. h) El funcionamiento de un organismo administrativo laboral único, con competencia provincial y municipal, en el ámbito público y privado que ejerza el poder de policía, participe en la negociación colectiva y en la solución de los conflictos individuales a través de la mediación, conciliación y arbitraje.`, plainLanguageExplanation: 'El trabajo es un derecho constitucional. El Estado regula las condiciones laborales de los empleados públicos: negociación colectiva con los principios laborales clásicos, salario mínimo no inferior al vital y móvil, inembargabilidad del hogar familiar, fomento del asociacionismo gremial y organismo laboral único provincial.', practicalEffects: [], examples: ['Un empleado público provincial tiene derecho a que sus condiciones de trabajo sean fijadas a través de la negociación colectiva, con interpretación favorable al trabajador en caso de duda.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho al trabajo', 'negociación colectiva', 'salario mínimo', 'gremios', 'empleados públicos', 'inembargabilidad hogar', 'trabajo decente'], order: 81, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-83', lawId: 'const-entre-rios', number: '83', title: 'Política ambiental — sustentabilidad, precaución y energías renovables', originalText: `El Estado fija la política ambiental y garantiza la aplicación de los principios de sustentabilidad, precaución, equidad intergeneracional, prevención, utilización racional, progresividad y responsabilidad. El poder de policía en la materia será de competencia concurrente entre la Provincia, municipios y comunas. Asegura la preservación, recuperación, mejoramiento de los ecosistemas y sus corredores biológicos y la conservación de la diversidad biológica. Promueve la creación de bancos estatales de reservas genéticas de especies y prohíbe la introducción de las exóticas perjudiciales. Promueve el consumo responsable, el uso de tecnologías y elementos no contaminantes, las prácticas disponibles más avanzadas y seguras, una gestión integral de los residuos y su eventual reutilización y reciclaje. Fomenta la incorporación de fuentes de energía renovables y limpias. Establece medidas preventivas y precautorias del daño ambiental.`, currentText: `El Estado fija la política ambiental y garantiza la aplicación de los principios de sustentabilidad, precaución, equidad intergeneracional, prevención, utilización racional, progresividad y responsabilidad. El poder de policía en la materia será de competencia concurrente entre la Provincia, municipios y comunas. Asegura la preservación, recuperación, mejoramiento de los ecosistemas y sus corredores biológicos y la conservación de la diversidad biológica. Promueve la creación de bancos estatales de reservas genéticas de especies y prohíbe la introducción de las exóticas perjudiciales. Promueve el consumo responsable, el uso de tecnologías y elementos no contaminantes, las prácticas disponibles más avanzadas y seguras, una gestión integral de los residuos y su eventual reutilización y reciclaje. Fomenta la incorporación de fuentes de energía renovables y limpias. Establece medidas preventivas y precautorias del daño ambiental.`, plainLanguageExplanation: 'El Estado define la política ambiental con principios de sustentabilidad, precaución e igualdad intergeneracional. La policía ambiental es competencia concurrente entre provincia y municipios. Promueve energías renovables, reciclaje y prohibe especies exóticas dañinas.', practicalEffects: [], examples: ['Un municipio puede aplicar poder de policía ambiental en su jurisdicción con base en la competencia concurrente establecida en este artículo, por ejemplo clausurando un vertedero ilegal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['política ambiental', 'sustentabilidad', 'precaución', 'biodiversidad', 'energías renovables', 'reciclaje', 'daño ambiental'], order: 82, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-84', lawId: 'const-entre-rios', number: '84', title: 'Ente ambiental — evaluación de impacto, participación ciudadana y fondo de recomposición', originalText: `Un ente tendrá a su cargo el diseño y aplicación de la política ambiental. Son sus instrumentos, sin perjuicio de otros que se establezcan: la evaluación ambiental estratégica; un plan de gestión estratégico; el estudio y evaluación de impacto ambiental y acumulativo; el ordenamiento ambiental territorial; los indicadores de sustentabilidad; el libre acceso a la información; la participación ciudadana en los procesos de toma de decisiones que afecten derechos y la educación ambiental, atendiendo principalmente a las culturas locales. La ley determinará la creación de un fondo de recomposición ambiental, y estrategias de mitigación y adaptación vinculadas a las causas y efectos del cambio ambiental global.`, currentText: `Un ente tendrá a su cargo el diseño y aplicación de la política ambiental. Son sus instrumentos, sin perjuicio de otros que se establezcan: la evaluación ambiental estratégica; un plan de gestión estratégico; el estudio y evaluación de impacto ambiental y acumulativo; el ordenamiento ambiental territorial; los indicadores de sustentabilidad; el libre acceso a la información; la participación ciudadana en los procesos de toma de decisiones que afecten derechos y la educación ambiental, atendiendo principalmente a las culturas locales. La ley determinará la creación de un fondo de recomposición ambiental, y estrategias de mitigación y adaptación vinculadas a las causas y efectos del cambio ambiental global.`, plainLanguageExplanation: 'Existe un ente especializado para implementar la política ambiental, con herramientas como evaluación de impacto, ordenamiento territorial y participación ciudadana. La ley debe crear un fondo de recomposición ambiental para financiar la recuperación de daños al ambiente.', practicalEffects: [], examples: ['Antes de aprobar una planta industrial contaminante, el ente ambiental provincial debe realizar un estudio de impacto ambiental y garantizar la participación ciudadana en el proceso de decisión.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ente ambiental', 'evaluación de impacto ambiental', 'participación ciudadana', 'ordenamiento territorial', 'fondo de recomposición ambiental'], order: 83, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-85', lawId: 'const-entre-rios', number: '85', title: 'Recursos naturales — dominio del Estado, agua como derecho humano y humedales', originalText: `Los recursos naturales existentes en el territorio provincial corresponden al dominio originario del Estado entrerriano, que ejerce el control y potestad para su aprovechamiento, preservación, conservación y defensa. Las leyes que establezcan su disposición deben asegurar su uso racional y sustentable y atender las necesidades locales. La Provincia reivindica su derecho a obtener compensaciones del Estado nacional por los ingresos que éste obtenga, directa o indirectamente, por el uso y aprovechamiento de sus recursos naturales. El Estado propicia por ley la creación de áreas protegidas, sobre la base de estudios técnicos. Reconoce el derecho de sus propietarios a recibir compensaciones económicas y exenciones impositivas, en su caso. El agua es un recurso natural, colectivo y esencial para el desarrollo integral de las personas y la perdurabilidad de los ecosistemas. El acceso al agua saludable, potable y su saneamiento es un derecho humano fundamental. Se asegura a todos los habitantes la continua disponibilidad del recurso. El servicio público de suministro de agua potable no podrá ser privatizado, a excepción del que presten las cooperativas y consorcios vecinales en forma individual o conjunta con el Estado provincial, los municipios, las comunas, los entes autárquicos y descentralizados, las empresas y sociedades del Estado. Los usuarios tendrán participación necesaria en la gestión. La Provincia concertará con las restantes jurisdicciones el uso y aprovechamiento de las cuencas hídricas comunes. Tendrá a su cargo la gestión y uso sustentable de las mismas, y de los sistemas de humedales, que se declaran libres de construcción de obras de infraestructura a gran escala que puedan interrumpir o degradar la libertad de sus aguas y el desarrollo natural de sus ecosistemas asociados. El Estado asegura la gestión sustentable y la preservación de los montes nativos, de las selvas ribereñas y de las especies autóctonas, fomentando actividades que salvaguarden la estabilidad ecológica. El propietario de montes nativos tiene derecho a ser compensado por su preservación. El suelo es un recurso natural y permanente de trabajo, producción y desarrollo. El Estado fomenta su preservación y recuperación, procura evitar la pérdida de fertilidad, degradación y erosión, y regula el empleo de las tecnologías de aplicación para un adecuado cumplimiento de su función social, ambiental y económica.`, currentText: `Los recursos naturales existentes en el territorio provincial corresponden al dominio originario del Estado entrerriano, que ejerce el control y potestad para su aprovechamiento, preservación, conservación y defensa. Las leyes que establezcan su disposición deben asegurar su uso racional y sustentable y atender las necesidades locales. La Provincia reivindica su derecho a obtener compensaciones del Estado nacional por los ingresos que éste obtenga, directa o indirectamente, por el uso y aprovechamiento de sus recursos naturales. El Estado propicia por ley la creación de áreas protegidas, sobre la base de estudios técnicos. Reconoce el derecho de sus propietarios a recibir compensaciones económicas y exenciones impositivas, en su caso. El agua es un recurso natural, colectivo y esencial para el desarrollo integral de las personas y la perdurabilidad de los ecosistemas. El acceso al agua saludable, potable y su saneamiento es un derecho humano fundamental. Se asegura a todos los habitantes la continua disponibilidad del recurso. El servicio público de suministro de agua potable no podrá ser privatizado, a excepción del que presten las cooperativas y consorcios vecinales en forma individual o conjunta con el Estado provincial, los municipios, las comunas, los entes autárquicos y descentralizados, las empresas y sociedades del Estado. Los usuarios tendrán participación necesaria en la gestión. La Provincia concertará con las restantes jurisdicciones el uso y aprovechamiento de las cuencas hídricas comunes. Tendrá a su cargo la gestión y uso sustentable de las mismas, y de los sistemas de humedales, que se declaran libres de construcción de obras de infraestructura a gran escala que puedan interrumpir o degradar la libertad de sus aguas y el desarrollo natural de sus ecosistemas asociados. El Estado asegura la gestión sustentable y la preservación de los montes nativos, de las selvas ribereñas y de las especies autóctonas, fomentando actividades que salvaguarden la estabilidad ecológica. El propietario de montes nativos tiene derecho a ser compensado por su preservación. El suelo es un recurso natural y permanente de trabajo, producción y desarrollo. El Estado fomenta su preservación y recuperación, procura evitar la pérdida de fertilidad, degradación y erosión, y regula el empleo de las tecnologías de aplicación para un adecuado cumplimiento de su función social, ambiental y económica.`, plainLanguageExplanation: 'Los recursos naturales pertenecen al dominio originario del Estado provincial. El agua es un derecho humano fundamental y el servicio de agua potable no puede privatizarse (excepto cooperativas). Los humedales son intangibles frente a grandes obras de infraestructura. Los montes nativos y el suelo son protegidos y sus propietarios pueden recibir compensaciones.', practicalEffects: [], examples: ['Privatizar el servicio de agua potable a una empresa multinacional sería inconstitucional en Entre Ríos; solo pueden gestionarlo cooperativas, el Estado o municipios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['recursos naturales', 'agua potable', 'derecho al agua', 'humedales', 'montes nativos', 'privatización prohibida', 'suelo'], order: 84, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-86', lawId: 'const-entre-rios', number: '86', title: 'Antilatifundio — arraigo del productor y restricción a extranjeros', originalText: `La Provincia promueve la unidad económica productiva mediante leyes que contemplen el arraigo del productor entrerriano, el crecimiento y desarrollo progresivo de las actividades productivas locales y el estímulo de la tenencia de la tierra por sus residentes. La legislación desalentará la especulación y la existencia de latifundios y el uso de la tierra en grandes superficies continuas o discontinuas, mediante regímenes tributarios, alícuotas progresivas u otras políticas activas. Resguardará el orden público en relación con la adquisición de inmuebles rurales por personas físicas o jurídicas extranjeras no residentes en el territorio nacional.`, currentText: `La Provincia promueve la unidad económica productiva mediante leyes que contemplen el arraigo del productor entrerriano, el crecimiento y desarrollo progresivo de las actividades productivas locales y el estímulo de la tenencia de la tierra por sus residentes. La legislación desalentará la especulación y la existencia de latifundios y el uso de la tierra en grandes superficies continuas o discontinuas, mediante regímenes tributarios, alícuotas progresivas u otras políticas activas. Resguardará el orden público en relación con la adquisición de inmuebles rurales por personas físicas o jurídicas extranjeras no residentes en el territorio nacional.`, plainLanguageExplanation: 'La Provincia combate la especulación y los latifundios con impuestos progresivos sobre la tenencia de grandes extensiones de tierra. Promueve el arraigo de productores locales y controla la adquisición de inmuebles rurales por extranjeros no residentes.', practicalEffects: [], examples: ['Un fondo de inversión extranjero que intente comprar miles de hectáreas en Entre Ríos puede ser limitado o condicionado por regulaciones basadas en este artículo constitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['latifundios', 'arraigo', 'especulación', 'alícuotas progresivas', 'tierra rural', 'extranjeros', 'producción local'], order: 85, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-87', lawId: 'const-entre-rios', number: '87', title: 'Régimen electoral — ley uniforme, sufragio universal y Tribunal Electoral', originalText: `La Legislatura dictará la ley electoral que será uniforme para toda la Provincia y reconocerá por base las prescripciones siguientes: 1º. El sufragio electoral será universal, secreto y obligatorio. 2º. Tendrán voto en las elecciones provinciales los ciudadanos argentinos que se hallen inscriptos en el padrón electoral de la Nación, por el que deberán celebrarse las elecciones de la Provincia. Cuando dicho padrón no se ajuste a los principios fundamentales establecidos en esta Constitución o en las leyes dictadas en su consecuencia para el ejercicio del sufragio, la Legislatura mandará confeccionar el registro cívico de Entre Ríos, bajo la dirección del Tribunal Electoral. 3º. Se asegura el pleno ejercicio de los derechos políticos, con arreglo al principio de la soberanía popular y las leyes que se dicten en consecuencia. El régimen electoral, que será uniforme para toda la Provincia, respetará los derechos establecidos en esta Constitución y determinará las limitaciones y prohibiciones al ejercicio del sufragio. 4º. La Provincia constituye un distrito electoral único y se subdividirá en secciones correspondientes a cada departamento y éstas en circuitos o mesas en las que se agruparán los electores. Se deberá establecer la fecha de las elecciones provinciales. Se considerará que ha habido elección válida en el distrito, sección o circuito cuando haya sido legal en la mayoría de las mesas receptoras de votos. A pedido de cualquiera de los partidos políticos y dentro del plazo que la ley señale, en toda clase de elecciones, se convocará a nueva elección en las mesas no constituidas o anuladas cuantas veces sea necesario, hasta que haya una elección válida. 5º. Ningún ciudadano podrá inscribirse sino en el distrito de su domicilio. 6º. Las elecciones ordinarias se verificarán en las fechas que fije la ley y las extraordinarias en cualquier tiempo, previa convocatoria que se publicará con una antelación no menor a sesenta días. Para las elecciones complementarias ese término se reduce a treinta días. 7º. Las mesas receptoras de votos estarán constituidas por un funcionario denominado presidente del comicio. El Tribunal Electoral insaculará también dos suplentes que reemplazarán a aquél en los casos que la ley determine. 8º. Durante las elecciones y en el radio del comicio no habrá más autoridad policial que la del presidente del mismo, cuyas órdenes y resoluciones deberán cumplir la fuerza pública y los ciudadanos. 9º. Toda elección debe durar ocho horas como mínimo y terminar en el día, sin que las autoridades y particulares puedan suspenderlas por motivo alguno. 10º. Tanto el escrutinio provisorio como el definitivo serán públicos, debiendo el primero hacerse enseguida de terminar la elección y consignarse el resultado en la misma acta del comicio firmando el presidente y demás personas que quieran hacerlo, entre ellas, los fiscales de los distintos partidos políticos intervinientes en la elección que participen del acto. 11º. Toda elección se hará por listas que serán oficializadas por el Tribunal Electoral. Se considerarán una sola lista las que tengan la mayoría de los candidatos comunes, aunque difiera el orden de colocación de los mismos. A los efectos del escrutinio definitivo, el orden de colocación de los candidatos lo determinará la lista que tenga la mayoría de la totalidad de votos, y si ninguna la tuviera, el de la lista oficializada. 12º. Los electores no podrán ser arrestados durante las horas del comicio atribuyéndoles la comisión de faltas o contravenciones, ni por la comisión de delitos, salvo supuestos de flagrancia o de mediar orden del juez competente. 13º. Una Junta Electoral Municipal formada por un juez de primera instancia de cualquier fuero y dos funcionarios del Ministerio Público, Fiscal y de la Defensa, y en caso de mediar varios de ellos por los más antiguos, o sus reemplazantes legales de la circunscripción respectiva, tendrán a su cargo la función electoral para los municipios y comunas de su jurisdicción, oficiando de secretario el del concejo deliberante del municipio de la localidad de asiento de dicha junta. Sus resoluciones, serán recurribles en los casos que se determinen legalmente. 14º. Un Tribunal Electoral compuesto del presidente y un miembro del Superior Tribunal de Justicia, de uno de los jueces de primera instancia de la capital, del vicepresidente primero del Senado y del presidente de la Cámara de Diputados, o sus reemplazantes legales, tendrá a su cargo: a) Designar, por sorteo público, los miembros de las mesas receptoras de votos y disponer las medidas conducentes a la organización y funcionamiento de los comicios. b) Decidir, en caso de impugnación, si concurren en los electos los requisitos constitucionales para el desempeño del cargo. c) Practicar los escrutinios definitivos en acto público, computando sólo los votos emitidos a favor de las listas oficializadas por el mismo tribunal. d) Calificar las elecciones de gobernador y vicegobernador, de convencionales, de senadores y diputados, juzgando definitivamente y sin recurso alguno, sobre su validez o invalidez y otorgando los títulos a los que resulten electos. e) Establecer el suplente que entrará en funciones conforme a lo que se establece en los artículos 90 y 91 debiendo comunicarlo a la cámara respectiva. Este Tribunal procederá como jurado en la apreciación de los hechos y sentenciará con arreglo a derecho. f) El Tribunal Electoral deberá expedirse dentro de los cuarenta y cinco días de sometidos a su consideración los asuntos de su competencia, bajo pena de destitución e inhabilitación por diez años para desempeñar empleo o función pública provincial, del miembro o miembros remisos en el desempeño de sus funciones. 15º. Toda falta grave, acto de fraude, coacción, soborno, cohecho o intimidación, ejercido por los empleados o funcionarios públicos, de cualquier jerarquía, como también por cualquier persona contra los electores, antes, durante o después del acto eleccionario, serán considerados como un atentado contra el derecho y la libertad electoral y serán penados con arreglo a lo que disponga la ley de la materia. 16º. La acción para acusar por faltas o delitos electorales será popular y se podrá ejercer hasta tres meses después de cometidos aquellos. La Legislatura no podrá dictar leyes de amnistía en esta materia y los actos de procedimiento judicial contra el acusado, interrumpirán las prescripciones de la acción y de la pena. 17º. Los cargos de autoridades de las mesas receptoras de votos del inciso 7° precedente y el ejercicio de la función de sufragar de los electores constituyen cargas públicas cuyo incumplimiento será considerado como una infracción susceptible de ser sancionada. 18º. La ley determinará las limitaciones y prohibiciones al ejercicio del sufragio, respetando los principios establecidos en esta Constitución.`, currentText: `La Legislatura dictará la ley electoral que será uniforme para toda la Provincia y reconocerá por base las prescripciones siguientes: 1º. El sufragio electoral será universal, secreto y obligatorio. 2º. Tendrán voto en las elecciones provinciales los ciudadanos argentinos que se hallen inscriptos en el padrón electoral de la Nación, por el que deberán celebrarse las elecciones de la Provincia. Cuando dicho padrón no se ajuste a los principios fundamentales establecidos en esta Constitución o en las leyes dictadas en su consecuencia para el ejercicio del sufragio, la Legislatura mandará confeccionar el registro cívico de Entre Ríos, bajo la dirección del Tribunal Electoral. 3º. Se asegura el pleno ejercicio de los derechos políticos, con arreglo al principio de la soberanía popular y las leyes que se dicten en consecuencia. El régimen electoral, que será uniforme para toda la Provincia, respetará los derechos establecidos en esta Constitución y determinará las limitaciones y prohibiciones al ejercicio del sufragio. 4º. La Provincia constituye un distrito electoral único y se subdividirá en secciones correspondientes a cada departamento y éstas en circuitos o mesas en las que se agruparán los electores. Se deberá establecer la fecha de las elecciones provinciales. Se considerará que ha habido elección válida en el distrito, sección o circuito cuando haya sido legal en la mayoría de las mesas receptoras de votos. A pedido de cualquiera de los partidos políticos y dentro del plazo que la ley señale, en toda clase de elecciones, se convocará a nueva elección en las mesas no constituidas o anuladas cuantas veces sea necesario, hasta que haya una elección válida. 5º. Ningún ciudadano podrá inscribirse sino en el distrito de su domicilio. 6º. Las elecciones ordinarias se verificarán en las fechas que fije la ley y las extraordinarias en cualquier tiempo, previa convocatoria que se publicará con una antelación no menor a sesenta días. Para las elecciones complementarias ese término se reduce a treinta días. 7º. Las mesas receptoras de votos estarán constituidas por un funcionario denominado presidente del comicio. El Tribunal Electoral insaculará también dos suplentes que reemplazarán a aquél en los casos que la ley determine. 8º. Durante las elecciones y en el radio del comicio no habrá más autoridad policial que la del presidente del mismo, cuyas órdenes y resoluciones deberán cumplir la fuerza pública y los ciudadanos. 9º. Toda elección debe durar ocho horas como mínimo y terminar en el día, sin que las autoridades y particulares puedan suspenderlas por motivo alguno. 10º. Tanto el escrutinio provisorio como el definitivo serán públicos, debiendo el primero hacerse enseguida de terminar la elección y consignarse el resultado en la misma acta del comicio firmando el presidente y demás personas que quieran hacerlo, entre ellas, los fiscales de los distintos partidos políticos intervinientes en la elección que participen del acto. 11º. Toda elección se hará por listas que serán oficializadas por el Tribunal Electoral. Se considerarán una sola lista las que tengan la mayoría de los candidatos comunes, aunque difiera el orden de colocación de los mismos. A los efectos del escrutinio definitivo, el orden de colocación de los candidatos lo determinará la lista que tenga la mayoría de la totalidad de votos, y si ninguna la tuviera, el de la lista oficializada. 12º. Los electores no podrán ser arrestados durante las horas del comicio atribuyéndoles la comisión de faltas o contravenciones, ni por la comisión de delitos, salvo supuestos de flagrancia o de mediar orden del juez competente. 13º. Una Junta Electoral Municipal formada por un juez de primera instancia de cualquier fuero y dos funcionarios del Ministerio Público, Fiscal y de la Defensa, y en caso de mediar varios de ellos por los más antiguos, o sus reemplazantes legales de la circunscripción respectiva, tendrán a su cargo la función electoral para los municipios y comunas de su jurisdicción, oficiando de secretario el del concejo deliberante del municipio de la localidad de asiento de dicha junta. Sus resoluciones, serán recurribles en los casos que se determinen legalmente. 14º. Un Tribunal Electoral compuesto del presidente y un miembro del Superior Tribunal de Justicia, de uno de los jueces de primera instancia de la capital, del vicepresidente primero del Senado y del presidente de la Cámara de Diputados, o sus reemplazantes legales, tendrá a su cargo: a) Designar, por sorteo público, los miembros de las mesas receptoras de votos y disponer las medidas conducentes a la organización y funcionamiento de los comicios. b) Decidir, en caso de impugnación, si concurren en los electos los requisitos constitucionales para el desempeño del cargo. c) Practicar los escrutinios definitivos en acto público, computando sólo los votos emitidos a favor de las listas oficializadas por el mismo tribunal. d) Calificar las elecciones de gobernador y vicegobernador, de convencionales, de senadores y diputados, juzgando definitivamente y sin recurso alguno, sobre su validez o invalidez y otorgando los títulos a los que resulten electos. e) Establecer el suplente que entrará en funciones conforme a lo que se establece en los artículos 90 y 91 debiendo comunicarlo a la cámara respectiva. Este Tribunal procederá como jurado en la apreciación de los hechos y sentenciará con arreglo a derecho. f) El Tribunal Electoral deberá expedirse dentro de los cuarenta y cinco días de sometidos a su consideración los asuntos de su competencia, bajo pena de destitución e inhabilitación por diez años para desempeñar empleo o función pública provincial, del miembro o miembros remisos en el desempeño de sus funciones. 15º. Toda falta grave, acto de fraude, coacción, soborno, cohecho o intimidación, ejercido por los empleados o funcionarios públicos, de cualquier jerarquía, como también por cualquier persona contra los electores, antes, durante o después del acto eleccionario, serán considerados como un atentado contra el derecho y la libertad electoral y serán penados con arreglo a lo que disponga la ley de la materia. 16º. La acción para acusar por faltas o delitos electorales será popular y se podrá ejercer hasta tres meses después de cometidos aquellos. La Legislatura no podrá dictar leyes de amnistía en esta materia y los actos de procedimiento judicial contra el acusado, interrumpirán las prescripciones de la acción y de la pena. 17º. Los cargos de autoridades de las mesas receptoras de votos del inciso 7° precedente y el ejercicio de la función de sufragar de los electores constituyen cargas públicas cuyo incumplimiento será considerado como una infracción susceptible de ser sancionada. 18º. La ley determinará las limitaciones y prohibiciones al ejercicio del sufragio, respetando los principios establecidos en esta Constitución.`, plainLanguageExplanation: 'Establece las bases del régimen electoral provincial: sufragio universal, secreto y obligatorio; la Provincia como distrito electoral único; el Tribunal Electoral como organismo calificador de las elecciones; y garantías para electores y autoridades del comicio.', practicalEffects: [], examples: ['Una persona designada presidente de mesa que no se presenta sin justificación puede ser sancionada administrativamente (inc. 17°).'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elecciones', 'sufragio universal', 'Tribunal Electoral', 'ley electoral', 'padrón electoral', 'escrutinio', 'distrito electoral'], order: 86, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-88', lawId: 'const-entre-rios', number: '88', title: 'Suspensión de convocatoria electoral', originalText: `El Poder Ejecutivo sólo podrá suspender la convocatoria a elecciones en caso de conmoción, insurrección o invasión.`, currentText: `El Poder Ejecutivo sólo podrá suspender la convocatoria a elecciones en caso de conmoción, insurrección o invasión.`, plainLanguageExplanation: 'Solo en situaciones de grave alteración del orden público (conmoción, insurrección o invasión) puede el Ejecutivo suspender la convocatoria a elecciones.', practicalEffects: [], examples: ['Durante una declaración de estado de sitio por insurrección, el Ejecutivo puede posponer las elecciones provinciales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elecciones', 'suspensión', 'estado de sitio', 'Poder Ejecutivo'], order: 87, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-89', lawId: 'const-entre-rios', number: '89', title: 'Elección directa de gobernador y vicegobernador', originalText: `El gobernador y vicegobernador serán elegidos directamente por el pueblo de la Provincia, a simple pluralidad de sufragios. En caso de empate se procederá a nueva elección.`, currentText: `El gobernador y vicegobernador serán elegidos directamente por el pueblo de la Provincia, a simple pluralidad de sufragios. En caso de empate se procederá a nueva elección.`, plainLanguageExplanation: 'El gobernador y vicegobernador son elegidos por voto popular directo; gana quien obtiene más votos. Si hay empate exacto, se realiza una nueva elección.', practicalEffects: [], examples: ['En unas elecciones donde el candidato A obtiene 150.000 votos y el B 149.999, el candidato A gana sin necesidad de segunda vuelta.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'vicegobernador', 'elección directa', 'pluralidad de sufragios'], order: 88, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-90', lawId: 'const-entre-rios', number: '90', title: 'Elección de senadores provinciales', originalText: `Los senadores serán elegidos directamente por el pueblo a razón de uno por cada departamento y a simple pluralidad de votos. Se elegirán suplentes por cada partido o agrupación para reemplazar a los que cesen en su mandato por muerte, renuncia, o cualquiera otra causa.`, currentText: `Los senadores serán elegidos directamente por el pueblo a razón de uno por cada departamento y a simple pluralidad de votos. Se elegirán suplentes por cada partido o agrupación para reemplazar a los que cesen en su mandato por muerte, renuncia, o cualquiera otra causa.`, plainLanguageExplanation: 'Cada departamento elige un senador por voto directo; gana el candidato con más votos. Cada partido elige también suplentes para cubrir vacantes.', practicalEffects: [], examples: ['El departamento Paraná elige su senador por mayoría simple; si el ganador renuncia, lo reemplaza el suplente de su partido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['senadores', 'elección directa', 'departamento', 'suplentes'], order: 89, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-91', lawId: 'const-entre-rios', number: '91', title: 'Elección de diputados por representación proporcional', originalText: `Los diputados serán elegidos directamente por el pueblo de la Provincia, en distrito único, por un sistema de representación proporcional; pero que asegure al partido mayoritario la mayoría absoluta de la representación. La ley determinará la forma de distribuir el resto de la representación. Se elegirán también lista de suplentes por cada partido o agrupación para reemplazar a los que cesen en su mandato por muerte, renuncia o cualquiera otra causa. Tratándose de los elegidos por las minorías se incorporarán los candidatos titulares de las listas proclamadas que no hayan resultado electos.`, currentText: `Los diputados serán elegidos directamente por el pueblo de la Provincia, en distrito único, por un sistema de representación proporcional; pero que asegure al partido mayoritario la mayoría absoluta de la representación. La ley determinará la forma de distribuir el resto de la representación. Se elegirán también lista de suplentes por cada partido o agrupación para reemplazar a los que cesen en su mandato por muerte, renuncia o cualquiera otra causa. Tratándose de los elegidos por las minorías se incorporarán los candidatos titulares de las listas proclamadas que no hayan resultado electos.`, plainLanguageExplanation: 'Los diputados se eligen en distrito único con representación proporcional, garantizando al partido ganador la mayoría absoluta de las bancas. Los partidos también presentan listas de suplentes.', practicalEffects: [], examples: ['Un partido que gana las elecciones obtiene al menos la mitad más uno de las bancas de diputados, aunque su porcentaje de votos sea menor.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['diputados', 'representación proporcional', 'distrito único', 'partido mayoritario', 'suplentes'], order: 90, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-92', lawId: 'const-entre-rios', number: '92', title: 'Mandato de cuatro años — elección simultánea', originalText: `El mandato de los funcionarios y representantes a que se refieren los artículos 89, 90 y 91 será de cuatro años. Todos serán elegidos simultáneamente en un solo acto electoral.`, currentText: `El mandato de los funcionarios y representantes a que se refieren los artículos 89, 90 y 91 será de cuatro años. Todos serán elegidos simultáneamente en un solo acto electoral.`, plainLanguageExplanation: 'El gobernador, vicegobernador, senadores y diputados provinciales tienen un mandato de cuatro años y son elegidos todos el mismo día.', practicalEffects: [], examples: ['En el año de elecciones provinciales, el mismo día se vota gobernador, vicegobernador, senadores y diputados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'cuatro años', 'elección simultánea'], order: 91, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-93', lawId: 'const-entre-rios', number: '93', title: 'Poder Legislativo — estructura bicameral', originalText: `El Poder Legislativo de la Provincia será ejercido por una Legislatura compuesta de dos cámaras, una de diputados y otra de senadores.`, currentText: `El Poder Legislativo de la Provincia será ejercido por una Legislatura compuesta de dos cámaras, una de diputados y otra de senadores.`, plainLanguageExplanation: 'El Poder Legislativo provincial es bicameral: Cámara de Diputados y Cámara de Senadores, que juntas conforman la Legislatura.', practicalEffects: [], examples: ['Para sancionarse una ley provincial, el proyecto debe ser aprobado tanto por diputados como por senadores.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Legislativo', 'Legislatura', 'bicameral', 'diputados', 'senadores'], order: 92, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-94', lawId: 'const-entre-rios', number: '94', title: 'Duración del mandato legislativo y renovación', originalText: `El mandato de los representantes durará cuatro años, a contar desde el día que se fija para la inauguración del período de las sesiones ordinarias, y ambas cámaras se renovarán totalmente al final de dicho término. En caso de vacancia de un cargo de representante, por muerte, renuncia u otra causa entrará en ejercicio el suplente respectivo.`, currentText: `El mandato de los representantes durará cuatro años, a contar desde el día que se fija para la inauguración del período de las sesiones ordinarias, y ambas cámaras se renovarán totalmente al final de dicho término. En caso de vacancia de un cargo de representante, por muerte, renuncia u otra causa entrará en ejercicio el suplente respectivo.`, plainLanguageExplanation: 'Los legisladores duran cuatro años y ambas cámaras se renuevan en bloque. Si un cargo queda vacante por renuncia o fallecimiento, asume el suplente.', practicalEffects: [], examples: ['Si un diputado fallece en ejercicio, el suplente de su lista entra automáticamente a ocupar la banca.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'renovación legislativa', 'vacancia', 'suplentes'], order: 93, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-95', lawId: 'const-entre-rios', number: '95', title: 'Incompatibilidades del cargo legislativo', originalText: `Son incompatibles los cargos de senador y diputado: a) Con el de funcionario o empleado público a sueldo de la Nación, de la Provincia o de las municipalidades, con excepción del profesorado nacional y de las comisiones honorarias eventuales, debiendo estas últimas ser aceptadas con el consentimiento previo de la cámara a que pertenezca. b) Con todo otro cargo de carácter electivo nacional, provincial, municipal o de otra provincia. c) Con el de funcionario o empleado dependiente de una empresa particular que se rija por concesiones de la Legislatura y que tenga, por ese hecho, relaciones permanentes con los poderes públicos de la Provincia. El representante que haya aceptado algún cargo incompatible con el suyo, quedará, por ese solo hecho, separado de la representación, debiendo la presidencia de la cámara respectiva comunicar la vacante, a sus efectos, al Tribunal Electoral.`, currentText: `Son incompatibles los cargos de senador y diputado: a) Con el de funcionario o empleado público a sueldo de la Nación, de la Provincia o de las municipalidades, con excepción del profesorado nacional y de las comisiones honorarias eventuales, debiendo estas últimas ser aceptadas con el consentimiento previo de la cámara a que pertenezca. b) Con todo otro cargo de carácter electivo nacional, provincial, municipal o de otra provincia. c) Con el de funcionario o empleado dependiente de una empresa particular que se rija por concesiones de la Legislatura y que tenga, por ese hecho, relaciones permanentes con los poderes públicos de la Provincia. El representante que haya aceptado algún cargo incompatible con el suyo, quedará, por ese solo hecho, separado de la representación, debiendo la presidencia de la cámara respectiva comunicar la vacante, a sus efectos, al Tribunal Electoral.`, plainLanguageExplanation: 'Un senador o diputado no puede ser empleado público remunerado ni ocupar otro cargo electivo. Si acepta un cargo incompatible, pierde automáticamente su banca.', practicalEffects: [], examples: ['Si un diputado provincial es designado ministro del Ejecutivo, pierde su banca de inmediato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidad', 'legisladores', 'cargo público', 'cargo electivo'], order: 94, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-96', lawId: 'const-entre-rios', number: '96', title: 'Composición de la Cámara de Diputados', originalText: `La Cámara de Diputados se compondrá de treinta y cuatro ciudadanos.`, currentText: `La Cámara de Diputados se compondrá de treinta y cuatro ciudadanos.`, plainLanguageExplanation: 'La Cámara de Diputados provincial está integrada por 34 miembros.', practicalEffects: [], examples: ['Para sesionar con quórum la Cámara de Diputados necesita la mayoría de sus 34 miembros presentes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Cámara de Diputados', 'composición', 'treinta y cuatro'], order: 95, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-97', lawId: 'const-entre-rios', number: '97', title: 'Requisitos para ser diputado', originalText: `Para ser diputado se requiere: 1º. Ciudadanía natural en ejercicio o legal después de cuatro años de obtenida. 2º. Veinticinco años de edad. 3º. Ser nativo de la Provincia o tener en ella domicilio inmediato de dos años.`, currentText: `Para ser diputado se requiere: 1º. Ciudadanía natural en ejercicio o legal después de cuatro años de obtenida. 2º. Veinticinco años de edad. 3º. Ser nativo de la Provincia o tener en ella domicilio inmediato de dos años.`, plainLanguageExplanation: 'Para ser diputado se necesita ser ciudadano argentino, tener al menos 25 años y ser entrerriano o tener dos años de residencia en la Provincia.', practicalEffects: [], examples: ['Un argentino naturalizado hace tres años que vive en Paraná no puede ser diputado aún, porque la ciudadanía legal requiere cuatro años.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['diputado', 'requisitos', 'ciudadanía', 'domicilio', 'edad'], order: 96, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-98', lawId: 'const-entre-rios', number: '98', title: 'Acusación en juicio político — competencia de Diputados', originalText: `Es de competencia exclusiva de la Cámara de Diputados acusar ante el Senado a los funcionarios sujetos a juicio político.`, currentText: `Es de competencia exclusiva de la Cámara de Diputados acusar ante el Senado a los funcionarios sujetos a juicio político.`, plainLanguageExplanation: 'Solo la Cámara de Diputados puede iniciar un juicio político, formulando la acusación que luego el Senado juzga.', practicalEffects: [], examples: ['Para enjuiciar políticamente al gobernador, diputados deben votar la acusación; luego el Senado actúa como tribunal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'acusación', 'Cámara de Diputados', 'competencia exclusiva'], order: 97, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-99', lawId: 'const-entre-rios', number: '99', title: 'Autoridades de la Cámara de Diputados', originalText: `En cada período ordinario, la Cámara de Diputados, designará un presidente, un vicepresidente primero y un vicepresidente segundo, los cuales entrarán a desempeñar la presidencia por su orden, y durarán en sus funciones hasta la iniciación del período ordinario siguiente.`, currentText: `En cada período ordinario, la Cámara de Diputados, designará un presidente, un vicepresidente primero y un vicepresidente segundo, los cuales entrarán a desempeñar la presidencia por su orden, y durarán en sus funciones hasta la iniciación del período ordinario siguiente.`, plainLanguageExplanation: 'Al inicio de cada período ordinario la Cámara elige su presidente y dos vicepresidentes, quienes conducen las sesiones hasta el inicio del año siguiente.', practicalEffects: [], examples: ['Si el presidente de la Cámara está ausente en una sesión, lo reemplaza el vicepresidente primero.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presidente de cámara', 'vicepresidente', 'autoridades legislativas'], order: 98, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-100', lawId: 'const-entre-rios', number: '100', title: 'Composición del Senado', originalText: `El Senado se compondrá de un senador, elegido a pluralidad de sufragios, por cada uno de los departamentos de la Provincia.`, currentText: `El Senado se compondrá de un senador, elegido a pluralidad de sufragios, por cada uno de los departamentos de la Provincia.`, plainLanguageExplanation: 'El Senado tiene un senador por cada departamento de Entre Ríos, elegido por mayoría simple de votos en su departamento.', practicalEffects: [], examples: ['Entre Ríos tiene 17 departamentos, por lo que el Senado cuenta con 17 senadores.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Senado', 'composición', 'senador por departamento'], order: 99, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-101', lawId: 'const-entre-rios', number: '101', title: 'Requisitos para ser senador', originalText: `Para ser senador se requiere: 1º. Ciudadanía natural en ejercicio o legal después de seis años de obtenida. 2º. Tener por lo menos treinta años de edad. 3º. Haber nacido en el departamento por el que sea elegido o tener dos años de domicilio inmediato en él.`, currentText: `Para ser senador se requiere: 1º. Ciudadanía natural en ejercicio o legal después de seis años de obtenida. 2º. Tener por lo menos treinta años de edad. 3º. Haber nacido en el departamento por el que sea elegido o tener dos años de domicilio inmediato en él.`, plainLanguageExplanation: 'Para ser senador se requiere ciudadanía argentina (si es naturalizado, al menos 6 años), tener 30 años y ser nativo del departamento o residir en él con 2 años de domicilio.', practicalEffects: [], examples: ['Un entrerriano de 29 años no puede ser senador aunque cumpla los demás requisitos; debe tener al menos 30.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['senador', 'requisitos', 'ciudadanía', 'edad', 'domicilio departamental'], order: 100, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-102', lawId: 'const-entre-rios', number: '102', title: 'Presidencia del Senado — vicegobernador y autoridades', originalText: `Es presidente del Senado el vicegobernador de la Provincia, pero no tiene voto sino en caso de empate. En cada período ordinario de sesiones el Senado nombrará un vicepresidente primero y un vicepresidente segundo, los cuales entrarán a desempeñar el cargo, por su orden, en defecto del presidente. Las autoridades elegidas durarán en sus funciones hasta la iniciación del período ordinario siguiente.`, currentText: `Es presidente del Senado el vicegobernador de la Provincia, pero no tiene voto sino en caso de empate. En cada período ordinario de sesiones el Senado nombrará un vicepresidente primero y un vicepresidente segundo, los cuales entrarán a desempeñar el cargo, por su orden, en defecto del presidente. Las autoridades elegidas durarán en sus funciones hasta la iniciación del período ordinario siguiente.`, plainLanguageExplanation: 'El vicegobernador preside el Senado pero solo vota en caso de empate. El Senado elige además un vicepresidente primero y uno segundo como reemplazantes.', practicalEffects: [], examples: ['Si hay empate en una votación del Senado, el vicegobernador desempata con su voto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Senado', 'vicegobernador', 'presidente del Senado', 'voto de calidad'], order: 101, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-103', lawId: 'const-entre-rios', number: '103', title: 'Atribuciones exclusivas del Senado', originalText: `Son atribuciones exclusivas del Senado: 1º. Juzgar en juicio público a los acusados por la Cámara de Diputados. 2º. Prestar o negar acuerdo al Poder Ejecutivo, en audiencia pública previa difusión del propuesto y de sus referencias personales, para el nombramiento de los miembros del Superior Tribunal de Justicia; los titulares de los Ministerios Públicos Fiscal y de la Defensa; restantes magistrados y funcionarios del Poder Judicial; fiscal de Estado; contador, tesorero; miembros del Tribunal de Cuentas; director general de escuelas; vocales del Consejo General de Educación y demás funcionarios para los cuales la ley establezca esta forma de nombramiento.`, currentText: `Son atribuciones exclusivas del Senado: 1º. Juzgar en juicio público a los acusados por la Cámara de Diputados. 2º. Prestar o negar acuerdo al Poder Ejecutivo, en audiencia pública previa difusión del propuesto y de sus referencias personales, para el nombramiento de los miembros del Superior Tribunal de Justicia; los titulares de los Ministerios Públicos Fiscal y de la Defensa; restantes magistrados y funcionarios del Poder Judicial; fiscal de Estado; contador, tesorero; miembros del Tribunal de Cuentas; director general de escuelas; vocales del Consejo General de Educación y demás funcionarios para los cuales la ley establezca esta forma de nombramiento.`, plainLanguageExplanation: 'El Senado tiene dos funciones exclusivas: actuar como tribunal en el juicio político y dar acuerdo (aprobación) al Ejecutivo para nombrar jueces, fiscales y otros altos funcionarios.', practicalEffects: [], examples: ['Para designar un miembro del Superior Tribunal de Justicia, el gobernador propone el candidato y el Senado debe aprobarlo en audiencia pública.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Senado', 'juicio político', 'acuerdo del Senado', 'designación de jueces', 'atribuciones exclusivas'], order: 102, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-104', lawId: 'const-entre-rios', number: '104', title: 'Sesiones ordinarias y extraordinarias', originalText: `Ambas cámaras se reunirán en sesiones ordinarias cada año desde el quince de febrero hasta el quince de diciembre. El Poder Ejecutivo las podrá convocar a sesión extraordinaria siempre que el interés público lo reclame.`, currentText: `Ambas cámaras se reunirán en sesiones ordinarias cada año desde el quince de febrero hasta el quince de diciembre. El Poder Ejecutivo las podrá convocar a sesión extraordinaria siempre que el interés público lo reclame.`, plainLanguageExplanation: 'El período ordinario de sesiones va del 15 de febrero al 15 de diciembre. Fuera de ese período, el Ejecutivo puede convocar sesiones extraordinarias por razones de interés público.', practicalEffects: [], examples: ['Si en enero surge una crisis que requiere una ley urgente, el gobernador puede convocar sesiones extraordinarias a la Legislatura.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sesiones ordinarias', 'sesiones extraordinarias', 'período legislativo'], order: 103, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-105', lawId: 'const-entre-rios', number: '105', title: 'Asamblea legislativa — apertura y mensaje del Ejecutivo', originalText: `Reunidas en Asamblea ambas cámaras y presidida por el presidente del Senado, abrirán sus sesiones ordinarias. En el mismo acto, el Poder Ejecutivo presentará el mensaje dando cuenta del estado de la administración.`, currentText: `Reunidas en Asamblea ambas cámaras y presidida por el presidente del Senado, abrirán sus sesiones ordinarias. En el mismo acto, el Poder Ejecutivo presentará el mensaje dando cuenta del estado de la administración.`, plainLanguageExplanation: 'Las sesiones ordinarias se inauguran con la Asamblea Legislativa (diputados y senadores reunidos), presidida por el vicegobernador. En esa ocasión el gobernador presenta su mensaje de apertura.', practicalEffects: [], examples: ['El 15 de febrero, el gobernador lee su discurso de apertura ante la Asamblea Legislativa presidida por el vicegobernador.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Asamblea Legislativa', 'apertura de sesiones', 'mensaje del Ejecutivo'], order: 104, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-106', lawId: 'const-entre-rios', number: '106', title: 'Prórroga de sesiones', originalText: `Pueden ser prorrogadas las sesiones por el Poder Ejecutivo, o por sanción legislativa, con el voto de la tercera parte de los miembros de cada cámara.`, currentText: `Pueden ser prorrogadas las sesiones por el Poder Ejecutivo, o por sanción legislativa, con el voto de la tercera parte de los miembros de cada cámara.`, plainLanguageExplanation: 'El período ordinario puede extenderse por decisión del Ejecutivo o por voto de al menos un tercio de los miembros de cada cámara.', practicalEffects: [], examples: ['Si el 15 de diciembre hay proyectos importantes pendientes, el gobernador puede prorrogar las sesiones para que se aprueben.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prórroga de sesiones', 'Poder Ejecutivo', 'Legislatura'], order: 105, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-107', lawId: 'const-entre-rios', number: '107', title: 'Quórum legislativo', originalText: `Cada cámara sesionará con la mayoría absoluta de sus miembros. Cuando por falta de quórum, fracasaran dos sesiones consecutivas de las establecidas por cada cámara, éstas podrán sesionar con la tercera parte de sus miembros. Tratándose de sesiones especiales, el quórum de la tercera parte regirá cuando la citación para las mismas, se haya hecho con anticipación de tres días por lo menos. Para la exclusión por ausentismo reiterado se requiere la presencia de la cuarta parte de la totalidad de los miembros de la cámara. En cualquier caso, podrán reunirse en menor número al solo efecto de acordar las medidas necesarias para compeler a los inasistentes por la fuerza pública y aplicar penas de multa o suspensión.`, currentText: `Cada cámara sesionará con la mayoría absoluta de sus miembros. Cuando por falta de quórum, fracasaran dos sesiones consecutivas de las establecidas por cada cámara, éstas podrán sesionar con la tercera parte de sus miembros. Tratándose de sesiones especiales, el quórum de la tercera parte regirá cuando la citación para las mismas, se haya hecho con anticipación de tres días por lo menos. Para la exclusión por ausentismo reiterado se requiere la presencia de la cuarta parte de la totalidad de los miembros de la cámara. En cualquier caso, podrán reunirse en menor número al solo efecto de acordar las medidas necesarias para compeler a los inasistentes por la fuerza pública y aplicar penas de multa o suspensión.`, plainLanguageExplanation: 'Normalmente se necesita mayoría absoluta (mitad más uno) para sesionar; si fracasan dos sesiones seguidas por falta de quórum, alcanza con un tercio. La exclusión de un legislador por ausentismo requiere presencia de al menos un cuarto de la cámara.', practicalEffects: [], examples: ['La Cámara de Diputados (34 miembros) necesita 18 presentes para sesionar; si fracasan dos sesiones, puede hacerlo con 12.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['quórum', 'mayoría absoluta', 'tercera parte', 'sesiones', 'ausentismo'], order: 106, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-108', lawId: 'const-entre-rios', number: '108', title: 'Simultaneidad de sesiones', originalText: `Ambas cámaras empiezan y concluyen sus sesiones legislativas simultáneamente. Ninguna de ellas, mientras se hallen reunidas, podrá suspender sus sesiones por más de tres días sin consentimiento de la otra.`, currentText: `Ambas cámaras empiezan y concluyen sus sesiones legislativas simultáneamente. Ninguna de ellas, mientras se hallen reunidas, podrá suspender sus sesiones por más de tres días sin consentimiento de la otra.`, plainLanguageExplanation: 'Las dos cámaras abren y cierran el período legislativo al mismo tiempo, y ninguna puede pausar sus sesiones más de tres días sin que la otra lo autorice.', practicalEffects: [], examples: ['Si Diputados quiere tomarse una semana de receso, necesita el acuerdo del Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['simultaneidad', 'sesiones', 'receso', 'cámaras'], order: 107, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-109', lawId: 'const-entre-rios', number: '109', title: 'Convocatoria para funciones no legislativas', originalText: `Para el desempeño de las funciones privativas de cada cámara, que no sean legislativas, podrán ser convocadas, en todo tiempo, por el Poder Ejecutivo o por sus presidentes respectivos y sesionar separadamente. A pedido de la tercera parte de sus miembros, el presidente deberá hacer la convocatoria y si se negare, los miembros que la pidieron podrán hacerla directamente.`, currentText: `Para el desempeño de las funciones privativas de cada cámara, que no sean legislativas, podrán ser convocadas, en todo tiempo, por el Poder Ejecutivo o por sus presidentes respectivos y sesionar separadamente. A pedido de la tercera parte de sus miembros, el presidente deberá hacer la convocatoria y si se negare, los miembros que la pidieron podrán hacerla directamente.`, plainLanguageExplanation: 'Para funciones propias no legislativas (como el acuerdo para designaciones o el juicio político), las cámaras pueden reunirse en cualquier momento. Si el presidente se niega a convocar, un tercio de los miembros puede convocar directamente.', practicalEffects: [], examples: ['El Senado puede reunirse en julio (fuera del período ordinario) para dar acuerdo a la designación de un juez propuesta por el gobernador.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['funciones privativas', 'convocatoria', 'cámaras', 'fuera de período'], order: 108, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-110', lawId: 'const-entre-rios', number: '110', title: 'Reglamento interno de las cámaras', originalText: `Cada cámara hará su reglamento que no podrán modificar sobre tablas y en un mismo día.`, currentText: `Cada cámara hará su reglamento que no podrán modificar sobre tablas y en un mismo día.`, plainLanguageExplanation: 'Cada cámara dicta su propio reglamento de funcionamiento, pero no puede modificarlo en el mismo día que lo trata (requiere al menos dos sesiones).', practicalEffects: [], examples: ['Si Diputados quiere cambiar una regla de procedimiento, no puede aprobarlo y hacerlo efectivo el mismo día; debe tratarlo en sesiones separadas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglamento', 'cámaras', 'autonomía legislativa'], order: 109, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-111', lawId: 'const-entre-rios', number: '111', title: 'Sanciones y exclusión de legisladores', originalText: `Cada cámara podrá, con dos tercios de la totalidad de sus miembros, corregir y aún excluir de su seno, a cualesquiera de ellos por desorden de conducta en el ejercicio de sus funciones o por indignidad y removerlo por inhabilidad física o moral sobreviniente a su incorporación; pero bastará la mayoría de uno sobre la mitad de los presentes, para decidir de la renuncia que hiciere de su cargo.`, currentText: `Cada cámara podrá, con dos tercios de la totalidad de sus miembros, corregir y aún excluir de su seno, a cualesquiera de ellos por desorden de conducta en el ejercicio de sus funciones o por indignidad y removerlo por inhabilidad física o moral sobreviniente a su incorporación; pero bastará la mayoría de uno sobre la mitad de los presentes, para decidir de la renuncia que hiciere de su cargo.`, plainLanguageExplanation: 'Con dos tercios de sus miembros totales, una cámara puede sancionar o expulsar a uno de sus integrantes por mala conducta. Para aceptar la renuncia de un legislador basta mayoría simple de los presentes.', practicalEffects: [], examples: ['Un diputado que comete actos indignos puede ser expulsado si 23 de los 34 diputados (dos tercios) votan su exclusión.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusión', 'legisladores', 'dos tercios', 'renuncia', 'mala conducta'], order: 110, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-112', lawId: 'const-entre-rios', number: '112', title: 'Juramento de legisladores', originalText: `Al incorporarse a las cámaras respectivas, los diputados y senadores prestarán juramento por la Patria y sus creencias o principios.`, currentText: `Al incorporarse a las cámaras respectivas, los diputados y senadores prestarán juramento por la Patria y sus creencias o principios.`, plainLanguageExplanation: 'Al asumir su cargo, cada legislador presta juramento de desempeñar fielmente su función; la fórmula puede adaptarse a las creencias personales del legislador.', practicalEffects: [], examples: ['Un diputado que no profesa ninguna religión puede jurar por sus principios en lugar de hacerlo por Dios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'legisladores', 'incorporación'], order: 111, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-113', lawId: 'const-entre-rios', number: '113', title: 'Inmunidad de opinión de los legisladores', originalText: `Los miembros del Poder Legislativo no pueden ser acusados, interrogados judicialmente, ni molestados, por opiniones que emitan en el desempeño de su mandato.`, currentText: `Los miembros del Poder Legislativo no pueden ser acusados, interrogados judicialmente, ni molestados, por opiniones que emitan en el desempeño de su mandato.`, plainLanguageExplanation: 'Los legisladores tienen inmunidad absoluta por lo que dicen en ejercicio de su función: nadie puede demandrarlos ni investigarlos judicialmente por sus discursos o votos en la Legislatura.', practicalEffects: [], examples: ['Un diputado que hace declaraciones polémicas durante un debate no puede ser querellado por difamación por esas palabras.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmunidad de opinión', 'legisladores', 'indemnidad'], order: 112, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-114', lawId: 'const-entre-rios', number: '114', title: 'Inmunidad de arresto de los legisladores', originalText: `Ningún senador o diputado, desde el día de su elección, puede ser detenido excepto el caso de ser sorprendido in fraganti en la ejecución de un delito que merezca pena corporal, en cuyo caso, se dará cuenta de la detención a la cámara respectiva, con la información sumaria del hecho.`, currentText: `Ningún senador o diputado, desde el día de su elección, puede ser detenido excepto el caso de ser sorprendido in fraganti en la ejecución de un delito que merezca pena corporal, en cuyo caso, se dará cuenta de la detención a la cámara respectiva, con la información sumaria del hecho.`, plainLanguageExplanation: 'Los legisladores no pueden ser detenidos preventivamente desde que son elegidos, salvo que sean sorprendidos cometiendo un delito grave en el acto; en ese caso se notifica a la cámara.', practicalEffects: [], examples: ['Si un senador es descubierto cometiendo una agresión, puede ser detenido en el acto; la policía debe informar al Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmunidad de arresto', 'desafuero', 'legisladores', 'flagrancia'], order: 113, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-115', lawId: 'const-entre-rios', number: '115', title: 'Desafuero legislativo', originalText: `Cuando se promueva juicio ante la justicia ordinaria contra cualquier senador o diputado, examinado el mérito del sumario en juicio público, podrá cada cámara, con dos tercios de votos de los presentes, levantar los fueros o suspender en sus funciones al acusado y ponerlo a disposición del juez competente para su juzgamiento.`, currentText: `Cuando se promueva juicio ante la justicia ordinaria contra cualquier senador o diputado, examinado el mérito del sumario en juicio público, podrá cada cámara, con dos tercios de votos de los presentes, levantar los fueros o suspender en sus funciones al acusado y ponerlo a disposición del juez competente para su juzgamiento.`, plainLanguageExplanation: 'Si se inicia una causa penal contra un legislador, su cámara puede votar el desafuero (levantamiento de fueros) con dos tercios de votos, habilitando al juez a procesarlo.', practicalEffects: [], examples: ['Un diputado imputado por corrupción puede ser desaforado si dos tercios de los presentes en Diputados votan a favor del levantamiento de fueros.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desafuero', 'fueros', 'dos tercios', 'juicio ordinario'], order: 114, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-116', lawId: 'const-entre-rios', number: '116', title: 'Interpelación de ministros', originalText: `Cada cámara, con aprobación de un tercio de sus miembros presentes, puede llamar a su seno a los ministros del Poder Ejecutivo para recibir las explicaciones e informes que crea convenientes, citándolos por lo menos con un día de anticipación, salvo caso de urgente gravedad y comunicándoles al citarlos, los puntos sobre los cuales hayan de informar.`, currentText: `Cada cámara, con aprobación de un tercio de sus miembros presentes, puede llamar a su seno a los ministros del Poder Ejecutivo para recibir las explicaciones e informes que crea convenientes, citándolos por lo menos con un día de anticipación, salvo caso de urgente gravedad y comunicándoles al citarlos, los puntos sobre los cuales hayan de informar.`, plainLanguageExplanation: 'Con un tercio de sus miembros presentes, cualquier cámara puede citar a un ministro para que explique su gestión. Debe avisarse con al menos un día de anticipación y comunicar los temas a tratar.', practicalEffects: [], examples: ['El Senado puede interpelar al Ministro de Salud para que explique el manejo del presupuesto sanitario, citándolo con un día de anticipación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interpelación', 'ministros', 'control legislativo', 'un tercio'], order: 115, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-117', lawId: 'const-entre-rios', number: '117', title: 'Pedido de informes al Ejecutivo', originalText: `Cada cámara, con la aprobación de tres de sus miembros, puede también pedir al Poder Ejecutivo, en cualquier época del período de sesiones, los datos e informes que crea necesarios para el mejor desempeño de sus funciones.`, currentText: `Cada cámara, con la aprobación de tres de sus miembros, puede también pedir al Poder Ejecutivo, en cualquier época del período de sesiones, los datos e informes que crea necesarios para el mejor desempeño de sus funciones.`, plainLanguageExplanation: 'Basta con que tres legisladores lo soliciten para que la cámara pueda pedir datos e informes al Poder Ejecutivo en cualquier momento del año legislativo.', practicalEffects: [], examples: ['Tres senadores que quieren conocer el estado de ejecución presupuestaria pueden solicitar formalmente un informe al Ejecutivo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pedido de informes', 'control legislativo', 'Poder Ejecutivo'], order: 116, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-118', lawId: 'const-entre-rios', number: '118', title: 'Remuneración de los legisladores', originalText: `Los servicios de los miembros de la Legislatura serán remunerados por el tesoro de la Provincia con una dotación que fijará la ley, la que no podrá ser alterada en el período del mandato.`, currentText: `Los servicios de los miembros de la Legislatura serán remunerados por el tesoro de la Provincia con una dotación que fijará la ley, la que no podrá ser alterada en el período del mandato.`, plainLanguageExplanation: 'Los legisladores cobran una dieta fijada por ley con cargo al tesoro provincial; esa dieta no puede modificarse durante el mandato en curso (ni reducirse ni aumentarse).', practicalEffects: [], examples: ['Una ley que aumenta la dieta de los legisladores no rige para los que ya están en funciones; aplica a los electos en las elecciones siguientes.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['dieta', 'remuneración', 'legisladores', 'intangibilidad'], order: 117, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-119', lawId: 'const-entre-rios', number: '119', title: 'Publicidad de las sesiones', originalText: `Las sesiones de ambas cámaras serán públicas, a menos que un grave interés, declarado por ellas mismas, exigiere lo contrario.`, currentText: `Las sesiones de ambas cámaras serán públicas, a menos que un grave interés, declarado por ellas mismas, exigiere lo contrario.`, plainLanguageExplanation: 'Las sesiones son abiertas al público por defecto; solo pueden ser secretas si la propia cámara declara que hay un grave interés que lo justifica.', practicalEffects: [], examples: ['Un debate sobre compra de armamento o inteligencia puede realizarse en sesión secreta si la cámara así lo decide.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidad', 'sesiones', 'sesión secreta', 'transparencia'], order: 118, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-120', lawId: 'const-entre-rios', number: '120', title: 'Poder disciplinario externo de las cámaras', originalText: `Cada cámara tendrá autoridad para corregir, con arreglo a los principios parlamentarios, a toda persona que, de fuera de su seno, viole los derechos de sus miembros, pudiendo además pasar los antecedentes a la justicia.`, currentText: `Cada cámara tendrá autoridad para corregir, con arreglo a los principios parlamentarios, a toda persona que, de fuera de su seno, viole los derechos de sus miembros, pudiendo además pasar los antecedentes a la justicia.`, plainLanguageExplanation: 'Las cámaras pueden sancionar a personas ajenas que interfieran o ataquen los derechos de los legisladores, y derivar el caso a la justicia ordinaria.', practicalEffects: [], examples: ['Alguien que amenaza a un diputado para condicionarlo puede ser sancionado por la cámara y denunciado penalmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['poder disciplinario', 'derechos legislativos', 'Legislatura'], order: 119, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-121', lawId: 'const-entre-rios', number: '121', title: 'Diario de sesiones', originalText: `Cada cámara confeccionará su diario de sesiones, en el que constará el trámite legislativo de los proyectos, el debate que genere su tratamiento y las sanciones legislativas. Se confeccionará un diario de sesiones de la Asamblea Legislativa, cuya impresión estará a cargo de la Cámara de Senadores.`, currentText: `Cada cámara confeccionará su diario de sesiones, en el que constará el trámite legislativo de los proyectos, el debate que genere su tratamiento y las sanciones legislativas. Se confeccionará un diario de sesiones de la Asamblea Legislativa, cuya impresión estará a cargo de la Cámara de Senadores.`, plainLanguageExplanation: 'Cada cámara publica un registro oficial de sus sesiones con los debates y votaciones. El diario de la Asamblea Legislativa (sesión conjunta) es responsabilidad del Senado.', practicalEffects: [], examples: ['El diario de sesiones es el documento oficial donde consta cómo votó cada legislador un proyecto de ley.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['diario de sesiones', 'transparencia', 'registro legislativo'], order: 120, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-122', lawId: 'const-entre-rios', number: '122', title: 'Atribuciones del Poder Legislativo', originalText: `Corresponde al Poder Legislativo: 1º. Aprobar o desechar los tratados con las otras provincias para fines de administración de justicia, de intereses económicos y trabajos de utilidad común. 2º. Legislar sobre todas las materias consignadas en la sección segunda, Régimen Económico, del Trabajo y Desarrollo Sustentable, con las orientaciones determinadas en la misma. 3º. Legislar sobre la organización de los municipios, comunas y policía, de acuerdo con lo que establece al respecto la presente Constitución. 4º. Dictar planes y reglamentos generales sobre enseñanza pública. 5º. Legislar sobre enseñanza y cualquier otro objeto de interés común o municipal, dejando a los respectivos municipios su aplicación. 6º. Determinar las formalidades con que se ha de llevar uniformemente el registro del estado civil de las personas. 7º. Dictar la legislación impositiva observando lo dispuesto por el artículo 79 y a esos fines y efectos establecerá impuestos, tasas y contribuciones cuyo monto fijará, en forma equitativa, proporcional o progresivamente, de acuerdo con el objeto perseguido y con el valor o el mayor valor de los bienes o de sus réditos, en su caso. 8º. Fijar el presupuesto de gastos y cálculo de recursos. La ley de presupuesto será la base a que debe sujetarse todo gasto de la administración general de la Provincia y en ella deberán figurar todos los ingresos y egresos ordinarios y extraordinarios de la administración, aun cuando hayan sido autorizados por leyes especiales. Si los recursos para cumplir estas leyes no se incluyeran en la de presupuesto, se considerarán derogadas, si no hubiesen tenido principio de ejecución y suspendidas si lo hubiesen tenido. En ningún caso podrá la Legislatura aumentar el monto de las partidas del cálculo de recursos presentado por el Poder Ejecutivo, ni autorizar por la ley de presupuesto una suma de gastos mayor que la de recursos, salvo el derecho del Poder Legislativo de crear nuevos impuestos o aumentar las tasas. 9º. El número de puestos y el monto de los sueldos proyectados por el Poder Ejecutivo en la ley de presupuesto, no podrán ser aumentados en ésta y dichos aumentos sólo se harán por medio de proyectos de ley que seguirán la tramitación ordinaria. 10º. En el caso de que el Poder Ejecutivo no remitiera el proyecto de ley de presupuesto general de la administración antes de terminar el octavo mes de sesiones ordinarias de la Legislatura y ésta considere necesario modificar el que rige, procederá a hacerlo tomando éste por base. Pronunciada tal resolución, corresponde a la Cámara de Diputados formular el proyecto de ley de presupuesto. Si el Poder Ejecutivo no remitiera el proyecto de ley de presupuesto general dentro de los ocho meses de iniciadas las sesiones ordinarias y si la Legislatura en el resto del período de dichas sesiones, no resolviera usar de la facultad acordada precedentemente, se tendrá el presupuesto en vigencia, como ley de presupuesto para el año siguiente. 11º. Las leyes impositivas regirán en tanto la Legislatura no las derogue ni las modifique, debiendo estas modificaciones hacerse por medio de ley especial. 12º. Crear impuestos transitorios, especificando este carácter y determinando el objeto de su creación. Su producido se aplicará exclusivamente al objeto que lo motiva y su recaudación cesará tan pronto como éste quede cumplido. Pero si producida la liquidación resultara un saldo excedente, éste pasará a rentas generales. 13º. Aprobar, observar o desechar las cuentas de inversión que le remitirá el Poder Ejecutivo en todo el mes de julio de cada período ordinario, abrazando el movimiento administrativo hasta el 31 de diciembre próximo anterior. Deberán formar parte de la cuenta de inversión y ser incluidos en el presupuesto general la totalidad de los recursos provinciales que sean administrados por cualquier entidad, dirección, comisión, junta, delegación o fideicomiso, incluso aquellos que sean compartidos con otras jurisdicciones en la parte correspondiente. Y estarán sujetos a la fiscalización de los organismos competentes. 14º. Crear o suprimir empleos para la mejor administración de la Provincia, siempre que no sean de los establecidos por esta Constitución, determinando sus atribuciones, responsabilidades y su dotación. 15º. Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades civiles de los funcionarios y, especialmente, de los recaudadores de renta, tesorero de la Provincia y demás administradores de dineros públicos. 16º. Fijar las divisiones territoriales para la mejor administración. 17º. Conceder amnistías por infracciones establecidas en sus leyes. 18º. Autorizar la cesión de parte del territorio de la Provincia, con dos tercios de votos de los presentes en sesión, para objetos de utilidad pública nacional o provincial; y con unanimidad de votos de la totalidad de ambas cámaras, cuando dicha cesión importe desmembramiento del territorio o abandono de jurisdicción dentro de los límites prescriptos por la Constitución Nacional. 19º. Legislar sobre tierras públicas de la Provincia debiendo dictarse una ley general sobre la materia. 20º. Dictar todas las leyes y reglamentos necesarios para poner en ejercicio los poderes y autoridades que establece esta Constitución. 21º. Calificar los casos de expropiación por causa de utilidad pública. 22º. Autorizar la ejecución de obras públicas exigidas por el interés de la Provincia. 23º. Dictar las leyes de organización y de procedimientos de los tribunales ordinarios y la del juicio por jurados. 24º. Autorizar el establecimiento de bancos dentro de las prescripciones de la Constitución Nacional. 25º. Facultar al Poder Ejecutivo, con la mitad más uno de los miembros de cada cámara, para contraer empréstitos o emitir fondos públicos con bases y objetos determinados, no pudiendo ser autorizados para equilibrar los gastos ordinarios de la administración. Los papeles de crédito público emitidos, llevarán transcriptas las disposiciones de la ley autorizante. En ningún caso la totalidad de los servicios de los empréstitos comprometerán más de la cuarta parte de las rentas de la Provincia y, ni el numerario obtenido de los mismos, ni los fondos públicos que se emitan, podrán ser aplicados a otros objetos que los determinados por la ley de su creación. 26º. Dictar la ley de elecciones generales de la Provincia. 27º. Conceder o negar licencia al gobernador y vicegobernador para salir temporalmente fuera de la Provincia, o de la Capital por más de quince días, por razones ajenas al desempeño del cargo. 28º. Crear reparticiones autárquicas pudiendo darles facultad para designar su personal y administrar los fondos que se les asigne, dentro de las prescripciones de la ley de creación. 29º. Reglamentar el uso público de símbolos o distintivos que no pertenezcan a la Nación Argentina o a países extranjeros. 30º. Legislar sobre asistencia social con miras a racionalizar la administración de los diversos servicios, a coordinarlos y a organizar el contralor de las inversiones de dineros públicos hechas por intermedio de las asociaciones benéficas privadas. 31º. Dictar todas aquellas leyes necesarias para el mejor desempeño de las anteriores atribuciones y para todo asunto de interés público y general de la Provincia, que por su naturaleza y objeto no corresponda privativamente al Congreso Nacional.`, currentText: `Corresponde al Poder Legislativo: 1º. Aprobar o desechar los tratados con las otras provincias para fines de administración de justicia, de intereses económicos y trabajos de utilidad común. 2º. Legislar sobre todas las materias consignadas en la sección segunda, Régimen Económico, del Trabajo y Desarrollo Sustentable, con las orientaciones determinadas en la misma. 3º. Legislar sobre la organización de los municipios, comunas y policía, de acuerdo con lo que establece al respecto la presente Constitución. 4º. Dictar planes y reglamentos generales sobre enseñanza pública. 5º. Legislar sobre enseñanza y cualquier otro objeto de interés común o municipal, dejando a los respectivos municipios su aplicación. 6º. Determinar las formalidades con que se ha de llevar uniformemente el registro del estado civil de las personas. 7º. Dictar la legislación impositiva observando lo dispuesto por el artículo 79 y a esos fines y efectos establecerá impuestos, tasas y contribuciones cuyo monto fijará, en forma equitativa, proporcional o progresivamente, de acuerdo con el objeto perseguido y con el valor o el mayor valor de los bienes o de sus réditos, en su caso. 8º. Fijar el presupuesto de gastos y cálculo de recursos. La ley de presupuesto será la base a que debe sujetarse todo gasto de la administración general de la Provincia y en ella deberán figurar todos los ingresos y egresos ordinarios y extraordinarios de la administración, aun cuando hayan sido autorizados por leyes especiales. Si los recursos para cumplir estas leyes no se incluyeran en la de presupuesto, se considerarán derogadas, si no hubiesen tenido principio de ejecución y suspendidas si lo hubiesen tenido. En ningún caso podrá la Legislatura aumentar el monto de las partidas del cálculo de recursos presentado por el Poder Ejecutivo, ni autorizar por la ley de presupuesto una suma de gastos mayor que la de recursos, salvo el derecho del Poder Legislativo de crear nuevos impuestos o aumentar las tasas. 9º. El número de puestos y el monto de los sueldos proyectados por el Poder Ejecutivo en la ley de presupuesto, no podrán ser aumentados en ésta y dichos aumentos sólo se harán por medio de proyectos de ley que seguirán la tramitación ordinaria. 10º. En el caso de que el Poder Ejecutivo no remitiera el proyecto de ley de presupuesto general de la administración antes de terminar el octavo mes de sesiones ordinarias de la Legislatura y ésta considere necesario modificar el que rige, procederá a hacerlo tomando éste por base. Pronunciada tal resolución, corresponde a la Cámara de Diputados formular el proyecto de ley de presupuesto. Si el Poder Ejecutivo no remitiera el proyecto de ley de presupuesto general dentro de los ocho meses de iniciadas las sesiones ordinarias y si la Legislatura en el resto del período de dichas sesiones, no resolviera usar de la facultad acordada precedentemente, se tendrá el presupuesto en vigencia, como ley de presupuesto para el año siguiente. 11º. Las leyes impositivas regirán en tanto la Legislatura no las derogue ni las modifique, debiendo estas modificaciones hacerse por medio de ley especial. 12º. Crear impuestos transitorios, especificando este carácter y determinando el objeto de su creación. Su producido se aplicará exclusivamente al objeto que lo motiva y su recaudación cesará tan pronto como éste quede cumplido. Pero si producida la liquidación resultara un saldo excedente, éste pasará a rentas generales. 13º. Aprobar, observar o desechar las cuentas de inversión que le remitirá el Poder Ejecutivo en todo el mes de julio de cada período ordinario, abrazando el movimiento administrativo hasta el 31 de diciembre próximo anterior. Deberán formar parte de la cuenta de inversión y ser incluidos en el presupuesto general la totalidad de los recursos provinciales que sean administrados por cualquier entidad, dirección, comisión, junta, delegación o fideicomiso, incluso aquellos que sean compartidos con otras jurisdicciones en la parte correspondiente. Y estarán sujetos a la fiscalización de los organismos competentes. 14º. Crear o suprimir empleos para la mejor administración de la Provincia, siempre que no sean de los establecidos por esta Constitución, determinando sus atribuciones, responsabilidades y su dotación. 15º. Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades civiles de los funcionarios y, especialmente, de los recaudadores de renta, tesorero de la Provincia y demás administradores de dineros públicos. 16º. Fijar las divisiones territoriales para la mejor administración. 17º. Conceder amnistías por infracciones establecidas en sus leyes. 18º. Autorizar la cesión de parte del territorio de la Provincia, con dos tercios de votos de los presentes en sesión, para objetos de utilidad pública nacional o provincial; y con unanimidad de votos de la totalidad de ambas cámaras, cuando dicha cesión importe desmembramiento del territorio o abandono de jurisdicción dentro de los límites prescriptos por la Constitución Nacional. 19º. Legislar sobre tierras públicas de la Provincia debiendo dictarse una ley general sobre la materia. 20º. Dictar todas las leyes y reglamentos necesarios para poner en ejercicio los poderes y autoridades que establece esta Constitución. 21º. Calificar los casos de expropiación por causa de utilidad pública. 22º. Autorizar la ejecución de obras públicas exigidas por el interés de la Provincia. 23º. Dictar las leyes de organización y de procedimientos de los tribunales ordinarios y la del juicio por jurados. 24º. Autorizar el establecimiento de bancos dentro de las prescripciones de la Constitución Nacional. 25º. Facultar al Poder Ejecutivo, con la mitad más uno de los miembros de cada cámara, para contraer empréstitos o emitir fondos públicos con bases y objetos determinados, no pudiendo ser autorizados para equilibrar los gastos ordinarios de la administración. Los papeles de crédito público emitidos, llevarán transcriptas las disposiciones de la ley autorizante. En ningún caso la totalidad de los servicios de los empréstitos comprometerán más de la cuarta parte de las rentas de la Provincia y, ni el numerario obtenido de los mismos, ni los fondos públicos que se emitan, podrán ser aplicados a otros objetos que los determinados por la ley de su creación. 26º. Dictar la ley de elecciones generales de la Provincia. 27º. Conceder o negar licencia al gobernador y vicegobernador para salir temporalmente fuera de la Provincia, o de la Capital por más de quince días, por razones ajenas al desempeño del cargo. 28º. Crear reparticiones autárquicas pudiendo darles facultad para designar su personal y administrar los fondos que se les asigne, dentro de las prescripciones de la ley de creación. 29º. Reglamentar el uso público de símbolos o distintivos que no pertenezcan a la Nación Argentina o a países extranjeros. 30º. Legislar sobre asistencia social con miras a racionalizar la administración de los diversos servicios, a coordinarlos y a organizar el contralor de las inversiones de dineros públicos hechas por intermedio de las asociaciones benéficas privadas. 31º. Dictar todas aquellas leyes necesarias para el mejor desempeño de las anteriores atribuciones y para todo asunto de interés público y general de la Provincia, que por su naturaleza y objeto no corresponda privativamente al Congreso Nacional.`, plainLanguageExplanation: 'Enumera las 31 atribuciones del Poder Legislativo: presupuesto, impuestos, amnistía, organización municipal, obras públicas, empréstitos, elecciones, leyes de procedimiento, entre otras. Es el catálogo de materias sobre las que puede legislar la Provincia.', practicalEffects: [], examples: ['Para que la Provincia tome un préstamo externo, la Legislatura debe autorizarlo con mayoría absoluta de cada cámara (inc. 25°).'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones legislativas', 'presupuesto', 'impuestos', 'empréstitos', 'amnistía', 'organización municipal'], order: 121, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-123', lawId: 'const-entre-rios', number: '123', title: 'Iniciativa legislativa — origen de las leyes', originalText: `Las leyes pueden tener origen en cualesquiera de las cámaras, por proyectos presentados por sus miembros, por el Poder Ejecutivo, por el Superior Tribunal de Justicia cuando se tratare de materias vinculadas a la organización judicial, y por el pueblo ejerciendo el derecho de iniciativa popular. Todos los proyectos deberán tener tratamiento parlamentario.`, currentText: `Las leyes pueden tener origen en cualesquiera de las cámaras, por proyectos presentados por sus miembros, por el Poder Ejecutivo, por el Superior Tribunal de Justicia cuando se tratare de materias vinculadas a la organización judicial, y por el pueblo ejerciendo el derecho de iniciativa popular. Todos los proyectos deberán tener tratamiento parlamentario.`, plainLanguageExplanation: 'Los proyectos de ley pueden presentarlos los propios legisladores, el Ejecutivo, el Superior Tribunal (en temas judiciales) o los ciudadanos mediante la iniciativa popular. Todos deben pasar por el Parlamento.', practicalEffects: [], examples: ['Un grupo de ciudadanos puede presentar un proyecto de ley mediante iniciativa popular; la Legislatura debe debatirlo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['iniciativa legislativa', 'proyecto de ley', 'iniciativa popular', 'Poder Ejecutivo'], order: 122, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-124', lawId: 'const-entre-rios', number: '124', title: 'Sanción sobre tablas', originalText: `Para que un proyecto de ley sea sancionado sobre tablas, será necesario dos tercios de votos de los presentes y esa sanción no podrá recaer en general y particular en un mismo día, en ambas cámaras.`, currentText: `Para que un proyecto de ley sea sancionado sobre tablas, será necesario dos tercios de votos de los presentes y esa sanción no podrá recaer en general y particular en un mismo día, en ambas cámaras.`, plainLanguageExplanation: 'Aprobar un proyecto "sobre tablas" (saltando el trámite de comisión) requiere dos tercios de los presentes, y no puede sancionarse en general y en particular el mismo día en ambas cámaras.', practicalEffects: [], examples: ['Un proyecto de emergencia puede tratarse sobre tablas si dos tercios de los diputados votan a favor del procedimiento abreviado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sobre tablas', 'dos tercios', 'sanción', 'procedimiento abreviado'], order: 123, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-125', lawId: 'const-entre-rios', number: '125', title: 'Proceso de sanción y promulgación de leyes', originalText: `Aprobado un proyecto por la cámara de su origen, pasa para su discusión a la otra cámara. Aprobado por ambas, pasa al Poder Ejecutivo para su examen, y si también lo aprueba, lo promulga como ley.`, currentText: `Aprobado un proyecto por la cámara de su origen, pasa para su discusión a la otra cámara. Aprobado por ambas, pasa al Poder Ejecutivo para su examen, y si también lo aprueba, lo promulga como ley.`, plainLanguageExplanation: 'El recorrido normal de un proyecto es: cámara de origen → cámara revisora → Poder Ejecutivo. Si el Ejecutivo lo aprueba, lo promulga; si no, lo veta.', practicalEffects: [], examples: ['Un proyecto presentado en Diputados que aprueba allí pasa al Senado; si el Senado también lo aprueba, va al gobernador para su promulgación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sanción', 'promulgación', 'cámara de origen', 'cámara revisora', 'proceso legislativo'], order: 124, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-126', lawId: 'const-entre-rios', number: '126', title: 'Promulgación tácita por silencio del Ejecutivo', originalText: `Se reputa aprobado por el Poder Ejecutivo todo proyecto no devuelto en el término de diez días hábiles.`, currentText: `Se reputa aprobado por el Poder Ejecutivo todo proyecto no devuelto en el término de diez días hábiles.`, plainLanguageExplanation: 'Si el gobernador no veta ni promulga expresamente una ley en 10 días hábiles, se considera promulgada automáticamente.', practicalEffects: [], examples: ['El gobernador recibe un proyecto el lunes; si el miércoles de la semana siguiente no lo vetó ni promulgó, queda promulgado por silencio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación tácita', 'silencio del Ejecutivo', 'diez días hábiles'], order: 125, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-127', lawId: 'const-entre-rios', number: '127', title: 'Veto durante clausura de las cámaras', originalText: `Si antes del vencimiento de los diez días hubiese tenido lugar la clausura de las cámaras, el Poder Ejecutivo deberá, dentro de dicho término, remitir el proyecto vetado a la secretaría del Senado, sin cuyo requisito no tendrá efecto el veto.`, currentText: `Si antes del vencimiento de los diez días hubiese tenido lugar la clausura de las cámaras, el Poder Ejecutivo deberá, dentro de dicho término, remitir el proyecto vetado a la secretaría del Senado, sin cuyo requisito no tendrá efecto el veto.`, plainLanguageExplanation: 'Si la Legislatura cierra antes de que venza el plazo de 10 días, el gobernador debe igualmente remitir el veto a la secretaría del Senado dentro de ese plazo; de lo contrario el veto no vale.', practicalEffects: [], examples: ['Si la Legislatura clausura el 15 de diciembre y el plazo de 10 días para vetar vence el 20 de diciembre, el gobernador debe enviar el veto a la secretaría del Senado antes del 20.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['veto', 'clausura', 'Senado', 'plazo'], order: 126, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-128', lawId: 'const-entre-rios', number: '128', title: 'Proyecto rechazado o enmendado — procedimiento', originalText: `Ningún proyecto de ley desechado totalmente por una de las cámaras podrá repetirse en las sesiones de aquel año, sino cuando vuelva a presentarse y fuera apoyado, por dos tercios de votos de los miembros presentes de la cámara que lo rechazó. Si sólo fuera adicionado o corregido por la cámara revisora, volverá a la de su origen y si en ésta se aprobaran las adiciones o correcciones por mayoría absoluta, pasará al Poder Ejecutivo. Si las adiciones o correcciones fueran desechadas volverá por segunda vez el proyecto a la cámara revisora, y si aquí fuesen nuevamente sancionadas por una mayoría de dos terceras partes de sus miembros, pasará el proyecto a la otra cámara y no se entenderá que ésta reprueba dichas adiciones o correcciones, si no concurre para ello el voto de dos terceras partes de sus miembros presentes.`, currentText: `Ningún proyecto de ley desechado totalmente por una de las cámaras podrá repetirse en las sesiones de aquel año, sino cuando vuelva a presentarse y fuera apoyado, por dos tercios de votos de los miembros presentes de la cámara que lo rechazó. Si sólo fuera adicionado o corregido por la cámara revisora, volverá a la de su origen y si en ésta se aprobaran las adiciones o correcciones por mayoría absoluta, pasará al Poder Ejecutivo. Si las adiciones o correcciones fueran desechadas volverá por segunda vez el proyecto a la cámara revisora, y si aquí fuesen nuevamente sancionadas por una mayoría de dos terceras partes de sus miembros, pasará el proyecto a la otra cámara y no se entenderá que ésta reprueba dichas adiciones o correcciones, si no concurre para ello el voto de dos terceras partes de sus miembros presentes.`, plainLanguageExplanation: 'Un proyecto rechazado no puede reintroducirse en el mismo año salvo con dos tercios de apoyo. Si la cámara revisora lo enmienda, vuelve a la cámara de origen; si ésta rechaza las enmiendas, la revisora puede insistir con dos tercios.', practicalEffects: [], examples: ['Un proyecto rechazado por Diputados no puede volver a presentarse ese mismo año salvo que dos tercios de los diputados lo apoyen.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['proyecto rechazado', 'cámara revisora', 'dos tercios', 'enmiendas', 'proceso legislativo'], order: 127, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-129', lawId: 'const-entre-rios', number: '129', title: 'Veto del Ejecutivo — procedimiento de insistencia', originalText: `Si el Poder Ejecutivo desechara en todo o en parte un proyecto de ley sancionado, vuelve con sus observaciones a la Legislatura, debiendo el presidente de la Asamblea pasarlo sin más trámite a las comisiones de ambas cámaras que tuvieron a su cargo el estudio del proyecto, las que constituidas en una sola comisión, deberán estudiar las observaciones del Poder Ejecutivo, debiendo expedirse dentro de un plazo no mayor de diez días. Transcurrido dicho término y aunque la comisión no se hubiere expedido, dentro de las cuarenta y ocho horas subsiguientes, las secretarías de ambas cámaras citarán para un término no mayor de tres días a sesión plenaria de la Legislatura, la que deberá pronunciarse dentro de los quince días a contar de la fecha establecida en la primera convocatoria. A este efecto regirán las disposiciones contenidas en el artículo 107. Si la Asamblea no se expidiera dentro del plazo señalado, en caso de veto total se considerará rechazado el proyecto y si el veto fuera parcial se tendrán por aprobadas las proposiciones del Poder Ejecutivo. Si se insiste en la primera sanción por dos tercios de votos presentes, o se aceptan por mayoría absoluta de los presentes las observaciones del Poder Ejecutivo, el proyecto será comunicado a éste para su cumplimiento. Las votaciones serán nominales y, tanto los nombres de los sufragantes como los fundamentos que hayan expuesto y las observaciones del Poder Ejecutivo, se publicarán inmediatamente por la prensa. En caso de veto total, no existiendo los dos tercios para la insistencia, el proyecto no podrá repetirse en las sesiones de aquel año. El veto parcial no invalida el resto de la ley que podrá ser puesta en vigor en las partes no afectadas por el mismo siempre que su aprobación parcial no altere el espíritu ni la unidad del proyecto sancionado por la Legislatura. A los efectos de este artículo y en el caso del artículo 127, se considerarán prorrogadas las sesiones por el término necesario para el pronunciamiento de la Legislatura.`, currentText: `Si el Poder Ejecutivo desechara en todo o en parte un proyecto de ley sancionado, vuelve con sus observaciones a la Legislatura, debiendo el presidente de la Asamblea pasarlo sin más trámite a las comisiones de ambas cámaras que tuvieron a su cargo el estudio del proyecto, las que constituidas en una sola comisión, deberán estudiar las observaciones del Poder Ejecutivo, debiendo expedirse dentro de un plazo no mayor de diez días. Transcurrido dicho término y aunque la comisión no se hubiere expedido, dentro de las cuarenta y ocho horas subsiguientes, las secretarías de ambas cámaras citarán para un término no mayor de tres días a sesión plenaria de la Legislatura, la que deberá pronunciarse dentro de los quince días a contar de la fecha establecida en la primera convocatoria. A este efecto regirán las disposiciones contenidas en el artículo 107. Si la Asamblea no se expidiera dentro del plazo señalado, en caso de veto total se considerará rechazado el proyecto y si el veto fuera parcial se tendrán por aprobadas las proposiciones del Poder Ejecutivo. Si se insiste en la primera sanción por dos tercios de votos presentes, o se aceptan por mayoría absoluta de los presentes las observaciones del Poder Ejecutivo, el proyecto será comunicado a éste para su cumplimiento. Las votaciones serán nominales y, tanto los nombres de los sufragantes como los fundamentos que hayan expuesto y las observaciones del Poder Ejecutivo, se publicarán inmediatamente por la prensa. En caso de veto total, no existiendo los dos tercios para la insistencia, el proyecto no podrá repetirse en las sesiones de aquel año. El veto parcial no invalida el resto de la ley que podrá ser puesta en vigor en las partes no afectadas por el mismo siempre que su aprobación parcial no altere el espíritu ni la unidad del proyecto sancionado por la Legislatura. A los efectos de este artículo y en el caso del artículo 127, se considerarán prorrogadas las sesiones por el término necesario para el pronunciamiento de la Legislatura.`, plainLanguageExplanation: 'Si el gobernador veta total o parcialmente una ley, la Legislatura puede insistir con dos tercios de los presentes. Si no logra ese quórum para insistir, el proyecto cae por ese año. El veto parcial no invalida el resto de la ley si su texto parcial mantiene unidad.', practicalEffects: [], examples: ['El gobernador veta una ley de aumento salarial; la Asamblea Legislativa convocada para insistir obtiene solo mayoría simple, no dos tercios, por lo que el proyecto queda vetado por ese año.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['veto', 'insistencia', 'dos tercios', 'veto parcial', 'Asamblea Legislativa'], order: 128, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-130', lawId: 'const-entre-rios', number: '130', title: 'Publicación de leyes modificadas', originalText: `Toda ley modificada en parte se publicará íntegra, incorporando a su texto las modificaciones, con excepción de los códigos de procedimientos u otras leyes que por su larga extensión hagan inconveniente la reimpresión, en cuyo caso, esta prescripción se cumplirá en cada nueva edición. Cuando en una ley se citen o se incorporen prescripciones de otra, las partes que se citen o incorporen, se insertarán íntegramente. El Poder Ejecutivo debe realizar la publicación dentro de los ocho días de promulgada la ley. En su defecto, el presidente de cualquiera de las cámaras legislativas, la dispondrá en un diario provincial de amplia difusión, teniendo la misma carácter de publicación oficial.`, currentText: `Toda ley modificada en parte se publicará íntegra, incorporando a su texto las modificaciones, con excepción de los códigos de procedimientos u otras leyes que por su larga extensión hagan inconveniente la reimpresión, en cuyo caso, esta prescripción se cumplirá en cada nueva edición. Cuando en una ley se citen o se incorporen prescripciones de otra, las partes que se citen o incorporen, se insertarán íntegramente. El Poder Ejecutivo debe realizar la publicación dentro de los ocho días de promulgada la ley. En su defecto, el presidente de cualquiera de las cámaras legislativas, la dispondrá en un diario provincial de amplia difusión, teniendo la misma carácter de publicación oficial.`, plainLanguageExplanation: 'Cuando se modifica una ley debe publicarse el texto actualizado completo (no solo los artículos cambiados). La publicación debe hacerse en 8 días; si el Ejecutivo no lo hace, puede hacerlo el presidente de cualquier cámara en un diario oficial.', practicalEffects: [], examples: ['Si se modifica el artículo 5 de una ley de 20 artículos, debe publicarse la ley entera con la modificación incorporada.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicación', 'leyes', 'promulgación', 'Boletín Oficial', 'texto actualizado'], order: 129, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-131', lawId: 'const-entre-rios', number: '131', title: 'Numeración correlativa y consolidación normativa', originalText: `Cuando se haga la publicación oficial de las leyes de la Provincia, se enumerarán ordinalmente y, en adelante, se mantendrá la numeración correlativa por la fecha de promulgación. La ley dispondrá las medidas que aseguren la actualización y consolidación permanente del orden normativo provincial. Se confeccionará además un anexo de derecho histórico, conteniendo las disposiciones derogadas.`, currentText: `Cuando se haga la publicación oficial de las leyes de la Provincia, se enumerarán ordinalmente y, en adelante, se mantendrá la numeración correlativa por la fecha de promulgación. La ley dispondrá las medidas que aseguren la actualización y consolidación permanente del orden normativo provincial. Se confeccionará además un anexo de derecho histórico, conteniendo las disposiciones derogadas.`, plainLanguageExplanation: 'Las leyes provinciales se numeran en orden cronológico de promulgación. Debe mantenerse actualizado y consolidado el texto normativo vigente, con un anexo histórico de normas derogadas.', practicalEffects: [], examples: ['La ley promulgada el 10 de marzo recibe el número siguiente al de la última ley promulgada, independientemente del orden en que fue presentada.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['numeración de leyes', 'consolidación normativa', 'derecho histórico', 'derogadas'], order: 130, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-132', lawId: 'const-entre-rios', number: '132', title: 'Fórmula de sanción de las leyes', originalText: `En la sanción de las leyes, se usará la siguiente fórmula: "La Legislatura de la Provincia de Entre Ríos, sanciona con fuerza de ley".`, currentText: `En la sanción de las leyes, se usará la siguiente fórmula: "La Legislatura de la Provincia de Entre Ríos, sanciona con fuerza de ley".`, plainLanguageExplanation: 'Toda ley provincial debe sancionarse con la fórmula "La Legislatura de la Provincia de Entre Ríos, sanciona con fuerza de ley"; es un requisito formal de validez.', practicalEffects: [], examples: ['Un proyecto aprobado sin esa fórmula podría ser cuestionado en su validez formal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fórmula legal', 'sanción', 'Legislatura'], order: 131, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-133', lawId: 'const-entre-rios', number: '133', title: 'Funciones de la Asamblea Legislativa', originalText: `Ambas cámaras sólo se reunirán para el desempeño de las funciones siguientes: 1º. Apertura de las sesiones ordinarias. 2º. Recibir el juramento de ley del gobernador y vicegobernador de la Provincia. 3º. Tomar en consideración la renuncia de los mismos funcionarios. 4º. Declarar, con dos tercios de los votos presentes de cada cámara, los casos de impedimento del gobernador, vicegobernador o de la persona que ejerza el Poder Ejecutivo. 5º. Realizar la elección de gobernador y vicegobernador que prevé el artículo 159. 6º. Considerar el veto del Poder Ejecutivo en la forma prescripta por el artículo 129.`, currentText: `Ambas cámaras sólo se reunirán para el desempeño de las funciones siguientes: 1º. Apertura de las sesiones ordinarias. 2º. Recibir el juramento de ley del gobernador y vicegobernador de la Provincia. 3º. Tomar en consideración la renuncia de los mismos funcionarios. 4º. Declarar, con dos tercios de los votos presentes de cada cámara, los casos de impedimento del gobernador, vicegobernador o de la persona que ejerza el Poder Ejecutivo. 5º. Realizar la elección de gobernador y vicegobernador que prevé el artículo 159. 6º. Considerar el veto del Poder Ejecutivo en la forma prescripta por el artículo 129.`, plainLanguageExplanation: 'La Asamblea Legislativa (reunión conjunta de las dos cámaras) solo puede reunirse para seis funciones específicas: apertura de sesiones, juramento del gobernador, renuncias, impedimentos, elección de gobernador y tratamiento de vetos.', practicalEffects: [], examples: ['Cuando asume el gobernador, presta juramento ante la Asamblea Legislativa reunida en pleno.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Asamblea Legislativa', 'apertura', 'juramento', 'gobernador', 'impedimento'], order: 132, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-134', lawId: 'const-entre-rios', number: '134', title: 'Nombramientos en Asamblea — mayoría y empate', originalText: `Todos los nombramientos deberán hacerse por mayoría absoluta de los presentes. Si hecho el escrutinio no resultare candidato con mayoría absoluta, deberá repetirse la votación contrayéndose a los candidatos que hubiesen obtenido más votos en la anterior, y en caso de empate, decidirá el presidente.`, currentText: `Todos los nombramientos deberán hacerse por mayoría absoluta de los presentes. Si hecho el escrutinio no resultare candidato con mayoría absoluta, deberá repetirse la votación contrayéndose a los candidatos que hubiesen obtenido más votos en la anterior, y en caso de empate, decidirá el presidente.`, plainLanguageExplanation: 'La Asamblea designa por mayoría absoluta; si en la primera vuelta nadie la alcanza, se vota entre los más votados. En caso de empate decide el presidente.', practicalEffects: [], examples: ['Si ningún candidato a gobernador suplente obtiene mayoría absoluta en primera vuelta, se repite la votación solo entre los dos más votados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nombramientos', 'Asamblea Legislativa', 'mayoría absoluta', 'empate'], order: 133, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-135', lawId: 'const-entre-rios', number: '135', title: 'Excusaciones en nombramientos de la Asamblea', originalText: `De las excusaciones que se presenten de nombramientos hechos por la Asamblea, conocerá ella misma, procediendo según fuese su resultado.`, currentText: `De las excusaciones que se presenten de nombramientos hechos por la Asamblea, conocerá ella misma, procediendo según fuese su resultado.`, plainLanguageExplanation: 'Si alguien designado por la Asamblea se excusa (rechaza el nombramiento), la propia Asamblea resuelve si acepta la excusa y qué hacer a continuación.', practicalEffects: [], examples: ['Si un legislador designado para integrar una comisión especial se excusa, la Asamblea decide si acepta la excusa y elige a otro.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['excusación', 'nombramiento', 'Asamblea Legislativa'], order: 134, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-136', lawId: 'const-entre-rios', number: '136', title: 'Presidencia de la Asamblea General', originalText: `Las reuniones de la Asamblea General serán presididas por el vicegobernador, en su defecto, por el vicepresidente primero del Senado o por el presidente de la Cámara de Diputados; a falta de ambos, por el legislador que designe la Asamblea.`, currentText: `Las reuniones de la Asamblea General serán presididas por el vicegobernador, en su defecto, por el vicepresidente primero del Senado o por el presidente de la Cámara de Diputados; a falta de ambos, por el legislador que designe la Asamblea.`, plainLanguageExplanation: 'La Asamblea la preside el vicegobernador; si falta, el vicepresidente primero del Senado o el presidente de Diputados; si ambos faltan, la Asamblea elige al presidente.', practicalEffects: [], examples: ['Si el vicegobernador está de viaje y el vice primero del Senado está ausente, preside el presidente de la Cámara de Diputados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presidencia', 'Asamblea Legislativa', 'vicegobernador', 'orden de prelación'], order: 135, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-137', lawId: 'const-entre-rios', number: '137', title: 'Quórum de la Asamblea Legislativa', originalText: `No podrá funcionar la Asamblea sin la mayoría de la totalidad de los miembros que la forman, salvo para la apertura del período legislativo y para recibir juramento del gobernador y vicegobernador, en cuyos casos, podrá hacerlo con la presencia de cualquier número.`, currentText: `No podrá funcionar la Asamblea sin la mayoría de la totalidad de los miembros que la forman, salvo para la apertura del período legislativo y para recibir juramento del gobernador y vicegobernador, en cuyos casos, podrá hacerlo con la presencia de cualquier número.`, plainLanguageExplanation: 'La Asamblea requiere mayoría absoluta del total de sus miembros para funcionar, excepto para los actos de apertura y juramento del gobernador, donde cualquier número alcanza.', practicalEffects: [], examples: ['Para declarar el impedimento del gobernador la Asamblea necesita mayoría de sus ~51 miembros; para la apertura de sesiones puede funcionar con cualquier número.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['quórum', 'Asamblea Legislativa', 'mayoría absoluta'], order: 136, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-138', lawId: 'const-entre-rios', number: '138', title: 'Funcionarios sujetos a juicio político', originalText: `Están sujetos al juicio político, el gobernador, vicegobernador, los ministros del Poder Ejecutivo, los miembros del Superior Tribunal de Justicia, de sus salas y el Defensor del Pueblo.`, currentText: `Están sujetos al juicio político, el gobernador, vicegobernador, los ministros del Poder Ejecutivo, los miembros del Superior Tribunal de Justicia, de sus salas y el Defensor del Pueblo.`, plainLanguageExplanation: 'El juicio político puede alcanzar al gobernador, vicegobernador, ministros, jueces del Superior Tribunal y el Defensor del Pueblo; es el mecanismo para destituirlos con garantías de proceso.', practicalEffects: [], examples: ['Si un ministro comete mal desempeño, puede ser acusado por cualquier diputado o por un ciudadano ante la Cámara de Diputados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'gobernador', 'ministros', 'Superior Tribunal', 'Defensor del Pueblo'], order: 137, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-139', lawId: 'const-entre-rios', number: '139', title: 'Quién puede iniciar el juicio político', originalText: `La acusación de los funcionarios sujetos a juicio político, será formulada ante la Cámara de Diputados, por cualesquiera de sus miembros o por cualquier particular.`, currentText: `La acusación de los funcionarios sujetos a juicio político, será formulada ante la Cámara de Diputados, por cualesquiera de sus miembros o por cualquier particular.`, plainLanguageExplanation: 'Cualquier diputado o cualquier ciudadano puede presentar una acusación de juicio político ante la Cámara de Diputados.', practicalEffects: [], examples: ['Un ciudadano afectado por una decisión irregular de un ministro puede presentar una denuncia de juicio político directamente ante Diputados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'acusación', 'Cámara de Diputados', 'acción popular'], order: 138, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-140', lawId: 'const-entre-rios', number: '140', title: 'Causales y forma de la acusación en juicio político', originalText: `La acusación se hará por escrito, determinando con toda precisión los hechos que sirvan de fundamento a aquélla. Son causales para el enjuiciamiento político el mal desempeño o la incapacidad física o mental sobreviniente que evidencie falta de idoneidad para el cargo.`, currentText: `La acusación se hará por escrito, determinando con toda precisión los hechos que sirvan de fundamento a aquélla. Son causales para el enjuiciamiento político el mal desempeño o la incapacidad física o mental sobreviniente que evidencie falta de idoneidad para el cargo.`, plainLanguageExplanation: 'La acusación debe ser escrita y detallada. Las causales son: mal desempeño del cargo o incapacidad física/mental sobreviniente.', practicalEffects: [], examples: ['Si un miembro del Superior Tribunal sufre una enfermedad que lo incapacita para ejercer su función, puede ser sometido a juicio político por incapacidad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'causales', 'mal desempeño', 'incapacidad', 'acusación escrita'], order: 139, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-141', lawId: 'const-entre-rios', number: '141', title: 'Comisión de Investigación en juicio político', originalText: `Presentada la denuncia, pasará sin más trámite a la Comisión de Investigación, que nombrará la Cámara de Diputados en su primera sesión ordinaria, no pudiendo facultar al presidente para que la nombre. Dicha comisión tendrá por objeto investigar la verdad de los hechos en que se funda la acusación, teniendo para ese efecto las más amplias facultades.`, currentText: `Presentada la denuncia, pasará sin más trámite a la Comisión de Investigación, que nombrará la Cámara de Diputados en su primera sesión ordinaria, no pudiendo facultar al presidente para que la nombre. Dicha comisión tendrá por objeto investigar la verdad de los hechos en que se funda la acusación, teniendo para ese efecto las más amplias facultades.`, plainLanguageExplanation: 'La denuncia pasa automáticamente a la Comisión de Investigación que la cámara designa al inicio del año. Esa comisión investiga con amplias facultades y no puede ser delegada al presidente de la cámara.', practicalEffects: [], examples: ['Apenas presentada una denuncia de juicio político, la Cámara crea o activa la Comisión de Investigación para que evalúe los hechos sin dilación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'Comisión de Investigación', 'investigación', 'Cámara de Diputados'], order: 140, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-142', lawId: 'const-entre-rios', number: '142', title: 'Derechos del acusado ante la Comisión de Investigación', originalText: `El acusado tendrá derecho de ser oído por la Comisión de Investigación, de interpelar por su intermedio a los testigos y de presentar los documentos de descargo que tuviere. Tendrá también el deber de contestar a todas las preguntas que la comisión le dirija respecto a la acusación.`, currentText: `El acusado tendrá derecho de ser oído por la Comisión de Investigación, de interpelar por su intermedio a los testigos y de presentar los documentos de descargo que tuviere. Tendrá también el deber de contestar a todas las preguntas que la comisión le dirija respecto a la acusación.`, plainLanguageExplanation: 'El funcionario acusado tiene derecho a defenderse ante la Comisión: declarar, interrogar testigos y presentar pruebas; pero también tiene la obligación de responder las preguntas de la Comisión.', practicalEffects: [], examples: ['El ministro acusado puede presentar documentos que demuestren que actuó legalmente y puede contrainterrogar a los testigos que lo incriminan.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'defensa', 'Comisión de Investigación', 'debido proceso'], order: 141, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-143', lawId: 'const-entre-rios', number: '143', title: 'Dictamen de la Comisión de Investigación', originalText: `La Comisión de Investigación consignará por escrito todas las declaraciones e informes relativos al proceso y terminado que haya su cometido, pasará a la cámara, con todos sus antecedentes, un informe escrito en que hará mérito de aquéllos y expresará su dictamen en favor o en contra de la acusación. La Comisión de Investigación deberá terminar su diligencia en el perentorio término de treinta días.`, currentText: `La Comisión de Investigación consignará por escrito todas las declaraciones e informes relativos al proceso y terminado que haya su cometido, pasará a la cámara, con todos sus antecedentes, un informe escrito en que hará mérito de aquéllos y expresará su dictamen en favor o en contra de la acusación. La Comisión de Investigación deberá terminar su diligencia en el perentorio término de treinta días.`, plainLanguageExplanation: 'La Comisión registra todo por escrito y tiene 30 días para expedirse. Entrega a la cámara un informe con su dictamen a favor o en contra de continuar con la acusación.', practicalEffects: [], examples: ['Si la Comisión concluye que los hechos no justifican la acusación, su dictamen negativo le llega a Diputados para que vote si igualmente continúa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'Comisión de Investigación', 'dictamen', 'treinta días'], order: 142, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-144', lawId: 'const-entre-rios', number: '144', title: 'Votación de la acusación en Diputados', originalText: `La cámara decidirá sin más trámite si se acepta o no el dictamen de la Comisión de Investigación, necesitando para aceptarlo dos tercios de votos de la totalidad de sus miembros, cuando el dictamen fuera favorable a la acusación. El quórum para esta sesión se compondrá de tres cuartos de los miembros de la cámara. En todo el trámite de juicio político no se admitirá la recusación de los integrantes de ninguna de las cámaras intervinientes.`, currentText: `La cámara decidirá sin más trámite si se acepta o no el dictamen de la Comisión de Investigación, necesitando para aceptarlo dos tercios de votos de la totalidad de sus miembros, cuando el dictamen fuera favorable a la acusación. El quórum para esta sesión se compondrá de tres cuartos de los miembros de la cámara. En todo el trámite de juicio político no se admitirá la recusación de los integrantes de ninguna de las cámaras intervinientes.`, plainLanguageExplanation: 'Para aceptar el dictamen que recomienda acusar se necesitan dos tercios del total de diputados (no solo de los presentes). La sesión requiere tres cuartos de los miembros. Ningún legislador puede ser recusado en este proceso.', practicalEffects: [], examples: ['Con 34 diputados, se necesitan 23 votos (dos tercios) para aceptar la acusación, y la sesión requiere 26 presentes (tres cuartos).'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'dos tercios', 'tres cuartos', 'acusación', 'quórum'], order: 143, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-145', lawId: 'const-entre-rios', number: '145', title: 'Suspensión automática al aceptarse la acusación', originalText: `Desde el momento en que la cámara haya aceptado la acusación contra un funcionario público, éste quedará de hecho suspendido en el ejercicio de sus funciones, gozando de medio sueldo.`, currentText: `Desde el momento en que la cámara haya aceptado la acusación contra un funcionario público, éste quedará de hecho suspendido en el ejercicio de sus funciones, gozando de medio sueldo.`, plainLanguageExplanation: 'En cuanto Diputados acepta la acusación, el funcionario queda automáticamente suspendido, con derecho a cobrar la mitad de su sueldo mientras dure el juicio.', practicalEffects: [], examples: ['El gobernador acusado deja de ejercer la gobernación desde que Diputados acepta la acusación, aunque todavía no fue condenado por el Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensión', 'juicio político', 'medio sueldo', 'acusación aceptada'], order: 144, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-146', lawId: 'const-entre-rios', number: '146', title: 'Comisión acusadora ante el Senado', originalText: `Admitida la acusación por la Cámara de Diputados, nombrará ésta una comisión de cinco de sus miembros para que la sostenga ante la Cámara de Senadores, juez de la causa, a la cual le será comunicado dicho nombramiento y la aceptación de la acusación.`, currentText: `Admitida la acusación por la Cámara de Diputados, nombrará ésta una comisión de cinco de sus miembros para que la sostenga ante la Cámara de Senadores, juez de la causa, a la cual le será comunicado dicho nombramiento y la aceptación de la acusación.`, plainLanguageExplanation: 'Diputados designa cinco de sus miembros para defender la acusación ante el Senado, que actúa como tribunal del juicio político.', practicalEffects: [], examples: ['Cinco diputados elegidos por la cámara presentan y sostienen los cargos contra el funcionario acusado durante el juicio ante el Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'comisión acusadora', 'Senado', 'Cámara de Diputados'], order: 145, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-147', lawId: 'const-entre-rios', number: '147', title: 'El Senado como Corte de Justicia', originalText: `El Senado se constituirá en Corte de Justicia, prestando cada uno de sus miembros un juramento especial de fallar conforme a los dictados de su conciencia.`, currentText: `El Senado se constituirá en Corte de Justicia, prestando cada uno de sus miembros un juramento especial de fallar conforme a los dictados de su conciencia.`, plainLanguageExplanation: 'Al juzgar, el Senado se transforma en tribunal especial; cada senador jura decidir según su conciencia, sin sujeción a mandato partidario.', practicalEffects: [], examples: ['Antes de votar la condena o absolución, cada senador presta juramento de fallar con imparcialidad y conforme a su conciencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Senado', 'Corte de Justicia', 'juicio político', 'juramento'], order: 146, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-148', lawId: 'const-entre-rios', number: '148', title: 'Presidencia del Senado en juicio político', originalText: `El Senado constituido en Corte de Justicia será presidido por el Presidente del Superior Tribunal de Justicia, o por su suplente legal, cuando el acusado sea el gobernador, el vicegobernador o un ministro del Poder Ejecutivo, y por el vicepresidente primero del Senado o por el vicepresidente segundo en su defecto, cuando el acusado sea un miembro del Poder Judicial.`, currentText: `El Senado constituido en Corte de Justicia será presidido por el Presidente del Superior Tribunal de Justicia, o por su suplente legal, cuando el acusado sea el gobernador, el vicegobernador o un ministro del Poder Ejecutivo, y por el vicepresidente primero del Senado o por el vicepresidente segundo en su defecto, cuando el acusado sea un miembro del Poder Judicial.`, plainLanguageExplanation: 'Cuando el acusado es del Ejecutivo, preside el presidente del Superior Tribunal; cuando es un juez, preside el vicepresidente primero del Senado. Esto evita conflictos de interés.', practicalEffects: [], examples: ['Si se juzga al gobernador, el Senado es presidido por el titular del Superior Tribunal; si se juzga a un magistrado judicial, lo preside el vice primero del Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'presidencia', 'Superior Tribunal', 'vicepresidente del Senado'], order: 147, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-149', lawId: 'const-entre-rios', number: '149', title: 'Procedimiento ante el Senado en juicio político', originalText: `Ante el Senado los términos serán fijos y perentorios, el proceso verbal y la sentencia por votación nominal, todo ello de conformidad a lo que la ley de la materia establezca.`, currentText: `Ante el Senado los términos serán fijos y perentorios, el proceso verbal y la sentencia por votación nominal, todo ello de conformidad a lo que la ley de la materia establezca.`, plainLanguageExplanation: 'El juicio en el Senado tiene plazos estrictos, es oral y la sentencia se decide con votación pública (cada senador vota por sí o por no en voz alta).', practicalEffects: [], examples: ['Cuando el Senado vota la condena, cada senador dice en voz alta su voto; queda registrado públicamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'términos perentorios', 'votación nominal', 'proceso verbal'], order: 148, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-150', lawId: 'const-entre-rios', number: '150', title: 'Quórum y mayoría para condena — plazo de 90 días', originalText: `El Senado no podrá funcionar como Corte de Justicia con menos de los dos tercios de la totalidad de sus miembros, ni pronunciar sentencia condenatoria, sino por la mayoría de los votos de esa misma totalidad. Deberá reunirse para tratar la acusación a los cinco días de presentada ésta y finalizar el juicio dentro del perentorio término de noventa días.`, currentText: `El Senado no podrá funcionar como Corte de Justicia con menos de los dos tercios de la totalidad de sus miembros, ni pronunciar sentencia condenatoria, sino por la mayoría de los votos de esa misma totalidad. Deberá reunirse para tratar la acusación a los cinco días de presentada ésta y finalizar el juicio dentro del perentorio término de noventa días.`, plainLanguageExplanation: 'El Senado necesita dos tercios de sus miembros para sesionar como tribunal, y mayoría absoluta del total para condenar. Tiene 5 días para comenzar y 90 días para terminar el juicio.', practicalEffects: [], examples: ['Con 17 senadores, se necesitan 12 para sesionar (dos tercios) y 9 para condenar (mayoría del total). El juicio debe concluir en 90 días.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'quórum', 'mayoría', 'noventa días', 'condena'], order: 149, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-151', lawId: 'const-entre-rios', number: '151', title: 'Penas en el juicio político', originalText: `La pena en el juicio político deberá concretarse a la separación del funcionario acusado, y aun a la inhabilitación para ejercer cargos públicos por tiempo determinado. Pero cuando del proceso resulte constatado un crimen o delito común, el reo será entregado a la justicia ordinaria con todos los antecedentes de su causa, para que le aplique la pena respectiva.`, currentText: `La pena en el juicio político deberá concretarse a la separación del funcionario acusado, y aun a la inhabilitación para ejercer cargos públicos por tiempo determinado. Pero cuando del proceso resulte constatado un crimen o delito común, el reo será entregado a la justicia ordinaria con todos los antecedentes de su causa, para que le aplique la pena respectiva.`, plainLanguageExplanation: 'El juicio político solo puede destituir e inhabilitar; no aplica penas penales. Si además se constata un delito penal, el caso pasa a la justicia ordinaria para la pena correspondiente.', practicalEffects: [], examples: ['Un gobernador condenado en juicio político pierde su cargo y puede quedar inhabilitado para ejercer funciones públicas; si además cometió malversación, el caso va a la justicia penal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'destitución', 'inhabilitación', 'justicia ordinaria'], order: 150, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-152', lawId: 'const-entre-rios', number: '152', title: 'Vencimiento del plazo — presunción de inocencia y garantías', originalText: `Vencido el término legal sin que medie un pronunciamiento del Senado, tal omisión crea una presunción, que no admite prueba en contrario, en favor de la inocencia del acusado, quien se reintegrará a la posesión de su cargo, sin que se le pueda oponer los efectos de una condena dictada con posterioridad. En toda la tramitación del juicio político se deberá asegurar el derecho de defensa, con asistencia letrada. El fallo que disponga la separación del funcionario deberá motivarse por escrito. El voto favorable a la propuesta, importará la adhesión a sus fundamentos, salvo que el legislador haya expresado las razones que sustenten su posición. Cada hecho motivo de acusación será votado separadamente.`, currentText: `Vencido el término legal sin que medie un pronunciamiento del Senado, tal omisión crea una presunción, que no admite prueba en contrario, en favor de la inocencia del acusado, quien se reintegrará a la posesión de su cargo, sin que se le pueda oponer los efectos de una condena dictada con posterioridad. En toda la tramitación del juicio político se deberá asegurar el derecho de defensa, con asistencia letrada. El fallo que disponga la separación del funcionario deberá motivarse por escrito. El voto favorable a la propuesta, importará la adhesión a sus fundamentos, salvo que el legislador haya expresado las razones que sustenten su posición. Cada hecho motivo de acusación será votado separadamente.`, plainLanguageExplanation: 'Si el Senado no se pronuncia en 90 días, el funcionario queda absuelto por presunción irrefutable y retoma su cargo. Todo juicio político debe garantizar defensa letrada, fallo fundado por escrito y votación separada por cada hecho imputado.', practicalEffects: [], examples: ['Si el Senado no dicta sentencia en 90 días, el gobernador suspendido retoma el cargo automáticamente, sin posibilidad de condenarle luego por los mismos hechos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'presunción de inocencia', 'vencimiento de plazo', 'derecho de defensa', 'fallo fundado'], order: 151, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-153', lawId: 'const-entre-rios', number: '153', title: 'Absolución — reintegro al cargo y cobro de sueldo', originalText: `Siendo absuelto el funcionario acusado, reasumirá inmediatamente las funciones de su cargo, debiendo en tal caso, como en el previsto por el artículo anterior, integrársele su sueldo por el tiempo de suspensión.`, currentText: `Siendo absuelto el funcionario acusado, reasumirá inmediatamente las funciones de su cargo, debiendo en tal caso, como en el previsto por el artículo anterior, integrársele su sueldo por el tiempo de suspensión.`, plainLanguageExplanation: 'Si el funcionario es absuelto, vuelve inmediatamente a su cargo y se le paga el medio sueldo que no cobró durante la suspensión.', practicalEffects: [], examples: ['Un ministro absuelto retoma su cartera al día siguiente y recibe el pago retroactivo del sueldo retenido durante el juicio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['absolución', 'juicio político', 'reintegro', 'sueldo'], order: 152, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-154', lawId: 'const-entre-rios', number: '154', title: 'Publicación de la sentencia del Senado', originalText: `Cualquiera que sea la sentencia del Senado, será inmediatamente publicada.`, currentText: `Cualquiera que sea la sentencia del Senado, será inmediatamente publicada.`, plainLanguageExplanation: 'La sentencia del Senado en juicio político — condena o absolución — debe publicarse de inmediato para garantizar la transparencia del proceso.', practicalEffects: [], examples: ['Tanto si el Senado condena como si absuelve al funcionario, la resolución se publica en el Boletín Oficial provincial de inmediato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sentencia', 'juicio político', 'publicación', 'transparencia'], order: 153, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-155', lawId: 'const-entre-rios', number: '155', title: 'Poder Ejecutivo — gobernador y vicegobernador', originalText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de gobernador de la Provincia. Al mismo tiempo y por el mismo período que se elige aquél, se nombrará un vicegobernador.`, currentText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de gobernador de la Provincia. Al mismo tiempo y por el mismo período que se elige aquél, se nombrará un vicegobernador.`, plainLanguageExplanation: 'El Poder Ejecutivo provincial lo ejerce el gobernador; junto con él se elige siempre un vicegobernador por el mismo período.', practicalEffects: [], examples: ['En las elecciones provinciales se vota una fórmula completa: gobernador y vicegobernador.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Ejecutivo', 'gobernador', 'vicegobernador'], order: 154, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-156', lawId: 'const-entre-rios', number: '156', title: 'Requisitos para gobernador y vicegobernador', originalText: `Para ser elegido gobernador o vicegobernador, se requiere: 1º. Tener treinta años de edad. 2º. Ser ciudadano natural o hijo de argentino que haya optado por la ciudadanía de sus padres. 3º. Estar domiciliado en la Provincia, el ciudadano no nacido en ésta, cuando menos dos años inmediatos a la elección, a no ser que la ausencia hubiese sido por servicios de la Nación o de la Provincia.`, currentText: `Para ser elegido gobernador o vicegobernador, se requiere: 1º. Tener treinta años de edad. 2º. Ser ciudadano natural o hijo de argentino que haya optado por la ciudadanía de sus padres. 3º. Estar domiciliado en la Provincia, el ciudadano no nacido en ésta, cuando menos dos años inmediatos a la elección, a no ser que la ausencia hubiese sido por servicios de la Nación o de la Provincia.`, plainLanguageExplanation: 'Para ser gobernador o vicegobernador: 30 años de edad, ser argentino nativo o hijo de argentino naturalizado, y residir en la Provincia al menos dos años previos (salvo ausencia por servicio público).', practicalEffects: [], examples: ['Un argentino de 29 años que vive en Entre Ríos no puede postularse hasta cumplir 30.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'vicegobernador', 'requisitos', 'edad', 'domicilio'], order: 155, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-157', lawId: 'const-entre-rios', number: '157', title: 'Duración del mandato del gobernador', originalText: `El gobernador y vicegobernador durarán cuatro años en el ejercicio de sus funciones y cesarán en ellas el mismo día que expire el período legal, sin que evento alguno pueda ser motivo para su prorrogación por un día más, ni tampoco para que se le complete más tarde, cuando el período haya sido interrumpido.`, currentText: `El gobernador y vicegobernador durarán cuatro años en el ejercicio de sus funciones y cesarán en ellas el mismo día que expire el período legal, sin que evento alguno pueda ser motivo para su prorrogación por un día más, ni tampoco para que se le complete más tarde, cuando el período haya sido interrumpido.`, plainLanguageExplanation: 'El mandato es de exactamente cuatro años; no puede extenderse ni un día ni completarse si fue interrumpido. El período finaliza en la fecha prevista, sin excepciones.', practicalEffects: [], examples: ['Si una crisis política interrumpe el mandato, al reincorporarse el gobernador no recupera el tiempo perdido; el período termina igual el día fijado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'cuatro años', 'gobernador', 'plazo improrrogable'], order: 156, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-158', lawId: 'const-entre-rios', number: '158', title: 'Acefalía del gobernador — orden de sucesión', originalText: `En caso de acefalía del cargo de gobernador, sus funciones serán desempeñadas por el vicegobernador, que las ejercerá durante el resto del período constitucional. Cuando se trate de un impedimento temporal, hasta que cese dicho impedimento. En caso de impedimento temporal del vicegobernador, éste será reemplazado por el vicepresidente primero del Senado, presidente de la Cámara de Diputados o presidente del Superior Tribunal de Justicia, por su orden.`, currentText: `En caso de acefalía del cargo de gobernador, sus funciones serán desempeñadas por el vicegobernador, que las ejercerá durante el resto del período constitucional. Cuando se trate de un impedimento temporal, hasta que cese dicho impedimento. En caso de impedimento temporal del vicegobernador, éste será reemplazado por el vicepresidente primero del Senado, presidente de la Cámara de Diputados o presidente del Superior Tribunal de Justicia, por su orden.`, plainLanguageExplanation: 'Si el gobernador queda vacante, el vicegobernador asume por el resto del período. Si es una ausencia temporal, hasta que regrese. Si el vicegobernador también está impedido, lo reemplaza el vice primero del Senado, luego el presidente de Diputados, y luego el presidente del Superior Tribunal.', practicalEffects: [], examples: ['Si el gobernador renuncia, el vicegobernador asume la gobernación hasta el final del mandato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía', 'gobernador', 'sucesión', 'vicegobernador', 'impedimento'], order: 157, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-159', lawId: 'const-entre-rios', number: '159', title: 'Acefalía simultánea de gobernador y vicegobernador', originalText: `En caso de acefalía simultánea del gobernador y vicegobernador, el Poder Ejecutivo, será ejercido por el vicepresidente primero del Senado y, en defecto de éste, por el presidente de la Cámara de Diputados y, en el de ambos, por el presidente del Superior Tribunal de Justicia, quienes convocarán a elección para reemplazarlos dentro de tres días, siempre que faltaran más de dos años para terminar el período constitucional. Si faltara menos de dos años, aquellos funcionarios asumirán el Poder Ejecutivo interinamente y la Legislatura, reunida en Asamblea, por mayoría absoluta de los presentes, designará gobernador y vicegobernador, pudiendo ser electo un miembro de la Legislatura o cualquier ciudadano que reúna las condiciones del artículo 156. A este objeto, la Asamblea deberá ser citada especialmente por su presidente en ejercicio con anticipación de cinco días por lo menos y para un plazo no mayor de diez días. En ambos casos, la elección se hará para completar el período constitucional y no podrá recaer en la persona que ejerce el Poder Ejecutivo.`, currentText: `En caso de acefalía simultánea del gobernador y vicegobernador, el Poder Ejecutivo, será ejercido por el vicepresidente primero del Senado y, en defecto de éste, por el presidente de la Cámara de Diputados y, en el de ambos, por el presidente del Superior Tribunal de Justicia, quienes convocarán a elección para reemplazarlos dentro de tres días, siempre que faltaran más de dos años para terminar el período constitucional. Si faltara menos de dos años, aquellos funcionarios asumirán el Poder Ejecutivo interinamente y la Legislatura, reunida en Asamblea, por mayoría absoluta de los presentes, designará gobernador y vicegobernador, pudiendo ser electo un miembro de la Legislatura o cualquier ciudadano que reúna las condiciones del artículo 156. A este objeto, la Asamblea deberá ser citada especialmente por su presidente en ejercicio con anticipación de cinco días por lo menos y para un plazo no mayor de diez días. En ambos casos, la elección se hará para completar el período constitucional y no podrá recaer en la persona que ejerce el Poder Ejecutivo.`, plainLanguageExplanation: 'Si faltan tanto el gobernador como el vicegobernador: si queda más de 2 años de mandato, el interino convoca elecciones en 3 días; si queda menos de 2 años, la Asamblea Legislativa elige gobernador y vicegobernador por mayoría absoluta.', practicalEffects: [], examples: ['Si el gobernador y vicegobernador renuncian con 3 años de mandato por cumplir, el vice primero del Senado convoca elecciones en 3 días.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía', 'gobernador', 'vicegobernador', 'elección', 'Asamblea Legislativa'], order: 158, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-160', lawId: 'const-entre-rios', number: '160', title: 'Elección abreviada en caso de acefalía total', originalText: `En el primer caso del artículo anterior, la elección se practicará reduciendo a la mitad de los términos del proceso eleccionario, con excepción del plazo de la convocatoria, y los electos tomarán posesión de sus cargos dentro de los quince días de verificado el escrutinio y hecha la proclamación.`, currentText: `En el primer caso del artículo anterior, la elección se practicará reduciendo a la mitad de los términos del proceso eleccionario, con excepción del plazo de la convocatoria, y los electos tomarán posesión de sus cargos dentro de los quince días de verificado el escrutinio y hecha la proclamación.`, plainLanguageExplanation: 'Cuando se llama a elecciones por acefalía total (más de 2 años de mandato restante), los plazos del proceso electoral se reducen a la mitad. Los nuevos electos asumen en 15 días.', practicalEffects: [], examples: ['Si normalmente el proceso electoral dura 60 días, en caso de acefalía se hace en 30; los ganadores asumen a los 15 días del escrutinio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía', 'elección abreviada', 'proceso electoral'], order: 159, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-161', lawId: 'const-entre-rios', number: '161', title: 'Reelección del gobernador y vicegobernador', originalText: `El gobernador y el vicegobernador podrán ser reelectos o sucederse recíprocamente solamente por un período en forma consecutiva o alternada.`, currentText: `El gobernador y el vicegobernador podrán ser reelectos o sucederse recíprocamente solamente por un período en forma consecutiva o alternada.`, plainLanguageExplanation: 'El gobernador y vicegobernador pueden ser reelegidos o intercambiar cargos solo una vez (un período adicional), ya sea de forma consecutiva o luego de un intermedio.', practicalEffects: [], examples: ['Un gobernador que completó su primer mandato puede ser reelecto por un segundo; terminado éste no puede volver a ser gobernador hasta que transcurra otro período completo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reelección', 'gobernador', 'vicegobernador', 'límite de mandatos'], order: 160, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-162', lawId: 'const-entre-rios', number: '162', title: 'Tratamiento oficial del gobernador y vicegobernador', originalText: `El tratamiento oficial del gobernador y del vicegobernador será el de "Señor gobernador" y "Señor vicegobernador".`, currentText: `El tratamiento oficial del gobernador y del vicegobernador será el de "Señor gobernador" y "Señor vicegobernador".`, plainLanguageExplanation: 'El protocolo establece que se debe dirigir al gobernador como "Señor gobernador" y al vicegobernador como "Señor vicegobernador".', practicalEffects: [], examples: ['En actos oficiales, los documentos y discursos deben usar el tratamiento constitucional establecido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'tratamiento oficial', 'protocolo'], order: 161, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-163', lawId: 'const-entre-rios', number: '163', title: 'Residencia y ausencias del gobernador', originalText: `El gobernador y el vicegobernador en ejercicio de sus funciones, residirán en la capital y no podrán ausentarse del territorio de la Provincia sin permiso de la Legislatura, o de la capital por más de quince días. En el receso de las cámaras, solo podrán ausentarse por un motivo urgente y por el tiempo indispensable, dando cuenta a aquéllas oportunamente.`, currentText: `El gobernador y el vicegobernador en ejercicio de sus funciones, residirán en la capital y no podrán ausentarse del territorio de la Provincia sin permiso de la Legislatura, o de la capital por más de quince días. En el receso de las cámaras, solo podrán ausentarse por un motivo urgente y por el tiempo indispensable, dando cuenta a aquéllas oportunamente.`, plainLanguageExplanation: 'El gobernador y vicegobernador deben residir en la capital y no pueden irse de la Provincia sin autorización legislativa, ni de la capital por más de 15 días. En el receso solo salen por urgencia.', practicalEffects: [], examples: ['Para viajar al exterior en misión oficial, el gobernador debe obtener permiso de la Legislatura.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'residencia', 'ausencia', 'permiso legislativo'], order: 162, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-164', lawId: 'const-entre-rios', number: '164', title: 'Juramento del gobernador y vicegobernador', originalText: `Al tomar posesión del cargo el gobernador y vicegobernador prestarán juramento por la Patria y sus creencias o principios, ante el presidente de la Asamblea Legislativa, en los términos siguientes: "Yo, N. N., juro por la Patria y ... cumplir y hacer cumplir la Constitución Nacional y la de la Provincia y desempeñar con lealtad y honradez el cargo de gobernador (o vicegobernador). Si así no lo hiciera, la Patria y... me lo demanden".`, currentText: `Al tomar posesión del cargo el gobernador y vicegobernador prestarán juramento por la Patria y sus creencias o principios, ante el presidente de la Asamblea Legislativa, en los términos siguientes: "Yo, N. N., juro por la Patria y ... cumplir y hacer cumplir la Constitución Nacional y la de la Provincia y desempeñar con lealtad y honradez el cargo de gobernador (o vicegobernador). Si así no lo hiciera, la Patria y... me lo demanden".`, plainLanguageExplanation: 'Al asumir, el gobernador y vicegobernador juran ante la Asamblea Legislativa cumplir la Constitución y ejercer el cargo con lealtad. La fórmula puede adaptarse a las creencias del funcionario.', practicalEffects: [], examples: ['El día de la asunción, el gobernador electo presta el juramento constitucional ante la Asamblea Legislativa reunida.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'gobernador', 'vicegobernador', 'Asamblea Legislativa'], order: 163, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-165', lawId: 'const-entre-rios', number: '165', title: 'Remuneración e incompatibilidades del gobernador', originalText: `Los servicios del gobernador y del vicegobernador serán remunerados por el tesoro de la Provincia y esta remuneración no podrá ser alterada en el período de su nombramiento. Durante éste, no podrán ejercer otro empleo ni recibir otro emolumento de la Nación o de la Provincia. El sueldo del gobernador y del vicegobernador será fijado por la ley.`, currentText: `Los servicios del gobernador y del vicegobernador serán remunerados por el tesoro de la Provincia y esta remuneración no podrá ser alterada en el período de su nombramiento. Durante éste, no podrán ejercer otro empleo ni recibir otro emolumento de la Nación o de la Provincia. El sueldo del gobernador y del vicegobernador será fijado por la ley.`, plainLanguageExplanation: 'El gobernador y vicegobernador cobran un sueldo fijo por ley que no puede cambiarse durante su mandato, y no pueden tener otro empleo ni cobrar otro ingreso público.', practicalEffects: [], examples: ['Si el gobernador es también profesor universitario, debe licenciarse sin goce de sueldo de esa función mientras ejerza la gobernación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración', 'incompatibilidad', 'gobernador', 'sueldo', 'intangibilidad'], order: 164, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-166', lawId: 'const-entre-rios', number: '166', title: 'Posesión del cargo — plazo y renuncia tácita', originalText: `El gobernador y vicegobernador deberán recibirse el día designado por la ley, considerándose dimitentes si no lo hicieran. En caso de encontrarse fuera de la República, o de mediar impedimento legal, podrán hacerlo hasta seis meses después.`, currentText: `El gobernador y vicegobernador deberán recibirse el día designado por la ley, considerándose dimitentes si no lo hicieran. En caso de encontrarse fuera de la República, o de mediar impedimento legal, podrán hacerlo hasta seis meses después.`, plainLanguageExplanation: 'Si el gobernador electo no asume en la fecha prevista sin justificación válida, se considera que renunció. Solo si está en el exterior o hay impedimento legal puede hacerlo hasta 6 meses después.', practicalEffects: [], examples: ['Un gobernador electo que no aparece el día de la asunción sin haber comunicado un impedimento legal pierde el cargo por renuncia tácita.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'posesión del cargo', 'renuncia tácita', 'asunción'], order: 165, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-167', lawId: 'const-entre-rios', number: '167', title: 'Ministros secretarios de Estado', originalText: `El despacho de los asuntos administrativos de la Provincia estará a cargo de ministros secretarios. Una ley especial, cuya iniciativa corresponde al Poder Ejecutivo, fijará el número de ellos y deslindará las ramas, competencias y las funciones adscriptas a cada uno de los ministros.`, currentText: `El despacho de los asuntos administrativos de la Provincia estará a cargo de ministros secretarios. Una ley especial, cuya iniciativa corresponde al Poder Ejecutivo, fijará el número de ellos y deslindará las ramas, competencias y las funciones adscriptas a cada uno de los ministros.`, plainLanguageExplanation: 'Los ministros gestionan la administración provincial. Su número y competencias se fijan por ley, cuya iniciativa corresponde al gobernador.', practicalEffects: [], examples: ['El número de ministerios y sus competencias se definen por ley; si el gobernador quiere crear un nuevo ministerio, debe enviar el proyecto a la Legislatura.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ministros', 'Poder Ejecutivo', 'administración provincial'], order: 166, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-168', lawId: 'const-entre-rios', number: '168', title: 'Requisitos para ser ministro', originalText: `Para ser nombrado ministro se requiere ser ciudadano argentino y tener veinticinco años de edad.`, currentText: `Para ser nombrado ministro se requiere ser ciudadano argentino y tener veinticinco años de edad.`, plainLanguageExplanation: 'Para ser ministro del Ejecutivo provincial basta con ser argentino y tener 25 años; no se exige residencia especial ni título profesional.', practicalEffects: [], examples: ['Un argentino de 25 años puede ser designado ministro aunque no sea entrerriano ni tenga título universitario.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ministro', 'requisitos', 'ciudadanía', 'edad'], order: 167, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-169', lawId: 'const-entre-rios', number: '169', title: 'Refrendo ministerial de los actos del gobernador', originalText: `Los ministros secretarios despacharán de acuerdo con el gobernador y refrendarán con sus firmas las resoluciones de éste, sin cuyo requisito no tendrán efecto, ni se les dará cumplimiento. Podrán, no obstante, expedirse por sí solos en todo lo referente al régimen interno de sus respectivos departamentos y dictar resoluciones de trámite.`, currentText: `Los ministros secretarios despacharán de acuerdo con el gobernador y refrendarán con sus firmas las resoluciones de éste, sin cuyo requisito no tendrán efecto, ni se les dará cumplimiento. Podrán, no obstante, expedirse por sí solos en todo lo referente al régimen interno de sus respectivos departamentos y dictar resoluciones de trámite.`, plainLanguageExplanation: 'Todo decreto del gobernador debe llevar la firma del ministro del área para ser válido. Los ministros también pueden dictar resoluciones propias sobre asuntos internos de su ministerio.', practicalEffects: [], examples: ['Un decreto que no lleva la firma del ministro correspondiente es nulo y los organismos no deben cumplirlo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['refrendo', 'ministros', 'decreto', 'validez', 'resolución'], order: 168, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-170', lawId: 'const-entre-rios', number: '170', title: 'Responsabilidad personal de los ministros', originalText: `Serán responsables de todas las órdenes y resoluciones que autoricen, sin que puedan pretender eximirse de responsabilidad por haber procedido en virtud de orden del gobernador.`, currentText: `Serán responsables de todas las órdenes y resoluciones que autoricen, sin que puedan pretender eximirse de responsabilidad por haber procedido en virtud de orden del gobernador.`, plainLanguageExplanation: 'Los ministros son personalmente responsables de los actos que firman. No pueden alegar que "lo ordenó el gobernador" para eludir su responsabilidad.', practicalEffects: [], examples: ['Un ministro que firma un decreto ilegal no puede excusarse diciendo que fue el gobernador quien lo ordenó; responde personalmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad ministerial', 'ministros', 'ordenes del gobernador'], order: 169, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-171', lawId: 'const-entre-rios', number: '171', title: 'Asistencia de ministros a las cámaras', originalText: `Los ministros deben asistir a las sesiones de las cámaras cuando fueren llamados por ellas; pueden también hacerlo cuando lo crean conveniente y tomar parte en sus discusiones, pero no tendrán voto.`, currentText: `Los ministros deben asistir a las sesiones de las cámaras cuando fueren llamados por ellas; pueden también hacerlo cuando lo crean conveniente y tomar parte en sus discusiones, pero no tendrán voto.`, plainLanguageExplanation: 'Los ministros tienen obligación de concurrir cuando la Legislatura los cita y pueden asistir voluntariamente para defender su gestión, pero no pueden votar.', practicalEffects: [], examples: ['La Cámara de Senadores puede citar al Ministro de Economía para que explique el presupuesto; el ministro debe asistir y puede participar del debate pero no votar.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ministros', 'Legislatura', 'asistencia', 'sin voto', 'control legislativo'], order: 170, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-172', lawId: 'const-entre-rios', number: '172', title: 'Memoria anual de los ministros', originalText: `En el octavo mes de sesiones ordinarias de la Legislatura, los ministros le presentarán la memoria detallada del estado de la administración de su respectivo departamento, indicando en ella las reformas que más aconseje la experiencia.`, currentText: `En el octavo mes de sesiones ordinarias de la Legislatura, los ministros le presentarán la memoria detallada del estado de la administración de su respectivo departamento, indicando en ella las reformas que más aconseje la experiencia.`, plainLanguageExplanation: 'Cada ministro debe presentar ante la Legislatura un informe anual detallado sobre su ministerio y proponer las reformas que considere necesarias.', practicalEffects: [], examples: ['En octubre (octavo mes), el Ministro de Educación presenta su memoria con estadísticas de matrícula, presupuesto ejecutado y reformas propuestas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['memoria ministerial', 'informe anual', 'Legislatura', 'ministros'], order: 171, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-173', lawId: 'const-entre-rios', number: '173', title: 'Tratamiento y remuneración de los ministros', originalText: `Los ministros tendrán el tratamiento oficial de "Señor ministro" y gozarán por sus servicios de un sueldo establecido por la ley, que no podrá ser alterado durante el tiempo que desempeñen sus funciones.`, currentText: `Los ministros tendrán el tratamiento oficial de "Señor ministro" y gozarán por sus servicios de un sueldo establecido por la ley, que no podrá ser alterado durante el tiempo que desempeñen sus funciones.`, plainLanguageExplanation: 'Los ministros son llamados "Señor ministro" y cobran una remuneración fijada por ley que no puede modificarse mientras estén en funciones.', practicalEffects: [], examples: ['Si la Legislatura sanciona un aumento de sueldos ministeriales durante el año, no puede aplicarse a los ministros que ya están en ejercicio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ministros', 'tratamiento', 'sueldo', 'intangibilidad'], order: 172, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-174', lawId: 'const-entre-rios', number: '174', title: 'El gobernador como Jefe del Estado provincial', originalText: `El gobernador es el Jefe del Estado.`, currentText: `El gobernador es el Jefe del Estado.`, plainLanguageExplanation: 'El gobernador es la máxima autoridad del Estado provincial y ejercer la jefatura de la administración pública de Entre Ríos.', practicalEffects: [], examples: ['En actos protocolares, el gobernador representa al Estado provincial frente a autoridades nacionales y extranjeras.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'Jefe del Estado', 'Poder Ejecutivo'], order: 173, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-175', lawId: 'const-entre-rios', number: '175', title: 'Atribuciones y deberes del Poder Ejecutivo', originalText: `Son atribuciones y deberes del Poder Ejecutivo: 1º. Participar de la formación de las leyes, con arreglo a esta Constitución, iniciándolas por medio de proyectos, proponiendo la derogación o modificación de las existentes o concurriendo a las discusiones de la Legislatura por medio de sus ministros. 2º. Promulgar y hacer ejecutar las leyes de la Provincia facilitando su cumplimiento por reglamentos y disposiciones especiales que no alteren su espíritu. 3º. Vetar las sanciones de la Legislatura, expresando en detalle los fundamentos del veto. 4º. Indultar o conmutar las penas impuestas, dentro de la jurisdicción provincial, previo informe favorable del Superior Tribunal, excepto en los casos de delitos electorales y con respecto a los funcionarios sometidos al procedimiento del juicio político o del jurado de enjuiciamiento. 5º. Representar a la Provincia en las relaciones oficiales con el Poder Ejecutivo nacional y demás gobernadores de Provincia. 6º. Celebrar y firmar tratados parciales con otras provincias para fines de administración de justicia, de intereses económicos y trabajos de utilidad común, sometiéndolos a la Legislatura para su aprobación, y oportunamente, al Congreso de la Nación, conforme al artículo 125 de la Constitución Nacional. 7º. Instruir a las cámaras con un mensaje, a la apertura de sus sesiones, sobre el estado general de la administración. 8º. Presentar dentro de los ocho meses de sesiones ordinarias de las cámaras, el proyecto de ley de presupuesto general de la administración y de las reparticiones autárquicas, acompañado del plan de recursos, el que no podrá exceder del mayor ingreso anual del último quinquenio, salvo en lo calculado por nuevos impuestos o aumentos de tasas. Dicho plazo se considerará improrrogable. 9º. Dar cuenta a la Legislatura, dentro de los ocho meses de sus sesiones ordinarias, del uso y ejercicio del presupuesto anterior. 10º. Decretar la inversión de la renta con arreglo a las leyes, debiendo hacer público mensualmente el estado de la tesorería. 11º. Hacer recaudar los impuestos y rentas de la Provincia debiendo los funcionarios encargados de la recaudación ejecutar administrativamente el pago en la forma que determine la ley, quedando libre al contribuyente su acción de ocurrir a los Tribunales para la decisión del caso, previa constancia de haber pagado. 12º. Prorrogar las sesiones ordinarias de las cámaras. 13º. Convocar a sesiones extraordinarias a la Legislatura, especificando el objeto o determinando los asuntos comprendidos en la convocatoria. 14º. Expedir las órdenes convenientes para toda elección popular en la oportunidad debida y sin poder por motivo alguno diferirlas sin acuerdo de las cámaras, salvo lo dispuesto en el artículo 88. 15º. Nombrar a los ministros secretarios y demás empleados de la administración, cuyo nombramiento no esté acordado a otro poder. Expedir títulos y despachos a los que nombre. 16º. Nombrar, con acuerdo del Senado, los miembros del Superior Tribunal de Justicia, los titulares del Ministerio Público Fiscal y de la Defensa, fiscal de Estado, contador general, tesorero general, miembros del Tribunal de Cuentas, director general de escuelas, vocales del Consejo General de Educación y los demás funcionarios para los cuales la ley establezca esta forma de nombramiento. Someter al acuerdo del Senado la propuesta para la designación de los restantes magistrados y funcionarios de los Ministerios Públicos, escogidos de una terna vinculante que, previo concurso público, le remitirá el Consejo de la Magistratura. Obtenido el mismo, proceder al nombramiento respectivo. 17º. Exonerar a los ministros secretarios de Estado y, en la forma que determine la ley respectiva, a los demás funcionarios y empleados cuyos nombramientos le esté atribuido, con excepción de los sujetos a juicio político y al jurado de enjuiciamiento. 18º. Nombrar a los jueces de paz, a propuesta en terna de los municipios o comunas del lugar de asiento del mismo. 19º. Prestar el auxilio de la fuerza pública a los Tribunales de Justicia, a los presidentes de las cámaras legislativas, a los municipios de la Provincia y demás autoridades, conforme a la ley y cuando lo soliciten. 20º. Tomar las medidas necesarias para conservar la paz y el orden público, por todos los medios que no estén expresamente prohibidos por esta Constitución y leyes vigentes. 21º. Ejercer la policía de la Provincia y la vigilancia e inspección de los establecimientos públicos de la misma. 22º. Ejercer inspección sobre las oficinas del registro del estado civil de las personas, exigiendo y promoviendo la corrección inmediata de las irregularidades y deficiencias que se noten. 23º. Conceder jubilaciones y pensiones conforme a la ley de la materia. Esta función es irrenunciable y deberá ejercerse por la Caja de Jubilaciones y Pensiones, que es el ente autárquico provincial encargado de atender el sistema previsional, a efectos de emitir el acto administrativo. 24º. Conocer y resolver originaria o recursivamente, por sí o con intervención de la autoridad que la ley establezca, los asuntos que en materia administrativa le sean planteados. Contra sus decisiones se podrá accionar judicialmente en forma directa ante el tribunal en lo contencioso administrativo, en mérito a lo dispuesto en el inciso 2º del artículo 205 de esta Constitución.`, currentText: `Son atribuciones y deberes del Poder Ejecutivo: 1º. Participar de la formación de las leyes, con arreglo a esta Constitución, iniciándolas por medio de proyectos, proponiendo la derogación o modificación de las existentes o concurriendo a las discusiones de la Legislatura por medio de sus ministros. 2º. Promulgar y hacer ejecutar las leyes de la Provincia facilitando su cumplimiento por reglamentos y disposiciones especiales que no alteren su espíritu. 3º. Vetar las sanciones de la Legislatura, expresando en detalle los fundamentos del veto. 4º. Indultar o conmutar las penas impuestas, dentro de la jurisdicción provincial, previo informe favorable del Superior Tribunal, excepto en los casos de delitos electorales y con respecto a los funcionarios sometidos al procedimiento del juicio político o del jurado de enjuiciamiento. 5º. Representar a la Provincia en las relaciones oficiales con el Poder Ejecutivo nacional y demás gobernadores de Provincia. 6º. Celebrar y firmar tratados parciales con otras provincias para fines de administración de justicia, de intereses económicos y trabajos de utilidad común, sometiéndolos a la Legislatura para su aprobación, y oportunamente, al Congreso de la Nación, conforme al artículo 125 de la Constitución Nacional. 7º. Instruir a las cámaras con un mensaje, a la apertura de sus sesiones, sobre el estado general de la administración. 8º. Presentar dentro de los ocho meses de sesiones ordinarias de las cámaras, el proyecto de ley de presupuesto general de la administración y de las reparticiones autárquicas, acompañado del plan de recursos, el que no podrá exceder del mayor ingreso anual del último quinquenio, salvo en lo calculado por nuevos impuestos o aumentos de tasas. Dicho plazo se considerará improrrogable. 9º. Dar cuenta a la Legislatura, dentro de los ocho meses de sus sesiones ordinarias, del uso y ejercicio del presupuesto anterior. 10º. Decretar la inversión de la renta con arreglo a las leyes, debiendo hacer público mensualmente el estado de la tesorería. 11º. Hacer recaudar los impuestos y rentas de la Provincia debiendo los funcionarios encargados de la recaudación ejecutar administrativamente el pago en la forma que determine la ley, quedando libre al contribuyente su acción de ocurrir a los Tribunales para la decisión del caso, previa constancia de haber pagado. 12º. Prorrogar las sesiones ordinarias de las cámaras. 13º. Convocar a sesiones extraordinarias a la Legislatura, especificando el objeto o determinando los asuntos comprendidos en la convocatoria. 14º. Expedir las órdenes convenientes para toda elección popular en la oportunidad debida y sin poder por motivo alguno diferirlas sin acuerdo de las cámaras, salvo lo dispuesto en el artículo 88. 15º. Nombrar a los ministros secretarios y demás empleados de la administración, cuyo nombramiento no esté acordado a otro poder. Expedir títulos y despachos a los que nombre. 16º. Nombrar, con acuerdo del Senado, los miembros del Superior Tribunal de Justicia, los titulares del Ministerio Público Fiscal y de la Defensa, fiscal de Estado, contador general, tesorero general, miembros del Tribunal de Cuentas, director general de escuelas, vocales del Consejo General de Educación y los demás funcionarios para los cuales la ley establezca esta forma de nombramiento. Someter al acuerdo del Senado la propuesta para la designación de los restantes magistrados y funcionarios de los Ministerios Públicos, escogidos de una terna vinculante que, previo concurso público, le remitirá el Consejo de la Magistratura. Obtenido el mismo, proceder al nombramiento respectivo. 17º. Exonerar a los ministros secretarios de Estado y, en la forma que determine la ley respectiva, a los demás funcionarios y empleados cuyos nombramientos le esté atribuido, con excepción de los sujetos a juicio político y al jurado de enjuiciamiento. 18º. Nombrar a los jueces de paz, a propuesta en terna de los municipios o comunas del lugar de asiento del mismo. 19º. Prestar el auxilio de la fuerza pública a los Tribunales de Justicia, a los presidentes de las cámaras legislativas, a los municipios de la Provincia y demás autoridades, conforme a la ley y cuando lo soliciten. 20º. Tomar las medidas necesarias para conservar la paz y el orden público, por todos los medios que no estén expresamente prohibidos por esta Constitución y leyes vigentes. 21º. Ejercer la policía de la Provincia y la vigilancia e inspección de los establecimientos públicos de la misma. 22º. Ejercer inspección sobre las oficinas del registro del estado civil de las personas, exigiendo y promoviendo la corrección inmediata de las irregularidades y deficiencias que se noten. 23º. Conceder jubilaciones y pensiones conforme a la ley de la materia. Esta función es irrenunciable y deberá ejercerse por la Caja de Jubilaciones y Pensiones, que es el ente autárquico provincial encargado de atender el sistema previsional, a efectos de emitir el acto administrativo. 24º. Conocer y resolver originaria o recursivamente, por sí o con intervención de la autoridad que la ley establezca, los asuntos que en materia administrativa le sean planteados. Contra sus decisiones se podrá accionar judicialmente en forma directa ante el tribunal en lo contencioso administrativo, en mérito a lo dispuesto en el inciso 2º del artículo 205 de esta Constitución.`, plainLanguageExplanation: 'Enumera las 24 atribuciones del gobernador: promulgar y vetar leyes, dictar reglamentos, nombrar y exonerar funcionarios, manejar la hacienda, convocar elecciones, conceder indultos, mantener el orden público, y actuar como agente del gobierno federal, entre otras.', practicalEffects: [], examples: ['Para indultar a un condenado en el ámbito provincial, el gobernador necesita informe previo favorable del Superior Tribunal (inc. 4°).'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones del Ejecutivo', 'gobernador', 'promulgación', 'veto', 'indulto', 'nombramiento', 'hacienda'], order: 174, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-176', lawId: 'const-entre-rios', number: '176', title: 'Gobernador como agente del gobierno nacional', originalText: `Es agente inmediato y directo del Gobierno nacional para hacer cumplir en la Provincia la Constitución, leyes y disposiciones de la Nación.`, currentText: `Es agente inmediato y directo del Gobierno nacional para hacer cumplir en la Provincia la Constitución, leyes y disposiciones de la Nación.`, plainLanguageExplanation: 'El gobernador no solo representa a la Provincia sino que también es responsable de hacer cumplir la Constitución Nacional y las leyes federales en su territorio.', practicalEffects: [], examples: ['Si el Congreso sanciona una ley federal, el gobernador debe hacerla ejecutar dentro de Entre Ríos aunque no la haya impulsado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobernador', 'agente federal', 'Constitución Nacional', 'leyes nacionales'], order: 175, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-177', lawId: 'const-entre-rios', number: '177', title: 'Necesidad de refrendo ministerial para decretos', originalText: `No puede expedir resoluciones ni decretos sin la firma del ministro respectivo. Podrá, no obstante, en caso de impedimento autorizar por decreto a un empleado caracterizado para refrendar sus actos, quedando éste sujeto a las responsabilidades de los ministros.`, currentText: `No puede expedir resoluciones ni decretos sin la firma del ministro respectivo. Podrá, no obstante, en caso de impedimento autorizar por decreto a un empleado caracterizado para refrendar sus actos, quedando éste sujeto a las responsabilidades de los ministros.`, plainLanguageExplanation: 'El gobernador no puede emitir resoluciones ni decretos válidos sin la firma del ministro del área. Si el ministro está impedido, puede designar otro funcionario que refrende con las mismas responsabilidades.', practicalEffects: [], examples: ['Un decreto firmado solo por el gobernador sin refrendo ministerial es nulo y no puede ejecutarse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['decreto', 'refrendo', 'gobernador', 'validez'], order: 176, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-178', lawId: 'const-entre-rios', number: '178', title: 'Boletín Oficial — acceso gratuito y digital', originalText: `El Boletín Oficial de la Provincia distribuirá de manera gratuita a todas las escuelas y bibliotecas públicas y populares para su libre consulta por la ciudadanía la publicación de leyes y decretos provinciales. Se dispondrá su publicación en el medio de almacenamiento de datos de acceso más completo que permita la tecnología disponible con validez legal. Los tres poderes del Estado tendrán garantizada su distribución.`, currentText: `El Boletín Oficial de la Provincia distribuirá de manera gratuita a todas las escuelas y bibliotecas públicas y populares para su libre consulta por la ciudadanía la publicación de leyes y decretos provinciales. Se dispondrá su publicación en el medio de almacenamiento de datos de acceso más completo que permita la tecnología disponible con validez legal. Los tres poderes del Estado tendrán garantizada su distribución.`, plainLanguageExplanation: 'El Boletín Oficial es gratuito para escuelas y bibliotecas, debe publicarse en el formato digital más accesible disponible y los tres poderes del Estado tienen derecho a recibirlo.', practicalEffects: [], examples: ['Cualquier escuela pública entrerriana tiene derecho a recibir gratuitamente el Boletín Oficial con todas las leyes y decretos provinciales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Boletín Oficial', 'publicación oficial', 'acceso gratuito', 'transparencia'], order: 177, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-179', lawId: 'const-entre-rios', number: '179', title: 'Responsabilidad solidaria del gobernador y ministros', originalText: `El gobernador y el vicegobernador, en su caso, y los ministros en los actos que legalicen con su firma o acuerdos en común, son solidariamente responsables, y pueden ser acusados ante el Senado.`, currentText: `El gobernador y el vicegobernador, en su caso, y los ministros en los actos que legalicen con su firma o acuerdos en común, son solidariamente responsables, y pueden ser acusados ante el Senado.`, plainLanguageExplanation: 'Cuando un decreto es firmado conjuntamente por el gobernador y el ministro, ambos responden solidariamente por él; el Senado puede juzgar a cualquiera de ellos.', practicalEffects: [], examples: ['Si un decreto firmado por el gobernador y el ministro de obras causa perjuicio irregular, ambos pueden ser acusados ante el Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad solidaria', 'gobernador', 'ministros', 'juicio político'], order: 178, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-180', lawId: 'const-entre-rios', number: '180', title: 'Consejo de la Magistratura — función y competencia', originalText: `El Consejo de la Magistratura es un órgano asesor permanente del Poder Ejecutivo. Tiene competencia exclusiva para proponerle, previa realización de concursos públicos y mediante ternas vinculantes, la designación en los cargos que correspondan de los magistrados y los funcionarios de los Ministerios Públicos del Poder Judicial.`, currentText: `El Consejo de la Magistratura es un órgano asesor permanente del Poder Ejecutivo. Tiene competencia exclusiva para proponerle, previa realización de concursos públicos y mediante ternas vinculantes, la designación en los cargos que correspondan de los magistrados y los funcionarios de los Ministerios Públicos del Poder Judicial.`, plainLanguageExplanation: 'El Consejo de la Magistratura es el organismo que, mediante concurso público, selecciona ternos de candidatos para cubrir cargos de jueces y fiscales. El Ejecutivo solo puede elegir entre esos tres candidatos.', practicalEffects: [], examples: ['Para designar un juez de primera instancia, el gobernador debe esperar que el Consejo realice un concurso y le envíe una terna; no puede designar a alguien por fuera de ella.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo de la Magistratura', 'concurso público', 'terna vinculante', 'jueces', 'fiscales'], order: 179, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-181', lawId: 'const-entre-rios', number: '181', title: 'Composición del Consejo de la Magistratura', originalText: `El Consejo se integra con la representación de: el Poder Ejecutivo, los abogados matriculados en la Provincia, los magistrados y funcionarios judiciales, los empleados del Poder Judicial, miembros de reconocida trayectoria del ámbito académico o científico y representantes de organizaciones sociales comprometidas con la defensa del sistema democrático y los derechos humanos. Será presidido por un representante del Poder Ejecutivo. La composición asegurará el equilibrio entre los sectores que lo integran. Durarán dos años en sus funciones pudiendo ser reelectos por una sola vez. Su desempeño será una carga pública honoraria.`, currentText: `El Consejo se integra con la representación de: el Poder Ejecutivo, los abogados matriculados en la Provincia, los magistrados y funcionarios judiciales, los empleados del Poder Judicial, miembros de reconocida trayectoria del ámbito académico o científico y representantes de organizaciones sociales comprometidas con la defensa del sistema democrático y los derechos humanos. Será presidido por un representante del Poder Ejecutivo. La composición asegurará el equilibrio entre los sectores que lo integran. Durarán dos años en sus funciones pudiendo ser reelectos por una sola vez. Su desempeño será una carga pública honoraria.`, plainLanguageExplanation: 'El Consejo es plurisectorial: incluye representantes del Ejecutivo, abogados, jueces, empleados judiciales, académicos y sociedad civil. Todos cumplen 2 años renovables una vez, ad honorem.', practicalEffects: [], examples: ['Un abogado que integra el Consejo de la Magistratura no cobra por esa función; es considerada una carga pública honoraria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo de la Magistratura', 'composición', 'plurisectorial', 'honorario'], order: 180, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-182', lawId: 'const-entre-rios', number: '182', title: 'Funciones del Consejo de la Magistratura', originalText: `Son funciones del Consejo de la Magistratura: a) Seleccionar, mediante concurso público de antecedentes, oposición y entrevista personal, siguiendo criterios objetivos predeterminados de evaluación, a los postulantes para cubrir los cargos inferiores de magistrados judiciales y funcionarios de los Ministerios Públicos Fiscal y de la Defensa. b) Intervenir en la selección de jueces de paz a propuesta de los municipios o comunas que lo soliciten. c) Emitir propuestas en ternas vinculantes y elevarlas al Poder Ejecutivo. d) Dictar su propia reglamentación administrativa.`, currentText: `Son funciones del Consejo de la Magistratura: a) Seleccionar, mediante concurso público de antecedentes, oposición y entrevista personal, siguiendo criterios objetivos predeterminados de evaluación, a los postulantes para cubrir los cargos inferiores de magistrados judiciales y funcionarios de los Ministerios Públicos Fiscal y de la Defensa. b) Intervenir en la selección de jueces de paz a propuesta de los municipios o comunas que lo soliciten. c) Emitir propuestas en ternas vinculantes y elevarlas al Poder Ejecutivo. d) Dictar su propia reglamentación administrativa.`, plainLanguageExplanation: 'El Consejo selecciona candidatos por concurso (antecedentes, examen y entrevista), elabora ternas vinculantes para el Ejecutivo, participa en la designación de jueces de paz y regula su propio funcionamiento.', practicalEffects: [], examples: ['Un abogado que quiere ser juez de primera instancia debe presentarse al concurso del Consejo; solo si queda en la terna puede ser designado por el gobernador.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo de la Magistratura', 'concurso', 'terna', 'selección judicial'], order: 181, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-183', lawId: 'const-entre-rios', number: '183', title: 'Jefe de policía departamental', originalText: `La policía de la ciudad y campaña, estará, en cada departamento a las órdenes de un jefe de policía nombrado por el Poder Ejecutivo.`, currentText: `La policía de la ciudad y campaña, estará, en cada departamento a las órdenes de un jefe de policía nombrado por el Poder Ejecutivo.`, plainLanguageExplanation: 'Cada departamento tiene su propio jefe de policía designado por el gobernador, que conduce tanto la policía urbana como la rural del departamento.', practicalEffects: [], examples: ['En el departamento Paraná, el jefe de policía es designado directamente por el gobernador de la Provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['policía', 'jefe de policía', 'departamento', 'Poder Ejecutivo'], order: 182, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-184', lawId: 'const-entre-rios', number: '184', title: 'Requisitos para ser jefe de policía', originalText: `Para ser jefe de policía se requiere: 1º. Ciudadanía natural o legal después de seis años de obtenida. 2º. Tener por lo menos treinta años de edad. 3º. No estar en servicio militar activo.`, currentText: `Para ser jefe de policía se requiere: 1º. Ciudadanía natural o legal después de seis años de obtenida. 2º. Tener por lo menos treinta años de edad. 3º. No estar en servicio militar activo.`, plainLanguageExplanation: 'Para ser jefe de policía: ciudadanía argentina (naturalizado con al menos 6 años), 30 años de edad y no estar en servicio militar activo.', practicalEffects: [], examples: ['Un militar en actividad no puede ser designado jefe de policía departamental aunque tenga las demás condiciones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jefe de policía', 'requisitos', 'ciudadanía', 'servicio militar'], order: 183, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-185', lawId: 'const-entre-rios', number: '185', title: 'Reglamento de policía', originalText: `Un reglamento general de policía determinará las funciones y responsabilidades de los empleados, así como la organización que deben tener las policías.`, currentText: `Un reglamento general de policía determinará las funciones y responsabilidades de los empleados, así como la organización que deben tener las policías.`, plainLanguageExplanation: 'La estructura, funciones y responsabilidades de la policía provincial se regulan por un reglamento general; la Constitución no las fija en detalle.', practicalEffects: [], examples: ['Los procedimientos de detención y la jerarquía policial se establecen en el reglamento general de policía, no en la Constitución.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['policía', 'reglamento', 'organización policial'], order: 184, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-186', lawId: 'const-entre-rios', number: '186', title: 'Poder Judicial — estructura', originalText: `El Poder Judicial de la Provincia será ejercido por un Superior Tribunal de Justicia y demás tribunales o jurados que las leyes establezcan.`, currentText: `El Poder Judicial de la Provincia será ejercido por un Superior Tribunal de Justicia y demás tribunales o jurados que las leyes establezcan.`, plainLanguageExplanation: 'El Poder Judicial provincial tiene a la cabeza el Superior Tribunal de Justicia; los demás tribunales de grado inferior son creados por ley.', practicalEffects: [], examples: ['El fuero laboral o el tribunal de familia son creados por ley, no por la Constitución directamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Judicial', 'Superior Tribunal', 'tribunales', 'jurados'], order: 185, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-187', lawId: 'const-entre-rios', number: '187', title: 'Composición del Superior Tribunal de Justicia', originalText: `El Superior Tribunal se compondrá por un número impar de miembros que no podrá ser inferior a cinco. Podrá dividirse en salas que entenderán en las distintas materias del derecho, en el número que lo requieran las necesidades judiciales. En caso de creación de nuevas salas, la ley determinará su jurisdicción y competencia, la forma en que se distribuirá el trabajo entre las de la misma materia y su conformación y funcionamiento, en los casos previstos por esta Constitución cuando deba actuar como tribunal pleno.`, currentText: `El Superior Tribunal se compondrá por un número impar de miembros que no podrá ser inferior a cinco. Podrá dividirse en salas que entenderán en las distintas materias del derecho, en el número que lo requieran las necesidades judiciales. En caso de creación de nuevas salas, la ley determinará su jurisdicción y competencia, la forma en que se distribuirá el trabajo entre las de la misma materia y su conformación y funcionamiento, en los casos previstos por esta Constitución cuando deba actuar como tribunal pleno.`, plainLanguageExplanation: 'El Superior Tribunal tiene un mínimo de 5 miembros (siempre número impar) y puede dividirse en salas especializadas por materia. La ley regula las competencias de cada sala.', practicalEffects: [], examples: ['Con 7 miembros, el Superior Tribunal puede funcionar con tres salas: civil, laboral y penal, cada una con sus propios magistrados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Superior Tribunal', 'composición', 'salas', 'tribunal pleno'], order: 186, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-188', lawId: 'const-entre-rios', number: '188', title: 'Requisitos para miembro del Superior Tribunal', originalText: `Para ser miembro del Superior Tribunal, Procurador General o Defensor General, se requiere ser ciudadano argentino, tener título nacional de abogado, treinta años de edad, seis por lo menos en el ejercicio activo de la profesión de abogado o de la magistratura.`, currentText: `Para ser miembro del Superior Tribunal, Procurador General o Defensor General, se requiere ser ciudadano argentino, tener título nacional de abogado, treinta años de edad, seis por lo menos en el ejercicio activo de la profesión de abogado o de la magistratura.`, plainLanguageExplanation: 'Para ser juez del Superior Tribunal, Procurador o Defensor General: argentino, abogado nacional, 30 años y 6 años de ejercicio profesional o en la magistratura.', practicalEffects: [], examples: ['Un abogado de 30 años con solo 4 años de ejercicio no puede integrar el Superior Tribunal; necesita 6 años de práctica.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Superior Tribunal', 'requisitos', 'abogado', 'magistratura'], order: 187, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-189', lawId: 'const-entre-rios', number: '189', title: 'Inamovilidad de los miembros del Superior Tribunal', originalText: `Los miembros del Superior Tribunal serán inamovibles mientras dure su buena conducta y sólo podrán ser removidos mediante el juicio político, en la forma establecida en esta Constitución.`, currentText: `Los miembros del Superior Tribunal serán inamovibles mientras dure su buena conducta y sólo podrán ser removidos mediante el juicio político, en la forma establecida en esta Constitución.`, plainLanguageExplanation: 'Los jueces del Superior Tribunal tienen estabilidad permanente en su cargo; no pueden ser removidos arbitrariamente. Solo el juicio político puede destituirlos.', practicalEffects: [], examples: ['El gobernador no puede remover a un juez del Superior Tribunal aunque esté en desacuerdo con sus fallos; solo el juicio político puede hacerlo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inamovilidad', 'Superior Tribunal', 'jueces', 'juicio político'], order: 188, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-190', lawId: 'const-entre-rios', number: '190', title: 'Requisitos para juez de primera instancia', originalText: `Para ser juez de primera instancia se requiere ser ciudadano argentino, tener título de abogado nacional, veintisiete años de edad y cinco por lo menos, en el ejercicio activo de la profesión o en la magistratura.`, currentText: `Para ser juez de primera instancia se requiere ser ciudadano argentino, tener título de abogado nacional, veintisiete años de edad y cinco por lo menos, en el ejercicio activo de la profesión o en la magistratura.`, plainLanguageExplanation: 'Para ser juez de primera instancia: argentino, abogado nacional, 27 años y 5 años de ejercicio profesional o en la magistratura (requisitos menores que para el Superior Tribunal).', practicalEffects: [], examples: ['Un abogado de 27 años con 5 años de ejercicio puede concursar para juez de primera instancia en Entre Ríos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juez de primera instancia', 'requisitos', 'abogado', 'magistratura'], order: 189, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-191', lawId: 'const-entre-rios', number: '191', title: 'Justicia de paz letrada', originalText: `La justicia de paz será letrada y funcionará en aquellos centros de población que, previo informe favorable del Superior Tribunal, la ley establezca conforme al grado de litigiosidad, extensión territorial y población. La competencia de la justicia de paz será establecida por la ley.`, currentText: `La justicia de paz será letrada y funcionará en aquellos centros de población que, previo informe favorable del Superior Tribunal, la ley establezca conforme al grado de litigiosidad, extensión territorial y población. La competencia de la justicia de paz será establecida por la ley.`, plainLanguageExplanation: 'Los juzgados de paz deben tener juez letrado (abogado), se crean donde la ley lo determine con el aval del Superior Tribunal, y sus competencias las fija la ley.', practicalEffects: [], examples: ['Una localidad pequeña con alto índice de conflictos vecinales puede solicitar la creación de un juzgado de paz letrado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['justicia de paz', 'letrada', 'competencia', 'Superior Tribunal'], order: 190, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-192', lawId: 'const-entre-rios', number: '192', title: 'Requisitos y principios de la justicia de paz', originalText: `Para desempeñar el cargo de juez de paz, deberán observarse los requisitos del artículo 190 debiendo la ley señalar las condiciones para el funcionamiento de los respectivos juzgados, garantizando en ellos procedimientos que respondan a los principios de inmediatez, informalidad, celeridad, accesibilidad y economía procesal aplicando, en la medida de lo posible, las formas alternativas de solución de conflictos.`, currentText: `Para desempeñar el cargo de juez de paz, deberán observarse los requisitos del artículo 190 debiendo la ley señalar las condiciones para el funcionamiento de los respectivos juzgados, garantizando en ellos procedimientos que respondan a los principios de inmediatez, informalidad, celeridad, accesibilidad y economía procesal aplicando, en la medida de lo posible, las formas alternativas de solución de conflictos.`, plainLanguageExplanation: 'El juez de paz debe cumplir los mismos requisitos que cualquier juez de primera instancia. Su proceso debe ser rápido, informal, accesible y promover la mediación y el acuerdo entre partes.', practicalEffects: [], examples: ['En una disputa de vecinos, el juzgado de paz puede convocar a una audiencia de mediación informal antes de dictar una sentencia formal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['justicia de paz', 'mediación', 'celeridad', 'accesibilidad'], order: 191, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-193', lawId: 'const-entre-rios', number: '193', title: 'Designación de magistrados judiciales', originalText: `Los miembros del Superior Tribunal de Justicia, los titulares de los Ministerios Públicos, y los demás magistrados y funcionarios del Poder Judicial serán designados de la forma prevista por los artículos 103, inciso 2° y 175, incisos 16º y 18º.`, currentText: `Los miembros del Superior Tribunal de Justicia, los titulares de los Ministerios Públicos, y los demás magistrados y funcionarios del Poder Judicial serán designados de la forma prevista por los artículos 103, inciso 2° y 175, incisos 16º y 18º.`, plainLanguageExplanation: 'Los altos magistrados se designan con acuerdo del Senado; los demás jueces y fiscales se seleccionan a través del Consejo de la Magistratura mediante concurso público y terna vinculante.', practicalEffects: [], examples: ['El nombramiento de un juez de cámara requiere que el Consejo haga el concurso, eleve la terna al gobernador, y éste pida acuerdo al Senado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['designación', 'magistrados', 'acuerdo del Senado', 'Consejo de la Magistratura'], order: 192, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-194', lawId: 'const-entre-rios', number: '194', title: 'Inamovilidad de los funcionarios judiciales letrados', originalText: `Los funcionarios letrados de la administración de justicia serán inamovibles mientras dure su buena conducta, y los no sujetos a juicio político, sólo podrán ser removidos por el jurado de enjuiciamiento, en la forma establecida en esta Constitución.`, currentText: `Los funcionarios letrados de la administración de justicia serán inamovibles mientras dure su buena conducta, y los no sujetos a juicio político, sólo podrán ser removidos por el jurado de enjuiciamiento, en la forma establecida en esta Constitución.`, plainLanguageExplanation: 'Los jueces de grado inferior y funcionarios judiciales tienen estabilidad en su cargo; solo el jurado de enjuiciamiento puede removerlos (a diferencia del Superior Tribunal, cuyo mecanismo es el juicio político).', practicalEffects: [], examples: ['Un juez de primera instancia no puede ser removido por el gobernador; solo el jurado de enjuiciamiento puede hacerlo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inamovilidad', 'jurado de enjuiciamiento', 'magistrados', 'Poder Judicial'], order: 193, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-195', lawId: 'const-entre-rios', number: '195', title: 'Remuneración de los funcionarios judiciales', originalText: `Los funcionarios judiciales letrados, percibirán por sus servicios, una compensación que determinará la ley la cual será pagada en época fija y no podrá ser disminuida mientras permaneciesen en sus funciones.`, currentText: `Los funcionarios judiciales letrados, percibirán por sus servicios, una compensación que determinará la ley la cual será pagada en época fija y no podrá ser disminuida mientras permaneciesen en sus funciones.`, plainLanguageExplanation: 'Los jueces y funcionarios judiciales cobran una remuneración fijada por ley que no puede reducirse mientras estén en funciones, garantizando su independencia económica.', practicalEffects: [], examples: ['Si hay ajuste presupuestario, los sueldos de los jueces no pueden bajarse; el Ejecutivo no puede reducirlos como represalia por fallos desfavorables.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración judicial', 'intangibilidad', 'independencia judicial'], order: 194, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-196', lawId: 'const-entre-rios', number: '196', title: 'Incompatibilidades de magistrados y funcionarios judiciales', originalText: `Los magistrados y funcionarios judiciales no podrán formar parte de corporación o centro político, inmiscuirse, en grado o en forma alguna, en actividades políticas, ni ejercer su profesión en ningún foro ni ante ningún tribunal. La violación de estas normas implicará una falta grave a los efectos de su enjuiciamiento en la forma prevista en esta Constitución.`, currentText: `Los magistrados y funcionarios judiciales no podrán formar parte de corporación o centro político, inmiscuirse, en grado o en forma alguna, en actividades políticas, ni ejercer su profesión en ningún foro ni ante ningún tribunal. La violación de estas normas implicará una falta grave a los efectos de su enjuiciamiento en la forma prevista en esta Constitución.`, plainLanguageExplanation: 'Los jueces y funcionarios judiciales tienen prohibición absoluta de participar en política o ejercer la abogacía. Cualquier violación constituye falta grave que puede llevar a su enjuiciamiento.', practicalEffects: [], examples: ['Un juez que aparece en actos partidarios o que representa privadamente a clientes en otro juzgado comete una falta grave que puede costarle el cargo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidades', 'magistrados', 'actividad política', 'ejercicio profesional'], order: 195, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-197', lawId: 'const-entre-rios', number: '197', title: 'Juramento de funcionarios judiciales', originalText: `Todo funcionario judicial, antes de entrar en el ejercicio de sus funciones, deberá prestar juramento en la forma y ante la autoridad que la ley determine, so pena de nulidad de lo que actuare sin llenar esta formalidad.`, currentText: `Todo funcionario judicial, antes de entrar en el ejercicio de sus funciones, deberá prestar juramento en la forma y ante la autoridad que la ley determine, so pena de nulidad de lo que actuare sin llenar esta formalidad.`, plainLanguageExplanation: 'Todo juez o funcionario judicial debe prestar juramento antes de asumir; si actúa sin haberlo hecho, sus actos son nulos.', practicalEffects: [], examples: ['Un juez que dicta sentencias antes de prestar juramento vería sus resoluciones declaradas nulas.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento judicial', 'nulidad', 'formalidades'], order: 196, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-198', lawId: 'const-entre-rios', number: '198', title: 'Tratamiento oficial de magistrados y funcionarios judiciales', originalText: `Los magistrados y funcionarios judiciales tendrán el tratamiento oficial de "Señor", antecediendo a la denominación del cargo que ocupa.`, currentText: `Los magistrados y funcionarios judiciales tendrán el tratamiento oficial de "Señor", antecediendo a la denominación del cargo que ocupa.`, plainLanguageExplanation: 'El tratamiento protocolar de los jueces es "Señor" seguido del nombre del cargo: "Señor Juez", "Señor Fiscal", etc.', practicalEffects: [], examples: ['En los escritos judiciales se debe dirigir al magistrado como "Señor Juez".'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tratamiento', 'magistrados', 'protocolo judicial'], order: 197, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-199', lawId: 'const-entre-rios', number: '199', title: 'Incompatibilidad de la justicia federal con la provincial', originalText: `Los magistrados y funcionarios de la Justicia Federal no podrán ejercer su profesión ante la jurisdicción provincial.`, currentText: `Los magistrados y funcionarios de la Justicia Federal no podrán ejercer su profesión ante la jurisdicción provincial.`, plainLanguageExplanation: 'Un juez o fiscal federal no puede actuar como abogado en causas de la justicia provincial de Entre Ríos.', practicalEffects: [], examples: ['Un fiscal federal no puede representar a un cliente en un juicio civil ante un tribunal provincial entrerriano.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['justicia federal', 'incompatibilidad', 'jurisdicción provincial'], order: 198, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-200', lawId: 'const-entre-rios', number: '200', title: 'Incompatibilidad por parentesco en el Superior Tribunal', originalText: `No podrán ser simultáneamente miembros del Superior Tribunal los parientes o afines dentro de cuarto grado civil, ni conocer en asuntos que hayan resuelto como jueces, parientes o afines dentro de dicho grado. En caso de parentesco sobreviniente, el que lo causare, abandonará el cargo.`, currentText: `No podrán ser simultáneamente miembros del Superior Tribunal los parientes o afines dentro de cuarto grado civil, ni conocer en asuntos que hayan resuelto como jueces, parientes o afines dentro de dicho grado. En caso de parentesco sobreviniente, el que lo causare, abandonará el cargo.`, plainLanguageExplanation: 'Familiares hasta 4° grado (primos inclusive) no pueden integrar simultáneamente el Superior Tribunal. Si una relación familiar surge después del nombramiento, quien la causó debe renunciar.', practicalEffects: [], examples: ['Si dos miembros del Superior Tribunal se casan, uno de ellos debe abandonar el cargo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['parentesco', 'Superior Tribunal', 'incompatibilidad familiar', 'excusación'], order: 199, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-201', lawId: 'const-entre-rios', number: '201', title: 'Ministerio Público — garantías e inamovilidad', originalText: `Los representantes del ministerio fiscal y ministerio pupilar en todas las instancias, quedarán equiparados a los miembros del Poder Judicial y en cuanto a las garantías establecidas en su favor en cuanto a las obligaciones especiales que les impone esta Constitución no pudiendo ser removidos sino por el jurado de enjuiciamiento, en la forma prevista en la misma.`, currentText: `Los representantes del ministerio fiscal y ministerio pupilar en todas las instancias, quedarán equiparados a los miembros del Poder Judicial y en cuanto a las obligaciones especiales que les impone esta Constitución no pudiendo ser removidos sino por el jurado de enjuiciamiento, en la forma prevista en la misma.`, plainLanguageExplanation: 'Los fiscales y defensores tienen las mismas garantías e inamovilidad que los jueces; solo el jurado de enjuiciamiento puede removerlos.', practicalEffects: [], examples: ['El gobernador no puede destituir a un fiscal provincial; su remoción requiere el proceso del jurado de enjuiciamiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Ministerio Público', 'fiscal', 'defensor', 'inamovilidad', 'jurado de enjuiciamiento'], order: 200, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-202', lawId: 'const-entre-rios', number: '202', title: 'Provisión de vacante en la magistratura', originalText: `Toda vacante en la magistratura deberá ser provista dentro del termino de treinta días de producida. En caso contrario, el Superior Tribunal proveerá a la designación en carácter provisorio.`, currentText: `Toda vacante en la magistratura deberá ser provista dentro del termino de treinta días de producida. En caso contrario, el Superior Tribunal proveerá a la designación en carácter provisorio.`, plainLanguageExplanation: 'Toda vacante judicial debe cubrirse dentro de los 30 días. Si vence ese plazo sin designación, el Superior Tribunal nombra en forma provisoria.', practicalEffects: [], examples: ['Si un juez de primera instancia renuncia, el cargo debe cubrirse en 30 días; pasado ese plazo, el Superior Tribunal nombra un juez interino.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['vacante', 'magistratura', 'designación provisoria', 'Superior Tribunal'], order: 201, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-203', lawId: 'const-entre-rios', number: '203', title: 'Exclusividad jurisdiccional del Poder Judicial', originalText: `El Poder Judicial conoce y decide en los casos contenciosos o voluntarios del derecho común, en las causas criminales, en las contencioso-administrativas y en los demás casos previstos en esta Constitución, siendo su potestad, en tal sentido, exclusiva, no pudiendo el Poder Legislativo o Ejecutivo, en ningún caso, arrogarse atribuciones judiciales ni hacer revivir procesos fenecidos, ni finalizar los existentes.`, currentText: `El Poder Judicial conoce y decide en los casos contenciosos o voluntarios del derecho común, en las causas criminales, en las contencioso-administrativas y en los demás casos previstos en esta Constitución, siendo su potestad, en tal sentido, exclusiva, no pudiendo el Poder Legislativo o Ejecutivo, en ningún caso, arrogarse atribuciones judiciales ni hacer revivir procesos fenecidos, ni finalizar los existentes.`, plainLanguageExplanation: 'Solo el Poder Judicial puede resolver causas judiciales. Los poderes Ejecutivo y Legislativo no pueden arrogarse funciones judiciales ni interferir en procesos en curso o ya concluidos.', practicalEffects: [], examples: ['El gobernador no puede dictar un decreto reviviendo un proceso judicial ya concluido.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Judicial', 'exclusividad jurisdiccional', 'separación de poderes'], order: 202, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-204', lawId: 'const-entre-rios', number: '204', title: 'Atribuciones generales del Superior Tribunal de Justicia', originalText: `El Superior Tribunal de Justicia tendrá las siguientes atribuciones generales, conforme a la reglamentación de las leyes respectivas: a) Representar al Poder Judicial de la Provincia y ejercer la superintendencia general de la administración de justicia. b) Nombrar y remover los empleados inferiores del Poder Judicial. c) Remover los jueces de paz legos, mientras subsistan. d) Dictar su reglamento interno y el de los juzgados de primera instancia. e) Sin perjuicio de la facultad de iniciativa legislativa conferida por el artículo 123, hacer saber al Poder Ejecutivo las necesidades que se señalen en el ejercicio de la administración de justicia, a efecto de que solicite a la Legislatura, la sanción de las leyes respectivas. f) Evacuar con carácter obligatorio los informes relativos a la administración judicial que le requiriesen el Poder Ejecutivo o cualesquiera de las cámaras.`, currentText: `El Superior Tribunal de Justicia tendrá las siguientes atribuciones generales, conforme a la reglamentación de las leyes respectivas: a) Representar al Poder Judicial de la Provincia y ejercer la superintendencia general de la administración de justicia. b) Nombrar y remover los empleados inferiores del Poder Judicial. c) Remover los jueces de paz legos, mientras subsistan. d) Dictar su reglamento interno y el de los juzgados de primera instancia. e) Sin perjuicio de la facultad de iniciativa legislativa conferida por el artículo 123, hacer saber al Poder Ejecutivo las necesidades que se señalen en el ejercicio de la administración de justicia, a efecto de que solicite a la Legislatura, la sanción de las leyes respectivas. f) Evacuar con carácter obligatorio los informes relativos a la administración judicial que le requiriesen el Poder Ejecutivo o cualesquiera de las cámaras.`, plainLanguageExplanation: 'El Superior Tribunal representa y superintende el Poder Judicial: designa y remueve empleados inferiores, dicta reglamentos y asesora al Poder Ejecutivo sobre necesidades legislativas en materia judicial.', practicalEffects: [], examples: ['El Superior Tribunal puede remover a un empleado de juzgado inferior por inconducta sin necesidad de juicio político.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Superior Tribunal', 'superintendencia', 'atribuciones generales', 'reglamento'], order: 203, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-205', lawId: 'const-entre-rios', number: '205', title: 'Atribuciones judiciales del Superior Tribunal de Justicia', originalText: `En materia judicial, el Superior Tribunal de Justicia tiene las siguientes atribuciones, de conformidad a las normas que establezcan las leyes de la materia: 1º. Ejercerá jurisdicción, originaria y exclusiva, en los siguientes casos: a) En las causas que le fueran sometidas sobre competencia o conflictos entre los poderes públicos de la Provincia o entre las ramas de un mismo poder. b) En los conflictos internos de las municipalidades y comunas y en los que se susciten entre ellas, y entre éstas y las autoridades de la Provincia. c) En las gestiones acerca de la constitucionalidad de leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan en materia regida por esta Constitución, que se promuevan directamente ante el mismo por vía de acción. d) En los recursos de revisión de causas fenecidas cualquiera sea la pena impuesta. e) En las cuestiones de competencia o de jurisdicción entre sus salas. f) En los recursos por retardo o denegación de justicia interpuestos contra sus salas. g) En la recusación de sus miembros. h) En las acciones de responsabilidad civil contra sus miembros y contra los jueces de primera instancia. i) En los asuntos administrativos o gestiones de jurisdicción voluntaria que se deriven del ejercicio de la superintendencia. 2º. Ejercerá jurisdicción, como Tribunal de última instancia: a) En las causas sobre constitucionalidad o inconstitucionalidad de leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan sobre materia regida por esta Constitución y que se hayan promovido ante los juzgados de primera instancia. b) En los demás casos establecidos en las leyes respectivas. c) En las causas contencioso administrativas atinentes al reconocimiento de los derechos, previa denegación o retardo de la autoridad administrativa competente, en la forma en que lo determine la ley respectiva. La vía judicial quedará directamente habilitada, a partir de la denegación expresa o tácita dictada, según los casos, por el gobernador, el presidente de cada una de las cámaras legislativas, el Superior Tribunal de Justicia en actos de gobierno, o mediando resolución definitiva de los entes autónomos o autárquicos, o de los ministros en los casos que las leyes lo establezcan. Por ley se podrán establecer otros supuestos en los que el agotamiento de la etapa administrativa se produzca en estamentos inferiores. Todo ello, sin perjuicio del control de legalidad que el Poder Ejecutivo realizará, cuando corresponda, respecto de los organismos de su dependencia. d) En la ejecución del acto administrativo firme. En tales causas, el Superior Tribunal tendrá facultad para mandar cumplir directamente sus sentencias por las oficinas o empleados respectivos, si la autoridad administrativa no lo hiciere dentro del plazo que establezca la sentencia. Los empleados a que alude este artículo, serán responsables por la falta de cumplimiento de las resoluciones del Superior Tribunal.`, currentText: `En materia judicial, el Superior Tribunal de Justicia tiene las siguientes atribuciones, de conformidad a las normas que establezcan las leyes de la materia: 1º. Ejercerá jurisdicción, originaria y exclusiva, en los siguientes casos: a) En las causas que le fueran sometidas sobre competencia o conflictos entre los poderes públicos de la Provincia o entre las ramas de un mismo poder. b) En los conflictos internos de las municipalidades y comunas y en los que se susciten entre ellas, y entre éstas y las autoridades de la Provincia. c) En las gestiones acerca de la constitucionalidad de leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan en materia regida por esta Constitución, que se promuevan directamente ante el mismo por vía de acción. d) En los recursos de revisión de causas fenecidas cualquiera sea la pena impuesta. e) En las cuestiones de competencia o de jurisdicción entre sus salas. f) En los recursos por retardo o denegación de justicia interpuestos contra sus salas. g) En la recusación de sus miembros. h) En las acciones de responsabilidad civil contra sus miembros y contra los jueces de primera instancia. i) En los asuntos administrativos o gestiones de jurisdicción voluntaria que se deriven del ejercicio de la superintendencia. 2º. Ejercerá jurisdicción, como Tribunal de última instancia: a) En las causas sobre constitucionalidad o inconstitucionalidad de leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan sobre materia regida por esta Constitución y que se hayan promovido ante los juzgados de primera instancia. b) En los demás casos establecidos en las leyes respectivas. c) En las causas contencioso administrativas atinentes al reconocimiento de los derechos, previa denegación o retardo de la autoridad administrativa competente, en la forma en que lo determine la ley respectiva. La vía judicial quedará directamente habilitada, a partir de la denegación expresa o tácita dictada, según los casos, por el gobernador, el presidente de cada una de las cámaras legislativas, el Superior Tribunal de Justicia en actos de gobierno, o mediando resolución definitiva de los entes autónomos o autárquicos, o de los ministros en los casos que las leyes lo establezcan. Por ley se podrán establecer otros supuestos en los que el agotamiento de la etapa administrativa se produzca en estamentos inferiores. Todo ello, sin perjuicio del control de legalidad que el Poder Ejecutivo realizará, cuando corresponda, respecto de los organismos de su dependencia. d) En la ejecución del acto administrativo firme. En tales causas, el Superior Tribunal tendrá facultad para mandar cumplir directamente sus sentencias por las oficinas o empleados respectivos, si la autoridad administrativa no lo hiciere dentro del plazo que establezca la sentencia. Los empleados a que alude este artículo, serán responsables por la falta de cumplimiento de las resoluciones del Superior Tribunal.`, plainLanguageExplanation: 'El Superior Tribunal tiene jurisdicción originaria y exclusiva en conflictos de poderes, constitucionalidad directa y revisión de causas fenecidas; y es tribunal de última instancia en cuestiones constitucionales y contencioso-administrativas.', practicalEffects: [], examples: ['Un ciudadano puede acudir directamente al Superior Tribunal si cuestiona la inconstitucionalidad de un decreto ejecutivo por vía de acción directa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Superior Tribunal', 'jurisdicción originaria', 'inconstitucionalidad', 'contencioso-administrativo', 'última instancia'], order: 204, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-206', lawId: 'const-entre-rios', number: '206', title: 'Leyes especiales para la administración de justicia', originalText: `La administración de justicia se regirá por leyes especiales que deslinden las atribuciones respectivas de todos los tribunales y determinen el orden de sus procedimientos. Los tribunales y jueces de la Provincia están obligados a publicar mensualmente la lista de los juicios pendientes de resolución o sentencia definitiva.`, currentText: `La administración de justicia se regirá por leyes especiales que deslinden las atribuciones respectivas de todos los tribunales y determinen el orden de sus procedimientos. Los tribunales y jueces de la Provincia están obligados a publicar mensualmente la lista de los juicios pendientes de resolución o sentencia definitiva.`, plainLanguageExplanation: 'Leyes especiales delimitan las atribuciones de cada tribunal. Los jueces deben publicar mensualmente la lista de causas pendientes de resolución, garantizando la transparencia judicial.', practicalEffects: [], examples: ['Un juez de primera instancia publica en el sitio del Poder Judicial la lista de expedientes en estado de dictar sentencia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['administración de justicia', 'leyes especiales', 'transparencia judicial', 'causas pendientes'], order: 205, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-207', lawId: 'const-entre-rios', number: '207', title: 'Ministerio Público — organización y funciones', originalText: `El Ministerio Público es un órgano autónomo en sus funciones, siendo parte integrante del Poder Judicial. Se compone de dos ramas independientes entre sí, Ministerio Público Fiscal y Ministerio Público de la Defensa, presididas por el Procurador General y el Defensor General respectivamente, y se integra por los funcionarios y empleados que se establezcan, respecto a los cuales les compete el ejercicio de la superintendencia. Tiene como misión promover la actuación de la justicia en defensa de la legalidad, de los derechos de los ciudadanos y del interés público en todas las causas y asuntos que se le imponga. En el caso del Ministerio Público Fiscal, ejerce la acción penal pública y conduce la investigación, con arreglo a los principios de legalidad, objetividad, imparcialidad, especialidad, oportunidad, unidad de actuación y dependencia jerárquica. En el caso del Ministerio de la Defensa, le compete la asistencia integral de su representado. Designa y remueve su personal, propone y ejecuta su presupuesto. Tiene, respecto a los funcionarios de sus ministerios, la atribución de cubrir con carácter provisorio toda vacante atendiendo, si las hubiere, las nóminas del Consejo de la Magistratura y hasta que sea cubierta mediante el sistema previsto por esta Constitución. La actuación y organización general será regulada por la ley, en la que el régimen subrogatorio deberá establecerse para que se articule dentro de la estructura respectiva, pudiendo solo excepcionalmente hacerse de otro modo.`, currentText: `El Ministerio Público es un órgano autónomo en sus funciones, siendo parte integrante del Poder Judicial. Se compone de dos ramas independientes entre sí, Ministerio Público Fiscal y Ministerio Público de la Defensa, presididas por el Procurador General y el Defensor General respectivamente, y se integra por los funcionarios y empleados que se establezcan, respecto a los cuales les compete el ejercicio de la superintendencia. Tiene como misión promover la actuación de la justicia en defensa de la legalidad, de los derechos de los ciudadanos y del interés público en todas las causas y asuntos que se le imponga. En el caso del Ministerio Público Fiscal, ejerce la acción penal pública y conduce la investigación, con arreglo a los principios de legalidad, objetividad, imparcialidad, especialidad, oportunidad, unidad de actuación y dependencia jerárquica. En el caso del Ministerio de la Defensa, le compete la asistencia integral de su representado. Designa y remueve su personal, propone y ejecuta su presupuesto. Tiene, respecto a los funcionarios de sus ministerios, la atribución de cubrir con carácter provisorio toda vacante atendiendo, si las hubiere, las nóminas del Consejo de la Magistratura y hasta que sea cubierta mediante el sistema previsto por esta Constitución. La actuación y organización general será regulada por la ley, en la que el régimen subrogatorio deberá establecerse para que se articule dentro de la estructura respectiva, pudiendo solo excepcionalmente hacerse de otro modo.`, plainLanguageExplanation: 'El Ministerio Público es autónomo e integrado al Poder Judicial: la Fiscalía ejerce la acción penal, la Defensoría asiste integralmente al representado. Cada rama administra su presupuesto y personal.', practicalEffects: [], examples: ['El Defensor General designa provisionalmente a un defensor cuando hay vacante, mientras el Consejo de la Magistratura tramita el concurso.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Ministerio Público', 'Fiscalía', 'Defensoría', 'autonomía', 'Procurador General', 'Defensor General'], order: 206, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-208', lawId: 'const-entre-rios', number: '208', title: 'Fiscal anticorrupción del Ministerio Público', originalText: `Un Fiscal del Ministerio Público, con competencia en el territorio de la Provincia, tendrá a su cargo, la investigación y acusación de los hechos de corrupción y otros delitos contra la administración pública. Su titular y demás integrantes serán fiscales designados con intervención del Consejo de la Magistratura. La Procuración General asegurará los medios, el apoyo tecnológico, la continuidad y estabilidad, para el cumplimiento de su cometido.`, currentText: `Un Fiscal del Ministerio Público, con competencia en el territorio de la Provincia, tendrá a su cargo, la investigación y acusación de los hechos de corrupción y otros delitos contra la administración pública. Su titular y demás integrantes serán fiscales designados con intervención del Consejo de la Magistratura. La Procuración General asegurará los medios, el apoyo tecnológico, la continuidad y estabilidad, para el cumplimiento de su cometido.`, plainLanguageExplanation: 'Existe un fiscal especializado con competencia provincial para investigar y acusar hechos de corrupción y delitos contra la administración pública, apoyado tecnológica y logísticamente por la Procuración General.', practicalEffects: [], examples: ['Si un funcionario público es sospechado de malversación de fondos, el fiscal anticorrupción puede abrirle una investigación penal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fiscal anticorrupción', 'corrupción', 'administración pública', 'Ministerio Público', 'Consejo de la Magistratura'], order: 207, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-209', lawId: 'const-entre-rios', number: '209', title: 'Fiscal de Estado — funciones y garantías', originalText: `El fiscal de Estado es el encargado de defender el patrimonio del Estado Provincial. Es parte legítima y necesaria en los juicios contencioso-administrativos, de inconstitucionalidad y en toda controversia judicial en que se afecten intereses del Estado, pudiendo tomar intervención en los juicios de interés municipal cuando la gravedad de la cuestión, a su criterio, pudiera comprometer al erario provincial. La ley determinará los casos en que el Poder Ejecutivo podrá requerirle opinión o dictamen, y en los que realizará el cobro judicial de las acreencias fiscales y la forma en que ha de cumplir sus funciones. Ejerce el control de legalidad de todos los actos del poder público. Promueve la acción de inconstitucionalidad contra leyes, decretos, resoluciones, ordenanzas y cualquier acto que viole o contradiga una disposición de esta Constitución o de la Constitución Nacional, o cuando sean contrarios a los intereses del Estado. En estos supuestos, la representación del gobierno estará a cargo del funcionario que la ley designe. Antes del 31 de marzo de cada año informará el listado de juicios en trámite y su estado al gobernador y a la Legislatura. Para ser fiscal de Estado se requieren las mismas condiciones que para ser Procurador General de la Provincia. Es inamovible mientras dure su buena conducta y enjuiciable en la misma forma que éste.`, currentText: `El fiscal de Estado es el encargado de defender el patrimonio del Estado Provincial. Es parte legítima y necesaria en los juicios contencioso-administrativos, de inconstitucionalidad y en toda controversia judicial en que se afecten intereses del Estado, pudiendo tomar intervención en los juicios de interés municipal cuando la gravedad de la cuestión, a su criterio, pudiera comprometer al erario provincial. La ley determinará los casos en que el Poder Ejecutivo podrá requerirle opinión o dictamen, y en los que realizará el cobro judicial de las acreencias fiscales y la forma en que ha de cumplir sus funciones. Ejerce el control de legalidad de todos los actos del poder público. Promueve la acción de inconstitucionalidad contra leyes, decretos, resoluciones, ordenanzas y cualquier acto que viole o contradiga una disposición de esta Constitución o de la Constitución Nacional, o cuando sean contrarios a los intereses del Estado. En estos supuestos, la representación del gobierno estará a cargo del funcionario que la ley designe. Antes del 31 de marzo de cada año informará el listado de juicios en trámite y su estado al gobernador y a la Legislatura. Para ser fiscal de Estado se requieren las mismas condiciones que para ser Procurador General de la Provincia. Es inamovible mientras dure su buena conducta y enjuiciable en la misma forma que éste.`, plainLanguageExplanation: 'El Fiscal de Estado defiende el patrimonio provincial, es parte necesaria en juicios contencioso-administrativos y de inconstitucionalidad, ejerce control de legalidad y promueve acciones de inconstitucionalidad. Es inamovible mientras dure su buena conducta.', practicalEffects: [], examples: ['El Fiscal de Estado interviene en un juicio donde un proveedor reclama daños al Estado provincial por rescisión de contrato.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Fiscal de Estado', 'patrimonio provincial', 'control de legalidad', 'inconstitucionalidad', 'inamovilidad'], order: 208, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-210', lawId: 'const-entre-rios', number: '210', title: 'Contaduría General — funciones y organización', originalText: `La Contaduría General es el órgano rector de la contabilidad de la administración que tiene a su cargo el control interno de la gestión económico, financiera y patrimonial de la hacienda pública. Dicta las normas de contabilidad, elabora la cuenta general del ejercicio y los demás estados e informes sobre la gestión presupuestaria, financiera, económica y patrimonial. Está a cargo de un contador general. Interviene preventivamente en todos los actos que generen libramientos de pago con cargo a fondos previstos en el presupuesto general o en otras leyes que los autoricen, sin que ello implique sustituir los criterios de oportunidad o mérito. Verifica, antes de la contratación, el cumplimiento del procedimiento respectivo. Sin su aprobación no podrán autorizarse gastos ni emitirse órdenes de pago, salvo si hubiere insistencia por acuerdo de ministros, en cuyo caso, si mantiene sus observaciones, deberá dar publicidad inmediata a su resolución y dentro de los quince días, poner los antecedentes en conocimiento del Tribunal de Cuentas.`, currentText: `La Contaduría General es el órgano rector de la contabilidad de la administración que tiene a su cargo el control interno de la gestión económico, financiera y patrimonial de la hacienda pública. Dicta las normas de contabilidad, elabora la cuenta general del ejercicio y los demás estados e informes sobre la gestión presupuestaria, financiera, económica y patrimonial. Está a cargo de un contador general. Interviene preventivamente en todos los actos que generen libramientos de pago con cargo a fondos previstos en el presupuesto general o en otras leyes que los autoricen, sin que ello implique sustituir los criterios de oportunidad o mérito. Verifica, antes de la contratación, el cumplimiento del procedimiento respectivo. Sin su aprobación no podrán autorizarse gastos ni emitirse órdenes de pago, salvo si hubiere insistencia por acuerdo de ministros, en cuyo caso, si mantiene sus observaciones, deberá dar publicidad inmediata a su resolución y dentro de los quince días, poner los antecedentes en conocimiento del Tribunal de Cuentas.`, plainLanguageExplanation: 'La Contaduría General controla internamente el gasto público: interviene previamente en todos los pagos. Si el Ejecutivo insiste por acuerdo de ministros, la Contaduría publica sus observaciones y notifica al Tribunal de Cuentas.', practicalEffects: [], examples: ['Si el Ejecutivo quiere pagar una obra pública sin el previo visto bueno de la Contaduría, necesita acuerdo de ministros; la Contaduría puede publicar su disconformidad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Contaduría General', 'control interno', 'gasto público', 'hacienda pública', 'Tribunal de Cuentas'], order: 209, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-211', lawId: 'const-entre-rios', number: '211', title: 'Tesorería General — funciones y organización', originalText: `La Tesorería General es el órgano rector del sistema de ingresos, pagos y custodia de las disponibilidades de la hacienda pública. Está a cargo de un tesorero general. Recepciona la recaudación de los ingresos de la administración provincial y efectúa los pagos y las entregas de fondos, autorizados por la Contaduría General. Ejerce la supervisión y coordinación de todas las unidades o servicios de tesorería que operen en la administración pública, dictando las normas y fijando los procedimientos pertinentes. Publica mensualmente, previa presentación al Poder Ejecutivo, el estado de la tesorería.`, currentText: `La Tesorería General es el órgano rector del sistema de ingresos, pagos y custodia de las disponibilidades de la hacienda pública. Está a cargo de un tesorero general. Recepciona la recaudación de los ingresos de la administración provincial y efectúa los pagos y las entregas de fondos, autorizados por la Contaduría General. Ejerce la supervisión y coordinación de todas las unidades o servicios de tesorería que operen en la administración pública, dictando las normas y fijando los procedimientos pertinentes. Publica mensualmente, previa presentación al Poder Ejecutivo, el estado de la tesorería.`, plainLanguageExplanation: 'La Tesorería General recauda ingresos, efectúa pagos autorizados por la Contaduría, coordina todas las unidades de tesorería y publica mensualmente el estado de caja.', practicalEffects: [], examples: ['La Tesorería General transfiere los fondos de coparticipación a los municipios una vez que la Contaduría General autoriza el libramiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tesorería General', 'ingresos', 'pagos', 'hacienda pública', 'tesorero general'], order: 210, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-212', lawId: 'const-entre-rios', number: '212', title: 'Requisitos y mandato del Contador y Tesorero General', originalText: `Para ser titular de la Contaduría General o de la Tesorería General se requiere ser ciudadano argentino, tener treinta años y título universitario de contador público con seis años de antigüedad. Sus funciones son incompatibles con el ejercicio profesional. Durarán ocho años en sus funciones, pudiendo ser reelectos. Son enjuiciables en la misma forma que los jueces de primera instancia. La ley establecerá la organización de la Contaduría General y de la Tesorería General así como demás competencias, atribuciones y responsabilidades.`, currentText: `Para ser titular de la Contaduría General o de la Tesorería General se requiere ser ciudadano argentino, tener treinta años y título universitario de contador público con seis años de antigüedad. Sus funciones son incompatibles con el ejercicio profesional. Durarán ocho años en sus funciones, pudiendo ser reelectos. Son enjuiciables en la misma forma que los jueces de primera instancia. La ley establecerá la organización de la Contaduría General y de la Tesorería General así como demás competencias, atribuciones y responsabilidades.`, plainLanguageExplanation: 'Para ser Contador o Tesorero General se requieren ciudadanía argentina, 30 años y título de contador público con 6 años de antigüedad. Duran 8 años, pueden ser reelectos y son enjuiciables como jueces de primera instancia.', practicalEffects: [], examples: ['Un abogado no puede ser nombrado Contador General ya que el cargo requiere título de contador público.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Contaduría General', 'Tesorería General', 'requisitos', 'mandato', 'contador público'], order: 211, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-213', lawId: 'const-entre-rios', number: '213', title: 'Tribunal de Cuentas — funciones y atribuciones', originalText: `El Tribunal de Cuentas es un órgano de control externo con autonomía funcional. Sin perjuicio de la atribución conferida por el inciso 13º del artículo 122 de esta Constitución, tiene a su cargo las siguientes funciones: 1º. Resolver sobre la percepción e inversión de caudales públicos a cargo de los funcionarios y administradores de la Provincia, de las personas o entidades que manejen fondos públicos y de los municipios, mientras éstos no cuenten con sus propios órganos de control. En las contrataciones de alta significación económica, el control deberá realizarse desde su origen, sin perjuicio de la verificación posterior correspondiente a la inversión de la renta. En estos supuestos la ley deslindará las competencias del Tribunal de Cuentas y de la Contaduría. 2º. Ejercer la auditoría de la administración pública, entes autárquicos, empresas del Estado y todo otro organismo estatal que administre, gestione, erogue e invierta recursos públicos. 3º. Formular instrucciones y recomendaciones tendientes a prevenir o corregir cualquier irregularidad vinculada con los fondos públicos, sin que ello implique sustituir los criterios de oportunidad o mérito que determinaron el gasto. El Tribunal de Cuentas no ejerce funciones judiciales. Las resoluciones sobre las cuentas y las responsabilidades podrán ser apeladas ante el fuero contencioso administrativo, las que en estado y, en su caso, serán giradas a la Fiscalía de Estado para su ejecución. Presentado el informe del Poder Ejecutivo sobre ejecución presupuestaria y resultados de la gestión financiera a la Legislatura, previo a su tratamiento, será remitido al Tribunal de Cuentas para que dictamine sobre el mismo. El Tribunal deberá remitir a la Legislatura su memoria y rendición de cuentas del año anterior para su consideración, antes del 31 de marzo de cada año.`, currentText: `El Tribunal de Cuentas es un órgano de control externo con autonomía funcional. Sin perjuicio de la atribución conferida por el inciso 13º del artículo 122 de esta Constitución, tiene a su cargo las siguientes funciones: 1º. Resolver sobre la percepción e inversión de caudales públicos a cargo de los funcionarios y administradores de la Provincia, de las personas o entidades que manejen fondos públicos y de los municipios, mientras éstos no cuenten con sus propios órganos de control. En las contrataciones de alta significación económica, el control deberá realizarse desde su origen, sin perjuicio de la verificación posterior correspondiente a la inversión de la renta. En estos supuestos la ley deslindará las competencias del Tribunal de Cuentas y de la Contaduría. 2º. Ejercer la auditoría de la administración pública, entes autárquicos, empresas del Estado y todo otro organismo estatal que administre, gestione, erogue e invierta recursos públicos. 3º. Formular instrucciones y recomendaciones tendientes a prevenir o corregir cualquier irregularidad vinculada con los fondos públicos, sin que ello implique sustituir los criterios de oportunidad o mérito que determinaron el gasto. El Tribunal de Cuentas no ejerce funciones judiciales. Las resoluciones sobre las cuentas y las responsabilidades podrán ser apeladas ante el fuero contencioso administrativo, las que en estado y, en su caso, serán giradas a la Fiscalía de Estado para su ejecución. Presentado el informe del Poder Ejecutivo sobre ejecución presupuestaria y resultados de la gestión financiera a la Legislatura, previo a su tratamiento, será remitido al Tribunal de Cuentas para que dictamine sobre el mismo. El Tribunal deberá remitir a la Legislatura su memoria y rendición de cuentas del año anterior para su consideración, antes del 31 de marzo de cada año.`, plainLanguageExplanation: 'El Tribunal de Cuentas controla externamente el uso de fondos públicos, audita la administración y sus entes, formula recomendaciones y dictamina sobre la ejecución presupuestaria. No ejerce funciones judiciales.', practicalEffects: [], examples: ['Antes de aprobar el presupuesto ejecutado, la Legislatura lo remite al Tribunal de Cuentas para que emita su dictamen.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tribunal de Cuentas', 'control externo', 'auditoría', 'hacienda pública', 'presupuesto'], order: 212, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-214', lawId: 'const-entre-rios', number: '214', title: 'Composición y designación del Tribunal de Cuentas', originalText: `El Tribunal de Cuentas está compuesto por cinco miembros. Un Presidente con título de abogado y dos vocales con título de contador público. Todos ellos y los fiscales del Tribunal, que serán contadores y abogados en igual número, son designados de conformidad con el artículo 217. Los otros dos vocales, son designados en representación parlamentaria de la mayoría y la primera minoría de la Cámara de Diputados, con título de abogado o de contador público, teniendo mandato hasta el término del período constitucional. Todos ellos podrán ser removidos por el Jurado de Enjuiciamiento como los señores jueces y fiscales y tendrán sus mismas incompatibilidades y prerrogativas. En cuanto a sus remuneraciones se equipararán a la de los jueces y fiscales de las Cámaras de Apelaciones.`, currentText: `El Tribunal de Cuentas está compuesto por cinco miembros. Un Presidente con título de abogado y dos vocales con título de contador público. Todos ellos y los fiscales del Tribunal, que serán contadores y abogados en igual número, son designados de conformidad con el artículo 217. Los otros dos vocales, son designados en representación parlamentaria de la mayoría y la primera minoría de la Cámara de Diputados, con título de abogado o de contador público, teniendo mandato hasta el término del período constitucional. Todos ellos podrán ser removidos por el Jurado de Enjuiciamiento como los señores jueces y fiscales y tendrán sus mismas incompatibilidades y prerrogativas. En cuanto a sus remuneraciones se equipararán a la de los jueces y fiscales de las Cámaras de Apelaciones.`, plainLanguageExplanation: 'El Tribunal de Cuentas tiene cinco miembros: presidente abogado, dos vocales contadores y dos vocales de representación parlamentaria. Todos tienen las mismas inmunidades e incompatibilidades que los jueces y cobran como camaristas.', practicalEffects: [], examples: ['Los dos vocales de representación parlamentaria duran hasta que termine el período constitucional del cuerpo que los designó.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tribunal de Cuentas', 'composición', 'vocales', 'abogado', 'contador público'], order: 213, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-215', lawId: 'const-entre-rios', number: '215', title: 'Defensoría del Pueblo — misión y atribuciones', originalText: `La Defensoría del Pueblo es un órgano unipersonal e independiente. Su misión es la defensa, protección y promoción de los derechos humanos y demás derechos, garantías e intereses tutelados en el ordenamiento jurídico, frente a hechos, actos u omisiones de la administración pública y de prestadores de servicios públicos o privados contratados por el Estado. Tiene legitimación procesal activa y prelación en sus presentaciones administrativas y puede solicitar informes y formular requerimientos a las autoridades públicas y a los prestadores de servicios. Sus actuaciones serán gratuitas para quien las requiera.`, currentText: `La Defensoría del Pueblo es un órgano unipersonal e independiente. Su misión es la defensa, protección y promoción de los derechos humanos y demás derechos, garantías e intereses tutelados en el ordenamiento jurídico, frente a hechos, actos u omisiones de la administración pública y de prestadores de servicios públicos o privados contratados por el Estado. Tiene legitimación procesal activa y prelación en sus presentaciones administrativas y puede solicitar informes y formular requerimientos a las autoridades públicas y a los prestadores de servicios. Sus actuaciones serán gratuitas para quien las requiera.`, plainLanguageExplanation: 'La Defensoría del Pueblo defiende derechos y garantías frente a la administración pública y concesionarios de servicios. Tiene legitimación procesal activa y sus actuaciones son gratuitas para el ciudadano.', practicalEffects: [], examples: ['Un ciudadano que sufre cortes reiterados de agua por la empresa concesionaria puede presentar su queja gratuitamente ante la Defensoría del Pueblo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Defensoría del Pueblo', 'derechos humanos', 'administración pública', 'legitimación procesal', 'gratuidad'], order: 214, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-216', lawId: 'const-entre-rios', number: '216', title: 'Defensor del Pueblo — designación y mandato', originalText: `Está a cargo de un Defensor del Pueblo designado por ambas cámaras con el voto de al menos dos tercios de los miembros presentes en sesión especial convocada al efecto. Debe tener como mínimo treinta años de edad y las demás condiciones para ser diputado. Goza de iguales inmunidades, remuneración y prerrogativas que los diputados y le alcanzan las inhabilidades, incompatibilidades y causales de remoción establecidas para los jueces. Su mandato es de cinco años, pudiendo ser reelecto y sólo podrá ser removido por juicio político. Es asistido por defensores adjuntos cuyo número, ámbito de actuación y funciones específicas establecerá la ley.`, currentText: `Está a cargo de un Defensor del Pueblo designado por ambas cámaras con el voto de al menos dos tercios de los miembros presentes en sesión especial convocada al efecto. Debe tener como mínimo treinta años de edad y las demás condiciones para ser diputado. Goza de iguales inmunidades, remuneración y prerrogativas que los diputados y le alcanzan las inhabilidades, incompatibilidades y causales de remoción establecidas para los jueces. Su mandato es de cinco años, pudiendo ser reelecto y sólo podrá ser removido por juicio político. Es asistido por defensores adjuntos cuyo número, ámbito de actuación y funciones específicas establecerá la ley.`, plainLanguageExplanation: 'El Defensor del Pueblo es elegido por ambas cámaras con dos tercios de votos. Dura 5 años, puede ser reelecto y solo puede ser removido por juicio político. Tiene las mismas inmunidades que un diputado.', practicalEffects: [], examples: ['Si la Legislatura no reúne los dos tercios necesarios en sesión especial, no puede designar al Defensor del Pueblo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Defensor del Pueblo', 'designación', 'dos tercios', 'mandato', 'juicio político'], order: 215, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-217', lawId: 'const-entre-rios', number: '217', title: 'Autonomía y designación de órganos de control', originalText: `El Defensor del Pueblo, la Fiscalía de Estado, el Tribunal de Cuentas y la Contaduría General son órganos autónomos en sus funciones, proponen y ejecutan su propio presupuesto; designan y remueven su personal. El nombramiento del contador general, del tesorero general, de los miembros del Tribunal de Cuentas que no tengan otra forma prevista por esta Constitución y sus fiscales, se realizará previo concurso público que la ley ordenará conforme a los siguientes criterios rectores: un jurado de concurso será convocado en cada caso por el Poder Ejecutivo el que designará su representante y asegurará la participación igualitaria de los sectores académicos, de las asociaciones civiles cuyo objeto principal sea la promoción de la transparencia y la ética en la función pública, con personería jurídica y domicilio en la Provincia y de las entidades representativas de las profesiones exigidas. Sus integrantes se desempeñarán en forma honoraria y elegirán una terna que será elevada al Poder Ejecutivo para su designación con el acuerdo del Senado.`, currentText: `El Defensor del Pueblo, la Fiscalía de Estado, el Tribunal de Cuentas y la Contaduría General son órganos autónomos en sus funciones, proponen y ejecutan su propio presupuesto; designan y remueven su personal. El nombramiento del contador general, del tesorero general, de los miembros del Tribunal de Cuentas que no tengan otra forma prevista por esta Constitución y sus fiscales, se realizará previo concurso público que la ley ordenará conforme a los siguientes criterios rectores: un jurado de concurso será convocado en cada caso por el Poder Ejecutivo el que designará su representante y asegurará la participación igualitaria de los sectores académicos, de las asociaciones civiles cuyo objeto principal sea la promoción de la transparencia y la ética en la función pública, con personería jurídica y domicilio en la Provincia y de las entidades representativas de las profesiones exigidas. Sus integrantes se desempeñarán en forma honoraria y elegirán una terna que será elevada al Poder Ejecutivo para su designación con el acuerdo del Senado.`, plainLanguageExplanation: 'Los órganos de control son autónomos: ejecutan su propio presupuesto y designan su personal. Sus titulares se eligen por concurso público con jurado integrado por el Estado, academia y sociedad civil, y la designación final requiere acuerdo del Senado.', practicalEffects: [], examples: ['El Tribunal de Cuentas convoca a concurso para cubrir una vacante de vocal contador, con jurado integrado por el Ejecutivo, universidades y colegios profesionales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['órganos de control', 'autonomía', 'concurso público', 'Tribunal de Cuentas', 'Defensoría del Pueblo', 'Fiscalía de Estado'], order: 216, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-218', lawId: 'const-entre-rios', number: '218', title: 'Jurado de Enjuiciamiento — integración', originalText: `Los funcionarios judiciales letrados a que se refieren los artículos 194 y 201, no sujetos a juicio político, podrán ser acusados, por faltas o delitos cometidos en el desempeño de sus funciones, ante el Jurado de Enjuiciamiento. Estará integrado por tres miembros del Superior Tribunal, dos legisladores y cuatro abogados inscriptos en la matrícula de la Provincia y domiciliados en ella que reúnan los requisitos para ser miembro del Superior Tribunal; dos designados por organizaciones sociales en representación ciudadana debidamente reconocidas en la defensa del sistema democrático y los derechos humanos. Los restantes integrantes serán sorteados o designados para que el tribunal quede constituido el 1º de enero de cada año.`, currentText: `Los funcionarios judiciales letrados a que se refieren los artículos 194 y 201, no sujetos a juicio político, podrán ser acusados, por faltas o delitos cometidos en el desempeño de sus funciones, ante el Jurado de Enjuiciamiento. Estará integrado por tres miembros del Superior Tribunal, dos legisladores y cuatro abogados inscriptos en la matrícula de la Provincia y domiciliados en ella que reúnan los requisitos para ser miembro del Superior Tribunal; dos designados por organizaciones sociales en representación ciudadana debidamente reconocidas en la defensa del sistema democrático y los derechos humanos. Los restantes integrantes serán sorteados o designados para que el tribunal quede constituido el 1º de enero de cada año.`, plainLanguageExplanation: 'El Jurado de Enjuiciamiento juzga a funcionarios judiciales letrados no sujetos a juicio político. Se integra con miembros del Superior Tribunal, legisladores, abogados matriculados y representantes de organizaciones civiles de derechos humanos.', practicalEffects: [], examples: ['Un juez de Cámara acusado de faltas en el ejercicio de sus funciones comparece ante el Jurado de Enjuiciamiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'funcionarios judiciales', 'integración', 'remoción'], order: 217, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-219', lawId: 'const-entre-rios', number: '219', title: 'Otros funcionarios sujetos al Jurado de Enjuiciamiento', originalText: `El fiscal de Estado, el contador general, el tesorero general de la Provincia, los miembros del Tribunal de Cuentas, el director general de escuelas y vocales del Consejo General de Educación, quedan sometidos al régimen del Jurado de Enjuiciamiento.`, currentText: `El fiscal de Estado, el contador general, el tesorero general de la Provincia, los miembros del Tribunal de Cuentas, el director general de escuelas y vocales del Consejo General de Educación, quedan sometidos al régimen del Jurado de Enjuiciamiento.`, plainLanguageExplanation: 'El Fiscal de Estado, el Contador General, el Tesorero General, los miembros del Tribunal de Cuentas, el Director General de Escuelas y los vocales del Consejo General de Educación son enjuiciables ante el Jurado de Enjuiciamiento.', practicalEffects: [], examples: ['Si el Director General de Escuelas comete una falta grave en el ejercicio de sus funciones, puede ser acusado ante el Jurado de Enjuiciamiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'Fiscal de Estado', 'Tribunal de Cuentas', 'Consejo General de Educación'], order: 218, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-220', lawId: 'const-entre-rios', number: '220', title: 'Procedimiento ante el Jurado de Enjuiciamiento', originalText: `La ley respectiva determinará los delitos y faltas de los funcionarios que autoricen la acusación de los mismos ante el Jurado y reglamentará el procedimiento a que debe ajustarse la sustanciación de las causas promovidas.`, currentText: `La ley respectiva determinará los delitos y faltas de los funcionarios que autoricen la acusación de los mismos ante el Jurado y reglamentará el procedimiento a que debe ajustarse la sustanciación de las causas promovidas.`, plainLanguageExplanation: 'La ley define qué delitos y faltas habilitan la acusación ante el Jurado de Enjuiciamiento y reglamenta el procedimiento que rige la sustanciación de las causas.', practicalEffects: [], examples: ['La ley establece que un juez puede ser acusado ante el Jurado por prevaricato o inconducta reiterada.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'procedimiento', 'acusación', 'ley reglamentaria'], order: 219, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-221', lawId: 'const-entre-rios', number: '221', title: 'Recusación y excusación de miembros del Jurado', originalText: `Los miembros del jurado podrán ser recusados y excusarse por causa fundada, debiendo, en tal caso, integrarse en la forma que prescriba la ley respectiva.`, currentText: `Los miembros del jurado podrán ser recusados y excusarse por causa fundada, debiendo, en tal caso, integrarse en la forma que prescriba la ley respectiva.`, plainLanguageExplanation: 'Los miembros del Jurado pueden ser recusados o excusarse por causa fundada. En ese caso el Jurado se integra conforme lo prescribe la ley.', practicalEffects: [], examples: ['Un miembro del Jurado que tiene amistad íntima con el acusado puede excusarse de intervenir en el juicio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'recusación', 'excusación', 'integración'], order: 220, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-222', lawId: 'const-entre-rios', number: '222', title: 'Suspensión del funcionario acusado ante el Jurado', originalText: `El funcionario acusado podrá ser suspendido en su cargo por el Jurado durante el curso de la sustanciación de la causa.`, currentText: `El funcionario acusado podrá ser suspendido en su cargo por el Jurado durante el curso de la sustanciación de la causa.`, plainLanguageExplanation: 'El Jurado puede suspender preventivamente al funcionario acusado durante la tramitación del juicio de enjuiciamiento.', practicalEffects: [], examples: ['El Jurado suspende a un juez de Cámara con goce de haberes mientras se sustancia su enjuiciamiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'suspensión preventiva', 'funcionario acusado'], order: 221, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-223', lawId: 'const-entre-rios', number: '223', title: 'Veredicto del Jurado de Enjuiciamiento', originalText: `El Jurado pronunciará su veredicto dentro de un término perentorio de treinta días desde que la causa quedare en estado, absolviendo o destituyendo al empleado. En el primer caso, el funcionario quedará restablecido en la posesión de su cargo y, en el segundo, separado definitivamente del mismo, sujeto a la ley ordinaria, debiendo el Jurado comunicar tal hecho a la autoridad correspondiente a efectos de que se proceda a la designación de su reemplazante, en la forma prevista en esta Constitución.`, currentText: `El Jurado pronunciará su veredicto dentro de un término perentorio de treinta días desde que la causa quedare en estado, absolviendo o destituyendo al empleado. En el primer caso, el funcionario quedará restablecido en la posesión de su cargo y, en el segundo, separado definitivamente del mismo, sujeto a la ley ordinaria, debiendo el Jurado comunicar tal hecho a la autoridad correspondiente a efectos de que se proceda a la designación de su reemplazante, en la forma prevista en esta Constitución.`, plainLanguageExplanation: 'El Jurado debe dictar veredicto en 30 días. Si absuelve, el funcionario recupera su cargo; si destituye, queda separado definitivamente y sujeto a la justicia ordinaria.', practicalEffects: [], examples: ['El Jurado destituye a un Contador General por irregularidades en fondos, y el cargo queda vacante para nuevo concurso.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'veredicto', 'destitución', 'absolución', 'plazo'], order: 222, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-224', lawId: 'const-entre-rios', number: '224', title: 'Consecuencia del vencimiento del plazo del Jurado', originalText: `Vencido el término legal sin que medie un pronunciamiento del Jurado, tal omisión crea una presunción, que no admite prueba en contrario, en favor de la inocencia del acusado, quien se reintegrará a la posesión de su cargo, sin que se le puedan oponer los efectos de una condena dictada con posterioridad.`, currentText: `Vencido el término legal sin que medie un pronunciamiento del Jurado, tal omisión crea una presunción, que no admite prueba en contrario, en favor de la inocencia del acusado, quien se reintegrará a la posesión de su cargo, sin que se le puedan oponer los efectos de una condena dictada con posterioridad.`, plainLanguageExplanation: 'Si el Jurado no emite veredicto dentro del plazo legal, se presume inocente al acusado y este se reintegra a su cargo de pleno derecho, sin que una condena posterior pueda afectar ese reintegro.', practicalEffects: [], examples: ['Si el Jurado no resuelve en 30 días, el juez acusado se reintegra a sus funciones de pleno derecho.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'plazo', 'presunción de inocencia', 'reintegro'], order: 223, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-225', lawId: 'const-entre-rios', number: '225', title: 'Sanción al miembro del Jurado remiso', originalText: `Cada uno de los miembros del Jurado, remiso en el desempeño de su cargo, será pasible de la sanción que determine la ley.`, currentText: `Cada uno de los miembros del Jurado, remiso en el desempeño de su cargo, será pasible de la sanción que determine la ley.`, plainLanguageExplanation: 'El miembro del Jurado que no cumple con sus obligaciones queda sujeto a la sanción que determine la ley correspondiente.', practicalEffects: [], examples: ['Un legislador integrante del Jurado que no concurre a las audiencias sin justificación puede ser sancionado conforme a la ley.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'sanción', 'remisión'], order: 224, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-226', lawId: 'const-entre-rios', number: '226', title: 'Designación de miembros y suplentes del Jurado', originalText: `La ley respectiva determinará la forma en que se proveerá a la designación de los miembros del Jurado y suplentes.`, currentText: `La ley respectiva determinará la forma en que se proveerá a la designación de los miembros del Jurado y suplentes.`, plainLanguageExplanation: 'La ley regula el procedimiento para designar a los miembros titulares y suplentes del Jurado de Enjuiciamiento.', practicalEffects: [], examples: ['La ley establece que los abogados integrantes del Jurado se sortean de una lista de candidatos que reúnen los requisitos constitucionales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'designación', 'suplentes'], order: 225, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-227', lawId: 'const-entre-rios', number: '227', title: 'Delitos comunes cometidos por funcionarios enjuiciables', originalText: `Los funcionarios judiciales, enjuiciables ante el Jurado, acusados de delitos ajenos a sus funciones, serán juzgados en la misma forma que los demás habitantes de la Provincia, no pudiendo ser detenidos sin suspensión previa decretada por el Jurado, salvo el caso de infraganti delito.`, currentText: `Los funcionarios judiciales, enjuiciables ante el Jurado, acusados de delitos ajenos a sus funciones, serán juzgados en la misma forma que los demás habitantes de la Provincia, no pudiendo ser detenidos sin suspensión previa decretada por el Jurado, salvo el caso de infraganti delito.`, plainLanguageExplanation: 'Si un funcionario sujeto al Jurado comete un delito común, es juzgado como cualquier ciudadano. Sin embargo, no puede ser detenido sin previa suspensión por el Jurado, excepto en caso de flagrante delito.', practicalEffects: [], examples: ['Un juez acusado de conducción peligrosa de vehículo puede ser investigado penalmente sin enjuiciamiento previo, pero no detenido sin la suspensión del Jurado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'delito común', 'detención', 'infraganti'], order: 226, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-228', lawId: 'const-entre-rios', number: '228', title: 'Comunicación del pronunciamiento judicial al Jurado', originalText: `El pronunciamiento definitivo de la justicia ordinaria será comunicado al Jurado a los efectos del restablecimiento o separación definitiva del funcionario acusado.`, currentText: `El pronunciamiento definitivo de la justicia ordinaria será comunicado al Jurado a los efectos del restablecimiento o separación definitiva del funcionario acusado.`, plainLanguageExplanation: 'La sentencia firme de la justicia ordinaria sobre el funcionario se comunica al Jurado, que procede a restituirlo en su cargo o separarlo definitivamente.', practicalEffects: [], examples: ['Si la justicia penal condena a un juez acusado de delito ajeno a sus funciones, le comunica la sentencia al Jurado para que proceda a la destitución.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Jurado de Enjuiciamiento', 'justicia ordinaria', 'sentencia', 'restablecimiento', 'separación'], order: 227, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-229', lawId: 'const-entre-rios', number: '229', title: 'Concepto de municipio', originalText: `El municipio es una comunidad sociopolítica natural y esencial, con vida urbana propia e intereses específicos que unida por lazos de vecindad y arraigo territorial, concurre en la búsqueda del bien común.`, currentText: `El municipio es una comunidad sociopolítica natural y esencial, con vida urbana propia e intereses específicos que unida por lazos de vecindad y arraigo territorial, concurre en la búsqueda del bien común.`, plainLanguageExplanation: 'El municipio es una comunidad natural con identidad urbana y lazo territorial propio, orientada al bien común de sus vecinos.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['municipio', 'comunidad sociopolítica', 'bien común', 'vecindad', 'autonomía local'], order: 228, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-230', lawId: 'const-entre-rios', number: '230', title: 'Umbral poblacional para constituir municipio', originalText: `Todo centro de población estable de más de mil quinientos habitantes dentro del ejido constituye un municipio, que será gobernado con arreglo a las disposiciones de esta Constitución.`, currentText: `Todo centro de población estable de más de mil quinientos habitantes dentro del ejido constituye un municipio, que será gobernado con arreglo a las disposiciones de esta Constitución.`, plainLanguageExplanation: 'Todo centro de más de 1.500 habitantes constituye un municipio que se rige por esta Constitución.', practicalEffects: [], examples: ['Una localidad de 2.000 habitantes que supera el umbral constitucional pasa a organizarse como municipio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['municipio', 'umbral poblacional', '1500 habitantes', 'ejido'], order: 229, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-231', lawId: 'const-entre-rios', number: '231', title: 'Autonomía de los municipios entrerrianos', originalText: `Se asegura autonomía institucional, política, administrativa, económica y financiera a todos los municipios entrerrianos, los que ejercen sus funciones con independencia de todo otro poder. Los municipios con más de diez mil habitantes podrán dictar sus propias cartas orgánicas.`, currentText: `Se asegura autonomía institucional, política, administrativa, económica y financiera a todos los municipios entrerrianos, los que ejercen sus funciones con independencia de todo otro poder. Los municipios con más de diez mil habitantes podrán dictar sus propias cartas orgánicas.`, plainLanguageExplanation: 'Todos los municipios entrerrianos gozan de autonomía plena. Los que superan los 10.000 habitantes pueden dictar su propia carta orgánica municipal.', practicalEffects: [], examples: ['Paraná, con más de 10.000 habitantes, puede convocar a una Convención para dictar su carta orgánica municipal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['autonomía municipal', 'carta orgánica', '10000 habitantes', 'municipios entrerrianos'], order: 230, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-232', lawId: 'const-entre-rios', number: '232', title: 'Régimen de comunas', originalText: `Las comunidades cuya población estable legalmente determinada no alcance el mínimo previsto para ser municipios constituyen comunas, teniendo las atribuciones que se establezcan.`, currentText: `Las comunidades cuya población estable legalmente determinada no alcance el mínimo previsto para ser municipios constituyen comunas, teniendo las atribuciones que se establezcan.`, plainLanguageExplanation: 'Los asentamientos que no alcanzan el mínimo de habitantes para ser municipio se organizan como comunas con las atribuciones que fije la ley.', practicalEffects: [], examples: ['Un pueblo de 800 habitantes no puede constituirse como municipio sino que se organiza como comuna.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comunas', 'umbral poblacional', 'municipio', 'autonomía local'], order: 231, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-233', lawId: 'const-entre-rios', number: '233', title: 'Órganos del gobierno municipal', originalText: `El gobierno de los municipios está compuesto por dos órganos: uno ejecutivo y otro deliberativo.`, currentText: `El gobierno de los municipios está compuesto por dos órganos: uno ejecutivo y otro deliberativo.`, plainLanguageExplanation: 'El gobierno municipal se organiza en dos órganos: el ejecutivo (presidencia municipal) y el deliberativo (concejo deliberante).', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobierno municipal', 'órgano ejecutivo', 'órgano deliberativo', 'concejo deliberante'], order: 232, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-234', lawId: 'const-entre-rios', number: '234', title: 'Departamento ejecutivo — presidente municipal', originalText: `El departamento ejecutivo está a cargo de un funcionario con el título de presidente municipal, que es elegido por el voto directo del pueblo a simple pluralidad de sufragios. En la misma fórmula y por el mismo período se elegirá un vicepresidente municipal. En caso de empate en el comicio, se convocará a nuevas elecciones dentro del plazo de diez días de concluido el escrutinio, entre las fórmulas que hayan igualado, debiendo el acto eleccionario realizarse dentro de los veinte días subsiguientes. Para ser presidente y vicepresidente municipal, se requiere tener como mínimo veinticinco años de edad y cuatro años de residencia inmediata en la jurisdicción. Durarán cuatro años en el ejercicio de sus funciones, pudiendo ser reelectos o sucederse recíprocamente por un período consecutivo más y luego sólo por períodos alternados. En caso de ausencia definitiva del cargo del presidente municipal, sus funciones serán desempeñadas por el vicepresidente, que las ejercerá durante el resto del período constitucional. Cuando el impedimento sea temporal y no exceda de cinco días hábiles, será reemplazado mientras dure el mismo, por un secretario municipal. Cuando el impedimento exceda el plazo precedentemente señalado, ejercerá sus funciones el vicepresidente municipal.`, currentText: `El departamento ejecutivo está a cargo de un funcionario con el título de presidente municipal, que es elegido por el voto directo del pueblo a simple pluralidad de sufragios. En la misma fórmula y por el mismo período se elegirá un vicepresidente municipal. En caso de empate en el comicio, se convocará a nuevas elecciones dentro del plazo de diez días de concluido el escrutinio, entre las fórmulas que hayan igualado, debiendo el acto eleccionario realizarse dentro de los veinte días subsiguientes. Para ser presidente y vicepresidente municipal, se requiere tener como mínimo veinticinco años de edad y cuatro años de residencia inmediata en la jurisdicción. Durarán cuatro años en el ejercicio de sus funciones, pudiendo ser reelectos o sucederse recíprocamente por un período consecutivo más y luego sólo por períodos alternados. En caso de ausencia definitiva del cargo del presidente municipal, sus funciones serán desempeñadas por el vicepresidente, que las ejercerá durante el resto del período constitucional. Cuando el impedimento sea temporal y no exceda de cinco días hábiles, será reemplazado mientras dure el mismo, por un secretario municipal. Cuando el impedimento exceda el plazo precedentemente señalado, ejercerá sus funciones el vicepresidente municipal.`, plainLanguageExplanation: 'El presidente municipal es elegido por voto directo por 4 años. Puede ser reelecto una vez consecutiva y luego solo en períodos alternados. El vicepresidente lo reemplaza en ausencia definitiva.', practicalEffects: [], examples: ['Un presidente municipal que completa su segundo mandato consecutivo debe esperar un período antes de volver a postularse.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presidente municipal', 'vicepresidente municipal', 'elección directa', 'reelección', 'mandato'], order: 233, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-235', lawId: 'const-entre-rios', number: '235', title: 'Obligaciones del departamento ejecutivo municipal', originalText: `El departamento ejecutivo está obligado a cumplir y hacer cumplir las ordenanzas dictadas por el concejo deliberante, administrar los intereses locales y remitir anualmente una memoria y la cuenta de percepción e inversión de su administración para su aprobación. Ejercerá la representación del municipio y demás atribuciones que la carta o ley orgánica prescriban.`, currentText: `El departamento ejecutivo está obligado a cumplir y hacer cumplir las ordenanzas dictadas por el concejo deliberante, administrar los intereses locales y remitir anualmente una memoria y la cuenta de percepción e inversión de su administración para su aprobación. Ejercerá la representación del municipio y demás atribuciones que la carta o ley orgánica prescriban.`, plainLanguageExplanation: 'El Ejecutivo municipal debe cumplir las ordenanzas del concejo deliberante, administrar los intereses locales y presentar anualmente la rendición de cuentas de su gestión.', practicalEffects: [], examples: ['El presidente municipal debe presentar ante el concejo deliberante la rendición de cuentas del año anterior antes del 31 de marzo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['departamento ejecutivo', 'ordenanzas', 'rendición de cuentas', 'administración local'], order: 234, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-236', lawId: 'const-entre-rios', number: '236', title: 'Concejo deliberante — integración y mandato', originalText: `El órgano deliberativo está integrado por un concejo deliberante presidido por el vicepresidente municipal, cuyos restantes miembros son elegidos directamente por el pueblo de acuerdo al sistema de representación proporcional, en la forma que establece el artículo 91 de esta Constitución. El número de concejales será determinado por la carta o ley orgánica, según corresponda. Su mandato se extiende a cuatro años. Para acceder al cargo se requiere mayoría de edad y tener como mínimo cuatro años de residencia inmediata en el municipio. En las deliberaciones el vicepresidente tiene voz, y sólo vota en caso de empate. Los concejales elegirán de su seno un vicepresidente primero y un vicepresidente segundo, que desempeñarán el cargo, por su orden, en defecto del presidente del concejo.`, currentText: `El órgano deliberativo está integrado por un concejo deliberante presidido por el vicepresidente municipal, cuyos restantes miembros son elegidos directamente por el pueblo de acuerdo al sistema de representación proporcional, en la forma que establece el artículo 91 de esta Constitución. El número de concejales será determinado por la carta o ley orgánica, según corresponda. Su mandato se extiende a cuatro años. Para acceder al cargo se requiere mayoría de edad y tener como mínimo cuatro años de residencia inmediata en el municipio. En las deliberaciones el vicepresidente tiene voz, y sólo vota en caso de empate. Los concejales elegirán de su seno un vicepresidente primero y un vicepresidente segundo, que desempeñarán el cargo, por su orden, en defecto del presidente del concejo.`, plainLanguageExplanation: 'El concejo deliberante es presidido por el vicepresidente municipal. Los concejales se eligen por representación proporcional por 4 años. El vicepresidente solo vota en caso de empate.', practicalEffects: [], examples: ['Si hay empate en una votación del concejo, el vicepresidente municipal desempata con su voto.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concejo deliberante', 'representación proporcional', 'concejales', 'mandato', 'vicepresidente municipal'], order: 235, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-237', lawId: 'const-entre-rios', number: '237', title: 'Dictado de carta orgánica municipal por Convención', originalText: `Los municipios habilitados por esta Constitución podrán dictar su carta orgánica por medio de una Convención, convocada por el departamento ejecutivo en virtud de ordenanza sancionada al efecto, en fecha que no podrá coincidir con otros actos eleccionarios. La Convención estará integrada por un número igual al doble de los miembros del concejo deliberante. Los convencionales serán elegidos por el pueblo de sus respectivas jurisdicciones, por el sistema de representación proporcional y deberán cumplir su función en un plazo no mayor de tres meses contados a partir de su integración, prorrogable por igual período. Para ser convencional se requieren las mismas condiciones exigidas para concejal. El cargo de convencional es compatible con cualquier otro cargo público nacional, provincial o municipal que no sea el de gobernador, vicegobernador, ministro, magistrado judicial, presidente y vicepresidente municipal, concejal, legislador y jefe de policía. La ordenanza de convocatoria determinará los demás aspectos del régimen electoral y establecerá el presupuesto de la Convención.`, currentText: `Los municipios habilitados por esta Constitución podrán dictar su carta orgánica por medio de una Convención, convocada por el departamento ejecutivo en virtud de ordenanza sancionada al efecto, en fecha que no podrá coincidir con otros actos eleccionarios. La Convención estará integrada por un número igual al doble de los miembros del concejo deliberante. Los convencionales serán elegidos por el pueblo de sus respectivas jurisdicciones, por el sistema de representación proporcional y deberán cumplir su función en un plazo no mayor de tres meses contados a partir de su integración, prorrogable por igual período. Para ser convencional se requieren las mismas condiciones exigidas para concejal. El cargo de convencional es compatible con cualquier otro cargo público nacional, provincial o municipal que no sea el de gobernador, vicegobernador, ministro, magistrado judicial, presidente y vicepresidente municipal, concejal, legislador y jefe de policía. La ordenanza de convocatoria determinará los demás aspectos del régimen electoral y establecerá el presupuesto de la Convención.`, plainLanguageExplanation: 'Los municipios habilitados pueden dictar su carta orgánica mediante una Convención convocada por el ejecutivo. Los convencionales se eligen por representación proporcional y tienen hasta 3 meses (prorrogable por igual período) para aprobar la carta.', practicalEffects: [], examples: ['El municipio de Concordia convoca a una Convención para redactar su carta orgánica, con convencionales elegidos por los vecinos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carta orgánica', 'Convención', 'convencionales', 'municipio', 'representación proporcional'], order: 236, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-238', lawId: 'const-entre-rios', number: '238', title: 'Contenidos mínimos de la carta orgánica municipal', originalText: `Las cartas orgánicas municipales deberán observar lo dispuesto en los artículos 234 y 236 precedentes y en particular deberán asegurar: a) Los principios del régimen democrático, participativo, representativo y republicano, la elección directa de sus autoridades y el voto universal, igual, secreto y obligatorio que incluya a los extranjeros. b) Un régimen electoral directo para presidente y vicepresidente municipal y los concejales y la adopción para la asignación de bancas en el concejo de un sistema de representación proporcional que asegure la participación efectiva de las minorías, con arreglo a lo establecido en el artículo 91 de esta Constitución. c) La adopción de normas de ética pública con ajuste a las pautas establecidas por esta Constitución. d) Un sistema de contralor interno y un organismo de control externo de las cuentas públicas. e) El derecho de consulta, iniciativa, referéndum, plebiscito y revocatoria de mandato. f) El procedimiento para su reforma.`, currentText: `Las cartas orgánicas municipales deberán observar lo dispuesto en los artículos 234 y 236 precedentes y en particular deberán asegurar: a) Los principios del régimen democrático, participativo, representativo y republicano, la elección directa de sus autoridades y el voto universal, igual, secreto y obligatorio que incluya a los extranjeros. b) Un régimen electoral directo para presidente y vicepresidente municipal y los concejales y la adopción para la asignación de bancas en el concejo de un sistema de representación proporcional que asegure la participación efectiva de las minorías, con arreglo a lo establecido en el artículo 91 de esta Constitución. c) La adopción de normas de ética pública con ajuste a las pautas establecidas por esta Constitución. d) Un sistema de contralor interno y un organismo de control externo de las cuentas públicas. e) El derecho de consulta, iniciativa, referéndum, plebiscito y revocatoria de mandato. f) El procedimiento para su reforma.`, plainLanguageExplanation: 'Las cartas orgánicas deben garantizar democracia, representación proporcional, ética pública, control de cuentas, mecanismos de democracia semidirecta (referéndum, revocatoria) y procedimiento de reforma.', practicalEffects: [], examples: ['La carta orgánica de Paraná debe incluir el referéndum y la revocatoria de mandato entre sus mecanismos de participación ciudadana.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carta orgánica', 'contenidos mínimos', 'democracia semidirecta', 'ética pública', 'control de cuentas'], order: 237, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-239', lawId: 'const-entre-rios', number: '239', title: 'Municipios sin carta orgánica — ley orgánica', originalText: `Se regirán por ley orgánica los municipios habilitados para dictar sus propias cartas mientras no hagan uso de ese derecho, y los restantes previstos en esta Constitución.`, currentText: `Se regirán por ley orgánica los municipios habilitados para dictar sus propias cartas mientras no hagan uso de ese derecho, y los restantes previstos en esta Constitución.`, plainLanguageExplanation: 'Los municipios que aún no dictaron su carta orgánica, y los que no alcanzan el umbral para hacerlo, se rigen por la ley orgánica municipal provincial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['municipio', 'ley orgánica', 'carta orgánica', 'régimen subsidiario'], order: 238, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-240', lawId: 'const-entre-rios', number: '240', title: 'Competencias municipales', originalText: `Los municipios tienen las siguientes competencias: 1º. Gobernar y administrar los intereses locales orientados al bien común. 2º. Convocar a los comicios para la elección de las autoridades municipales. La validez o nulidad de la elección, la proclamación de los electos y la expedición de los diplomas respectivos estará a cargo de los organismos electorales previsto en el artículo 87, inciso 13º, de esta Constitución. 3º. Juzgar políticamente a sus autoridades en la forma establecida en la respectiva carta o ley orgánica municipal. 4º. Nombrar y remover a sus funcionarios y agentes. 5º. Concertar convenios colectivos de trabajo y preservar los sistemas locales de seguridad social existentes. 6º. Proponer las ternas para la designación de los jueces de paz de la circunscripción. 7º. Regular el procedimiento para el juzgamiento de las infracciones que corresponda aplicar y fijar las sanciones correspondientes. 8º. Establecer los órganos que intervendrán en el juzgamiento y sanción de las infracciones municipales, organizando un régimen jurisdiccional a cargo de jueces de faltas, fijando una instancia de apelación. Los funcionarios que ejerzan tales roles serán designados a través de un procedimiento que garantice la idoneidad de sus integrantes. 9º. Crear la Defensoría del Pueblo. 10º. Confeccionar y aprobar su presupuesto de gastos y cálculo de recursos. 11º. Establecer, recaudar y administrar sus recursos, rentas y bienes propios. 12º. Regular, disponer y administrar, en su ámbito de aplicación, los bienes del dominio público y privado municipal. 13º. Administrar las tierras fiscales ubicadas dentro del ejido e incorporar a través de los trámites pertinentes, los bienes que les correspondan. 14º. La atención primaria de la salud, a su expreso requerimiento, y con la consiguiente transferencia de recursos. 15º. Establecer políticas públicas para la integración de personas con discapacidad. 16º. Contraer empréstitos con objeto determinado. 17º. Disponer restricciones y servidumbres administrativas al dominio. 18º. Interesar la necesidad de expropiación por causa de utilidad pública, solicitando a la Provincia el dictado de la ley respectiva con derecho de iniciativa legislativa. 19º. Realizar las obras públicas y prestar los servicios de naturaleza o interés municipal. 20º. Promover la creación de cinturones frutihortícolas. 21º. Ejercer el poder de policía y funciones respecto a: a) Planeamiento y desarrollo social. b) Salud pública, asistencia social y educación, en lo que sea de su competencia. c) Seguridad, higiene, bromatología, pesas y medidas. d) Planeamiento y ordenamiento territorial, vialidad, rutas y caminos, apertura, construcción y mantenimiento de calles. e) Planes edilicios, control de la construcción, política de vivienda, diseño y estética urbana, plazas, paseos, edificios públicos y uso de espacios públicos. f) Tránsito y transporte urbanos. g) Protección del ambiente, del equilibrio ecológico y la estética paisajística. Podrán ejercer acciones de protección ambiental más allá de sus límites territoriales, en tanto se estén afectando o puedan afectarse los intereses locales. h) Servicios fúnebres y cementerios. i) Abastecimiento, mercados, plantas de faenas, proceso y transformación, cuya producción se destine al consumo. j) Defensa de los derechos de usuarios y consumidores. k) Turismo, deportes, actividades recreativas y espectáculos públicos. 22º. Fomentar instituciones culturales y expresiones artísticas y artesanales. 23º. Preservar y defender el patrimonio histórico cultural, artístico y arquitectónico. 24º. Concertar con la Nación, las provincias y otros municipios y comunas, convenios interjurisdiccionales, pudiendo crear entes o consorcios con conocimiento de la Legislatura. 25º. Ejercer cualquier otra competencia de interés municipal no enunciada por esta Constitución y las que sean indispensables para hacer efectivos sus fines.`, currentText: `Los municipios tienen las siguientes competencias: 1º. Gobernar y administrar los intereses locales orientados al bien común. 2º. Convocar a los comicios para la elección de las autoridades municipales. La validez o nulidad de la elección, la proclamación de los electos y la expedición de los diplomas respectivos estará a cargo de los organismos electorales previsto en el artículo 87, inciso 13º, de esta Constitución. 3º. Juzgar políticamente a sus autoridades en la forma establecida en la respectiva carta o ley orgánica municipal. 4º. Nombrar y remover a sus funcionarios y agentes. 5º. Concertar convenios colectivos de trabajo y preservar los sistemas locales de seguridad social existentes. 6º. Proponer las ternas para la designación de los jueces de paz de la circunscripción. 7º. Regular el procedimiento para el juzgamiento de las infracciones que corresponda aplicar y fijar las sanciones correspondientes. 8º. Establecer los órganos que intervendrán en el juzgamiento y sanción de las infracciones municipales, organizando un régimen jurisdiccional a cargo de jueces de faltas, fijando una instancia de apelación. Los funcionarios que ejerzan tales roles serán designados a través de un procedimiento que garantice la idoneidad de sus integrantes. 9º. Crear la Defensoría del Pueblo. 10º. Confeccionar y aprobar su presupuesto de gastos y cálculo de recursos. 11º. Establecer, recaudar y administrar sus recursos, rentas y bienes propios. 12º. Regular, disponer y administrar, en su ámbito de aplicación, los bienes del dominio público y privado municipal. 13º. Administrar las tierras fiscales ubicadas dentro del ejido e incorporar a través de los trámites pertinentes, los bienes que les correspondan. 14º. La atención primaria de la salud, a su expreso requerimiento, y con la consiguiente transferencia de recursos. 15º. Establecer políticas públicas para la integración de personas con discapacidad. 16º. Contraer empréstitos con objeto determinado. 17º. Disponer restricciones y servidumbres administrativas al dominio. 18º. Interesar la necesidad de expropiación por causa de utilidad pública, solicitando a la Provincia el dictado de la ley respectiva con derecho de iniciativa legislativa. 19º. Realizar las obras públicas y prestar los servicios de naturaleza o interés municipal. 20º. Promover la creación de cinturones frutihortícolas. 21º. Ejercer el poder de policía y funciones respecto a: a) Planeamiento y desarrollo social. b) Salud pública, asistencia social y educación, en lo que sea de su competencia. c) Seguridad, higiene, bromatología, pesas y medidas. d) Planeamiento y ordenamiento territorial, vialidad, rutas y caminos, apertura, construcción y mantenimiento de calles. e) Planes edilicios, control de la construcción, política de vivienda, diseño y estética urbana, plazas, paseos, edificios públicos y uso de espacios públicos. f) Tránsito y transporte urbanos. g) Protección del ambiente, del equilibrio ecológico y la estética paisajística. Podrán ejercer acciones de protección ambiental más allá de sus límites territoriales, en tanto se estén afectando o puedan afectarse los intereses locales. h) Servicios fúnebres y cementerios. i) Abastecimiento, mercados, plantas de faenas, proceso y transformación, cuya producción se destine al consumo. j) Defensa de los derechos de usuarios y consumidores. k) Turismo, deportes, actividades recreativas y espectáculos públicos. 22º. Fomentar instituciones culturales y expresiones artísticas y artesanales. 23º. Preservar y defender el patrimonio histórico cultural, artístico y arquitectónico. 24º. Concertar con la Nación, las provincias y otros municipios y comunas, convenios interjurisdiccionales, pudiendo crear entes o consorcios con conocimiento de la Legislatura. 25º. Ejercer cualquier otra competencia de interés municipal no enunciada por esta Constitución y las que sean indispensables para hacer efectivos sus fines.`, plainLanguageExplanation: 'Los municipios tienen 25 competencias propias: gobierno local, elecciones, administración, tributación, obras y servicios públicos, salud, educación, medio ambiente, tránsito, cultura y patrimonio, entre otras.', practicalEffects: [], examples: ['El municipio de Gualeguaychú puede regular el tránsito urbano y cobrar multas de tránsito en el ejido municipal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['competencias municipales', 'poder de policía', 'obras públicas', 'servicios públicos', 'tributación municipal'], order: 239, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-241', lawId: 'const-entre-rios', number: '241', title: 'Habilitación de la vía contencioso-administrativa municipal', originalText: `Se establece a los fines de la habilitación de la vía judicial contencioso administrativa que la instancia quedará agotada con la denegación expresa o tácita dictada, según los casos, por el presidente municipal y el vicepresidente municipal respecto de los asuntos administrativos del concejo deliberante.`, currentText: `Se establece a los fines de la habilitación de la vía judicial contencioso administrativa que la instancia quedará agotada con la denegación expresa o tácita dictada, según los casos, por el presidente municipal y el vicepresidente municipal respecto de los asuntos administrativos del concejo deliberante.`, plainLanguageExplanation: 'La vía judicial contencioso-administrativa queda habilitada cuando el presidente o vicepresidente municipal deniega expresa o tácitamente un asunto administrativo del concejo deliberante.', practicalEffects: [], examples: ['Si el presidente municipal no responde un recurso del concejo en el plazo legal, la denegatoria tácita habilita la vía judicial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contencioso-administrativo', 'denegatoria', 'presidente municipal', 'concejo deliberante'], order: 240, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-242', lawId: 'const-entre-rios', number: '242', title: 'Habilitaciones adicionales de los municipios', originalText: `Para el cumplimento de sus competencias, el municipio está habilitado a: a) Promover en la comunidad la participación activa de los pobladores, juntas vecinales y demás organizaciones intermedias. b) Formar parte de organismos de carácter regional, realizar gestiones y celebrar acuerdos en el orden internacional respetando las facultades de los gobiernos federal y provincial. c) Ejercer, en los establecimientos de utilidad nacional y provincial, los poderes municipales compatibles con la finalidad y competencias de aquellos.`, currentText: `Para el cumplimento de sus competencias, el municipio está habilitado a: a) Promover en la comunidad la participación activa de los pobladores, juntas vecinales y demás organizaciones intermedias. b) Formar parte de organismos de carácter regional, realizar gestiones y celebrar acuerdos en el orden internacional respetando las facultades de los gobiernos federal y provincial. c) Ejercer, en los establecimientos de utilidad nacional y provincial, los poderes municipales compatibles con la finalidad y competencias de aquellos.`, plainLanguageExplanation: 'Los municipios también pueden fomentar la participación ciudadana, integrar organismos regionales y ejercer poderes municipales en establecimientos de utilidad nacional o provincial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['municipios', 'participación ciudadana', 'organismos regionales', 'habilitaciones'], order: 241, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-243', lawId: 'const-entre-rios', number: '243', title: 'Composición del tesoro municipal', originalText: `El tesoro del municipio estará formado por: 1º. Lo recaudado en concepto de impuestos, tasas, derechos, contribuciones, cánones, regalías y demás tributos. 2º. Los ingresos percibidos en concepto de coparticipaciones provincial y federal. 3º. Las rentas derivadas de los actos de administración y el capital proveniente de la enajenación de sus bienes. 4º. El producido de las multas que imponga en ejercicio de sus competencias. 5º. Los empréstitos, operaciones de crédito, donaciones, legados y subsidios. 6º. Todo otro ingreso propio de la naturaleza y competencia municipal definida en esta Constitución.`, currentText: `El tesoro del municipio estará formado por: 1º. Lo recaudado en concepto de impuestos, tasas, derechos, contribuciones, cánones, regalías y demás tributos. 2º. Los ingresos percibidos en concepto de coparticipaciones provincial y federal. 3º. Las rentas derivadas de los actos de administración y el capital proveniente de la enajenación de sus bienes. 4º. El producido de las multas que imponga en ejercicio de sus competencias. 5º. Los empréstitos, operaciones de crédito, donaciones, legados y subsidios. 6º. Todo otro ingreso propio de la naturaleza y competencia municipal definida en esta Constitución.`, plainLanguageExplanation: 'El tesoro municipal se integra con impuestos, tasas, coparticipación provincial y federal, rentas de bienes, multas, empréstitos y todo ingreso municipal.', practicalEffects: [], examples: ['Los ingresos de la tasa de barrido y alumbrado más las transferencias de coparticipación integran el tesoro del municipio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tesoro municipal', 'coparticipación', 'impuestos', 'tasas', 'recursos municipales'], order: 242, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-244', lawId: 'const-entre-rios', number: '244', title: 'Facultad tributaria exclusiva de los municipios', originalText: `Los municipios ejercerán de modo exclusivo su facultad de imposición respecto a personas, cosas o actividades sujetas a su jurisdicción, respetando los principios de la tributación y la armonización con los regímenes impositivos provincial y federal.`, currentText: `Los municipios ejercerán de modo exclusivo su facultad de imposición respecto a personas, cosas o actividades sujetas a su jurisdicción, respetando los principios de la tributación y la armonización con los regímenes impositivos provincial y federal.`, plainLanguageExplanation: 'Los municipios ejercen de modo exclusivo su potestad tributaria en su jurisdicción, coordinándose con los regímenes provincial y federal.', practicalEffects: [], examples: ['El municipio puede crear una tasa de habilitación comercial que no sea idéntica a un impuesto provincial ya existente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultad tributaria', 'municipio', 'exclusividad', 'armonización impositiva'], order: 243, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-245', lawId: 'const-entre-rios', number: '245', title: 'Criterios de coparticipación impositiva municipal', originalText: `La asignación de la coparticipación a municipios y comunas se efectuará, teniendo en cuenta, para la distribución primaria, las competencias, servicios y funciones de la Provincia y el conjunto de municipios, y para la distribución secundaria criterios objetivos de reparto que contemplen los principios de proporcionalidad y redistribución solidaria, mediante aplicación de indicadores devolutivos, redistributivos y de eficiencia fiscal que tiendan a lograr un grado equivalente de desarrollo y de calidad de vida de los habitantes.`, currentText: `La asignación de la coparticipación a municipios y comunas se efectuará, teniendo en cuenta, para la distribución primaria, las competencias, servicios y funciones de la Provincia y el conjunto de municipios, y para la distribución secundaria criterios objetivos de reparto que contemplen los principios de proporcionalidad y redistribución solidaria, mediante aplicación de indicadores devolutivos, redistributivos y de eficiencia fiscal que tiendan a lograr un grado equivalente de desarrollo y de calidad de vida de los habitantes.`, plainLanguageExplanation: 'La distribución de coparticipación a municipios y comunas considera competencias, servicios y criterios objetivos de proporcionalidad y redistribución solidaria entre las jurisdicciones.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['coparticipación', 'distribución primaria', 'distribución secundaria', 'municipios', 'comunas'], order: 244, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-246', lawId: 'const-entre-rios', number: '246', title: 'Sistema de coparticipación garantizada a municipios', originalText: `Esta Constitución garantiza el siguiente sistema de coparticipación impositiva obligatoria: a) Impuestos Nacionales: de la totalidad de los ingresos tributarios que a la Provincia le correspondan en concepto de coparticipación federal de impuestos nacionales, sea por régimen general u otro que lo complemente o sustituya y que no tengan afectación específica, el monto a distribuir a los municipios no podrá ser inferior al dieciséis por ciento y a las comunas, al uno por ciento. b) Impuestos Provinciales: de la totalidad de la recaudación de los ingresos tributarios provinciales, el monto a distribuir a los municipios no podrá ser inferior al dieciocho por ciento y a las comunas al uno por ciento. La Provincia transferirá automática y diariamente, el monto de dichas coparticipaciones. No habrá transferencia de competencias, servicios o funciones sin la respectiva asignación de recursos aprobada por ley y ratificada por ordenanza del municipio o comuna.`, currentText: `Esta Constitución garantiza el siguiente sistema de coparticipación impositiva obligatoria: a) Impuestos Nacionales: de la totalidad de los ingresos tributarios que a la Provincia le correspondan en concepto de coparticipación federal de impuestos nacionales, sea por régimen general u otro que lo complemente o sustituya y que no tengan afectación específica, el monto a distribuir a los municipios no podrá ser inferior al dieciséis por ciento y a las comunas, al uno por ciento. b) Impuestos Provinciales: de la totalidad de la recaudación de los ingresos tributarios provinciales, el monto a distribuir a los municipios no podrá ser inferior al dieciocho por ciento y a las comunas al uno por ciento. La Provincia transferirá automática y diariamente, el monto de dichas coparticipaciones. No habrá transferencia de competencias, servicios o funciones sin la respectiva asignación de recursos aprobada por ley y ratificada por ordenanza del municipio o comuna.`, plainLanguageExplanation: 'La Constitución garantiza que los municipios reciban mínimo el 18% de la coparticipación provincial y el 16% de la federal. Las comunas reciben mínimo el 1% de cada fuente. La transferencia es automática y diaria.', practicalEffects: [], examples: ['Si la recaudación del impuesto sobre ingresos brutos provinciales es de $100.000, el conjunto de municipios recibe al menos $18.000.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['coparticipación garantizada', 'municipios', 'comunas', 'automaticidad', 'impuestos provinciales', 'impuestos nacionales'], order: 245, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-247', lawId: 'const-entre-rios', number: '247', title: 'Empréstitos municipales — condiciones y límites', originalText: `Los municipios podrán contraer empréstitos, destinados exclusivamente a la inversión en bienes de capital o en obras y servicios públicos de infraestructura, no pudiendo ser autorizados para equilibrar los gastos ordinarios de la administración. Se requerirá la mayoría absoluta de la totalidad de los miembros del concejo deliberante. En todo empréstito deberá establecerse su monto, plazo, destino, tasa de interés, servicios de amortización y los recursos que se afecten en garantía. Los servicios de amortización por capital e intereses no deberán comprometer, en conjunto, más del veinte por ciento de la renta. En situaciones excepcionales, debidamente fundadas y con el voto de las dos terceras partes de la totalidad de los miembros del concejo deliberante, podrán contraer empréstitos para financiar gastos corrientes, los que deberán tener fecha de vencimiento y ser cancelados durante el período de la gestión de los funcionarios que los suscriben.`, currentText: `Los municipios podrán contraer empréstitos, destinados exclusivamente a la inversión en bienes de capital o en obras y servicios públicos de infraestructura, no pudiendo ser autorizados para equilibrar los gastos ordinarios de la administración. Se requerirá la mayoría absoluta de la totalidad de los miembros del concejo deliberante. En todo empréstito deberá establecerse su monto, plazo, destino, tasa de interés, servicios de amortización y los recursos que se afecten en garantía. Los servicios de amortización por capital e intereses no deberán comprometer, en conjunto, más del veinte por ciento de la renta. En situaciones excepcionales, debidamente fundadas y con el voto de las dos terceras partes de la totalidad de los miembros del concejo deliberante, podrán contraer empréstitos para financiar gastos corrientes, los que deberán tener fecha de vencimiento y ser cancelados durante el período de la gestión de los funcionarios que los suscriben.`, plainLanguageExplanation: 'Los municipios solo pueden tomar deuda para inversión en capital o infraestructura, con mayoría absoluta del concejo. El servicio de deuda no puede superar el 20% de la renta. Excepcionalmente, con 2/3 del concejo, pueden financiar gastos corrientes.', practicalEffects: [], examples: ['Un municipio que quiere construir un hospital puede tomar un empréstito si el servicio de deuda no supera el 20% de su renta anual.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['empréstitos municipales', 'concejo deliberante', 'inversión', 'infraestructura', 'límite de deuda'], order: 246, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-248', lawId: 'const-entre-rios', number: '248', title: 'Protección de recursos municipales ante ejecuciones', originalText: `Esta Constitución declara que los recursos de los municipios y comunas son indispensables para el normal funcionamiento de los servicios públicos, independientemente de que aquellos como personas jurídicas públicas puedan ser judicialmente demandados, sin necesidad de autorización previa y sin privilegio alguno. Si fueran condenados al pago de una deuda, sólo podrán ser ejecutados en la forma ordinaria y embargadas sus rentas hasta un veinte por ciento, presumiéndose que la proporción restante como así también los recursos propios serán destinados al pago de emolumentos remuneratorios, de carácter alimentario y a la satisfacción de obras o servicios públicos esenciales, cuya prestación no puede cancelarse, suspenderse o diferirse sin afectar la cobertura de necesidades básicas de la población. Se exceptúan de esta disposición las rentas o bienes especialmente afectados en garantía de una obligación. Por ordenanza podrá autorizarse un embargo mayor, que no podrá superar el treinta y cinco por ciento de sus rentas.`, currentText: `Esta Constitución declara que los recursos de los municipios y comunas son indispensables para el normal funcionamiento de los servicios públicos, independientemente de que aquellos como personas jurídicas públicas puedan ser judicialmente demandados, sin necesidad de autorización previa y sin privilegio alguno. Si fueran condenados al pago de una deuda, sólo podrán ser ejecutados en la forma ordinaria y embargadas sus rentas hasta un veinte por ciento, presumiéndose que la proporción restante como así también los recursos propios serán destinados al pago de emolumentos remuneratorios, de carácter alimentario y a la satisfacción de obras o servicios públicos esenciales, cuya prestación no puede cancelarse, suspenderse o diferirse sin afectar la cobertura de necesidades básicas de la población. Se exceptúan de esta disposición las rentas o bienes especialmente afectados en garantía de una obligación. Por ordenanza podrá autorizarse un embargo mayor, que no podrá superar el treinta y cinco por ciento de sus rentas.`, plainLanguageExplanation: 'Si un municipio es condenado a pagar una deuda, solo se pueden embargar sus rentas hasta el 20% (o 35% por ordenanza), preservando el resto para servicios esenciales y salarios.', practicalEffects: [], examples: ['Un acreedor que ganó un juicio contra un municipio solo puede embargar hasta el 20% de sus rentas municipales ordinarias.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['recursos municipales', 'embargo', 'servicios públicos', 'personas jurídicas públicas', 'límite de embargo'], order: 247, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-249', lawId: 'const-entre-rios', number: '249', title: 'Cese del presidente o vicepresidente municipal', originalText: `El presidente o vicepresidente municipal cesarán en sus cargos de pleno derecho en caso de recibir condena penal firme que acarree inhabilitación por delito cometido contra la administración pública. Por voto de los dos tercios del concejo deliberante serán destituidos por causa de incapacidad sobreviniente que les impida desempeñar sus cargos.`, currentText: `El presidente o vicepresidente municipal cesarán en sus cargos de pleno derecho en caso de recibir condena penal firme que acarree inhabilitación por delito cometido contra la administración pública. Por voto de los dos tercios del concejo deliberante serán destituidos por causa de incapacidad sobreviniente que les impida desempeñar sus cargos.`, plainLanguageExplanation: 'El presidente o vicepresidente municipal cesa de pleno derecho ante condena penal firme con inhabilitación por delito contra la administración pública. También puede ser destituido por 2/3 del concejo por incapacidad sobreviniente.', practicalEffects: [], examples: ['Un presidente municipal condenado por malversación de fondos cesa automáticamente en su cargo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presidente municipal', 'cese', 'condena penal', 'inhabilitación', 'administración pública'], order: 248, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-250', lawId: 'const-entre-rios', number: '250', title: 'Corrección y exclusión de concejales por el concejo', originalText: `El concejo deliberante podrá, con el voto favorable de los dos tercios de la totalidad de sus miembros, corregir y aun excluir de su seno a cualquier concejal por desorden de conducta en el ejercicio de sus funciones o por causa de incapacidad sobreviniente que le impida desempeñar su cargo. Cesarán en su cargo de pleno derecho en caso de recibir condena penal firme que acarree inhabilitación por delito cometido contra la administración pública.`, currentText: `El concejo deliberante podrá, con el voto favorable de los dos tercios de la totalidad de sus miembros, corregir y aun excluir de su seno a cualquier concejal por desorden de conducta en el ejercicio de sus funciones o por causa de incapacidad sobreviniente que le impida desempeñar su cargo. Cesarán en su cargo de pleno derecho en caso de recibir condena penal firme que acarree inhabilitación por delito cometido contra la administración pública.`, plainLanguageExplanation: 'El concejo puede corregir o excluir a un concejal por desorden de conducta o incapacidad sobreviniente, con 2/3 del total de miembros. También cesan de pleno derecho ante condena penal con inhabilitación por delito contra la administración pública.', practicalEffects: [], examples: ['Un concejal que habitualmente perturba el orden de las sesiones puede ser excluido por los 2/3 del concejo deliberante.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concejal', 'exclusión', 'concejo deliberante', 'condena penal', 'administración pública'], order: 249, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-251', lawId: 'const-entre-rios', number: '251', title: 'Electores municipales y comunales', originalText: `Son electores municipales y comunales: 1º. Los argentinos inscriptos en el registro electoral correspondiente. 2º. Los extranjeros con más de dos años de domicilio inmediato y continuo en el municipio al tiempo de su inscripción en el padrón, que sepan leer y escribir en idioma nacional y se hallen inscriptos en un registro especial, cuyas formalidades y demás requisitos determinará la carta o la ley orgánica.`, currentText: `Son electores municipales y comunales: 1º. Los argentinos inscriptos en el registro electoral correspondiente. 2º. Los extranjeros con más de dos años de domicilio inmediato y continuo en el municipio al tiempo de su inscripción en el padrón, que sepan leer y escribir en idioma nacional y se hallen inscriptos en un registro especial, cuyas formalidades y demás requisitos determinará la carta o la ley orgánica.`, plainLanguageExplanation: 'Son electores municipales los argentinos inscriptos y los extranjeros con más de 2 años de domicilio continuo que saben leer y escribir en español y se inscriben en el padrón especial.', practicalEffects: [], examples: ['Un ciudadano italiano con 3 años de domicilio en el municipio puede votar en las elecciones municipales si se inscribió en el padrón especial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['electores municipales', 'extranjeros', 'domicilio', 'padrón electoral', 'voto'], order: 250, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-252', lawId: 'const-entre-rios', number: '252', title: 'Incompatibilidades de autoridades municipales', originalText: `La carta o la ley orgánica deberán establecer el régimen de incompatibilidades para el presidente y vicepresidente municipal, miembros del concejo deliberante y demás funcionarios.`, currentText: `La carta o la ley orgánica deberán establecer el régimen de incompatibilidades para el presidente y vicepresidente municipal, miembros del concejo deliberante y demás funcionarios.`, plainLanguageExplanation: 'La carta orgánica o ley orgánica debe fijar el régimen de incompatibilidades para el presidente municipal, vicepresidente, concejales y demás funcionarios municipales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidades', 'presidente municipal', 'concejales', 'carta orgánica'], order: 251, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-253', lawId: 'const-entre-rios', number: '253', title: 'Organización y régimen de comunas', originalText: `La ley reglamentará el régimen de las comunas y determinará su circunscripción territorial y categorías, asegurando su organización bajo los principios del sistema democrático, con elección directa de sus autoridades, competencias y asignación de recursos. Se incluye la potestad para el dictado de ordenanzas, alcance de sus facultades tributarias, el ejercicio del poder de policía, la realización de obras públicas, la prestación de los servicios básicos, la regulación de la forma de adquisición de bienes y las demás facultades que se estimen pertinentes.`, currentText: `La ley reglamentará el régimen de las comunas y determinará su circunscripción territorial y categorías, asegurando su organización bajo los principios del sistema democrático, con elección directa de sus autoridades, competencias y asignación de recursos. Se incluye la potestad para el dictado de ordenanzas, alcance de sus facultades tributarias, el ejercicio del poder de policía, la realización de obras públicas, la prestación de los servicios básicos, la regulación de la forma de adquisición de bienes y las demás facultades que se estimen pertinentes.`, plainLanguageExplanation: 'La ley regula las comunas: sus categorías, organización democrática, elección directa de autoridades, tributación, poder de policía, obras públicas, servicios y otras facultades pertinentes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comunas', 'ley reglamentaria', 'organización democrática', 'autonomía local'], order: 252, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-254', lawId: 'const-entre-rios', number: '254', title: 'Asociación departamental de municipios y comunas', originalText: `La Provincia promueve en cada uno de los departamentos la asociación de los municipios y las comunas para intereses comunes, que no podrá alterar el alcance y contenidos de la autonomía local reconocida en esta Constitución.`, currentText: `La Provincia promueve en cada uno de los departamentos la asociación de los municipios y las comunas para intereses comunes, que no podrá alterar el alcance y contenidos de la autonomía local reconocida en esta Constitución.`, plainLanguageExplanation: 'La Provincia promueve la asociación de municipios y comunas dentro de cada departamento para fines comunes, sin afectar la autonomía local reconocida constitucionalmente.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['asociación municipal', 'departamento', 'autonomía local', 'cooperación intercomunal'], order: 253, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-255', lawId: 'const-entre-rios', number: '255', title: 'Acuerdo intermunicipal departamental — fines y requisitos', originalText: `El acuerdo intermunicipal, intercomunal o interjurisdiccional deberá ser celebrado con el concurso de las dos terceras partes de los municipios y comunas existentes en el departamento. El instrumento constitutivo establecerá las funciones de su órgano común garantizando la participación igualitaria de sus integrantes y sus recursos económicos, y deberá orientarse a los siguientes fines: a) Promover en el ámbito departamental el acceso de toda la población a los servicios públicos de carácter municipal o comunal. b) Impulsar la cooperación recíproca entre sus integrantes para atender los intereses comunes, a través de la afectación de recursos locales, la coordinación de servicios y la ejecución de políticas concertadas. c) Proveer a la asistencia entre sus integrantes en condiciones de reciprocidad en materia jurídica, técnica, económica y de toda aquella que se considere conducente. d) Colaborar con el ejercicio de competencias provinciales y nacionales, debiendo en el convenio respectivo determinar su alcance.`, currentText: `El acuerdo intermunicipal, intercomunal o interjurisdiccional deberá ser celebrado con el concurso de las dos terceras partes de los municipios y comunas existentes en el departamento. El instrumento constitutivo establecerá las funciones de su órgano común garantizando la participación igualitaria de sus integrantes y sus recursos económicos, y deberá orientarse a los siguientes fines: a) Promover en el ámbito departamental el acceso de toda la población a los servicios públicos de carácter municipal o comunal. b) Impulsar la cooperación recíproca entre sus integrantes para atender los intereses comunes, a través de la afectación de recursos locales, la coordinación de servicios y la ejecución de políticas concertadas. c) Proveer a la asistencia entre sus integrantes en condiciones de reciprocidad en materia jurídica, técnica, económica y de toda aquella que se considere conducente. d) Colaborar con el ejercicio de competencias provinciales y nacionales, debiendo en el convenio respectivo determinar su alcance.`, plainLanguageExplanation: 'El acuerdo intermunicipal requiere 2/3 de los municipios y comunas del departamento. Busca promover el acceso a servicios, la cooperación, la asistencia recíproca y la coordinación con competencias provinciales y nacionales.', practicalEffects: [], examples: ['Los municipios de un departamento forman un consorcio para gestionar conjuntamente el servicio de agua potable.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acuerdo intermunicipal', 'departamento', 'cooperación', 'servicios públicos municipales'], order: 254, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-256', lawId: 'const-entre-rios', number: '256', title: 'Facultades de la organización departamental', originalText: `La ley precisará los alcances de las facultades, recursos y obligaciones de la organización departamental.`, currentText: `La ley precisará los alcances de las facultades, recursos y obligaciones de la organización departamental.`, plainLanguageExplanation: 'La ley fijará las facultades, recursos y obligaciones de la organización departamental de municipios y comunas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['organización departamental', 'facultades', 'recursos', 'ley reglamentaria'], order: 255, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-257', lawId: 'const-entre-rios', number: '257', title: 'Educación como derecho humano fundamental', originalText: `La educación es el derecho humano fundamental de aprender durante toda la vida accediendo a los conocimientos y a la información necesarios en el ejercicio pleno de la ciudadanía, para una sociedad libre, igualitaria, democrática, justa, participativa y culturalmente diversa. El Estado asume la obligación primordial e indelegable de proveer a la educación común, como instrumento de movilidad social, con la participación de la familia y de las instituciones de gestión privada reconocidas. Promueve la erradicación del analfabetismo, imparte la educación sexual para todos los niveles y modalidades del sistema educativo, garantiza el acceso universal a los bienes culturales y la vinculación ética entre educación, trabajo y ambiente.`, currentText: `La educación es el derecho humano fundamental de aprender durante toda la vida accediendo a los conocimientos y a la información necesarios en el ejercicio pleno de la ciudadanía, para una sociedad libre, igualitaria, democrática, justa, participativa y culturalmente diversa. El Estado asume la obligación primordial e indelegable de proveer a la educación común, como instrumento de movilidad social, con la participación de la familia y de las instituciones de gestión privada reconocidas. Promueve la erradicación del analfabetismo, imparte la educación sexual para todos los niveles y modalidades del sistema educativo, garantiza el acceso universal a los bienes culturales y la vinculación ética entre educación, trabajo y ambiente.`, plainLanguageExplanation: 'La educación es un derecho humano fundamental. El Estado tiene la obligación indelegable de proveerla como instrumento de movilidad social, promoviendo la erradicación del analfabetismo y garantizando educación sexual y acceso a bienes culturales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación', 'derecho humano', 'movilidad social', 'educación sexual', 'acceso universal'], order: 256, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-258', lawId: 'const-entre-rios', number: '258', title: 'Gratuidad y obligatoriedad de la educación pública', originalText: `El Estado garantiza a los habitantes la igualdad de oportunidades para el acceso, permanencia, reingreso y egreso en todos los niveles de la educación obligatoria. La educación común en la Provincia es gratuita y laica en los niveles inicial, primario, secundario y superior de las instituciones de gestión estatal. La obligatoriedad corresponde a los niveles inicial, primario y secundario o al período mayor que la legislación determine.`, currentText: `El Estado garantiza a los habitantes la igualdad de oportunidades para el acceso, permanencia, reingreso y egreso en todos los niveles de la educación obligatoria. La educación común en la Provincia es gratuita y laica en los niveles inicial, primario, secundario y superior de las instituciones de gestión estatal. La obligatoriedad corresponde a los niveles inicial, primario y secundario o al período mayor que la legislación determine.`, plainLanguageExplanation: 'La educación pública es gratuita y laica en todos los niveles de gestión estatal. La obligatoriedad abarca los niveles inicial, primario y secundario.', practicalEffects: [], examples: ['Un alumno en un establecimiento estatal de nivel secundario no paga aranceles porque la educación pública es gratuita y laica.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación gratuita', 'laicismo', 'obligatoriedad', 'niveles educativos'], order: 257, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-259', lawId: 'const-entre-rios', number: '259', title: 'Obligación escolar del Estado y los habitantes', originalText: `La educación que el Estado se obliga a impartir y los habitantes están obligados a recibir deberá proveerse en escuelas públicas, de gestión estatal o privada, que ofrezcan garantías de estabilidad y eficiencia educativa, ajustándose a las normas que se dicten en la materia. La obligación escolar se considerará incumplida por el Estado siempre que no se acredite el mínimo de educación obligatoria establecido por esta Constitución.`, currentText: `La educación que el Estado se obliga a impartir y los habitantes están obligados a recibir deberá proveerse en escuelas públicas, de gestión estatal o privada, que ofrezcan garantías de estabilidad y eficiencia educativa, ajustándose a las normas que se dicten en la materia. La obligación escolar se considerará incumplida por el Estado siempre que no se acredite el mínimo de educación obligatoria establecido por esta Constitución.`, plainLanguageExplanation: 'El Estado incumple su obligación si no garantiza el mínimo educativo constitucional. Tanto los establecimientos estatales como los privados deben ofrecer garantías de estabilidad y eficiencia.', practicalEffects: [], examples: ['Si en una localidad no hay escuela secundaria y el Estado no la provee, incumple su obligación constitucional educativa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligación educativa', 'Estado', 'establecimientos educativos', 'educación obligatoria'], order: 258, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-260', lawId: 'const-entre-rios', number: '260', title: 'Lineamientos curriculares transversales', originalText: `Los lineamientos curriculares para cada nivel educativo obligatorio, integrarán, de manera transversal, educación con: cultura, derechos humanos, culturas ancestrales, cooperativismo y mutualismo, educación sexual, para la paz y para la no violencia, trabajo, ciencia y tecnología. La educación ambiental, los lenguajes artísticos, la educación física y el deporte escolar son inherentes a la educación común. Los institutos de formación superior y del personal de seguridad incluirán los derechos humanos en sus planes de estudio.`, currentText: `Los lineamientos curriculares para cada nivel educativo obligatorio, integrarán, de manera transversal, educación con: cultura, derechos humanos, culturas ancestrales, cooperativismo y mutualismo, educación sexual, para la paz y para la no violencia, trabajo, ciencia y tecnología. La educación ambiental, los lenguajes artísticos, la educación física y el deporte escolar son inherentes a la educación común. Los institutos de formación superior y del personal de seguridad incluirán los derechos humanos en sus planes de estudio.`, plainLanguageExplanation: 'Los currículos deben integrar transversalmente derechos humanos, culturas ancestrales, cooperativismo, educación sexual, ambiente, artes y deporte. Los institutos de formación superior y policial deben incluir derechos humanos.', practicalEffects: [], examples: ['Un plan de estudios secundario en Entre Ríos debe incluir educación ambiental y derechos humanos de forma transversal.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lineamientos curriculares', 'transversalidad', 'derechos humanos', 'educación ambiental', 'cooperativismo'], order: 259, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-261', lawId: 'const-entre-rios', number: '261', title: 'Sistema educativo provincial — carácter y articulación', originalText: `El sistema educativo provincial es de carácter esencialmente nacional. Integrará las realidades provinciales, locales y regionales. Asegura el derecho de los padres a la libre elección del establecimiento educativo para sus hijos, la formación vinculada con el trabajo social y productivo, la creatividad, el pensamiento crítico y autónomo y la relación escuela, ciencia y tecnología. El Estado articulará acciones con los municipios, comunas y organizaciones de la comunidad, dirigidas a la creación y funcionamiento de escuelas, pudiendo contribuir a su sostenimiento siempre que funcionen con las garantías aquí establecidas.`, currentText: `El sistema educativo provincial es de carácter esencialmente nacional. Integrará las realidades provinciales, locales y regionales. Asegura el derecho de los padres a la libre elección del establecimiento educativo para sus hijos, la formación vinculada con el trabajo social y productivo, la creatividad, el pensamiento crítico y autónomo y la relación escuela, ciencia y tecnología. El Estado articulará acciones con los municipios, comunas y organizaciones de la comunidad, dirigidas a la creación y funcionamiento de escuelas, pudiendo contribuir a su sostenimiento siempre que funcionen con las garantías aquí establecidas.`, plainLanguageExplanation: 'El sistema educativo es de carácter nacional pero integra realidades locales. Garantiza la libre elección de establecimiento y vincula educación con trabajo, creatividad y tecnología. El Estado articula con municipios y organizaciones comunitarias.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sistema educativo', 'libre elección', 'educación y trabajo', 'articulación comunitaria'], order: 260, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-262', lawId: 'const-entre-rios', number: '262', title: 'Acciones del Consejo General de Educación para zonas desfavorables', originalText: `El Consejo General de Educación dispondrá acciones positivas para brindar progresivamente a las escuelas de zonas desfavorables, alejadas del radio urbano, periurbanas y rurales, los recursos necesarios para fortalecer el arraigo del docente al mismo, la permanencia de los alumnos en el sistema y doble escolaridad que permita complementar lo curricular con actividades recreativo formativas. Dispondrá la creación de instancias educativas y de capacitación para las personas privadas de su libertad en las unidades penitenciarias provinciales.`, currentText: `El Consejo General de Educación dispondrá acciones positivas para brindar progresivamente a las escuelas de zonas desfavorables, alejadas del radio urbano, periurbanas y rurales, los recursos necesarios para fortalecer el arraigo del docente al mismo, la permanencia de los alumnos en el sistema y doble escolaridad que permita complementar lo curricular con actividades recreativo formativas. Dispondrá la creación de instancias educativas y de capacitación para las personas privadas de su libertad en las unidades penitenciarias provinciales.`, plainLanguageExplanation: 'El Consejo General de Educación debe apoyar progresivamente a escuelas rurales y desfavorecidas para retener docentes, mantener a los alumnos en el sistema y ofrecer doble escolaridad. También debe proveer educación en unidades penitenciarias.', practicalEffects: [], examples: ['Una escuela rural aislada recibe mayores recursos y vivienda docente por aplicación de las acciones positivas del Consejo General de Educación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo General de Educación', 'escuelas rurales', 'acciones positivas', 'doble escolaridad', 'educación penitenciaria'], order: 261, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-263', lawId: 'const-entre-rios', number: '263', title: 'Consejo General de Educación — integración y autonomía', originalText: `La organización y dirección técnica y administrativa de la enseñanza común, será confiada a un Consejo General de Educación, autónomo en sus funciones, compuesto por un director general de escuelas, que ejercerá su presidencia y cuatro vocales, nombrados, uno y otros, por el Poder Ejecutivo, con acuerdo del Senado, por un período de cuatro años. Sus atribuciones serán deslindadas por la ley.`, currentText: `La organización y dirección técnica y administrativa de la enseñanza común, será confiada a un Consejo General de Educación, autónomo en sus funciones, compuesto por un director general de escuelas, que ejercerá su presidencia y cuatro vocales, nombrados, uno y otros, por el Poder Ejecutivo, con acuerdo del Senado, por un período de cuatro años. Sus atribuciones serán deslindadas por la ley.`, plainLanguageExplanation: 'El Consejo General de Educación es el órgano autónomo que dirige la educación común. Se integra por un Director General de Escuelas y cuatro vocales designados por el Ejecutivo con acuerdo del Senado por 4 años.', practicalEffects: [], examples: ['El Poder Ejecutivo designa al Director General de Escuelas con acuerdo del Senado; sin ese acuerdo la designación no es válida.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo General de Educación', 'Director General de Escuelas', 'autonomía', 'acuerdo del Senado'], order: 262, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-264', lawId: 'const-entre-rios', number: '264', title: 'Director General de Escuelas — requisitos y funciones', originalText: `El director general de escuelas es responsable del gobierno y administración de la educación. Además de las condiciones que establezca la ley, debe ser argentino nativo o naturalizado y docente con diez años de ejercicio en cualquier modalidad. Iguales condiciones deben reunir los vocales. El Consejo General de Educación, mantendrá actualizada y en condiciones de accesibilidad pública, una base informativa y estadística que facilite el planeamiento del sistema.`, currentText: `El director general de escuelas es responsable del gobierno y administración de la educación. Además de las condiciones que establezca la ley, debe ser argentino nativo o naturalizado y docente con diez años de ejercicio en cualquier modalidad. Iguales condiciones deben reunir los vocales. El Consejo General de Educación, mantendrá actualizada y en condiciones de accesibilidad pública, una base informativa y estadística que facilite el planeamiento del sistema.`, plainLanguageExplanation: 'El Director General de Escuelas debe ser argentino y docente con 10 años de ejercicio. El Consejo General mantiene una base pública de datos estadísticos para el planeamiento educativo.', practicalEffects: [], examples: ['Un pedagogo extranjero no puede ser nombrado Director General de Escuelas porque la Constitución exige ciudadanía argentina.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Director General de Escuelas', 'requisitos', 'docente', 'estadística educativa'], order: 263, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-265', lawId: 'const-entre-rios', number: '265', title: 'Jerarquización de instituciones educativas', originalText: `El Estado impulsa la jerarquización funcional de las instituciones educativas. Incorpora la comunidad educativa, municipios y comunas e instituciones intermedias en la gestión. Las instituciones escolares dispondrán de plantas funcionales completas, que incluyan equipos interdisciplinarios.`, currentText: `El Estado impulsa la jerarquización funcional de las instituciones educativas. Incorpora la comunidad educativa, municipios y comunas e instituciones intermedias en la gestión. Las instituciones escolares dispondrán de plantas funcionales completas, que incluyan equipos interdisciplinarios.`, plainLanguageExplanation: 'El Estado promueve la jerarquización de las escuelas, involucra a la comunidad en la gestión y exige plantas funcionales completas con equipos interdisciplinarios en cada institución.', practicalEffects: [], examples: ['Una escuela secundaria debe contar con psicopedagogo, asistente social y orientador vocacional como parte de su planta funcional completa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['instituciones educativas', 'planta funcional', 'equipos interdisciplinarios', 'comunidad educativa'], order: 264, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-266', lawId: 'const-entre-rios', number: '266', title: 'Consejo departamental de educación', originalText: `Habrá en cada departamento un consejo departamental de educación, en forma honoraria, con participación de la comunidad educativa, los municipios y comunas.`, currentText: `Habrá en cada departamento un consejo departamental de educación, en forma honoraria, con participación de la comunidad educativa, los municipios y comunas.`, plainLanguageExplanation: 'Cada departamento tendrá un consejo departamental de educación integrado honorariamente por representantes de la comunidad educativa, municipios y comunas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['consejo departamental de educación', 'participación', 'municipios', 'comunas'], order: 265, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-267', lawId: 'const-entre-rios', number: '267', title: 'Docentes titulados — perfeccionamiento y libertad de cátedra', originalText: `La educación es confiada a docentes titulados. El Estado asegura el respeto a la labor del maestro y la formación docente de grado, y se obliga a brindarles perfeccionamiento gratuito, permanente y en servicio. El docente ejerce su profesión sobre la base de la responsabilidad, el respeto a la libertad de cátedra y de enseñanza, en el marco de las normas pedagógicas y curriculares establecidas por el Consejo General de Educación.`, currentText: `La educación es confiada a docentes titulados. El Estado asegura el respeto a la labor del maestro y la formación docente de grado, y se obliga a brindarles perfeccionamiento gratuito, permanente y en servicio. El docente ejerce su profesión sobre la base de la responsabilidad, el respeto a la libertad de cátedra y de enseñanza, en el marco de las normas pedagógicas y curriculares establecidas por el Consejo General de Educación.`, plainLanguageExplanation: 'Solo docentes titulados pueden enseñar. El Estado garantiza perfeccionamiento docente gratuito y permanente. Los docentes gozan de libertad de cátedra dentro del marco curricular del Consejo General de Educación.', practicalEffects: [], examples: ['Un docente tiene derecho a acceder gratuitamente a cursos de capacitación organizados por el Consejo General de Educación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['docentes titulados', 'perfeccionamiento', 'libertad de cátedra', 'Consejo General de Educación'], order: 266, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-268', lawId: 'const-entre-rios', number: '268', title: 'Presupuesto educativo mínimo garantizado', originalText: `El presupuesto educativo para atender el fondo de educación común esta formado por el veintiocho por ciento, como mínimo, de las rentas generales disponibles de la Provincia y por los demás recursos que la ley establezca. Se destinará al sostenimiento de la educación obligatoria, al pago de los gastos y sueldos que ella demande y a la extensión de su obligatoriedad. Las rentas escolares de toda la Provincia serán administradas por el Consejo General de Educación que rendirá cuenta anualmente ante el Tribunal de Cuentas, de la administración e inversión de los fondos que le fueren entregados.`, currentText: `El presupuesto educativo para atender el fondo de educación común esta formado por el veintiocho por ciento, como mínimo, de las rentas generales disponibles de la Provincia y por los demás recursos que la ley establezca. Se destinará al sostenimiento de la educación obligatoria, al pago de los gastos y sueldos que ella demande y a la extensión de su obligatoriedad. Las rentas escolares de toda la Provincia serán administradas por el Consejo General de Educación que rendirá cuenta anualmente ante el Tribunal de Cuentas, de la administración e inversión de los fondos que le fueren entregados.`, plainLanguageExplanation: 'La educación recibe mínimo el 28% de las rentas generales provinciales. Las rentas escolares las administra el Consejo General de Educación y rinde cuentas anualmente ante el Tribunal de Cuentas.', practicalEffects: [], examples: ['Si las rentas generales de la Provincia son $100.000, el fondo de educación no puede ser inferior a $28.000.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presupuesto educativo', '28%', 'fondo de educación', 'Consejo General de Educación', 'Tribunal de Cuentas'], order: 267, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-269', lawId: 'const-entre-rios', number: '269', title: 'Autonomía y gratuidad de la Universidad Provincial', originalText: `La Universidad Provincial tiene plena autonomía. El Estado garantiza su autarquía y gratuidad e impulsa su articulación pedagógica con los institutos dependientes del Consejo General de Educación.`, currentText: `La Universidad Provincial tiene plena autonomía. El Estado garantiza su autarquía y gratuidad e impulsa su articulación pedagógica con los institutos dependientes del Consejo General de Educación.`, plainLanguageExplanation: 'La Universidad Provincial es autónoma y autárquica. El Estado garantiza su gratuidad y promueve su articulación con los institutos educativos provinciales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Universidad Provincial', 'autonomía', 'autarquía', 'gratuidad', 'articulación pedagógica'], order: 268, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-270', lawId: 'const-entre-rios', number: '270', title: 'Becas, bibliotecas y póliza escolar', originalText: `El Estado: -Fomenta el funcionamiento de las bibliotecas escolares y populares. -Sostiene el sistema provincial de becas, destinado a los alumnos cuya situación socioeconómica, ponga en riesgo su ingreso y permanencia en el sistema educativo. -Contrata una póliza escolar obligatoria, a su cargo, para los alumnos matriculados de todos los niveles y modalidades de escuelas de gestión estatal y privadas gratuitas.`, currentText: `El Estado: -Fomenta el funcionamiento de las bibliotecas escolares y populares. -Sostiene el sistema provincial de becas, destinado a los alumnos cuya situación socioeconómica, ponga en riesgo su ingreso y permanencia en el sistema educativo. -Contrata una póliza escolar obligatoria, a su cargo, para los alumnos matriculados de todos los niveles y modalidades de escuelas de gestión estatal y privadas gratuitas.`, plainLanguageExplanation: 'El Estado fomenta bibliotecas, sostiene becas para alumnos en riesgo socioeconómico y contrata obligatoriamente una póliza de seguro escolar a su cargo para todos los alumnos de escuelas estatales y privadas gratuitas.', practicalEffects: [], examples: ['Un alumno de familia de bajos recursos puede solicitar una beca provincial para no desertar del secundario.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['becas', 'bibliotecas escolares', 'póliza escolar', 'Estado educativo', 'inclusión educativa'], order: 269, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-271', lawId: 'const-entre-rios', number: '271', title: 'Política provincial de ciencia y tecnología', originalText: `La Provincia desarrolla la política de ciencia y tecnología como bien público y garantiza la libertad de la investigación científica y tecnológica, el aprovechamiento social de los conocimientos en orden al bienestar general e impulsa el fortalecimiento de la capacidad tecnológica y creativa del sistema productivo de bienes y servicios y, en particular, de las pequeñas y medianas empresas. A fin de articular las actividades que en materia de desarrollo e investigación científica y tecnológica se realicen, habrá un sistema de ciencia y tecnología que promoverá la integración de universidades, institutos, centros de investigación públicos y privados.`, currentText: `La Provincia desarrolla la política de ciencia y tecnología como bien público y garantiza la libertad de la investigación científica y tecnológica, el aprovechamiento social de los conocimientos en orden al bienestar general e impulsa el fortalecimiento de la capacidad tecnológica y creativa del sistema productivo de bienes y servicios y, en particular, de las pequeñas y medianas empresas. A fin de articular las actividades que en materia de desarrollo e investigación científica y tecnológica se realicen, habrá un sistema de ciencia y tecnología que promoverá la integración de universidades, institutos, centros de investigación públicos y privados.`, plainLanguageExplanation: 'La ciencia y tecnología son bienes públicos. La Provincia garantiza la libertad de investigación y promueve la capacidad tecnológica de las PyMEs. Un sistema de CyT integra universidades y centros de investigación.', practicalEffects: [], examples: ['Una PyME entrerriana puede acceder a programas provinciales de innovación tecnológica financiados como política pública de CyT.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ciencia y tecnología', 'investigación', 'PyMEs', 'innovación', 'bien público'], order: 270, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-272', lawId: 'const-entre-rios', number: '272', title: 'Reforma de la Constitución por Convención especial', originalText: `La presente Constitución, no podrá ser reformada, en todo o en parte, sino por una Convención especialmente nombrada para ese efecto por el pueblo de la Provincia, en elección directa.`, currentText: `La presente Constitución, no podrá ser reformada, en todo o en parte, sino por una Convención especialmente nombrada para ese efecto por el pueblo de la Provincia, en elección directa.`, plainLanguageExplanation: 'La Constitución provincial solo puede reformarse mediante una Convención Reformadora elegida por el pueblo en elección directa.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reforma constitucional', 'Convención', 'elección directa'], order: 271, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-273', lawId: 'const-entre-rios', number: '273', title: 'Convocatoria de la Convención reformadora', originalText: `La Convención será convocada por una ley en que se declare la necesidad o conveniencia de la reforma, expresándose al mismo tiempo, si ésta debe ser general o parcial y determinando, en caso de ser parcial, los artículos o la materia sobre los cuales ha de versar la reforma. La ley que se dé con ese objeto, deberá ser sancionada con dos tercios de votos del número total de los miembros de cada cámara; y, si fuese vetada, será necesario para su promulgación, que la Asamblea insista con igual número de votos.`, currentText: `La Convención será convocada por una ley en que se declare la necesidad o conveniencia de la reforma, expresándose al mismo tiempo, si ésta debe ser general o parcial y determinando, en caso de ser parcial, los artículos o la materia sobre los cuales ha de versar la reforma. La ley que se dé con ese objeto, deberá ser sancionada con dos tercios de votos del número total de los miembros de cada cámara; y, si fuese vetada, será necesario para su promulgación, que la Asamblea insista con igual número de votos.`, plainLanguageExplanation: 'La Convención se convoca por ley declaratoria sancionada con 2/3 del total de miembros de cada Cámara. La ley debe especificar si la reforma es total o parcial y, en este último caso, los artículos a reformar.', practicalEffects: [], examples: ['Si la Legislatura quiere reformar parcialmente la Constitución, necesita 2/3 de la totalidad de cada Cámara para la ley de convocatoria.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención reformadora', 'ley declaratoria', 'dos tercios', 'reforma constitucional'], order: 272, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-274', lawId: 'const-entre-rios', number: '274', title: 'Límites de la Convención reformadora', originalText: `La Convención no podrá comprender en la reforma otros puntos que los especificados en la ley de convocatoria; pero no estará tampoco obligada a variar, suprimir o complementar, las disposiciones de la Constitución, cuando considere que no existe la necesidad o conveniencia de la reforma declarada por la ley.`, currentText: `La Convención no podrá comprender en la reforma otros puntos que los especificados en la ley de convocatoria; pero no estará tampoco obligada a variar, suprimir o complementar, las disposiciones de la Constitución, cuando considere que no existe la necesidad o conveniencia de la reforma declarada por la ley.`, plainLanguageExplanation: 'La Convención no puede reformar puntos ajenos a la ley de convocatoria, pero tampoco está obligada a modificar la Constitución si no lo considera necesario.', practicalEffects: [], examples: ['Si la ley de convocatoria solo autoriza reformar el régimen electoral, la Convención no puede modificar el Poder Judicial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención reformadora', 'límites', 'ley de convocatoria', 'reforma constitucional'], order: 273, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-275', lawId: 'const-entre-rios', number: '275', title: 'Plazo para nueva ley de reforma constitucional', originalText: `En el caso del artículo anterior, la Legislatura no podrá insistir, dictando nueva ley de reforma, mientras no hayan transcurrido por lo menos dos períodos legislativos sin contar el que correspondiera a la ley de la reforma.`, currentText: `En el caso del artículo anterior, la Legislatura no podrá insistir, dictando nueva ley de reforma, mientras no hayan transcurrido por lo menos dos períodos legislativos sin contar el que correspondiera a la ley de la reforma.`, plainLanguageExplanation: 'Si la Convención decide no reformar, la Legislatura no puede aprobar otra ley de reforma hasta que transcurran al menos 2 períodos legislativos (sin contar el de la ley rechazada).', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reforma constitucional', 'plazo', 'Legislatura', 'período legislativo'], order: 274, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-276', lawId: 'const-entre-rios', number: '276', title: 'Requisitos para ser Convencional reformador', originalText: `Para ser Convencional se requiere: ser argentino, con ciudadanía natural en ejercicio o legal después de cuatro años de obtenida y tener veinticinco años de edad. El cargo de Convencional, es compatible con cualquier otro cargo público nacional o provincial, que no sea el de gobernador, vicegobernador, ministro, presidente de municipalidad o jefe de policía.`, currentText: `Para ser Convencional se requiere: ser argentino, con ciudadanía natural en ejercicio o legal después de cuatro años de obtenida y tener veinticinco años de edad. El cargo de Convencional, es compatible con cualquier otro cargo público nacional o provincial, que no sea el de gobernador, vicegobernador, ministro, presidente de municipalidad o jefe de policía.`, plainLanguageExplanation: 'Para ser Convencional se requiere ser argentino y tener 25 años. El cargo es compatible con la mayoría de cargos públicos, excepto gobernador, vicegobernador, ministro, presidente de municipalidad o jefe de policía.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convencional', 'requisitos', 'compatibilidad', 'reforma constitucional'], order: 275, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-277', lawId: 'const-entre-rios', number: '277', title: 'Composición y elección de la Convención reformadora', originalText: `La Convención se compondrá de un número de miembros igual al de la totalidad de senadores y diputados. Serán elegidos en la misma forma que estos últimos y gozarán de las mismas inmunidades y remuneración mientras ejerzan su cargo.`, currentText: `La Convención se compondrá de un número de miembros igual al de la totalidad de senadores y diputados. Serán elegidos en la misma forma que estos últimos y gozarán de las mismas inmunidades y remuneración mientras ejerzan su cargo.`, plainLanguageExplanation: 'La Convención tiene el mismo número de miembros que el total de senadores y diputados. Se eligen igual que los legisladores y gozan de las mismas inmunidades y remuneración durante su mandato.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención reformadora', 'composición', 'elección', 'inmunidades'], order: 276, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-278', lawId: 'const-entre-rios', number: '278', title: 'Funcionamiento y sede de la Convención reformadora', originalText: `La Convención funcionará en la capital de la Provincia y se instalará en el local de la Honorable Legislatura o en el que ella misma pueda determinar. Tendrá facultades para designar su personal y confeccionar su presupuesto.`, currentText: `La Convención funcionará en la capital de la Provincia y se instalará en el local de la Honorable Legislatura o en el que ella misma pueda determinar. Tendrá facultades para designar su personal y confeccionar su presupuesto.`, plainLanguageExplanation: 'La Convención sesiona en la capital provincial, en el edificio de la Legislatura o en otro que ella determine. Designa su propio personal y elabora su presupuesto.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención reformadora', 'sede', 'capital provincial', 'presupuesto propio'], order: 277, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-279', lawId: 'const-entre-rios', number: '279', title: 'Duración de la Convención reformadora', originalText: `La Convención funcionará durante el término de un año, a contar desde la fecha de la solemne instalación, debiendo ésta producirse dentro de los noventa días de la elección de Convencionales. Podrá, asimismo, fijar el término de sus sesiones, el cual será prorrogable, no pudiendo exceder del año antes establecido.`, currentText: `La Convención funcionará durante el término de un año, a contar desde la fecha de la solemne instalación, debiendo ésta producirse dentro de los noventa días de la elección de Convencionales. Podrá, asimismo, fijar el término de sus sesiones, el cual será prorrogable, no pudiendo exceder del año antes establecido.`, plainLanguageExplanation: 'La Convención debe instalarse dentro de los 90 días de la elección y funciona por 1 año como máximo. Puede prorrogar sus sesiones dentro de ese año.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención reformadora', 'duración', 'instalación', 'sesiones'], order: 278, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-280', lawId: 'const-entre-rios', number: '280', title: 'Reglamentación de derechos declarados — plazo transitorio', originalText: `A los fines de la aplicación del artículo 62 la reglamentación de las normas, leyes y ordenanzas que declaren derechos y a la fecha de entrar en vigencia de la presente, no se encuentren sancionadas, tendrá un período de cuatro años para realizarla en su respectivo ámbito de competencia.`, currentText: `A los fines de la aplicación del artículo 62 la reglamentación de las normas, leyes y ordenanzas que declaren derechos y a la fecha de entrar en vigencia de la presente, no se encuentren sancionadas, tendrá un período de cuatro años para realizarla en su respectivo ámbito de competencia.`, plainLanguageExplanation: 'Los poderes públicos tienen 4 años para reglamentar las normas que declaren derechos y que aún no contaran con reglamentación al entrar en vigencia esta Constitución.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'reglamentación', 'derechos declarados', 'plazo'], order: 279, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-281', lawId: 'const-entre-rios', number: '281', title: 'Sanción de leyes orgánicas y reglamentos provisorios', originalText: `La Legislatura sancionará las leyes orgánicas y las reformas a las leyes existentes que fueran menester para el funcionamiento de las instituciones creadas por esta Constitución y las modificaciones introducidas por la misma. Si transcurriera más de un año sin sancionarse alguna de esas leyes o reformas, el Poder Ejecutivo quedará facultado para dictar, con carácter provisorio, los decretos reglamentarios que exija la aplicación de los nuevos preceptos constitucionales. Dichos reglamentos quedarán sin efecto con la sanción de las leyes respectivas que producirán la derogación automática de aquéllos.`, currentText: `La Legislatura sancionará las leyes orgánicas y las reformas a las leyes existentes que fueran menester para el funcionamiento de las instituciones creadas por esta Constitución y las modificaciones introducidas por la misma. Si transcurriera más de un año sin sancionarse alguna de esas leyes o reformas, el Poder Ejecutivo quedará facultado para dictar, con carácter provisorio, los decretos reglamentarios que exija la aplicación de los nuevos preceptos constitucionales. Dichos reglamentos quedarán sin efecto con la sanción de las leyes respectivas que producirán la derogación automática de aquéllos.`, plainLanguageExplanation: 'La Legislatura tiene 1 año para sancionar las leyes orgánicas que requiere la nueva Constitución. Si no lo hace, el Ejecutivo puede dictar decretos provisorios que quedan sin efecto al aprobarse las leyes respectivas.', practicalEffects: [], examples: ['Si la Legislatura no sanciona la ley orgánica del Consejo de la Magistratura en 1 año, el Ejecutivo puede dictar un decreto provisorio para su funcionamiento.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'leyes orgánicas', 'decretos provisorios', 'Poder Ejecutivo', 'Legislatura'], order: 280, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-282', lawId: 'const-entre-rios', number: '282', title: 'Leyes orgánicas vigentes — compatibilidad transitoria', originalText: `Las actuales leyes orgánicas continuarán en vigencia, en lo que sean compatibles con esta Constitución, hasta que la Legislatura sancione las que correspondan a las disposiciones de este estatuto constitucional.`, currentText: `Las actuales leyes orgánicas continuarán en vigencia, en lo que sean compatibles con esta Constitución, hasta que la Legislatura sancione las que correspondan a las disposiciones de este estatuto constitucional.`, plainLanguageExplanation: 'Las leyes orgánicas existentes siguen vigentes en todo lo que no contradiga la nueva Constitución, hasta que la Legislatura dicte las nuevas leyes que esta Constitución requiere.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'leyes orgánicas', 'compatibilidad', 'legislatura'], order: 281, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-283', lawId: 'const-entre-rios', number: '283', title: 'Prohibición transitoria de nombrar familiares en empleos públicos', originalText: `Hasta tanto se sancione la ley que establezca y determine los cargos políticos sin estabilidad que pueden ser designados sin concurso, los funcionarios de los organismos, reparticiones públicas de la provincia, los municipios y las comunas que gozan de la facultad de nombramiento de personal, no podrán ejercerla en su entidad respecto de sus familiares comprendidos en el tercer grado de consanguinidad o de afinidad, en ningún empleo público permanente.`, currentText: `Hasta tanto se sancione la ley que establezca y determine los cargos políticos sin estabilidad que pueden ser designados sin concurso, los funcionarios de los organismos, reparticiones públicas de la provincia, los municipios y las comunas que gozan de la facultad de nombramiento de personal, no podrán ejercerla en su entidad respecto de sus familiares comprendidos en el tercer grado de consanguinidad o de afinidad, en ningún empleo público permanente.`, plainLanguageExplanation: 'En forma transitoria, ningún funcionario con potestad de nombramiento puede designar en cargos permanentes a familiares hasta el 3.° grado de consanguinidad o afinidad, hasta que se dicte la ley regulatoria.', practicalEffects: [], examples: ['Un intendente no puede nombrar a su hermano (2.° grado) en un cargo permanente hasta que se sancione la ley regulatoria de cargos políticos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'nepotismo', 'empleo público', 'consanguinidad', 'nombramiento'], order: 282, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-284', lawId: 'const-entre-rios', number: '284', title: 'Competencia transitoria del STJ en materia contencioso-administrativa', originalText: `Hasta tanto se dicten las normas de creación de los tribunales inferiores en lo contencioso administrativo, mantendrá su competencia originaria en la materia el Superior Tribunal de Justicia.`, currentText: `Hasta tanto se dicten las normas de creación de los tribunales inferiores en lo contencioso administrativo, mantendrá su competencia originaria en la materia el Superior Tribunal de Justicia.`, plainLanguageExplanation: 'Hasta que se creen los tribunales contencioso-administrativos inferiores, el Superior Tribunal de Justicia sigue siendo el órgano competente en esa materia en instancia originaria.', practicalEffects: [], examples: ['Una empresa que impugna un acto administrativo provincial debe litigar ante el Superior Tribunal de Justicia hasta que se creen los juzgados contencioso-administrativos.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'contencioso-administrativo', 'Superior Tribunal de Justicia', 'competencia'], order: 283, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-285', lawId: 'const-entre-rios', number: '285', title: 'Decreto 39/03 — vigencia transitoria del Consejo de la Magistratura', originalText: `Hasta tanto se dicte la norma reglamentaria del Consejo de la Magistratura seguirá rigiendo el Decreto Nro. 39/03 del Poder Ejecutivo y sus modificatorios.`, currentText: `Hasta tanto se dicte la norma reglamentaria del Consejo de la Magistratura seguirá rigiendo el Decreto Nro. 39/03 del Poder Ejecutivo y sus modificatorios.`, plainLanguageExplanation: 'Hasta que se sancione la ley del Consejo de la Magistratura, su funcionamiento se rige por el Decreto 39/03 del Poder Ejecutivo y sus modificaciones.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'Consejo de la Magistratura', 'Decreto 39/03', 'reglamentación'], order: 284, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-286', lawId: 'const-entre-rios', number: '286', title: 'Juzgados de paz legos — transformación progresiva en letrados', originalText: `Los juzgados de paz legos, pasarán a ser juzgados de paz letrados cuando se produzcan las vacancias de sus titulares, excepto que estén ocupados por abogados, en cuyo caso la transformación será automática.`, currentText: `Los juzgados de paz legos, pasarán a ser juzgados de paz letrados cuando se produzcan las vacancias de sus titulares, excepto que estén ocupados por abogados, en cuyo caso la transformación será automática.`, plainLanguageExplanation: 'Los juzgados de paz sin jueces letrados se transformarán en juzgados letrados al producirse la vacante. Si el titular ya es abogado, la transformación opera en forma automática.', practicalEffects: [], examples: ['Si el juez de paz lego de un municipio renuncia, su juzgado pasa automáticamente a ser juzgado de paz letrado.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'juzgados de paz', 'legos', 'letrados', 'vacante'], order: 285, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-287', lawId: 'const-entre-rios', number: '287', title: 'Libertad condicional — competencia transitoria del juez de ejecución', originalText: `Hasta tanto se dicte la norma que determine los órganos competentes para resolver las solicitudes de libertad condicional de los penados, el juez de ejecución de penas y medidas de seguridad resolverá sobre el trámite respectivo que deberá asegurar inexcusablemente la asistencia letrada del solicitante y la intervención del Ministerio Fiscal durante todo el desarrollo del mismo, siendo sus resoluciones recurribles.`, currentText: `Hasta tanto se dicte la norma que determine los órganos competentes para resolver las solicitudes de libertad condicional de los penados, el juez de ejecución de penas y medidas de seguridad resolverá sobre el trámite respectivo que deberá asegurar inexcusablemente la asistencia letrada del solicitante y la intervención del Ministerio Fiscal durante todo el desarrollo del mismo, siendo sus resoluciones recurribles.`, plainLanguageExplanation: 'Transitoriamente, el juez de ejecución de penas resuelve las solicitudes de libertad condicional, garantizando asistencia letrada y participación del Ministerio Fiscal. Sus resoluciones son recurribles.', practicalEffects: [], examples: ['Un condenado que solicita libertad condicional tramita el pedido ante el juez de ejecución, con su abogado y el Fiscal actuando en el expediente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'libertad condicional', 'juez de ejecución', 'Ministerio Fiscal', 'asistencia letrada'], order: 286, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-288', lawId: 'const-entre-rios', number: '288', title: 'Integración de la Cámara de Diputados — artículo 96 transitorio', originalText: `La integración dispuesta en el artículo 96 de la Cámara de Diputados comenzará a regir cuando se produzca su renovación.`, currentText: `La integración dispuesta en el artículo 96 de la Cámara de Diputados comenzará a regir cuando se produzca su renovación.`, plainLanguageExplanation: 'La nueva composición de la Cámara de Diputados prevista en el artículo 96 entrará en vigencia recién cuando se produzca la renovación de ese cuerpo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'Cámara de Diputados', 'integración', 'renovación', 'artículo 96'], order: 287, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-289', lawId: 'const-entre-rios', number: '289', title: 'Artículo 161 — reelección del gobernador, aplicación inmediata', originalText: `La disposición del artículo 161 será de aplicación inmediata, no se computarán a los fines del citado dispositivo los mandatos cumplidos. Se considerará al actual período de gobierno como primero a los fines del artículo 161.`, currentText: `La disposición del artículo 161 será de aplicación inmediata, no se computarán a los fines del citado dispositivo los mandatos cumplidos. Se considerará al actual período de gobierno como primero a los fines del artículo 161.`, plainLanguageExplanation: 'El límite de mandatos del gobernador (art. 161) rige de inmediato. Los mandatos anteriores no se computan; el período en curso al sancionarse la Constitución se cuenta como el primero.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'gobernador', 'reelección', 'límite de mandatos', 'artículo 161'], order: 288, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-290', lawId: 'const-entre-rios', number: '290', title: 'Reformas municipales de la Sección IX — vigencia diferida', originalText: `Las reformas introducidas en la Sección IX, artículos 233, 234, 235, 236 y 253, regirán a partir del próximo período de gobierno, siendo aplicable hasta el vencimiento de los actuales mandatos lo dispuesto por el Régimen Municipal vigente.`, currentText: `Las reformas introducidas en la Sección IX, artículos 233, 234, 235, 236 y 253, regirán a partir del próximo período de gobierno, siendo aplicable hasta el vencimiento de los actuales mandatos lo dispuesto por el Régimen Municipal vigente.`, plainLanguageExplanation: 'Las reformas de los artículos 233, 234, 235, 236 y 253 sobre el régimen municipal entran en vigor desde el próximo período de gobierno; hasta entonces rige el Régimen Municipal anterior.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'régimen municipal', 'Sección IX', 'vigencia diferida'], order: 289, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-291', lawId: 'const-entre-rios', number: '291', title: 'Segundo mandato de presidentes municipales — aplicación transitoria del art. 234', originalText: `A los efectos de garantizar la aplicación del artículo 234, se establece que aquellos ciudadanos que a la fecha de la sanción de esta Constitución se encontraren desempeñando su segundo mandato consecutivo como presidentes municipales, sólo podrán en lo sucesivo ser electos en períodos alternados.`, currentText: `A los efectos de garantizar la aplicación del artículo 234, se establece que aquellos ciudadanos que a la fecha de la sanción de esta Constitución se encontraren desempeñando su segundo mandato consecutivo como presidentes municipales, sólo podrán en lo sucesivo ser electos en períodos alternados.`, plainLanguageExplanation: 'Un presidente municipal que está en su segundo mandato consecutivo al sancionarse la Constitución solo podrá ser electo en períodos alternados, aplicando de inmediato el límite de reelección del art. 234.', practicalEffects: [], examples: ['Un intendente que cumplía su segundo mandato en 2008 no puede ser reelecto en 2011 pero sí en 2015.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'presidente municipal', 'reelección', 'períodos alternados', 'artículo 234'], order: 290, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-292', lawId: 'const-entre-rios', number: '292', title: 'Incremento gradual de remesas coparticipables — plazo cinco años desde 2010', originalText: `A los efectos del cumplimiento del artículo 246, el gobierno provincial deberá incrementar anual, gradual, igual y proporcionalmente, las remesas en un plazo no mayor a cinco años, a partir del ejercicio fiscal dos mil diez.`, currentText: `A los efectos del cumplimiento del artículo 246, el gobierno provincial deberá incrementar anual, gradual, igual y proporcionalmente, las remesas en un plazo no mayor a cinco años, a partir del ejercicio fiscal dos mil diez.`, plainLanguageExplanation: 'El Gobierno provincial debió aumentar en forma gradual y proporcional las remesas coparticipables a municipios y comunas hasta alcanzar el nivel exigido por el art. 246, completando el proceso en 2015.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'coparticipación', 'remesas', 'incremento gradual', 'artículo 246'], order: 291, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-293', lawId: 'const-entre-rios', number: '293', title: 'Automaticidad de la coparticipación — plazo máximo doce meses', originalText: `Una ley reglamentará la implementación de la automaticidad de la remisión de fondos coparticipables a los municipios y comunas que establece el artículo 246 de este capítulo. Establécese un plazo máximo improrrogable de doce meses, para la puesta en vigencia de esta norma.`, currentText: `Una ley reglamentará la implementación de la automaticidad de la remisión de fondos coparticipables a los municipios y comunas que establece el artículo 246 de este capítulo. Establécese un plazo máximo improrrogable de doce meses, para la puesta en vigencia de esta norma.`, plainLanguageExplanation: 'La Legislatura tuvo 12 meses improrrogables para dictar la ley que instrumenta la remisión automática de fondos coparticipables a municipios y comunas según el art. 246.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'coparticipación', 'automaticidad', 'plazo', 'municipios'], order: 292, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-294', lawId: 'const-entre-rios', number: '294', title: 'Municipios de segunda categoría — derechos adquiridos y art. 234', originalText: `Los municipios de segunda categoría, aún cuando no alcancen a la fecha de sanción de la presente el número de habitantes exigido por el artículo 230, mantendrán la condición adquirida. Para el caso de tales municipios se considerará la vigencia de las disposiciones del artículo 234 a partir de la próxima elección municipal, dado que sus integrantes resultaron electos como miembros de la junta de fomento, no como titulares del departamento ejecutivo.`, currentText: `Los municipios de segunda categoría, aún cuando no alcancen a la fecha de sanción de la presente el número de habitantes exigido por el artículo 230, mantendrán la condición adquirida. Para el caso de tales municipios se considerará la vigencia de las disposiciones del artículo 234 a partir de la próxima elección municipal, dado que sus integrantes resultaron electos como miembros de la junta de fomento, no como titulares del departamento ejecutivo.`, plainLanguageExplanation: 'Los municipios de segunda categoría conservan su categoría aunque no alcancen el mínimo de habitantes del art. 230. Las reglas de reelección del art. 234 se aplican desde la próxima elección municipal.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'municipios segunda categoría', 'derechos adquiridos', 'artículo 234', 'categorización'], order: 293, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-295', lawId: 'const-entre-rios', number: '295', title: 'Juramento de observancia de la Constitución', originalText: `Se encomienda a los titulares de los poderes del Estado la recepción del juramento de observancia de esta Constitución a quienes se desempeñen en ellos.`, currentText: `Se encomienda a los titulares de los poderes del Estado la recepción del juramento de observancia de esta Constitución a quienes se desempeñen en ellos.`, plainLanguageExplanation: 'Los titulares de cada poder del Estado (Ejecutivo, Legislativo y Judicial) deben tomar juramento de cumplir esta Constitución a todos los funcionarios que actúen en su ámbito.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'juramento', 'observancia', 'poderes del Estado'], order: 294, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-296', lawId: 'const-entre-rios', number: '296', title: 'Fecha de entrada en vigencia — 1° de noviembre de 2008', originalText: `La presente Constitución regirá desde 1º de noviembre de dos mil ocho.`, currentText: `La presente Constitución regirá desde 1º de noviembre de dos mil ocho.`, plainLanguageExplanation: 'Esta Constitución provincial entró en vigencia el 1.° de noviembre de 2008.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposición transitoria', 'vigencia', '2008', 'constitución provincial'], order: 295, segments: [], amendments: [] },
  { id: 'const-entre-rios-art-297', lawId: 'const-entre-rios', number: '297', title: 'Promulgación y firmantes de la Constitución', originalText: `Téngase por ley fundamental de la Provincia, publíquese, regístrese y comuníquese para que se cumpla. Firmantes Dr. Jorge Pedro Busti.- Presidente Graciela Pasi de Garelli.- Prosecretaria Dr. José A. Reviriego.- Secretario.`, currentText: `Téngase por ley fundamental de la Provincia, publíquese, regístrese y comuníquese para que se cumpla. Firmantes Dr. Jorge Pedro Busti.- Presidente Graciela Pasi de Garelli.- Prosecretaria Dr. José A. Reviriego.- Secretario.`, plainLanguageExplanation: 'Cláusula de promulgación de la Constitución, firmada por el presidente de la Convención Constituyente Dr. Jorge Pedro Busti y sus secretarios.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación', 'firmantes', 'Convención Constituyente', 'Jorge Pedro Busti'], order: 296, segments: [], amendments: [] },
];
